window.HADITH_CACHE["nasai_8"] = {"4001":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ يَعْنِي ابْنَ جَعْفَرٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي حَرْمَلَةَ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اقْتَنَى كَلْبًا إِلَّا كَلْبَ مَاشِيَةٍ أَوْ كَلْبَ صَيْدٍ نَقَصَ مِنْ عَمَلِهِ كُلَّ يَوْمٍ قِيرَاطٌقَالَ عَبْدُ اللَّهِ وَقَالَ أَبُو هُرَيْرَةَ أَوْ كَلْبَ حَرْثٍ","id":"Telah mengabarkan kepada kami [Ali bin Hujr], ia berkata; telah menceritakan kepada kami [Isma'il yaitu Ibnu Ja'far], ia berkata; telah menceritakan kepada kami [Muhammad bin Abu Harmalah] dari [Salim bin Abdullah] dari [Ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"\"Barang siapa yang memeliha anjing kecuali anjing penjaga hewan ternak, pemburu maka telah berkurang dari pahalanya setiap hari sebanyak satu qirath. Berkata Abdullah dan berkata Abu Hurairah; atau anjing penjaga tanaman\" "},"4002":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ أَنَّهُ سَمِعَ أَبَا مَسْعُودٍ عُقْبَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ثَمَنِ الْكَلْبِ وَمَهْرِ الْبَغِيِّ وَحُلْوَانِ الْكَاهِنِ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Abu Bakar bin Abdurrahman bin Al Harits bin Hisyam] bahwa ia mendengar [Abu Mas'ud 'Uqbah] berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari harga anjing dan memberi upah pelacur serta bayaran dukun."},"4003":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَنْبَأَنَا مَعْرُوفُ بْنُ سُوَيْدٍ الْجُذَامِيُّ أَنَّ عَلِيَّ بْنَ رَبَاحٍ اللَّخْمِيَّ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحِلُّ ثَمَنُ الْكَلْبِ وَلَا حُلْوَانُ الْكَاهِنِ وَلَا م��هْرُ الْبَغِيِّ","id":"Telah mengabarkan kepada kami [Yunus bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Ibnu Wahb], ia berkata; telah memberitakan kepada kami [Ma'ruf bin Suwaid Al Judzami] bahwa [Ali bin Radbah Al Lakhmi] telah menceritakan kepada kepadanya bahwa ia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Tidak halal harga anjing, bayaran dukun dan upah pezina.\""},"4004":{"ar":"أَخْبَرَنَا شُعَيْبُ بْنُ يُوسُفَ عَنْ يَحْيَى عَنْ مُحَمَّدِ بْنِ يُوسُفَ عَنْ السَّائِبِ بْنِ يَزِيدَ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَرُّ الْكَسْبِ مَهْرُ الْبَغِيِّ وَثَمَنُ الْكَلْبِ وَكَسْبُ الْحَجَّامِ","id":"Telah mengabarkan kepada kami [Syu'aib bin Yusuf] dari [Yahya] dari [Muhammad bin Yusuf] dari [As Saib bin Yazid] dari [Rafi' bin Khadij], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seburuk-buruk pekerjaan adalah upah pelacur, harga anjing dan profesi tukang bekam.\""},"4005":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ الْحَسَنِ الْمِقْسَمِيُّ قَالَ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ ثَمَنِ السِّنَّوْرِ وَالْكَلْبِ إِلَّا كَلْبَ صَيْدٍقَالَ أَبُو عَبْد الرَّحْمَنِ وَحَدِيثُ حَجَّاجٍ عَنْ حَمَّادِ بْنِ سَلَمَةَ لَيْسَ هُوَ بِصَحِيحٍ","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Hasan Al Miqsami], ia berkata; telah menceritakan kepada kami [Hajjaj bin Muhammad] dari [Hammad bin Salamah] dari [Abu Az Zubair] dari [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari harga kucing dan anjing kecuali anjing pemburu. Abu Abdurrahman berkata; dan hadits Hajjaj dari Hammad bin Salamah tidak shahih. "},"4006":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا ابْنُ سَوَاءٍ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ أَبِي مَالِكٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ لِي كِلَابًا مُكَلَّبَةً فَأَفْتِنِي فِيهَا قَالَ مَا أَمْسَكَ عَلَيْكَ كِلَابُكَ فَكُلْ قُلْتُ وَإِنْ قَتَلْنَ قَالَ وَإِنْ قَتَلْنَ قَالَ أَفْتِنِي فِي قَوْسِي قَالَ مَا رَدَّ عَلَيْكَ سَهْمُكَ فَكُلْ قَالَ وَإِنْ تَغَيَّبَ عَلَيَّ قَالَ وَإِنْ تَغَيَّبَ عَلَيْكَ مَا لَمْ تَجِدْ فِيهِ أَثَرَ سَهْمٍ غَيْرَ سَهْمِكَ أَوْ تَجِدْهُ قَدْ صَلَّ يَعْنِي قَدْ أَنْتَنَقَالَ ابْنُ سَوَاءٍ وَسَمِعْتُهُ مِنْ أَبِي مَالِكٍ عُبَيْدِ اللَّهِ بْنِ الْأَخْنَسِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Ibnu Sawa`], ia berkata; telah menceritakan kepada kami [Sa'id] dari [Abu Malik] dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya] bahwa seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; wahai Rasulullah, sesungguhnya saya memiliki beberapa ekor anjing yang terlatih, maka berilah saya fatwa mengenainya! Beliau bersabda: \"Apa yang ditangkap anjing-anjingmu untukmu makanlah.\" Saya katakan; walaupun mereka membunuh buruan? Beliau bersabda: \"Walaupun mereka membunuh buruan.\" Ia berkata; berilah saya fatwa mengenai busurku. Beliau bersabda: \"Apa yang dibawa kembali oleh anak panahmu untukmu maka makanlah.\" Ia berkata; walaupun tidak kelihatan olehku? Beliau bersabda: \" Walaupun tidak kelihatan olehmu selama engkau tidak mendapati bekas anak panah selain anak panahmu atau engkau mendapatinya telah membusuk.\" [Ibnu Sawa`] berkata; saya mendengarnya dari [Abu Malik 'Ubaidullah bin Al Akhnas] dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya] dari Nabi shallallahu 'alaihi wasallam. "},"4007":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ عَنْ زَائِدَةَ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ بْنِ رَافِعٍ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَبَيْنَمَا نَحْنُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ذِي الْحُلَيْفَةِ مِنْ تِهَامَةَ فَأَصَابُوا إِبِلًا وَغَنَمًا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أُخْرَيَاتِ الْقَوْمِ فَعَجَّلَ أَوَّلُهُمْ فَذَبَحُوا وَنَصَبُوا الْقُدُورَ فَدُفِعَ إِلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِالْقُدُورِ فَأُكْفِئَتْ ثُمَّ قَسَّمَ بَيْنَهُمْ فَعَدَلَ عَشْرًا مِنْ الشَّاءِ بِبَعِيرٍ فَبَيْنَمَا هُمْ كَذَلِكَ إِذْ نَدَّ بَعِيرٌ وَلَيْسَ فِي الْقَوْمِ إِلَّا خَيْلٌ يَسِيرَةٌ فَطَلَبُوهُ فَأَعْيَاهُمْ فَرَمَاهُ رَجُلٌ بِسَهْمٍ فَحَبَسَهُ اللَّهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِهَذِهِ الْبَهَائِمِ أَوَابِدَ كَأَوَابِدِ الْوَحْشِ فَمَا غَلَبَكُمْ مِنْهَا فَاصْنَعُوا بِهِ هَكَذَا","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman], ia berkata; telah menceritakan kepada kami [Husain bin Ali] dari [Zaidah] dari [Sa'id bin Masruq] dari ['Abayah bin Rifa'ah bin Rafi'] dari [Rafi' bin Khadij], ia berkata; ketika kami bersama Rasulullah shallallahu 'alaihi wasallam di Dzul Hulaifah dari Mekkah mereka mendapatkan unta dan kambing, sedangkan Rasulullah shallallahu 'alaihi wasallam berada pada beberapa kelompok orang yang terlambat, kemudian orang yang pertama bersegera menyembelih dan meletakkan kuali, kemudian Rasulullah shallallahu 'alaihi wasallam terdorong untuk menuju kepada mereka kemudian beliau memerintahkan agar isi kuali dikeluarkan, kemudian beliau membagi diantara mereka, dan menyamakan sepuluh kambing dengan satu unta. Ketika mereka dalam keadaan demikian, tiba-tiba terdapat unta yang lepas, mereka tidak memiliki kecuali kuda yang tidak kencang larinya. Mereka mencarinya dan lelah karenanya, kemudin seorang laki-laki memanahnya dengan anak panah kemudian Allah menahan unta tersebut. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya binatang-binatang ini memiliki binanatang-binatang yang menjadi liar, seperti liarnya binatang liar, maka apa yang kalian mampu lakukan terhadapnya maka lakukanlah.\" "},"4008":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ مَنِيعٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ قَالَ أَخْبَرَنِي عَاصِمٌ الْأَحْوَلُ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّيْدِ فَقَالَ إِذَا رَمَيْتَ سَهْمَكَ فَاذْكُرْ اسْمَ اللَّهِ عَزَّ وَجَلَّ فَإِنْ وَجَدْتَهُ قَدْ قُتِلَ فَكُلْ إِلَّا أَنْ تَجِدَهُ قَدْ وَقَعَ فِي مَاءٍ وَلَا تَدْرِي الْمَاءُ قَتَلَهُ أَوْ سَهْمُكَ","id":"Telah mengabarkan kepada kami [Ahmad bin Mani'], ia berkata; telah menceritakan kepada kami [Abdullah bin Al Mubarak], ia berkata; telah mengabarkan kepadaku ['Ashim Al Ahwali] dari [Asy Sya'bi] dari ['Adi bin Hatim], ia berkata; saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam shallallahu 'alaihi wasallam mengenai hewan buruan, kemudian beliau bersabda: \"Apabila engkau melepaskan anak panahmu maka sebutlah nama Allah 'azza wajalla, kemudian apabila engkau mendapatinya telah terbunuh maka makanlah, kecuali engkau dapati dia telah terjatuh dalam air, dan engkau tidak mengetahui apakah air tersebut yang membuatnya mati atau anak panahmu.\""},"4009":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَحْيَى بْنِ الْحَارِثِ قَالَ حَدَّثَنَا أَحْمَدُ بْنُ أَبِي شُعَيْبٍ قَالَ حَدَّثَنَا مُوسَى بْنُ أَعْيَنَ عَنْ مَعْمَرٍ عَنْ عَاصِمِ بْنِ سُلَيْمَانَ عَنْ عَامِرٍ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍأَنَّهُ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّيْدِ فَقَالَ إِذَا أَرْسَلْتَ سَهْمَكَ وَكَلْبَكَ وَذَكَرْتَ اسْمَ اللَّهِ فَقَتَلَ سَهْمُكَ فَكُلْ قَالَ فَإِنْ بَاتَ عَنِّي لَيْلَةً يَا رَسُولَ اللَّهِ قَالَ إِنْ وَجَدْتَ سَهْمَكَ وَلَمْ تَجِدْ فِيهِ أَثَرَ شَيْءٍ غَيْرَهُ فَكُلْ وَإِنْ وَقَعَ فِي الْمَاءِ فَلَا تَأْكُلْ","id":"Telah mengabarkan kepada kami ['Amr bin Yahya bin Al Harits], ia berkata; telah menceritakan kepada kami [Ahmad bin Abu Syu'aib], ia berkata; telah menceritakan kepada kami [Musa bin A'yan] dari [Ma'mar] dari ['Ashim bin Sulaiman] dari ['Amir Asy Sya'bi] dari ['Adi bin Hatim] bahwa ia bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai hewan buruan, maka beliau bersabda: \"Apabila engkau melepas anak panah dan anjingmu dan menyebutkan nama Allah kemudian anak panahmu membunuh maka makanlah.\" Adi berkata: walaupun telah bermalam satu malam wahai Rasulullah? Beliau bersabda: \"Apabila engkau mendapatkan anak panahmu dan tidak mendapatkan padanya bekas sesuatu selainnya maka makanlah, dan apabila terjatuh ke dalam air maka janganlah engkau makan.\""},"4010":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ أَنْبَأَنَا أَبُو بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا أَهْلُ الصَّيْدِ وَإِنَّ أَحَدَنَا يَرْمِي الصَّيْدَ فَيَغِيبُ عَنْهُ اللَّيْلَةَ وَاللَّيْلَتَيْنِ فَيَبْتَغِي الْأَثَرَ فَيَجِدُهُ مَيِّتًا وَسَهْمُهُ فِيهِ قَالَ إِذَا وَجَدْتَ السَّهْمَ فِيهِ وَلَمْ تَجِدْ فِيهِ أَثَرَ سَبُعٍ وَعَلِمْتَ أَنَّ سَهْمَكَ قَتَلَهُ فَكُلْ","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub], ia berkata; telah menceritakan kepada kami [Husyaim], ia berkata; telah memberitakan kepada kami [Abu Bisyr] dari [Sa'id bin Jubair] dari ['Adi bin Hatim], ia berkata; saya katakan; wahai Rasulullah, sesungguhnya kami adalah orang-orang yang biasa berburu, dan salah seorang diantara kami memanah hewan buruan kemudian menghilang darinya satu malam dan dua malam. Kemudian ia mencarinya, dan mendapatinya telah mati dan anak panahnya berada padanya. Beliau bersabda: \"Apabila ia mendapati anak panahnya padanya dan tidak mendapati padanya bekas binatang buas dan ia mengetahui bahwa anak panahnya telah membunuhnya maka makanlah.\""},"4011":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى وَإِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَا حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ عَدِيِّ بْنِ حَاتِمٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا رَأَيْتَ سَهْمَكَ فِيهِ وَلَمْ تَرَ فِيهِ أَثَرًا غَيْرَهُ وَعَلِمْتَ أَنَّهُ قَتَلَهُ فَكُلْ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dan [Isma'il bin Mas'ud] mereka berkata; telah menceritakan kepada kami [Khalid] dari [Syu'bah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari ['Adi bin Hatim] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila engkau melihat anak panahmu ada padanya dan engkau tidakmelihat padanya bekas selainnya dan engkau tahu bahwa anak panah tersebut telah membunuhnya maka makanlah.\""},"4012":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ بْنِ مَيْسَرَةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَرْمِي الصَّيْدَ فَأَطْلُبُ أَثَرَهُ بَعْدَ لَيْلَةٍ قَالَ إِذَا وَجَدْتَ فِيهِ سَهْمَكَ وَلَمْ يَأْكُلْ مِنْهُ سَبُعٌ فَكُلْ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la], ia berkata; telah menceritakan kepada kami telah menceritakan kepada kami [Khalid], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abdul Malik bin Maisarah] dari [Sa'id bin Jubair] dari ['Adi bin Hatim], ia berkata; saya katakan; wahai Rasulullah, saya memanah hewan buruanku kemudian saya mencari jejaknya setelah satu malam, Beliau bersabda: \" Apabila engkau dapatkan padanya anak panahmu, dan tidak ada hewan buas yang memakannya maka makanlah.\" "},"4013":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ خَالِدٍ الْخَلَّالُ قَالَ حَدَّثَنَا مَعْنٌ قَالَ أَنْبَأَنَا مُعَاوِيَةُ وَهُوَ ابْنُ صَالِحٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِيهِ عَنْ أَبِي ثَعْلَبَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الَّذِي يُدْرِكُ صَيْدَهُ بَعْدَ ثَلَاثٍ فَلْيَأْكُلْهُ إِلَّا أَنْ يُنْتِنَ","id":"Telah mengabarkan kepada kami [Ahmad bin Khalid Al Khalal], ia berkata; telah menceritakan kepada kami [Ma'n], ia berkata; telah memberitakan kepada kami [Mu'awiyah yaitu Ibnu Shalih] dari [Abdurrahman bin Jubair bin Nufair] dari [ayahnya] dari [Abu Tsa'labah] dari Nabi shallallahu 'alaihi wasallam mengenai orang yang menjumpai hewan buruan buruannya setelah tiga hari, beliau bersabda: \"Hendaknya ia memakannya kecuali apabila telah membusuk.\""},"4014":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ عَنْ سِمَاكٍ قَالَ سَمِعْتُ مُرِّيَّ بْنَ قَطَرِيٍّ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أُرْسِلُ كَلْبِي فَيَأْخُذُ الصَّيْدَ وَلَا أَجِدُ مَا أُذَكِّيهِ بِهِ فَأُذَكِّيهِ بِالْمَرْوَةِ وَالْعَصَا قَالَ أَهْرِقْ الدَّمَ بِمَا شِئْتَ وَاذْكُرْ اسْمَ اللَّهِ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Khalid] dari [Syu'bah] dari [Simak], ia berkata; saya mendengar [Murri bin Qathari] dari ['Adi bin Hatim], ia berkata; saya berkata; wahai Rasulullah, saya mengirim anjingku kemudian ia menangkap hewan buruan, dan saya tidak mendapatkan Sesuatu untuk menyembelihnya, kemudian saya menyembelihnya dengan batu putih yang dibuat seperti pisau dan sebuah tongkat. Beliau bersabda: \"Alirkanlah darah dengan apa yang engkau kehendaki, dan sebutlah nama Allah 'azza wajalla.\""},"4015":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ قُدَامَةَ عَنْ جَرِيرٍ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامٍ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي أُرْسِلُ الْكِلَابَ الْمُعَلَّمَةَ فَتُمْسِكُ عَلَيَّ فَآكُلُ مِنْهُ قَالَ إِذَا أَرْسَلْتَ الْكِلَابَ يَعْنِي الْمُعَلَّمَةَ وَذَكَرْتَ اسْمَ اللَّهِ فَأَمْسَكْنَ عَلَيْكَ فَكُلْ قُلْتُ وَإِنْ قَتَلْنَ قَالَ وَإِنْ قَتَلْنَ مَا لَمْ يَشْرَكْهَا كَلْبٌ لَيْسَ مِنْهَا قُلْتُ وَإِنِّي أَرْمِي الصَّيْدَ بِالْمِعْرَاضِ فَأُصِيبُ فَآكُلُ قَالَ إِذَا رَمَيْتَ بِالْمِعْرَاضِ وَسَمَّيْتَ فَخَزَقَ فَكُلْ وَإِذَا أَصَابَ بِعَرْضِهِ فَلَا تَأْكُلْ","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] dari [Jarir] dari [Manshur] dari [Ibrahim] dari [Hammam] dari ['Adi bin Hatim], ia berkata; saya mengatakan; wahai Rasulullah, sesungguhnya saya mengirimkan beberapa ekor anjing yang terlatih, kemudian mereka menangkap buruan untukku, lalu saya memakan sebagian darinya. Beliau bersabda: \"Apabila engkau mengirim anjing-anjingmu yang terlatih dan engkau menyebutkan nama Allah kemudian mereka menangkap buruan untukmu maka makanlah.\" Saya katakan; walaupun mereka membunuhnya? Beliau bersabda: \"Walaupun mereka membunuhnya selama tidak ada anjing selainnya yang ikut serta. Saya katakan; dan saya memanah hewan buruanku dengan anak panah tanpa mata panah, kemudian saya mengenai buruan, dan memakannya. Beliau bersabda: \"Apabila engkau memanah dengan anak panah yang tak bermata panah dan engkau telah menyebutkan nama Allah dan anak panah tersebut menusuk maka makanlah, dan apabila mengenai dengan bagian tumpunya maka jangan engkau makan.\""},"4016":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي السَّفَرِ عَنْ الشَّعْبِيِّ قَالَ سَمِعْتُ عَدِيَّ بْنَ حَاتِمٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمِعْرَاضِ فَقَالَ إِذَا أَصَابَ بِحَدِّهِ فَكُلْ وَإِذَا أَصَابَ بِعَرْضِهِ فَقُتِلَ فَإِنَّهُ وَقِيذٌ فَلَا تَأْكُلْ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Muhammad bin Ja'far], ia berkata; telah menceritakan kepada kami [Syu'bah], ia berkata; telah menceritakan kepada kami [Abdullah bin Abu As Safar] dari [Asy Sya'bi], ia berkata; saya mendengar ['Adi bin Hatim], ia berkata; saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai anak panah tanpa mata. Kemudian beliau bersabda: \"Apabila ia mengenai dengan bagian tajamnya maka makanlah dan apabila mengenai dengan bagian tumpulnya kemudian terbunuh maka sesungguhnya buruan tersebut merupakan hewan yang mati karena benda tumpul, maka jangan engkau makan.\""},"4017":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ مُحَمَّدٍ الذَّرَّاعُ قَالَ حَدَّثَنَا أَبُو مُحْصَنٍ قَالَ حَدَّثَنَا حُصَيْنٌ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَيْدِ الْمِعْرَاضِ فَقَالَ إِذَا أَصَابَ بِحَدِّهِ فَكُلْ وَإِذَا أَصَابَ بِعَرْضِهِ فَلَا تَأْكُلْ","id":"Telah mengabarkan kepada kami [Al Husain bin Muhammad Adz Dzarra'], ia berkata; telah menceritakan kepada kami [Abu Muhshan], ia berkata; telah menceritakan kepada kami [Hushain] dari [Asy Sya'bi] dari ['Adi bin Hatim], ia berkata; saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai hewan buruan dengan anak panah tanpa mata panah, kemudian beliau bersabda: \"Apabila mengenai dengan bagian yang tajam maka makanlah, dan apabila mengenai dengan bagian yang tumpul maka jangan engkau makan.\""},"4018":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا عِيسَى بْنُ يُونُسَ وَغَيْرُهُ عَنْ زَكَرِيَّا عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَيْدِ الْمِعْرَاضِ فَقَالَ مَا أَصَبْتَ بِحَدِّهِ فَكُلْ وَمَا أَصَابَ بِعَرْضِهِ فَهُوَ وَقِيذٌ","id":"Telah mengabarkan kepada kami [Ali bin Hujr], ia berkata; telah memberitakan kepada kami [Isa bin Yunus] dan yang lainnya dari [Zakariya] dari [Asy Sya'bi] dari ['Adi bin Hatim], ia berkata; saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai hewan buruan dengan anak panah tanpa mata panah, maka beliau bersabda: \"Apa yang engkau kenai dengan bagian tajamnya maka makanlah dan apa yang engkau kenai dengan bagian tumpulnya maka itu adalah hewan yang mati karena benda tumpul.\""},"4019":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ أَبِي مُوسَى ح وَأَنْبَأَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي مُوسَى عَنْ وَهْبِ بْنِ مُنَبِّهٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ سَكَنَ الْبَادِيَةَ جَفَا وَمَنْ اتَّبَعَ الصَّيْدَ غَفَلَ وَمَنْ اتَّبَعَ السُّلْطَانَ افْتُتِنَوَاللَّفْظُ لِابْنِ الْمُثَنَّى","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Abdurrahman] dari [Sufyan] dari [Abu Musa], telah menceritakan dan memberitakan kepada kami [Muhammad bin Al Mutsanna] dari [Abdurrahman], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Musa] dari [Wahb bin Munabbih] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa yang tinggal di pelosok maka ia hidup keras, barangsiapa yang mengikuti hewan buruan ia akan lalai, barangsiapa yang mengikuti kemauan penguasa maka ia akan terfitnah, \" lafazh ini milik Ibn Al Mutsanna."},"4020":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ الْبَحْرَانِيُّ قَالَ حَدَّثَنَا حَبَّانُ وَهُوَ ابْنُ هِلَالٍ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ مُوسَى بْنِ طَلْحَةَ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَ أَعْرَابِيٌّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَرْنَبٍ قَدْ شَوَاهَا فَوَضَعَهَا بَيْنَ يَدَيْهِ فَأَمْسَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَأْكُلْ وَأَمَرَ الْقَوْمَ أَنْ يَأْكُلُوا وَأَمْسَكَ الْأَعْرَابِيُّ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَمْنَعُكَ أَنْ تَأْكُلَ قَالَ إِنِّي أَصُومُ ثَلَاثَةَ أَيَّامٍ مِنْ كُلِّ شَهْرٍ قَالَ إِنْ كُنْتَ صَائِمًا فَصُمْ الْغُرَّ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'mar Al Bahrani], ia berkata; telah menceritakan kepada kami [Habban yaitu Ibnu Hilal], ia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Abdul Malik bin 'Umair] dari [Musa bin Thalhah] dari [Abu Hurairah], ia berkata; telah datang seorang badui kepada Nabi shallallahu 'alaihi wasallam membawa kelinci yang telah ia baker, kemudian ia meletakkannya dihadapan beliau. Kemudian Rasulullah shallallahu 'alaihi wasallam menahan diri tidak memakannya, dan beliau memerintahkan orang-orang agar memakannya, dan orang badui tersebut menahan untuk makan. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Apa yang menghalangimu untuk makan?\" Ia berkata; sesungguhnya Saya sedang berpuasa tiga hari dari setiap bulan. Beliau bersabda: \"Apabila engkau berpuasa maka berpuasalah tanggal tiga belas, empat belas dan lima belas.\" "},"4021":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ حَكِيمِ بْنِ جُبَيْرٍ وَعَمْرِو بْنِ عُثْمَانَ وَمُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ مُوسَى بْنِ طَلْحَةَ عَنْ ابْنِ الْحَوْتَكِيَّةِ قَالَقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ مَنْ حَاضِرُنَا يَوْمَ الْقَاحَةِ قَالَ قَالَ أَبُو ذَرٍّ أَنَا أُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَرْنَبٍ فَقَالَ الرَّجُلُ الَّذِي جَاءَ بِهَا إِنِّي رَأَيْتُهَا تَدْمَى فَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَأْكُلْ ثُمَّ إِنَّهُ قَالَ كُلُوا فَقَالَ رَجُلٌ إِنِّي صَائِمٌ قَالَ وَمَا صَوْمُكَ قَالَ مِنْ كُلِّ شَهْرٍ ثَلَاثَةُ أَيَّامٍ قَالَ فَأَيْنَ أَنْتَ عَنْ الْبِيضِ الْغُرِّ ثَلَاثَ عَشْرَةَ وَأَرْبَعَ عَشْرَةَ وَخَمْسَ عَشْرَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Hakim bin Jubair] dan ['Amr bin Utsman] dan [Muhammad bin Abdurrahman] dari [Musa bin Thalhah] dari [Ibnu Al Hautakiyah], ia berkata; Umar radliallahu 'anhu berkata; siapakah yang hadir bersama kami pada saat kejadian di Al Qahah? Ibnu Al Hautakiyah berkata; [Abu Dzar] berkata; Rasulullah shallallahu 'alaihi wasallam diberi seekor kelinci, kemudian seorang laki-laki yang membawanya berkata; sesungguhnya saya melihatnya bercucuran darah. Nabi shallallahu 'alaihi wasallam tidak memakannya kemudian beliau bersabda: \"Makanlah kalian.\" Kemudian seseorang berkata; saya berpuasa. Beliau bersabda: \"Apakah puasamu?\" Ia berkata; puasa tiga hari setiap bulan. Beliau bersabda: \"Dimana engkau dari hari bidh? Yaitu tiga belas, empat belas dan lima belas?\""},"4022":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ عَنْ هِشَامٍ وَهُوَ ابْنُ زَيْدٍ قَالَ سَمِعْتُ أَنَسًا يَقُولُأَنْفَجْنَا أَرْنَبًا بِمَرِّ الظَّهْرَانِ فَأَخَذْتُهَا فَجِئْتُ بِهَا إِلَى أَبِي طَلْحَةَ فَذَبَحَهَا فَبَعَثَنِي بِفَخِذَيْهَا وَوَرِكَيْهَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَبِلَهُ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud], ia berkata; telah menceritakan kepada kami [Khalid] dari [Syu'bah] dari [Hisyam yaitu Ibnu Zaid], ia berkata; saya mendengar [Anas] berkata; kami mengeluarkan kelinci dari tempatnya di Marrizh Zhahran, kemudian Saya mengambilnya, lalu saya bewa kepada Abu Thalhah dan ia menyembelihnya. Kemudian ia mengutusku membawa dua paha kelinci tersebut serta dua pangkal pahanya kepada Rasulullah shallallahu 'alaihi wasallam, dan beliau menerimanya."},"4023":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَفْصٌ عَنْ عَاصِمٍ وَدَاوُدَ عَنْ الشَّعْبِيِّ عَنْ ابْنِ صَفْوَانَ قَالَأَصَبْتُ أَرْنَبَيْنِ فَلَمْ أَجِدْ مَا أُذَكِّيهِمَا بِهِ فَذَكَّيْتُهُمَا بِمَرْوَةٍ فَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَمَرَنِي بِأَكْلِهِمَا","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Hafsh] dari ['Ashim] dan [Daud] dari [Asy Sya'bi] dari [Ibnu Shafwan], ia berkata; saya mendapatkan dua kelinci dan tidak mendapatkan sesuatu untuk menyembelihnya, kemudian saya menyembelih menggunakan batu putih yang dibentuk seperti pisau. Lalu saya bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai hal tersebut dan beliau memerintahkanku untuk memakannya."},"4024":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى الْمِنْبَرِ سُئِلَ عَنْ الضَّبِّ فَقَالَ لَا آكُلُهُ وَلَا أُحَرِّمُهُ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Malik] dari [Abdullah bin Dinar] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam sedang berada di atas mimbar ditanya mengenai Biawak. Kemudian beliau bersabda: \"Saya tidak memakannya dan tidak mengharamkannya.\""},"4025":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ نَافِعٍ وَعَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ مَا تَرَى فِي الضَّبِّ قَالَ لَسْتُ بِآكِلِهِ وَلَا مُحَرِّمِهِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Nafi'] dan [Abdullah bin Dinar] dari [Ibnu Umar] bahwa seorang laki-laki berkata; wahai Rasulullah, bagaimana pendapat anda mengenai biawak? Beliau bersabda: \"Saya tidak memakannya dan tidak mengharamkannya.\""},"4026":{"ar":"أَخْبَرَنَا كَثِيرُ بْنُ عُبَيْدٍ عَنْ مُحَمَّدِ بْنِ حَرْبٍ عَنْ الزُّبَيْدِيِّ قَالَ أَخْبَرَنِي الزُّهْرِيُّ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ خَالِدِ بْنِ الْوَلِيدِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِضَبٍّ مَشْوِيٍّ فَقُرِّبَ إِلَيْهِ فَأَهْوَى إِلَيْهِ بِيَدِهِ لِيَأْكُلَ مِنْهُ قَالَ لَهُ مَنْ حَضَرَ يَا رَسُولَ اللَّهِ إِنَّهُ لَحْمُ ضَبٍّ فَرَفَعَ يَدَهُ عَنْهُ فَقَالَ لَهُ خَالِدُ بْنُ الْوَلِيدِ يَا رَسُولَ اللَّهِ أَحَرَامٌ الضَّبُّ قَالَ لَا وَلَكِنْ لَمْ يَكُنْ بِأَرْضِ قَوْمِي فَأَجِدُنِي أَعَافُهُ فَأَهْوَى خَالِدٌ إِلَى الضَّبِّ فَأَكَلَ مِنْهُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْظُرُ","id":"Telah mengabarkan kepada kami [Katsir bin 'Ubaid] dari [Muhammad bin Harb] dari [Az Zubaidi], ia berkata; telah mengabarkan kepadaku [Az Zuhri] dari [Abu Umamah bin Sahl] dari [Abdullah bin 'Abbas] dari [Khalid bin Al Walid] bahwa Rasulullah shallallahu 'alaihi wasallam diberi biawak bakar kemudian didekatkan kepadanya, kemudian beliau mengulurkan tangannya untuk makan sebagian darinya. Orang yang hadir berkata; wahai Rasulullah, sesungguhnya itu adalah daging biawak. Kemudian beliau mengangkat tangannya, kemudian Khalid bin Al Walid berkata; wahai Rasulullah, apakah biawak itu haram? Beliau bersabda: \"Tidak, akan tetapi itu tidak ada di negeri kaumku Sehingga saya dapati diriku tidak menyukainya.\" Kemudian Khalid mengulurkan tangannya ke biawak tersebut dan memakan sebagian darinya, sedang Rasulullah shallallahu 'alaihi wasallam melihat. "},"4027":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلٍ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ أَخْبَرَهُ أَنَّ خَالِدَ بْنَ الْوَلِيدِ أَخْبَرَهُأَنَّهُ دَخَلَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مَيْمُونَةَ بِنْتِ الْحَارِثِ وَهِيَ خَالَتُهُ فَقُدِّمَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَحْمُ ضَبٍّ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَأْكُلُ شَيْئًا حَتَّى يَعْلَمَ مَا هُوَ فَقَالَ بَعْضُ النِّسْوَةِ أَلَا تُخْبِرْنَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَأْكُلُ فَأَخْبَرَتْهُ أَنَّهُ لَحْمُ ضَبٍّ فَتَرَكَهُ قَالَ خَالِدٌ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَرَامٌ هُوَ قَالَ لَا وَلَكِنَّهُ طَعَامٌ لَيْسَ فِي أَرْضِ قَوْمِي فَأَجِدُنِي أَعَافُهُ قَالَ خَالِدٌ فَاجْتَرَرْتُهُ إِلَيَّ فَأَكَلْتُهُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْظُرُوَحَدَّثَهُ ابْنُ الْأَصَمِّ عَنْ مَيْمُونَةَ وَكَانَ فِي حِجْرِهَا","id":"Telah mengabarkan kepada kami [Abu Daud], ia berkata; telah menceritakan kepada kami [Ya'qub bin Ibrahim], ia berkata; telah menceritakan kepada kami [Ayahku] dari [Shalih] dari [Ibnu Syihab] dari [Abu Umamah bin Sahl] dari [Ibnu Abbas] bahwa ia telah mengabarkan kepadanya bahwa [Khalid bin Al Walid] telah mengabarkan kepadanya bahwa ia bersama Rasulullah shallallahu 'alaihi wasallam menemui Maimunah binti Al Harits dan ia adalah bibi Khalid. Kemudian dipersembahkan kepada Rasulullah shallallahu 'alaihi wasallam daging biawak, dan Rasulullah shallallahu 'alaihi wasallam tidak memakan sedikitpunn hingga beliau mengetahui apakah itu. Kemudian sebagian isteri mengatakan; tidakkah kalian mengabarkan kepada Rasulullah shallallahu 'alaihi wasallam apa yang beliau makan? Kemudian Maimunah mengabarkan kepadanya bahwa itu adalah daging biawak. Lalu beliau meninggalkannya, Khalid berkata; saya telah bertanya kepada Rasulullah shallallahu 'alaihi wasallam; apakah daging biawak itu haram? Maka beliau bersabda: \"Tidak, akan tetapi itu adalah makanan yang tidak ada di negeri kaumku sehingga saya dapati diriku tidak menyukainya. Khalid berkata; kemudian saya menariknya kepadaku dan memakannya dan Rasulullah shallallahu 'alaihi wasallam melihat. Dan hadits tersebut telah diriwayatkan Ibnu Al Asham dari Maimunah dan ia adalah orang yang berada dalam asuhannya. "},"4028":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَأَهْدَتْ خَالَتِي إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقِطًا وَسَمْنًا وَأَضُبًّا فَأَكَلَ مِنْ الْأَقِطِ وَالسَّمْنِ وَتَرَكَ الْأَضُبَّ تَقَذُّرًا وَأُكِلَ عَلَى مَائِدَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَوْ كَانَ حَرَامًا مَا أُكِلَ عَلَى مَائِدَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud], ia berkata; telah menceritakan kepada kami [Khalid], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Abbas], ia berkata; bibiku telah menghadiahkan kepada Rasulullah shallallahu 'alaihi wasallam keju, mentega dan biawak. Kemudian beliau makan sebagian mentega serta keju dan meninggalkan biawak Karena merasa tidak senang. Dan daging tersebut dimakan dalam hidangan Rasulullah shallallahu 'alaihi wasallam, seandainya hal itu adalah haram maka tidak akan dimakan dalam hidangan Rasulullah shallallahu 'alaihi wasallam. "},"4029":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ أَنْبَأَنَا أَبُو بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّهُ سُئِلَ عَنْ أَكْلِ الضِّبَابِ فَقَالَ أَهْدَتْ أُمُّ حُفَيْدٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمْنًا وَأَقِطًا وَأَضُبًّا فَأَكَلَ مِنْ السَّمْنِ وَالْأَقِطِ وَتَرَكَ الضِّبَابَ تَقَذُّرًا لَهُنَّ فَلَوْ كَانَ حَرَامًا مَا أُكِلَ عَلَى مَائِدَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا أَمَرَ بِأَكْلِهِنَّ","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub], ia berkata; telah menceritakan kepada kami [Husyaim], ia berkata; telah memberitakan kepada kami [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa ia ditanya mengenai makan biawak, kemudian berkata; Ummu Hufaid telah menghadiahkan kepada Rasulullah shallallahu 'alaihi wasallam mentega, keju dan biawak, kemudian beliau makan sebagian dari mentega dan keju dan meninggalkan biawak, karena merasa tidak senang. Seandainya hal itu adalah haram maka tidak akan dimakan pada hidangan Rasulullah shallallahu 'alaihi wasallam dan tidak memerintahkan untuk memakannya. "},"4030":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ مَنْصُورٍ الْبَلْخِيُّ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ سَلَّامُ بْنُ سُلَيْمٍ عَنْ حُصَيْنٍ عَنْ زَيْدِ بْنِ وَهْبٍ عَنْ ثَابِتِ بْنِ يَزِيدَ الْأَنْصَارِيِّ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَنَزَلْنَا مَنْزِلًا فَأَصَابَ النَّاسُ ضِبَابًا فَأَخَذْتُ ضَبًّا فَشَوَيْتُهُ ثُمَّ أَتَيْتُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذَ عُودًا يَعُدُّ بِهِ أَصَابِعَهُ ثُمَّ قَالَ إِنَّ أُمَّةً مِنْ بَنِي إِسْرَائِيلَ مُسِخَتْ دَوَابَّ فِي الْأَرْضِ وَإِنِّي لَا أَدْرِي أَيُّ الدَّوَابِّ هِيَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّ النَّاسَ قَدْ أَكَلُوا مِنْهَا قَالَ فَمَا أَمَرَ بِأَكْلِهَا وَلَا نَهَى","id":"Telah mengabarkan kepada kami [Sulaiman bin Manshur Al Balkhi], ia berkata; telah menceritakan kepada kami [Abu Al Ahwash Sallam bin Sulaim] dari [Hushain] dari [Zaid bin Wahb] dari [Tsabit bin Yazid Al Anshari] ia berkata; kami bersama Rasulullah shallallahu 'alaihi wasallam pada suatu safar, lalu kami singgah disebuah rumah, lalu orang-orang menemukan beberapa biawak, lalu aku mengambil seekor dan membakarnya kemudian menyuguhkannya kepada Nabi shallallahu 'alaihi wasallam, lalu beliau mengambil ranting dan menghitung jari-jarinya dengannya dan bersabda: \"Sungguh sebuah umat dari Bani Israil telah dirubah menjadi hewan melata dibumi, dan aku tidak tahu hewan apakah itu, \" aku berkata; wahai Rasulullah sesungguhnya orang-orang telah memakannya. Tsabit berkata; maka beliau tidak menyuruh untuk memakannya dan tidak melarangnya."},"4031":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَزِيدَ قَالَ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنِي عَدِيُّ بْنُ ثَابِتٍ قَالَ سَمِعْتُ زَيْدَ بْنَ وَهْبٍ يُحَدِّثُ عَنْ ثَابِتِ بْنِ وَدِيعَةَ قَالَجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِضَبٍّ فَجَعَلَ يَنْظُرُ إِلَيْهِ وَيُقَلِّبُهُ وَقَالَ إِنَّ أُمَّةً مُسِخَتْ لَا يُدْرَى مَا فَعَلَتْ وَإِنِّي لَا أَدْرِي لَعَلَّ هَذَا مِنْهَا","id":"Telah mengabarkan kepada kami ['Amr bin Yazid], ia berkata; telah menceritakan kepada kami [Bahz bin Asad], ia berkata; telah menceritakan kepada kami [Syu'bah], ia berkata; telah menceritakan kepadaku ['Adi bin Tsabit], ia berkata; saya mendengar [Zaid bin Wahb] menceritakan dari [Tsabit bin Wadi'ah], ia berkata; telah datang seorang laki-laki kepada Rasulullah shallallahu 'alaihi wasallam membawa seekor biawak kemudian beliau melihatnya dan membaliknya serta bersabda: \"Sesungguhnya sebuah umat telah dirubah bentuknya, tidak diketahui apa yang mereka lakukan dan saya tidak tahu barangkali ini sebagian dari mereka.\""},"4032":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ زَيْدِ بْنِ وَهْبٍ عَنْ الْبَرَاءِ بْنِ عَازِبٍ عَنْ ثَابِتِ ابْنِ وَدِيعَةَأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِضَبٍّ فَقَالَ إِنَّ أُمَّةً مُسِخَتْ وَاللَّهُ أَعْلَمُ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Abdurrahman], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Zaid bin Wahb] dari [Al Bar` bin 'Azib] dari [Tsabit bin Wadi'ah] bahwa seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam membawa biawak, kemudian beliau bersabda: \"Sesungguhnya sebuah umat telah dirubah bentuknya.\" Wallahu a'lam."},"4033":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي ابْنُ جُرَيْجٍ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ ابْنِ أَبِي عَمَّارٍ قَالَسَأَلْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ عَنْ الضَّبُعِ فَأَمَرَنِي بِأَكْلِهَا فَقُلْتُ أَصَيْدٌ هِيَ قَالَ نَعَمْ قُلْتُ أَسَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur], ia berkata; telah menceritakan kepada kami [Sufyan], ia berkata; telah menceritakan kepadaku [Ibnu Juraij] dari [Abdullah bin 'Ubaid bin Umair] dari [Ibnu Abu 'Ammar], ia berkata; saya bertanya kepada [Jabir bin Abdullah] mengenai biawak, kemudian ia memerintahku untuk memakannya. Kemudian saya katakan; apakah itu merupakan hewan buruan? Ia berkata; ya. Saya katakan; apakah engkau mendengarnya dari Rasulullah shallallahu 'alaihi wasallam? Maka ia berkata; ya. "},"4034":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا مَالِكٌ عَنْ إِسْمَعِيلَ بْنِ أَبِي حَكِيمٍ عَنْ عَبِيدَةَ بْنِ سُفْيَانَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ ذِي نَابَ مِنْ السِّبَاعِ فَأَكْلُهُ حَرَامٌ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur], ia berkata; telah menceritakan kepada kami [Abdurrahman], ia berkata; telah menceritakan kepada kami [Malik] dari [Isma'il bin Abu Hakim] dari ['Ubaidah bin Sufyan] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Semua yang memiliki taring dari binatan buas haram dimakan.\""},"4035":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى عَنْ سُفْيَانَ عَنْ الزُّهْرِيِّ عَنْ أَبِي إِدْرِيسَ عَنْ أَبِي ثَعْلَبَةَ الْخُشَنِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ أَكْلِ كُلِّ ذِي نَابٍ مِنْ السِّبَاعِ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dan [Muhammad Al Mutsanna] dari [Sufyan] dari [Az Zuhri] dari [Abu Idris] dari [Abu Tsa'labah Al Khusyani] bahwa Nabi shallallahu 'alaihi wasallam melarang dari memakan setiap yang memiliki taring dari binatang buas. "},"4036":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا بَقِيَّةُ عَنْ بَحِيرٍ عَنْ خَالِدٍ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِي ثَعْلَبَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَحِلُّ النُّهْبَى وَلَا يَحِلُّ مِنْ السِّبَاعِ كُلُّ ذِي نَابٍ وَلَا تَحِلُّ الْمُجَثَّمَةُ","id":"Telah mengabarkan kepada kami ['Amr bin Utsman], ia berkata; telah menceritakan kepada kami [Baqiyah] dari [Bahir] dari [Khalid] dari [Jubair bin Nufair] dari [Abu Tsa'labah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal perampasan dan tidak halal setiap yang memiliki taring dari binatang buas serta menjadikan binatang sebagai sasaran memanah.\""},"4037":{"ar":"أَخْبَرَنَا قُتَيْبَةُ وَأَحْمَدُ بْنُ عَبْدَةَ قَالَا حَدَّثَنَا حَمَّادٌ عَنْ عَمْرٍو وَهُوَ ابْنُ دِينَارٍ عَنْ مُحَمَّدِ بْنِ عَلِيٍّ عَنْ جَابِرٍ قَالَنَهَى وَذَكَرَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ خَيْبَرَ عَنْ لُحُومِ الْحُمُرِ وَأَذِنَ فِي الْخَيْلِ","id":"Telah mengabarkan kepada kami [Qutaibah] dan [Ahmad bin 'Abdah] mereka berakata; telah menceritakan kepada kami [Hammad] dari ['Amr yaitu Ibnu Dinar] dari [Muhammad bin Ali] dari [Jabir], ia berkata; Rasulullah shallallahu 'alaihi wasallam pada saat perang Khaibar melarang makan daging keledai dan mengizinkan untuk makan daging kuda."},"4038":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ جَابِرٍ قَالَأَطْعَمَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لُحُومَ الْخَيْلِ وَنَهَانَا عَنْ لُحُومِ الْحُمُرِ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Sufyan] dari ['Amr] dari [Jabir], ia berkata; Rasulullah shallallahu 'alaihi wasallam memberi kami makan daging kuda dan melarang kami dari daging keledai."},"4039":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ الْحُسَيْنِ وَهُوَ ابْنُ وَاقِدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ وَعَمْرُو بْنُ دِينَارٍ عَنْ جَابِرٍ و عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ عَطَاءٍ عَنْ جَابِرٍ قَالَأَطْعَمَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ خَيْبَرَ لُحُومَ الْخَيْلِ وَنَهَانَا عَنْ لُحُومِ الْحُمُرِ","id":"Telah mengabarkan kepada kami [Al Husain bin Huraits], ia berkata; telah menceritakan kepada kami [Al Fadhl bin Musa] dari [Al Husain yaitu Ibnu Waqid] dari [Abu Az Zubair] dari [Jabir], dan ['Amr bin Dinar] dari [Jabir] dan [Ibnu Abu Najih] dari ['Atho`] dari [Jabir], ia berkata; Rasulullah shallallahu 'alaihi wasallam memberi makan kami pada saat Perang Khaibar daging kuda dan melarang kami dari daging keledai."},"4040":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ وَهُوَ ابْنُ عَمْرٍو قَالَ حَدَّثَنَا عَبْدُ الْكَرِيمِ عَنْ عَطَاءٍ عَنْ جَابِرٍ قَالَكُنَّا نَأْكُلُ لُحُومَ الْخَيْلِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Ali bin Hujr], ia berkata; telah menceritakan kepada kami ['Ubaidullah yaitu Ibnu 'Amr], ia berkata; telah menceritakan kepada kami [Abdul Karim] dari ['Atho`] dari [Jabir], ia berkata; kami pernah makan daging kuda pada zaman Rasulullah shallallahu 'alaihi wasallam. "},"4041":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ قَالَ حَدَّثَنِي ثَوْرُ بْنُ يَزِيدَ عَنْ صَالِحِ بْنِ يَحْيَى بْنِ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ خَالِدِ بْنِ الْوَلِيدِأَنَّهُ سَمِعَ رَسُولَ ال��َّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَحِلُّ أَكْلُ لُحُومِ الْخَيْلِ وَالْبِغَالِ وَالْحَمِيرِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah menceritakan kepada kami [Baqiyah bin Al Walid], ia berkata; telah menceritakan kepadaku [Tsaur bin Yazid] dari [Shalih bin Yahya bin Al Miqdam bin Ma'dikarib] dari [ayahnya] dari [kakeknya] dari [Khalid bin Walid] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal makan daging kuda, baghal dan keledai.\""},"4042":{"ar":"أَخْبَرَنَا كَثِيرُ بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا بَقِيَّةُ عَنْ ثَوْرِ بْنِ يَزِيدَ عَنْ صَالِحِ بْنِ يَحْيَى بْنِ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ خَالِدِ بْنِ الْوَلِيدِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ أَكْلِ لُحُومِ الْخَيْلِ وَالْبِغَالِ وَالْحَمِيرِ وَكُلِّ ذِي نَابٍ مِنْ السِّبَاعِ","id":"Telah mengabarkan kepada kami [Katsir bin 'Ubaid], ia berkata; telah menceritakan kepada kami [Baqiyah] dari [Tsaur bin Yazid] dari [Shalih bin Yahya bin Al Miqdam bin Ma'dikarib] dari [ayahnya] dari [kakeknya] dari [Khalid bin Al Walid] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari memakan daging kuda, baghal dan keledai serta segala yang memiliki taring dari binatang buas. "},"4043":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ عَبْدِ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ عَبْدِ الْكَرِيمِ عَنْ عَطَاءٍ عَنْ جَابِرٍ قَالَكُنَّا نَأْكُلُ لُحُومَ الْخَيْلِ قُلْتُ الْبِغَالَ قَالَ لَا","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dari [Abdurrahman] dari [Sufyan] dari [Abdul Karim] dari ['Atho`] dari [Jabir] ia berkata; kami makan daging kuda. Saya berkata bagaimana dengan baghal? ia menjawab; tidak."},"4044":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ سُفْيَانَ عَنْ الزُّهْرِيِّ عَنْ الْحَسَنِ بْنِ مُحَمَّدٍ وَعَبْدِ اللَّهِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِمَا قَالَقَالَ عَلِيٌّ لِابْنِ عَبَّاسٍ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ نِكَاحِ الْمُتْعَةِ وَعَنْ لُحُومِ الْحُمُرِ الْأَهْلِيَّةِ يَوْمَ خَيْبَرَ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dan [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, lafazhnya adalah lafazh Al Harits dari [Sufyan] dari [Az Zuhri] dari [Al Hasan bin Muhammad] dan [Abdullah bin Muhammad] dari [ayah mereka], ia berkata; [Ali] berkata kepada Ibnu Abbas; sesungguhnya Nabi shallallahu 'alaihi wasallam melarang dari nikah mut'ah dan daging keledai jinak pada saat perang Khaibar. "},"4045":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ وَمَالِكٌ وَأُسَامَةُ عَنْ ابْنِ شِهَابٍ عَنْ الْحَسَنِ وَعَبْدِ اللَّهِ ابْنَيْ مُحَمَّدٍ عَنْ أَبِيهِمَا عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ مُتْعَةِ النِّسَاءِ يَوْمَ خَيْبَرَ وَعَنْ لُحُومِ الْحُمُرِ الْإِنْسِيَّةِ","id":"Telah mengabarkan kepada kami [Sulaiman bin Daud], ia berkata; telah menceritakan kepada kami [Abdullah bin Wahb], ia berkata; telah mengabarkan kepadaku [Yunus] dan [Malik] serta [Usamah] dari [Ibnu Syihab] dari [Al Hasan] serta [Abdullah] dua anak Muhammad dari [ayah mereka] dari [Ali bin Abu Thalib] radliallahu 'anhu, ia berkata; Rasulullah shallallahu 'alaihi wasallam telah melarang dari menikahi wanita secara mut'ah pada saat perang Khaibar dan dari daging keledai jinak."},"4046":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا مُحَمَّدُ بْنُ بِشْرٍ قَالَ أَنْبَأَنَا عُبَيْدُ اللَّهِ ح وَأَنْبَأَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْحُمُرِ الْأَهْلِيَّةِ يَوْمَ خَيْبَرَأَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا مُحَمَّدُ بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ وَلَمْ يَقُلْ خَيْبَرَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Muhammad bin Bisyr], ia berkata; telah memberitakan kepada kami ['Ubaidullah], telah menceritakan dan memberitakan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari keledai jinak pada saat perang Khaibar. telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Muhammad bin 'Ubaid], ia berkata; telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam seperti hadits tersebut namun ia tidak menyebutkan Khaibar."},"4047":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ عَاصِمٍ عَنْ الشَّعْبِيِّ عَنْ الْبَرَاءِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ خَيْبَرَ عَنْ لُحُومِ الْحُمُرِ الْإِنْسِيَّةِ نَضِيجًا وَنِيئًا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Abdur Razzaq], ia berkata; telah menceritakan kepada kami [Ma'mar] dari ['Ashim] dari [Asy Sya'bi] dari [Al Barra`], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang pada saat perang Khaibar dari daging keledai jinak baik sudah matang atau masih mentah. "},"4048":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ الْمُقْرِئُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ الشَّيْبَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى قَالَأَصَبْنَا يَوْمَ خَيْبَرَ حُمُرًا خَارِجًا مِنْ الْقَرْيَةِ فَطَبَخْنَاهَا فَنَادَى مُنَادِي النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ حَرَّمَ لُحُومَ الْحُمُرِ فَأَكْفِئُوا الْقُدُورَ بِمَا فِيهَا فَأَكْفَأْنَاهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Yazid Al Muqri`], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq Asy Syaibani] dari [Abdullah bin Abu Aufa], ia berkata; kami telah mendapat keledai yang keluar dari kampong pada saat perang Khaibar, kemudian kami memasaknya lalu seorang penyeru Nabi shallallahu 'alaihi wasallam menyeru; sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah mengharamkan daging keledai maka baliklah kuali beserta dengan apa yang ada padanya. Maka kami membaliknya. "},"4049":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أَنَسٍ قَالَصَبَّحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْبَرَ فَخَرَجُوا إِلَيْنَا وَمَعَهُمْ الْمَسَاحِي فَلَمَّا رَأَوْنَا قَالُوا مُحَمَّدٌ وَالْخَمِيسُ وَرَجَعُوا إِلَى الْحِصْنِ يَسْعَوْنَ فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَيْهِ ثُمَّ قَالَ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ خَرِبَتْ خَيْبَرُ إِنَّا إِذَا نَزَلْنَا بِسَاحَةِ قَوْمٍ{ فَسَاءَ صَبَاحُ الْمُنْذَرِينَ }فَأَصَبْنَا فِيهَا حُمُرًا فَطَبَخْنَاهَا فَنَادَى مُنَادِي النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ وَرَسُولَهُ يَنْهَاكُمْ عَنْ لُحُومِ الْحُمُرِ فَإِنَّهَا رِجْسٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Yazid], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Ayyub] dari [Muhammad] dari [Anas], ia berkata; Rasulullah shallallahu 'alaihi wasallam menyerang Khaibar pada pagi hari kemudian mereka keluar kepada kami membawa sekop, kemudian tatkala melihat kami maka mereka mengatakan; Muhammad bersama dengan pasukan. Dan mereka kembali menuju benteng dengan setengah berlari. Kemudian Rasulullah shallallahu 'alaihi wasallam mengangkat kedua tangannya dan bersabda: \"Allahu akbar, Allahu akbar, Khaibar telah hancur. Sesungguhnya kami apabila turun turun dihalaman mereka, maka amat buruklah pagi hari yang dialami oleh orang-orang yang diperingatkan itu.\" Kemudian kami mendapatkan keledai lalu kami memasaknya. Kemudian penyeru Nabi shallallahu 'alaihi wasallam menyeru; sesungguhnya Allah 'azza wajalla dan RasulullahNya melarang kalian dari daging keledai sesungguhnya hal itu adalah najis."},"4050":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ أَنْبَأَنَا بَقِيَّةُ عَنْ بَحِيرٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِي ثَعْلَبَةَ الْخُشَنِيِّ أَنَّهُ حَدَّثَهُمْأَنَّهُمْ غَزَوْا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى خَيْبَرَ وَالنَّاسُ جِيَاعٌ فَوَجَدُوا فِيهَا حُمُرًا مِنْ حُمُرِ الْإِنْسِ فَذَبَحَ النَّاسُ مِنْهَا فَحُدِّثَ بِذَلِكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ عَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ فَأَذَّنَ فِي النَّاسِ أَلَا إِنَّ لُحُومَ الْحُمُرِ الْإِنْسِ لَا تَحِلُّ لِمَنْ يَشْهَدُ أَنِّي رَسُولُ اللَّهِ","id":"Telah mengabarkan kepada kami ['Amr bin Utsman] telah memberitakan kepada kami [Baqiyah] dari [Bahir] dari [Khalid bin Ma'dan] dari [Jubair bin Nufair] dari [Abu Tsa'labah Al Khusyani] bahwa ia menceritakan kepada mereka bahwa mereka berperang bersama Rasulullah shallallahu 'alaihi wasallam menuju Khaibar dan orang-orang dalam keadaan lapar. Kemudian mereka mendapatkan keledai jinak padanya, kemudian mereka menyembelih sebagiannya kemudian hal tersebut diceritakan kepada Nabi shallallahu 'alaihi wasallam, kemudian beliau memerintahkan Abdurrahman bin 'Auf kemudian ia mengumumkan diantara manusia; ketahuilah bahwa daging keledai jinak, keledai tersebut tidak halal bagi orang yang bersaksi bahwa aku adalah Rasulullah."},"4051":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ عَنْ بَقِيَّةَ قَالَ حَدَّثَنِي الزُّبَيْدِيُّ عَنْ الزُّهْرِيِّ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ أَبِي ثَعْلَبَةَ الْخُشَنِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ أَكْلِ كُلِّ ذِي نَابٍ مِنْ السِّبَاعِ وَعَنْ لُحُومِ الْحُمُرِ الْأَهْلِيَّةِ","id":"Telah mengabarkan kepada kami ['Amr bin Utsman] dari [Baqiyah], ia berkata; telah menceritakan kepadaku [Az Zubaidi] dari [Az Zuhri] dari [Abu Idris Al Khaulani] dari [Abu Tsa'labah Al Khusyani] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari memakan segala yang memiliki taring dari hewan buas dan dari daging keledai jinak."},"4052":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا الْمُفَضَّلُ هُوَ ابْنُ فَضَالَةَ عَنْ ابْنِ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَأَكَلْنَا يَوْمَ خَيْبَرَ لُحُومَ الْخَيْلِ وَالْوَحْشِ وَنَهَانَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْحِمَارِ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Mufadhdhal yaitu Ibnu Fadhalah] dari [Ibnu Juraij] dari [Abu Az Zubair] dari [Jabir], ia berkata; kami pada saat perang Khaibar makan daging kuda serta keledai liar, dan Nabi shallallahu 'alaihi wasallam melarang dari keledai. "},"4053":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا بَكْرٌ هُوَ ابْنُ مُضَرَ عَنْ ابْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ عِيسَى بْنِ طَلْحَةَ عَنْ عُمَيْرِ بْنِ سَلَمَةَ الضَّمْرِيِّ قَالَبَيْنَا نَحْنُ نَسِيرُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِبَعْضِ أَثَايَا الرَّوْحَاءِ وَهُمْ حُرُمٌ إِذَا حِمَارُ وَحْشٍ مَعْقُورٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعُوهُ فَيُوشِكُ صَاحِبُهُ أَنْ يَأْتِيَهُ فَجَاءَ رَجُلٌ مِنْ بَهْزٍ هُوَ الَّذِي عَقَرَ الْحِمَارَ فَقَالَ يَا رَسُولَ اللَّهِ شَأْنَكُمْ هَذَا الْحِمَارُ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَا بَكْرٍ يُقَسِّمُهُ بَيْنَ النَّاسِ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Bakr yaitu Ibnu Mudhar] dari [Ibnu Al Had] dari [Muhammad bin Ibrahim] dari [Isa bin Thalhah] dari ['Umair bin Salamah Adh Dhamri], ia berkata; ketika kami berjalan bersama Rasulullah shallallahu 'alaihi wasallam membawa sebagian tempat di Atsaya (tempat diantara dua tanah haram), dan mereka sedang beihram. Tiba-tiba terdapat keledai liar yang tersembelih, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pemiliknya akan datang kepadanya.\" Kemudian datanglah seorang laki-laki dari Bahz, ia adalah orang yang menyembelih keledai tersebut, kemudian Ia berkata; wahai Rasulullah, ambillah keledai ini. Lalu Rasulullah shallallahu 'alaihi wasallam memerintahkan Abu Bakar untuk membaginya diantara manusia. "},"4054":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ وَهْبٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنِي أَبُو عَبْدِ الرَّحِيمِ قَالَ حَدَّثَنِي زَيْدُ بْنُ أَبِي أُنَيْسَةَ عَنْ أَبِي حَازِمٍ عَنْ ابْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ أَبِي قَتَادَةَ قَالَأَصَابَ حِمَارًا وَحْشِيًّا فَأَتَى بِهِ أَصْحَابَهُ وَهُمْ مُحْرِمُونَ وَهُوَ حَلَالٌ فَأَكَلْنَا مِنْهُ فَقَالَ بَعْضُهُمْ لِبَعْضٍ لَوْ سَأَلْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْهُ فَسَأَلْنَاهُ فَقَالَ قَدْ أَحْسَنْتُمْ فَقَالَ لَنَا هَلْ مَعَكُمْ مِنْهُ شَيْءٌ قُلْنَا نَعَمْ قَالَ فَاهْدُوا لَنَا فَأَتَيْنَاهُ مِنْهُ فَأَكَلَ مِنْهُ وَهُوَ مُحْرِمٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Wahb], ia berkata; telah menceritakan kepada kami [Muhammad bin Salamah], ia berkata; telah menceritakan kepadaku [Abu Abdurrahin], ia berkata; telah menceritakan kepadaku [Zaid bin Abu Unaisah] dari [Abu Hazim] dari [Ibnu Abu Qatadah] dari [ayahnya yaitu Abu Qatadah], bahwa Ia mendapatkan unta liar kemudian ia membawanya kepada para sahabatnya yang sedang berihram, sedangkan ia tidak berihram. Kemudian kami makan sebagian darinya. Sebagian mereka berkata kepada sebagian yang lain, sendainya kita bertanya kepada Rasulullah shallallahu 'alaihi wasallam, kemudian kami bertanya kepada beliau. Beliau bersabda: \"Kalian telah berbuat baik\", kemudian beliau bersabda kepada kami: \"Apakah kalian memiliki sebagian darinya?\" kami mengatakan; ya. Beliau bersabda: \"Berilah kami hadiah.\" Maka kami memberi sebagian darinya kepada beliau. Kemudian beliau memakan sebagiannya sedang beliau dalam keadaan berihram. "},"4055":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ زَهْدَمٍأَنَّ أَبَا مُوسَى أُتِيَ بِدَجَاجَةٍ فَتَنَحَّى رَجُلٌ مِنْ الْقَوْمِ فَقَالَ مَا شَأْنُكَ قَالَ إِنِّي رَأَيْتُهَا تَأْكُلُ شَيْئًا قَذِرْتُهُ فَحَلَفْتُ أَنْ لَا آكُلَهُ فَقَالَ أَبُو مُوسَى ادْنُ فَكُلْ فَإِنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُهُ وَأَمَرَهُ أَنْ يُكَفِّرَ عَنْ يَمِينِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur], ia berkata; telah menceritakan kepada kami [Sufyan], ia berkata; telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Zahdam] bahwa Abu Musa diberi ayam kemudian Seseorang menjauh. Kemudian Abu Musa berkata; ada apa engkau? Ia berkata; sesungguhnya saya telah melihat memakan sesuatu yang tidak saya sukai, kemudian saya bersumpah untuk tidak memakannya. Kemudian [Abu Musa] berkata; mendekatlah dan makanlah sesungguhnya saya melihat Rasulullah shallallahu 'alaihi wasallam memakannya dan memerintahkannya. Dan Abu Musa memerintahkannya agar menebus sumpahnya. "},"4056":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ عَنْ أَيُّوبَ عَنْ الْقَاسِمِ التَّمِيمِيِّ عَنْ زَهْدَمٍ الْجَرْمِيِّ قَالَكُنَّا عِنْدَ أَبِي مُوسَى فَقُدِّمَ طَعَامُهُ وَقُدِّمَ فِي طَعَامِهِ لَحْمُ دَجَاجٍ وَفِي الْقَوْمِ رَجُلٌ مِنْ بَنِي تَيْمِ اللَّهِ أَحْمَرُ كَأَنَّهُ مَوْلًى فَلَمْ يَدْنُ فَقَالَ لَهُ أَبُو مُوسَى ادْنُ فَإِنِّي قَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ مِنْهُ","id":"Telah mengabarkan kepada kami [Ali bin Hujr], ia berkata; telah menceritakan kepada kami [Isma'il] dari [Ayyub] dari [Al Qasim At Taimi] dari [Zahdam Al Jarmi], ia berkata; kami pernah bersama Abu Musa kemudian disuguhkan makanannya dan di dalam makanannya disuguhkan daging ayam, dan diantara orang-orang terdapat seorang laki-laki dari Bani Taimillah ahmar, sepertinya ia adalah seorang budak dan ia tidak mendekat. Kemudian [Abu Musa] berkata kepadanya; mendekatlah, sesungguhnya saya telah melihat Rasulullah shallallahu 'alaihi wasallam memakan sebagian darinya. "},"4057":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ عَنْ بِشْرٍ هُوَ ابْنُ الْمُفَضَّلِ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ عَلِيِّ بْنِ الْحَكَمِ عَنْ مَيْمُونِ بْنِ مِهْرَانَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى يَوْمَ خَيْبَرَ عَنْ كُلِّ ذِي مِخْلَبٍ مِنْ الطَّيْرِ وَعَنْ كُلِّ ذِي نَابٍ مِنْ السِّبَاعِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dari [Bisyr yaitu Ibnu Al Mufadhdhal], ia berkata; telah menceritakan kepada kami [Sa'id] dari [Ali bin Al Hakam] dari [Maimun bin Mahran] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam pada saat perang Khaibar melarang dari setiap yang memilki kuku dari burung dan dari segala yang memiliki taring dari hewan buas. "},"4058":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ الْمُقْرِئُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ صُهَيْبٍ مَوْلَى ابْنِ عَامِرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ إِنْسَانٍ قَتَلَ عُصْفُورًا فَمَا فَوْقَهَا بِغَيْرِ حَقِّهَا إِلَّا سَأَلَهُ اللَّهُ عَزَّ وَجَلَّ عَنْهَا قِيلَ يَا رَسُولَ اللَّهِ وَمَا حَقُّهَا قَالَ يَذْبَحُهَا فَيَأْكُلُهَا وَلَا يَقْطَعُ رَأْسَهَا يَرْمِي بِهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Yazid Al Muqri`], ia berkata; telah menceritakan kepada kami [Sufyan] dari ['Amr] dari [Shuhaib] budak Ibnu 'Amir dari [Abdullah bin 'Amr] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang membunuh burung dan yang di atasnya tanpa hak kecuali Allah 'azza wajalla akan bertanya mengenainya.\" Dikatakan; wahai Rasulullah, apakah haknya? Beliau bersabda: \"Haknya adalah menyembelihnya, memakannya dan tidak memotong kepalanya dan membuangnya. "},"4059":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا مَالِكٌ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ سَعِيدِ بْنِ سَلَمَةَ عَنْ الْمُغِيرَةِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَاءِ الْبَحْرِ هُوَ الطَّهُورُ مَاؤُهُ الْحَلَالُ مَيْتَتُهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur], ia berkata; telah menceritakan kepada kami [Abdurrahman], ia berkata; telah menceritakan kepada kami [Malik] dari [Shafwan bin Sulaim] dari [Sa'id bin Salamah] dari [Al Mughirah bin Abu Burdah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam mengenai air laut; beliau bersabda: \"Laut itu suci airnya dan halal bangkainya.\""},"4060":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ آدَمَ قَالَ حَدَّثَنَا عَبْدَةُ عَنْ هِشَامٍ عَنْ وَهْبِ بْنِ كَيْسَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَبَعَثَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ ثَلَاثُ مِائَةٍ نَحْمِلُ زَادَنَا عَلَى رِقَابِنَا فَفَنِيَ زَادُنَا حَتَّى كَانَ يَكُونُ لِلرَّجُلِ مِنَّا كُلَّ يَوْمٍ تَمْرَةٌ فَقِيلَ لَهُ يَا أَبَا عَبْدِ اللَّهِ وَأَيْنَ تَقَعُ التَّمْرَةُ مِنْ الرَّجُلِ قَالَ لَقَدْ وَجَدْنَا فَقْدَهَا حِينَ فَقَدْنَاهَا فَأَتَيْنَا الْبَحْرَ فَإِذَا بِحُوتٍ قَذَفَهُ الْبَحْرُ فَأَكَلْنَا م��نْهُ ثَمَانِيَةَ عَشَرَ يَوْمًا","id":"Telah mengabarkan kepada kami [Muhammad bin Adam], ia berkata; telah menceritakan kepada kami ['Abdah] dari [Hisyam] dari [Wahb bin Kaisan] dari [Jabir bin Abdullah], ia berkata; Nabi shallallahu 'alaihi wasallam mengutus kami sedang kami berjumlah tiga ratus, kami membawa perbekalan kami di atas punggung kami. Kemudian perbekalan kami habis hingga setiap orang diantara kami setiap hari memiliki satu buah kurma. Kemudian dikatakan; wahai Abu Abdullah, dimanakah kurma tersebut terjatuh dari orang tersebut? Ia berkata; sungguh kami telah benar-benar kehilangan kurma ketika kehilang kurma tersebut. Kemudian kami datang ke laut kemudian tiba-tiba terdapat ikan paus yang didamparkan oleh laut, kemudian kami memakan darinya selama delapan belas hari. "},"4061":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ عَنْ سُفْيَانَ عَنْ عَمْرٍو قَالَ سَمِعْتُ جَابِرًا يَقُولُبَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَ مِائَةِ رَاكِبٍ أَمِيرُنَا أَبُو عُبَيْدَةَ بْنُ الْجَرَّاحِ نَرْصُدُ عِيرَ قُرَيْشٍ فَأَقَمْنَا بِالسَّاحِلِ فَأَصَابَنَا جُوعٌ شَدِيدٌ حَتَّى أَكَلْنَا الْخَبَطَ قَالَ فَأَلْقَى الْبَحْرُ دَابَّةً يُقَالُ لَهَا الْعَنْبَرُ فَأَكَلْنَا مِنْهُ نِصْفَ شَهْرٍ وَادَّهَنَّا مِنْ وَدَكِهِ فَثَابَتْ أَجْسَامُنَا وَأَخَذَ أَبُو عُبَيْدَةَ ضِلْعًا مِنْ أَضْلَاعِهِ فَنَظَرَ إِلَى أَطْوَلِ جَمَلٍ وَأَطْوَلِ رَجُلٍ فِي الْجَيْشِ فَمَرَّ تَحْتَهُ ثُمَّ جَاعُوا فَنَحَرَ رَجُلٌ ثَلَاثَ جَزَائِرَ ثُمَّ جَاعُوا فَنَحَرَ رَجُلٌ ثَلَاثَ جَزَائِرَ ثُمَّ جَاعُوا فَنَحَرَ رَجُلٌ ثَلَاثَ جَزَائِرَ ثُمَّ نَهَاهُ أَبُو عُبَيْدَةَقَالَ سُفْيَانُ قَالَ أَبُو الزُّبَيْرِ عَنْ جَابِرٍ فَسَأَلْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَلْ مَعَكُمْ مِنْهُ شَيْءٌ قَالَ فَأَخْرَجْنَا مِنْ عَيْنَيْهِ كَذَا وَكَذَا قُلَّةً مِنْ وَدَكٍ وَنَزَلَ فِي حَجَّاجِ عَيْنِهِ أَرْبَعَةُ نَفَرٍ وَكَانَ مَعَ أَبِي عُبَيْدَةَ جِرَابٌ فِيهِ تَمْرٌ فَكَانَ يُعْطِينَا الْقَبْضَةَ ثُمَّ صَارَ إِلَى التَّمْرَةِ فَلَمَّا فَقَدْنَاهَا وَجَدْنَا فَقْدَهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dari [Sufyan] dari ['Amr], ia berkata; saya mendengar [Jabir] berkata; Rasulullah shallallahu 'alaihi wasallam mengutus kami dan jumlah kami adalah tiga ratus orang, pemimpin kami adalah Abu 'Ubaidah bin Al Jarrah, kami mengintai kelompok dagang orang-orang Quraisy. Kemudian kami bermukim di tepi laut lalu kami tertimpa kelaparan yang sangat hingga kami makan daun yang terjatuh. Ia berkata; kemudian laut mendamparkan seekor binatang yang disebut ikan paus. Lalu kami memakan darinya selama setengah bulan. Dan kami berminyakan dari lemaknya, dan tubuh kami menjadi kuat. Kemudian Abu 'Ubaidah mengambil satu dari tulang-tulang rusuknya. Kemudian ia melihat kepada unta yang terpanjang serta orang yang tertinggi diantara pasukan. Lalu unta tersebut melewati di bawah tulang rusuk tersebut kemudian mereka merasa lapar, lalu seseorang menyembelih sebanyak tiga sembelihan kemudian mereka merasa lapar, lalu seseorang menyembelih tiga sembelihan kemudian mereka merasa lapar, lalu seseorang menyembelih tiga sembelihan kemudian Abu 'Ubaidah melarangnya. [Sufyan] berkata; telah berkata [Abu Az Zubair] dari [Jabir], kemudian kami bertanya kepada Nabi shallallahu 'alaihi wasallam lalu beliau bersabda: \"Apakah kalian membawa sebagiannya?\" ia berkata; kemudian kami mengeluarkan dari kedua mata ikan tersebut sekian dan sekian kendi dari lemak. Dan telah singgan di daerah Hajjaj 'ainih empat orang dan Abu 'Ubaidah memabawa kantong yang berisi kurma, dan ia memberi kami satu genggam hingga menjadi satu biji kurma, kemudian tatkala kami kehilangan kurma tersebut maka mendapatkannya."},"4062":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَبَعَثَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ أَبِي عُبَيْدَةَ فِي سَرِيَّةٍ فَنَفِدَ زَادُنَا فَمَرَرْنَا بِحُوتٍ قَدْ قَذَفَ بِهِ الْبَحْرُ فَأَرَدْنَا أَنْ نَأْكُلَ مِنْهُ فَنَهَانَا أَبُو عُبَيْدَةَ ثُمَّ قَالَ نَحْنُ رُسُلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي سَبِيلِ اللَّهِ كُلُوا فَأَكَلْنَا مِنْهُ أَيَّامًا فَلَمَّا قَدِمْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرْنَاهُ فَقَالَ إِنْ كَانَ بَقِيَ مَعَكُمْ شَيْءٌ فَابْعَثُوا بِهِ إِلَيْنَا","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub], ia berkata; telah menceritakan kepada kami [Husyaim], ia berkata; telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir], ia berkata; Nabi shallallahu 'alaihi wasallam mengutus kami bersama dengan Abu 'Ubaidah dalam sebuah ekspedisi kemudian perbekalan kami habis, lalu kami melewati seekor ikan hiu yang telah didamparkan oleh laut, kemudian kami hendak makan darinya dan Abu 'Ubaidah melarang kami. Kemudian ia berkata; kita adalah utusan Rasulullah shallallahu 'alaihi wasallam dan di jalan Allah. Makanlah, maka kami memakannya selama beberapa hari. Kemudian tatkala kami datang kepada Rasulullah shallallahu 'alaihi wasallam kami khabarkan hal tersebut kepadanya. Kemudian beliau bersabda: \"Apabia ada yang tersisa bersama kalian maka kirimkan kepada kami.\" "},"4063":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُمَرَ بْنِ عَلِيِّ بْنِ مُقَدَّمٍ الْمُقَدَّمِيُّ قَالَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَبَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ أَبِي عُبَيْدَةَ وَنَحْنُ ثَلَاثُ مِائَةٍ وَبِضْعَةَ عَشَرَ وَزَوَّدَنَا جِرَابًا مِنْ تَمْرٍ فَأَعْطَانَا قَبْضَةً قَبْضَةً فَلَمَّا أَنْ جُزْنَاهُ أَعْطَانَا تَمْرَةً تَمْرَةً حَتَّى إِنْ كُنَّا لَنَمُصُّهَا كَمَا يَمُصُّ الصَّبِيُّ وَنَشْرَبُ عَلَيْهَا الْمَاءَ فَلَمَّا فَقَدْنَاهَا وَجَدْنَا فَقْدَهَا حَتَّى إِنْ كُنَّا لَنَخْبِطُ الْخَبَطَ بِقِسِيِّنَا وَنَسَفُّهُ ثُمَّ نَشْرَبُ عَلَيْهِ مِنْ الْمَاءِ حَتَّى سُمِّينَا جَيْشَ الْخَبَطِ ثُمَّ أَجَزْنَا السَّاحِلَ فَإِذَا دَابَّةٌ مِثْلُ الْكَثِيبِ يُقَالُ لَهُ الْعَنْبَرُ فَقَالَ أَبُو عُبَيْدَةَ مَيْتَةٌ لَا تَأْكُلُوهُ ثُمَّ قَالَ جَيْشُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ وَنَحْنُ مُضْطَرُّونَ كُلُوا بِاسْمِ اللَّهِ فَأَكَلْنَا مِنْهُ وَجَعَلْنَا مِنْهُ وَشِيقَةً وَلَقَدْ جَلَسَ فِي مَوْضِعِ عَيْنِهِ ثَلَاثَةَ عَشَرَ رَجُلًا قَالَ فَأَخَذَ أَبُو عُبَيْدَةَ ضِلْعًا مِنْ أَضْلَاعِهِ فَرَحَلَ بِهِ أَجْسَمَ بَعِيرٍ مِنْ أَبَاعِرِ الْقَوْمِ فَأَجَازَ تَحْتَهُ فَلَمَّا قَدِمْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا حَبَسَكُمْ قُلْنَا كُنَّا نَتَّبِعُ عِيرَاتِ قُرَيْشٍ وَذَكَرْنَا لَهُ مِنْ أَمْرِ الدَّابَّةِ فَقَالَ ذَاكَ رِزْقٌ رَزَقَكُمُوهُ اللَّهُ عَزَّ وَجَلَّ أَمَعَكُمْ مِنْهُ شَيْءٌ قَالَ قُلْنَا نَعَمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Umar bin Ali bin Muqaddam Al Muqadami], ia berkata; telah menceritakan kepada kami [Mu'adz bin Hisyam], ia berkata; telah menceritakan kepadaku [ayahku] dari [Abu Az Zubair] dari [Jabir], ia berkata; Rasulullah shallallahu 'alaihi wasallam mengutus kami bersama Abu 'Ubaidah dan jumlah kami adalah seratus tiga belas dan beliau membekali satu kantong kurma, kemudian ia memberi kami satu genggam satu genggam. Kemudian setelah kami menghabiskannya lalu ia memberi kami satu kurma satu kurma hingga kami menghisab-hisab sebagaimana seorang bayi menghisab dan meminum air. Kemudian setelah kami kehilangan kurma tersebut maka kami benar-benar kehilangan kurma. Hingga kami memukul pohon agar daunnya rontok menggunakan busur kami memakannya dan minum airnya, hingga kami dinamai pasukan khabat (yang merontokkan daun pohon menggunakan busur). Kemudian kami melewati tepi laut, tiba-tiba terdapat hewan seperti bukit pasir yang disebut ikan paus. Kemudian Abu 'Ubaidah berkata; itu adalah bangkai janganlah kalian makan. Kemudian ia berkata; kalian adalah pasukan Rasulullah shallallahu 'alaihi wasallam dan berada di jalan Allah 'azza wajalla, dan kami dalam keadaan terdesak. Makanlah dengan menyebut nama Allah, maka kami makan sebagian darinya dan dendengnya. Sungguh tempat matanya telah diduduki oleh tiga belas orang. Kemudian Abu 'Ubaidah mengambil satu dari tulang-tulang rusuknya kemudian membawanya kepada unta yang terbesar kemudin unta tersebut melewati dibawahnya. Kemudian tatkala kami telah datang kepada Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Apakah yang menahan kalian?\" kami berkata; kami mengikuti kelompok dagang orang-orang Quraisy.... dan kami sebutkan kepada beliau perkara mengenai hewan tersebut. Kemudian beliau bersabda: \"Itu adalah rizqi yang telah Allah berikan kepada kalian, apakah kalian membawa sedikit darinya?\" kami mengatakan; ya. "},"4064":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ سَعِيدِ بْنِ خَالِدٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عُثْمَانَأَنَّ طَبِيبًا ذَكَرَ ضِفْدَعًا فِي دَوَاءٍ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قَتْلِهِ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Ibnu Abu Fudaik] dari [Ibnu Abu Dzi`b] dari [Sa'id bin Khalid] dari [Sa'id bin Al Musayyab] dari [Abdurrahman bin Utsman] bahwa terdapat seorang dokter menyebutkan kodok sebagai obat di hadapan Rasulullah shallallahu 'alaihi wasallam, kemudian beliau melarang dari membunuhnya."},"4065":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ عَنْ سُفْيَانَ وَهُوَ ابْنُ حَبِيبٍ عَنْ شُعْبَةَ عَنْ أَبِي يَعْفُورَ سَمِعَ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَى قَالَغَزَوْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْعَ غَزَوَاتٍ فَكُنَّا نَأْكُلُ الْجَرَادَ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dari [Sufyan] yaitu Ibnu Habib dari [Syu'bah] dari [Abu Ya'fur], ia mendengar [Abdullah bin Abu Aufa] berkata; kami berperang bersama Rasulullah shallallahu 'alaihi wasallam sebanyak tujuh peperangan, dan kami makan belalang."},"4066":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ سُفْيَانَ وَهُوَ ابْنُ عُيَيْنَةَ عَنْ أَبِي يَعْفُورَ قَالَسَأَلْتُ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَى عَنْ قَتْلِ الْجَرَادِ فَقَالَ غَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِتَّ غَزَوَاتٍ نَأْكُلُ الْجَرَادَ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Sufyan yaitu Ibnu 'Uyainah] dari [Abu Ya'fur], ia berkata; saya bertanya kepada [Abdullah bin Abu Aufa] mengenai membunuh belalang, kemudian ia berkata; saya pernah berperang bersama Rasulullah shallallahu 'alaihi wasallam sebanyak enam kali dan kami memakan belalang. "},"4067":{"ar":"أَخْبَرَنَا وَهْبُ بْنُ بَيَانٍ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدٍ وَأَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ نَمْلَةً قَرَصَتْ نَبِيًّا مِنْ الْأَنْبِيَاءِ فَأَمَرَ بِقَرْيَةِ النَّمْلِ فَأُحْرِقَتْ فَأَوْحَى اللَّهُ عَزَّ وَجَلَّ إِلَيْهِ أَنْ قَدْ قَرَصَتْكَ نَمْلَةٌ أَهْلَكْتَ أُمَّةً مِنْ الْأُمَمِ تُسَبِّحُ","id":"Telah mengabarkan kepada kami [Wahb bin Bayan], ia berkata; telah menceritakan kepada kami [Ibnu Wahb], ia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Sa'id] dan [Abu Salamah] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam bahwa seekor semut menggigit seorang Nabi dari nabi-nabi terdahulu, lalu ia memerintahkan untuk menghancurkan bangsa semut dan membakar mereka, Kemudian Allah Azza wa jalla mewahyukan bahwa engkau telah digigit seekor semut, dan engkau telah membinasakan sebuah umat diantara umat-umat yang bertasbih."},"4068":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا النَّضْرُ وَهُوَ ابْنُ شُمَيْلٍ قَالَ أَنْبَأَنَا أَشْعَثُ عَنْ الْحَسَنِنَزَلَ نَبِيٌّ مِنْ الْأَنْبِيَاءِ تَحْتَ شَجَرَةٍ فَلَدَغَتْهُ نَمْلَةٌ فَأَمَرَ بِبَيْتِهِنَّ فَحُرِّقَ عَلَى مَا فِيهَا فَأَوْحَى اللَّهُ إِلَيْهِ فَهَلَّا نَمْلَةٌ وَاحِدَةٌو قَالَ الْأَشْعَثُ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ ��َنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ وَزَادَ فَإِنَّهُنَّ يُسَبِّحْنَ أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ أَبِي هُرَيْرَةَ نَحْوَهُ وَلَمْ يَرْفَعْهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [An Nadhr yaitu Ibnu Syumail], ia berkata; telah memberitakan kepada kami [Asy'ats] dari [Al Hasan], ia berkata; seorang nabi telah singgal di bawah sebuah pohon kemudian ia disengat oleh seekor semut. Kemudian ia memerintahkan agar menghancurkan rumah semut tersebut, kemudian dibakarlah besarta penghuninya. Lalu Allah mewahyukan kepadanya; Apakah hanya satu ekor semut? [Al Asy'ats] berkata; dari [Ibnu Sirin] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti itu, dan Ia menambahkan; sesunggunya semut-semut tersebut sedang bertasbih. Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah menceritakan kepada kami [Mu'adz bin Hisyam], ia berkata; telah menceritakan kepadaku [ayahku] dari [Qatadah] dari [Al Hasan] dari [Abu Hurairah] seperti itu dan ia tidak memarfu'kannya. "},"4069":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ سَلْمٍ الْبَلْخِيُّ قَالَ حَدَّثَنَا النَّضْرُ وَهُوَ ابْنُ شُمَيْلٍ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ ابْنِ مُسْلِمٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أُمِّ سَلَمَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ رَأَى هِلَالَ ذِي الْحِجَّةِ فَأَرَادَ أَنْ يُضَحِّيَ فَلَا يَأْخُذْ مِنْ شَعْرِهِ وَلَا مِنْ أَظْفَارِهِ حَتَّى يُضَحِّيَ","id":"Telah mengabarkan kepada kami [Sulaiman bin Salm Al Balkhi], ia berkata; telah menceritakan kepada kami [An Nadhr yaitu Ibnu Syumail], ia berkata; telah memberitakan kepada kami [Syu'bah] dari [Malik bin Anas] dari [Ibnu Muslim] dari [Sa'id bin Al Musayyab] dari [Ummu Salamah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barang siapa yang melihat bulan sabit Bulan Dzul Hijjah kemudian ia hendak berkorban maka janganlah ia mengambil sebagian dari rambutnya dan kukunya hingga ia menyembelihnya.\""},"4070":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ عَنْ شُعَيْبٍ قَالَ أَنْبَأَنَا اللَّيْثُ قَالَ حَدَّثَنَا خَالِدُ بْنُ يَزِيدَ عَنْ ابْنِ أَبِي هِلَالٍ عَنْ عَمْرِو بْنِ مُسْلِمٍ أَنَّهُ قَالَ أَخْبَرَنِي ابْنُ الْمُسَيَّبِ أَنَّ أُمَّ سَلَمَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَرَادَ أَنْ يُضَحِّيَ فَلَا يَقْلِمْ مِنْ أَظْفَارِهِ وَلَا يَحْلِقْ شَيْئًا مِنْ شَعْرِهِ فِي عَشْرِ الْأُوَلِ مِنْ ذِي الْحِجَّةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Abdul Hakam] dari [Syu'aib], ia berkata; telah memberitakan kepada kami [Al Laits], ia berkata; telah menceritakan kepada kami [Khalid bin Yazid] dari [Ibnu Abu Hilal] dari ['Amr bin Muslim] bahwa ia berkata; telah mengabarkan kepadaku [Ibnu Al Musayyab] bahwa [Ummu salamah] isteri Nabi shallallahu 'alaihi wasallam telah mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang ingin bekorban maka janganlah ia memotong sebagian dari kukunya dan mencukur sebagian dari rambutnya pada sepuluh pertama bulan Dzul Hijjah.\""},"4071":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا شَرِيكٌ عَنْ عُثْمَانَ الْأَحْلَافِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَمَنْ أَرَادَ أَنْ يُضَحِّيَ فَدَخَلَتْ أَيَّامُ الْعَشْرِ فَلَا يَأْخُذْ مِنْ شَعْرِهِ وَلَا أَظْفَارِهِفَذَكَرْتُهُ لِعِكْرِمَةَ فَقَالَ أَلَا يَعْتَزِلُ النِّسَاءَ وَالطِّيبَ","id":"Telah mengabarkan kepada kami [Ali bin Hujr], ia berkata; telah memberitakan kepada kami [Syarik] dari [Utsman Al Ahlafi] dari [Said bin Al Musayyab] ia berkata; barangsiapa yang ingin menyembelih lalu masuk sepuluh hari, maka janganlah ia memotong sebagian dari rambut atau kukunya. Lalu saya menceritakan hal itu kepada [Ikrimah], ia menjawab, tidakkah ia menjauhi para wanita dan parfum."},"4072":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أُمِّ سَلَمَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا دَخَلَتْ الْعَشْرُ فَأَرَادَ أَحَدُكُمْ أَنْ يُضَحِّيَ فَلَا يَمَسَّ مِنْ شَعْرِهِ وَلَا مِنْ بَشَرِهِ شَيْئًا","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad bin Abdurrahman], ia berkata; telah menceritakan kepada kami [Sufyan], ia berkata; telah menceritakan kepadaku [Abdurrahman bin Humaid bin Abdurrahman bin 'Auf] dari [Sa'id bin Al Musayyab] dari [Ummu Salamah], beliau bersabda: \"Apabila telah masuk sepuluh hari kemudian salah seorang diantara kalian ingin berkorban maka hendaknya ia tidak mengambil sebagian dari rambutnya dan sebagian dari kulitnya sedikitpun.\""},"4073":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ أَبِي أَيُّوبَ وَذَكَرَ آخَرِينَ عَنْ عَيَّاشِ بْنِ عَبَّاسٍ الْقِتْبَانِيِّ عَنْ عِيسَى بْنِ هِلَالٍ الصَّدَفِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِرَجُلٍ أُمِرْتُ بِيَوْمِ الْأَضْحَى عِيدًا جَعَلَهُ اللَّهُ عَزَّ وَجَلَّ لِهَذِهِ الْأُمَّةِ فَقَالَ الرَّجُلُ أَرَأَيْتَ إِنْ لَمْ أَجِدْ إِلَّا مَنِيحَةً أُنْثَى أَفَأُضَحِّي بِهَا قَالَ لَا وَلَكِنْ تَأْخُذُ مِنْ شَعْرِكَ وَتُقَلِّمُ أَظْفَارَكَ وَتَقُصُّ شَارِبَكَ وَتَحْلِقُ عَانَتَكَ فَذَلِكَ تَمَامُ أُضْحِيَّتِكَ عِنْدَ اللَّهِ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami [Yunus bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Ibnu Wahb], ia berkata; telah mengabarkan kepadaku [Sa'id bin Abu Ayyub] dan ia menyebutkan yang lainnya dari ['Ayyasy bin 'Ayyasy bin Abbas Al Qatbani] dari [Isa bin Hilal Ash Shadafi] dari [Abdullah bin 'Amr bin Al 'Ash] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda kepada seseorang: \"Aku diperintah untuk menjadikan hari qurban sebagai hari raya yang Allah Azza wa jalla jadikan untuk umat ini, \" lalu seseorang berkata; bagaimana pendapatmu jika aku tidak mendapatkan kecuali hewan betina untuk diambil susunya, apakah aku menyembelihnya, beliau bersabda: \"Tidak, tapi potonglah rambutmu, kukumu, kumismu dan bulu kemaluanmu maka itu adalah kesempurnaan kurbanmu disisi Allah Azza wa jalla.\""},"4074":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ عَنْ شُعَيْبٍ عَنْ اللَّيْثِ عَنْ كَثِيرِ بْنِ فَرْقَدٍ عَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَذْبَحُ أَوْ يَنْحَرُ بِالْمُصَلَّى","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Abdul Hakam] dari [Syu'aib] dari [Al Laits] dari [Katsir bin Farqad] dari [Nafi'] bahwa [Abdullah] telah mengabarkannya bahwa Rasulullah shallallahu 'alaihi wasallam menyembelih di lapangan. "},"4075":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ عُثْمَانَ النُّفَيْلِيُّ قَالَ حَدَّثَنَا سَعِيدُ بْنُ عِيسَى قَالَ حَدَّثَنَا الْمُفَضَّلُ بْنُ فَضَالَةَ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحَرَ يَوْمَ الْأَضْحَى بِالْمَدِينَةِ قَالَ وَقَدْ كَانَ إِذَا لَمْ يَنْحَرْ يَذْبَحُ بِالْمُصَلَّى","id":"Telah mengabarkan kepada kami [Ali bin Utsman An Nufaili], ia berkata; telah menceritakan kepada kami [Sa'id bin Isa], ia berkata; telah menceritakan kepada kami [Al Mufadhdhal bin Fadhalah], ia berkata; telah menceritakan kepadaku [Abdullah bin Sulaiman], ia berkata; telah menceritakan kepadaku, [Nafi'] dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam menyembelih pada hari raya kurban di Madinah. Al Mufadhdhal berkata; Rasulullah shallallahu 'alaihi wasallam apabila tidak melakukan nahr maka beliau menyembelih di lapangan. "},"4076":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي الْأَحْوَصِ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ عَنْ جُنْدُبِ بْنِ سُفْيَانَ قَالَشَهِدْتُ أَضْحًى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى بِالنَّاسِ فَلَمَّا قَضَى الصَّلَاةَ رَأَى غَنَمًا قَدْ ذُبِحَتْ فَقَالَ مَنْ ذَبَحَ قَبْلَ الصَّلَاةِ فَلْيَذْبَحْ شَاةً مَكَانَهَا وَمَنْ لَمْ يَكُنْ ذَبَحَ فَلْيَذْبَحْ عَلَى اسْمِ اللَّهِ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dari [Abu Al Ahwash] dari [Al Aswad bin Qais] dari [Jundub bin Sufyan], ia berkata; saya menyaksikan shalat idul adhha bersama Rasulullah shallallahu 'alaihi wasallam, beliau shalat bersama orang-orang, kemudian setelah menyelesai melakukan shalat beliau melihat seekor kambing yang disembelih. Lalu beliau bersabda: \"Barang siapa yang menyembelih sebelum shalat maka hendaknya ia menyembelih kambing sebagai gantinya dan barang siapa yang belum menyembelih maka hendaknya ia menyembelih dengan nama Allah 'azza wajalla. "},"4077":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ بْنِ عَبْدِ الرَّحْمَنِ مَوْلَى بَنِي أَسَدٍ عَنْ أَبِي الضَّحَّاكِ عُبَيْدِ بْنِ فَيْرُوزَ مَوْلَى بَنِي شَيْبَانَ قَالَ قُلْتُ لِلْبَرَاءِحَدِّثْنِي عَمَّا نَهَى عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْأَضَاحِيِّ قَالَ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيَدِي أَقْصَرُ مِنْ يَدِهِ فَقَالَ أَرْبَعٌ لَا يَجُزْنَ الْعَوْرَاءُ الْبَيِّنُ عَوَرُهَا وَالْمَرِيضَةُ الْبَيِّنُ مَرَضُهَا وَالْعَرْجَاءُ الْبَيِّنُ ظَلْعُهَا وَالْكَسِيرَةُ الَّتِي لَا تُنْقِي قُلْتُ إِنِّي أَكْرَهُ أَنْ يَكُونَ فِي الْقَرْنِ نَقْصٌ وَأَنْ يَكُونَ فِي السِّنِّ نَقْصٌ قَالَ مَا كَرِهْتَهُ فَدَعْهُ وَلَا تُحَرِّمْهُ عَلَى أَحَدٍ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud], ia berkata; telah menceritakan kepada kami [Khalid] dari [Syu'bah] dari [Sulaiman bin Abdurrahman budak Bani Asad] dari [Abu Adh Dhuha 'Ubaid bin Fairuz budak Bani Syaiban], ia berkata; saya berkata kepada [Al Barra`]; ceritakan kepadaku mengenai apa yang dilarang Rasulullah shallallahu 'alaihi wasallam dari hewan kurban! Ia berkata; Rasulullah shallallahu 'alaihi wasallam berdiri dan tanganku lebih pendek daripada tangannya, kemudian beliau bersabda: \"Empat sifat yang tidak mencukupi, yaitu; buta sebelah matanya yang jelas kebutaannya, sakit yang jelas sakitnya, pincang yang jelas pincangnya, dan pecah kakinya yang tidak memiliki sumsum.\" Saya katakan; saya tidak suka pada tanduknya terdapat cacat, dan pada giginya terdapat cacar. Ia berkata; apa yang tidak engkau sukai maka tinggalkan dan jangan engkau haramkan atas seseorang. "},"4078":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَأَبُو دَاوُدَ وَيَحْيَى وَعَبْدُ الرَّحْمَنِ وَابْنُ أَبِي عَدِيٍّ وَأَبُو الْوَلِيدِ قَالُوا أَنْبَأَنَا شُعْبَةُ قَالَ سَمِعْتُ سُلَيْمَانَ بْنَ عَبْدِ الرَّحْمَنِ قَالَ سَمِعْتُ عُبَيْدَ بْنَ فَيْرُوزَ قَالَقُلْتُ لِلْبَرَاءِ بْنِ عَازِبٍ حَدِّثْنِي مَا كَرِهَ أَوْ نَهَى عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْأَضَاحِيِّ قَالَ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَكَذَا بِيَدِهِ وَيَدِي أَقْصَرُ مِنْ يَدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعَةٌ لَا يَجْزِينَ فِي الْأَضَاحِيِّ الْعَوْرَاءُ الْبَيِّنُ عَوَرُهَا وَالْمَرِيضَةُ الْبَيِّنُ مَرَضُهَا وَالْعَرْجَاءُ الْبَيِّنُ ظَلْعُهَا وَالْكَسِيرَةُ الَّتِي لَا تُنْقِي قَالَ فَإِنِّي أَكْرَهُ أَنْ يَكُونَ نَقْصٌ فِي الْقَرْنِ وَالْأُذُنِ قَالَ فَمَا كَرِهْتَ مِنْهُ فَدَعْهُ وَلَا تُحَرِّمْهُ عَلَى أَحَدٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar], ia berkata; telah menceritakan kepada kami [Muhammad bin Ja'far], [Abu Daud], [Yahya], [Abdurrahman] dan [Ibnu Abu 'Adi] serta [Abu Al Walid], mereka berkata; telah memberitakan kepada kami [Syu'bah], ia berkata; saya mendengar [Sulaiman bin Abdurrahman] berkata; saya mendengar ['Ubaid bin Fairuz] berkata; saya berkata kepada [Al Barra` bin 'Azib]; ceritakan kepadaku mengenai apa yang tidak disukai atau dilarang oleh Rasulullah shallallahu 'alaihi wasallam dari binatang kurban! Ia berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda demikian dengan tangannya dan tanganku lebih pendek dari tangan Rasulullah shallallahu 'alaihi wasallam: \"Empat sifat yang tidak mencukupi dalam hewan kurban yaitu; buta sebelah matanya yang jelas kebutaannya, sakit yang jelas sakitnya, pincang yang jelas pincangnya, dan pecah kakinya yang tidak memiliki sumsum.\" Saya katakan; saya tidak suka pada tanduknya terdapat cacat, dan pada telinganya terdapat cacat. Ia berkata; apa yang tidak engkau sukai maka tinggalkan dan jangan engkau haramkan atas seseorang. "},"4079":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ وَاللَّيْثُ بْنُ سَعْدٍ وَذَكَرَ آخَرَ وَقَدَّمَهُ أَنَّ سُلَيْمَانَ بْنَ عَبْدِ الرَّحْمَنِ حَدَّثَهُمْ عَنْ عُبَيْدِ بْنِ فَيْرُوزَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَشَارَ بِأَصَابِعِهِ وَأَصَابِعِي أَقْصَرُ مِنْ أَصَابِعِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُشِيرُ بِأُصْبُعِهِ يَقُولُ لَا يَجُوزُ مِنْ الضَّحَايَا الْعَوْرَاءُ الْبَيِّنُ عَوَرُهَا وَالْعَرْجَاءُ الْبَيِّنُ عَرَجُهَا وَالْمَرِيضَةُ الْبَيِّنُ مَرَضُهَا وَالْعَجْفَاءُ الَّتِي لَا تُنْقِي","id":"Telah mengabarkan kepada kami [Sulaiman bin Daud] dari [Ibnu Wahb], ia berkata; telah mengabarkan kepadaku ['Amr bin Al Harits] dan [Al Laits bin Sa'd] dan ia menyebutkan yang lain dan mengedepankannya bahwa [Sulaiman bin Abdurrahman] telah menceritakan kepada mereka dari ['Ubaid bin Fairuz] dari [Al Bara` bin 'Azib] berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam.. (dan ia memberikan isyarat dengan jari-jarinya) dan jariku-jariku lebih pendek dari jari-jari Rasulullah shallallahu 'alaihi wasallam, beliau memberikan isyarat dengan jarinya bersabda: \"Tidak boleh ada hewan kurban yang buta sebelah matanya yang jelas kebutaannya, sakit yang jelas sakitnya, pincang yang jelas pincangnya, dan pecah kakinya yang tidak memiliki sumsum.\" "},"4080":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ آدَمَ عَنْ عَبْدِ الرَّحِيمِ وَهُوَ ابْنُ سُلَيْمَانَ عَنْ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ أَبِي إِسْحَقَ عَنْ شُرَيْحِ بْنِ النُّعْمَانِ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَسْتَشْرِفَ الْعَيْنَ وَالْأُذُنَ وَأَنْ لَا نُضَحِّيَ بِمُقَابَلَةٍ وَلَا مُدَابَرَةٍ وَلَا بَتْرَاءَ وَلَا خَرْقَاءَ","id":"Telah mengabarkan kepadaku [Muhammad bin Adam] dari [Abdur Rahim yaitu Ibnu Sulaiman] dari [Zakariya bin Abu Zaidah] dari [Abu Ishaq] dari [Syuraih bin An Nu'man] dari [Ali radliallahu 'anhu], ia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan kami untuk memeriksa mata dan telinga serta tidak berkurban dengan hewan yang terpotong dari ujung telinganya dan dibiarkan tergantung, yang terpotong dari belakang telinganya dan dibiarkan tergantung, dan yang terpotong telinganya serta yang lubang telinganya."},"4081":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدِ بْنِ أَعْيَنَ قَالَ حَدَّثَنَا زُهَيْرٌ قَالَ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ شُرَيْحِ بْنِ النُّعْمَانِ قَالَ أَبُو إِسْحَقَ وَكَانَ رَجُلَ صِدْقٍ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَسْتَشْرِفَ الْعَيْنَ وَالْأُذُنَ وَأَنْ لَا نُضَحِّيَ بِعَوْرَاءَ وَلَا مُقَابَلَةٍ وَلَا مُدَابَرَةٍ وَلَا شَرْقَاءَ وَلَا خَرْقَاءَ","id":"Telah mengabarkan kepada kami [Abu Daud], ia berkata; telah menceritakan kepada kami [Al Hasan bin Muhammad bin A'yan], ia berkata; telah menceritakan kepada kami [Zuhair], ia berkata; telah menceritakan kepada kami [Abu Ishaq] dari [Syuraih bin An Nu'man], telah berkata Abu Ishaq dan ia adalah orang yang jujur, dari [Ali radliallahu 'anhu], ia berkata; Rasulullah shallallahu 'alaihi wasallam telah memerintahkan kami agar memperhatikan mata, dan telinga dan tidak berkurban dengan hewan yang buta sebelah matanya, yang terpotong dari ujung telinganya, yang terpotong dari belakang telinganya, dan yang terbelah menjadi dua serta yang lubang telinganya."},"4082":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ نَاصِحٍ قَالَ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ أَبِي إِسْحَقَ عَنْ شُرَيْحِ بْنِ النُّعْمَانِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نُضَحِّيَ بِمُقَابَلَةٍ أَوْ مُدَابَرَةٍ أَوْ شَرْقَاءَ أَوْ خَرْقَاءَ أَوْ جَدْعَاءَ","id":"Telah mengabarkan kepada kami [Ahmad bin Nashih], ia berkata; telah menceritakan kepada kami [Abu Bakar bin 'Ayyasy] dari [Abu Ishaq] dari [Syuraih bin An Nu'man] dari [Ali bin Abu Thalib] radliallahu 'anhu, ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang kami untuk berkurban dengan hewan yang terpotong dari ujung telinganya, atau yang terpotong dari belakang telinganya atau yang terbelah menjadi dua, atau yang lubang telinganya atau yang terpotong telinganya. "},"4083":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا شُجَاعُ بْنُ الْوَلِيدِ قَالَ حَدَّثَنِي زِيَادُ بْنُ خَيْثَمَةَ قَالَ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ شُرَيْحِ بْنِ النُّعْمَانِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُضَحَّى بِمُقَابَلَةٍ وَلَا مُدَابَرَةٍ وَلَا شَرْقَاءَ وَلَا خَرْقَاءَ وَلَا عَوْرَاءَ","id":"Telah mengabarkan kepada kami [Harun bin Abdullah], ia berkata; telah menceritakan kepada kami [Syuja' bin Al Walid], ia berkata; telah menceritakan kepadaku [Ziyad bin Khaitsamah], ia berkata; telah menceritakan kepada kami [Abu Ishaq] dari [Syuraih bin An Nu'man] dari [Ali] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam bersabda; \"Tidak boleh dikurbankan dengan hewan yang terpotong dari ujung telingannya, yang terpotong dari belakang telinganya, yang terbelah telinganya, dan yang lubang telinganya serta yang buta sebelah matanya.\""},"4084":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ أَنَّ سَلَمَةَ وَهُوَ ابْنُ كُهَيْلٍ أَخْبَرَهُ قَالَ سَمِعْتُ حُجَيَّةَ بْنَ عَدِيٍّ يَقُولُ سَمِعْتُ عَلِيًّا يَقُولُأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَسْتَشْرِفَ الْعَيْنَ وَالْأُذُنَ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Khalid] telah menceritakan kepada kami [Syu'bah] bahwa [Salamah yaitu Ibnu Kuhail] telah mengabarkan kepadanya, ia berkata; saya mendengar [Hujayyah bin 'Adi] berkata; saya mendengar [Ali] berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan kami agar meneliti mata dan telinga."},"4085":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ عَنْ سُفَيَانَ وَهُوَ ابْنُ حَبِيبٍ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ جُرَيِّ بْنِ كُلَيْبٍ قَالَ سَمِعْتُ عَلِيًّا يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُضَحَّى بِأَعْضَبِ الْقَرْنِفَذَكَرْتُ ذَلِكَ لِسَعِيدِ بْنِ الْمُسَيَّبِ قَالَ نَعَمْ إِلَّا عَضَبَ النِّصْفِ وَأَكْثَرَ مِنْ ذَلِكَ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dari [Sufyan yaitu Ibnu Habib] dari [Syu'bah] dari [Qatadah] dari [Jurai bin Kulaib], ia berkata; saya mendengar [Ali] berkata; Rasulullah shallallahu 'alaihi wasallam melarang berkurban dengan hewan yang bertanduk pecah. Kemudian hal tersebut saya sebutkan kepada Sa'id bin Al Musayyab maka Ia berkata; ya, hanya saja yang tanduknya pecah setengah atau lebih dari itu. "},"4086":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ سُلَيْمَانُ بْنُ سَيْفٍ قَالَ حَدَّثَنَا الْحَسَنُ وَهُوَ ابْنُ أَعْيَنَ وَأَبُو جَعْفَرٍ يَعْنِي النُّفَيْلِيَّ قَالَا حَدَّثَنَا زُهَيْرٌ قَالَ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَذْبَحُوا إِلَّا مُسِنَّةً إِلَّا أَنْ يَعْسُرَ عَلَيْكُمْ فَتَذْبَحُوا جَذَعَةً مِنْ الضَّأْنِ","id":"Telah mengabarkan kepada kami [Abu Daud Sulaiman bin Saif], ia berkata; telah menceritakan kepada kami [Al Hasan yaitu Ibnu A'yan] dan [Abu Ja'far yaitu An Nufaili] mereka berkata; telah menceritakan kepada kami [Zuhair], ia berkata; telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menyembelih kecuali domba yang berumur dua tahun, kecuali mengalami kesulitan maka sembelihlah yang berumur satu tahun.\""},"4087":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطَاهُ غَنَمًا يُقَسِّمُهَا عَلَى صَحَابَتِهِ فَبَقِيَ عَتُودٌ فَذَكَرَهُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ضَحِّ بِهِ أَنْتَ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Abu Al Khair] dari ['Uqbah bin 'Amir] bahwa Rasulullah shallallahu 'alaihi wasallam telah memberinya kambing yang banyak yang ia bagikan kepada isterinya kemudian tersisa kambing kacang, kemudian ia menyampaikannya kepada Rasulullah shallallahu 'alaihi wasallam lalu beliau bersabda: \"Berkurbanlah dengannya.\""},"4088":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ دُرُسْتَ قَالَ حَدَّثَنَا أَبُو إِسْمَعِيلَ وَهُوَ الْقَنَّادُ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنِي بَعْجَةُ بْنُ عَبْدِ اللَّهِ عَنْ عُقْبَةَ بْنِ عَامِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَسَّمَ بَيْنَ أَصْحَابِهِ ضَحَايَا فَصَارَتْ لِي جَذَعَةٌ فَقُلْتُ يَا رَسُولَ اللَّهِ صَارَتْ لِي جَذَعَةٌ فَقَالَ ضَحِّ بِهَا","id":"Telah mengabarkan kepada kami [Yahya bin Durust], ia berkata; telah menceritakan kepada kami [Abu Isma'il yaitu Al Qannad], ia berkata; telah menceritakan kepada kami [Yahya], ia berkata; telah menceritakan kepadaku [Ba'jah bin Abdullah] dari ['Uqbah bin 'Amir] bahwa Rasulullah shallallahu 'alaihi wasallam telah membagikan hewan kurban diantara isteri-isterinya dan saya memiliki kambing yang berumur satu tahun. Kemudian saya katakan; wahai Rasulullah, saya memiliki kambing yang berumur satu tahun. Maka beliau bersabda: \"Berkurbanlah dengannya.\""},"4089":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ بَعْجَةَ بْنِ عَبْدِ اللَّهِ الْجُهَنِيِّ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَقَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ أَصْحَابِهِ أَضَاحِيَّ فَأَصَابَنِي جَذَعَةٌ فَقُلْتُ يَا رَسُولَ اللَّهِ أَصَابَتْنِي جَذَعَةٌ فَقَالَ ضَحِّ بِهَا","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud], ia berkata; telah menceritakan kepada kami [Khalid], ia berkata; telah menceritakan kepada kami [Hisyam] dari [Yahya bin Abu Katsir] dari [Ba'jah bin Abdullah Al Juhani] dari ['Uqbah bin 'Amir], ia berkata; Rasulullah shallallahu 'alaihi wasallam telah membagi hewan-hewan kurban diantara para isterinya. Dan saya mendapatkan kambing yang berumur satu tahun. Kemudian saya katakan; wahai Rasulullah, saya telah mendapatkan kambing yang berumur satu tahun. Kemudian beliau bersabda: \"Berkurbanlah dengannya.\""},"4090":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرٌو عَنْ بُكَيْرِ بْنِ الْأَشَجِّ عَنْ مُعَاذِ بْنِ عَبْدِ اللَّهِ بْنِ خُبَيْبٍ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَضَحَّيْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِجَذَعٍ مِنْ الضَّأْنِ","id":"Telah mengabarkan kepada kami [Sulaiman bin Daud] dari [Ibnu Wahb], ia berkata; telah mengabarkan kepadaku ['Amr] dari [Bukair bin Al Asyaj] dari [Mu'adz bin Abdullah bin Khubaib] dari ['Uqbah bin 'Amir], ia berkata; kami berkurban bersama Rasulullah shallallahu 'alaihi wasallam dengan domba yang berumur satu tahun."},"4091":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ ��لسَّرِيِّ فِي حَدِيثِهِ عَنْ أَبِي الْأَحْوَصِ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ قَالَكُنَّا فِي سَفَرٍ فَحَضَرَ الْأَضْحَى فَجَعَلَ الرَّجُلُ مِنَّا يَشْتَرِي الْمُسِنَّةَ بِالْجَذَعَتَيْنِ وَالثَّلَاثَةِ فَقَالَ لَنَا رَجُلٌ مِنْ مُزَيْنَةَ كُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَحَضَرَ هَذَا الْيَوْمُ فَجَعَلَ الرَّجُلُ يَطْلُبُ الْمُسِنَّةَ بِالْجَذَعَتَيْنِ وَالثَّلَاثَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْجَذَعَ يُوفِي مِمَّا يُوفِي مِنْهُ الثَّنِيُّ","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dalam haditsnya dari [Abu Al Ahwash] dari ['Ashim bin Kulaib] dari [ayahnya], ia berkata; kami berada dalam suatu perjalanan kemudian telah datang hari raya Adhha, kemudian seseorang diantara kami membeli seekor domba yang berumur dua tahun ditukar dengan dua ekor domba yang berumur satu tahun atau tiga ekor. Kemudian [seseorang] dari Muzainah berkata kepada kami; dahulu kami bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan kemudian datang hari Adhha ini, kemudian seseorang meminta seekor domba yang berumur satu tahun ditukar dengan dua atau tiga ekor domba yang berumur satu tahun. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya domba yang berumur satu tahun mencukupi apa yang apa yang dicukupi oleh domba yang berumur tiga tahun.\""},"4092":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمِ بْنِ كُلَيْبٍ قَالَ سَمِعْتُ أَبِي يُحَدِّثُ عَنْ رَجُلٍ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ الْأَضْحَى بِيَوْمَيْنِ نُعْطِي الْجَذَعَتَيْنِ بِالثَّنِيَّةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْجَذَعَةَ تُجْزِئُ مَا تُجْزِئُ مِنْهُ الثَّنِيَّةُ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Khalid], ia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Ashim bin Kulaib], ia berkata; saya mendengar [ayahku] menceritakan dari [seorang laki-laki], ia berkata; kami pernah bersama Nabi shallallahu 'alaihi wasallam dua hari sebelum hari idul Adhha, kami memberi dua domba yang berumur satu tahun ditukar dengan yang berumur tiga tahun. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya domba yang berumur satu tahun mencukupi apa yang dicukupi oleh domba yang berumur tiga tahun.\""},"4093":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا إِسْمَعِيلُ عَنْ عَبْدِ الْعَزِيزِ وَهُوَ ابْنُ صُهَيْبٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُضَحِّي بِكَبْشَيْنِقَالَ أَنَسٌ وَأَنَا أُضَحِّي بِكَبْشَيْنِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah menceritakan kepada kami [Isma'il] dari [Abdul 'Aziz yaitu Ibnu Shuhaib] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam pernah berkurban dengan dua ekor kambing kibas. Anas berkata; sedangkan saya berkurban dengan dua ekor kambing kibas. "},"4094":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ خَالِدٍ قَالَ حَدَّثَنَا حُمَيْدٌ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَضَحَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِكَبْشَيْنِ أَمْلَحَيْنِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dari [Khalid], ia berkata; telah menceritakan kepada kami [Humaid] dari [Tsabit] dari [Anas], ia berkata; Rasulullah shallallahu 'alaihi wasallam berkurban dengan dua kambing kibas yang gemuk. "},"4095":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَضَحَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِكَبْشَيْنِ أَمْلَحَيْنِ أَقْرَنَيْنِ ذَبَحَهُمَا بِيَدِهِ وَسَمَّى وَكَبَّرَ وَوَضَعَ رِجْلَهُ عَلَى صِفَاحِهِمَا","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Anas], ia berkata; Nabi shallallahu 'alaihi wasallam berkurban dengan dua ekor kambing kibas yang bertanduk, beliau menyembelihnya dengan tangannya, mengucapkan bismillah dan bertakbir serta meletakkan kakinya pada samping leher. "},"4096":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا حَاتِمُ بْنُ وَرْدَانَ عَنْ أَيُّوبَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أَضْحًى وَانْكَفَأَ إِلَى كَبْشَيْنِ أَمْلَحَيْنِ فَذَبَحَهُمَا مُخْتَصَرٌ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud], ia berkata; telah menceritakan kepada kami [Hatim bin Wardan] dari [Ayyub] dari [Muhammad bin Sirin] dari [Anas bin Malik], ia berkata; Rasulullah shallallahu 'alaihi wasallam berkhutbah kepada kami pada idul Adhha dan beliau menuju kepada dua kambing kibasnya yang gemuk kemudian menyembelihnya. "},"4097":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ فِي حَدِيثِهِ عَنْ يَزِيدَ بْنِ زُرَيْعٍ عَنْ ابْنِ عَوْنٍ عَنْ مُحَمَّدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِ قَالَثُمَّ انْصَرَفَ كَأَنَّهُ يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ النَّحْرِ إِلَى كَبْشَيْنِ أَمْلَحَيْنِ فَذَبَحَهُمَا وَإِلَى جُذَيْعَةٍ مِنْ الْغَنَمِ فَقَسَمَهَا بَيْنَنَا","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dalam haditsnya dari [Yazid bin Zurai'] dari [Ibnu 'Aun] dari [Muhammad] dari [Abdurrahman bin Abu Bakarah] dari [ayahnya], ia berkata; kemudian beliau pergi yakni Nabi shallallahu 'alaihi wasallam pada hari Qurban, menuju ke dua ekor kambing kibas yang gemuk, lalu beliau menyembelih keduanya, dan menuju pada potongan daging kambing dan membagi untuk kami."},"4098":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ أَبُو سَعِيدٍ الْأَشَجُّ قَالَ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ قَالَضَحَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِكَبْشٍ أَقْرَنَ فَحِيلٍ يَمْشِي فِي سَوَادٍ وَيَأْكُلُ فِي سَوَادٍ وَيَنْظُرُ فِي سَوَادٍ","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id Abu Sa'id Al Asyaj], ia berkata; telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Ja'far bin Muhammad] dari [ayahnya] dari [Abu Sa'id], ia berkata; Rasulullah shallallahu 'alaihi wasallam berkurban dengan seekor kambing kibas yang bertanduk dan kuat, ia berkaki hitam, bermulut hitam, dan mermata hitam."},"4099":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ الْحَكَمِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ الثَّوْرِيُّ عَنْ أَبِيهِ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ بْنِ رَافِعٍ عَنْ جَدِّهِ رَافِعِ بْنِ خَدِيجٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجْعَلُ فِي قَسْمِ الْغَنَائِمِ عَشْرًا مِنْ الشَّاءِ بِبَعِيرٍقَالَ شُعْبَةُ وَأَكْبَرُ عِلْمِي أَنِّي سَمِعْتُهُ مِنِ سَعِيدِ بْنِ مَسْرُوقٍ وَحَدَّثَنِي بِهِ سُفْيَانُ عَنْهُ وَاللَّهُ تَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah bin Al Hakam] berkata telah menceritakan kepada kami [Muhammad bin Ja'far], ia berkata; telah menceritakan kepada kami [Syu'bah], ia berkata; telah menceritakan kepada kami [Sufyan Ats Tsauri] dari [ayahnya] dari ['Abadah bin Rifa'ah bin Rafi'] dari [kakeknya yaitu Rafi' bin Khadij], ia berkata; Rasulullah shallallahu 'alaihi wasallam di dalam pembagian harta rampasan perang menjadikan sepuluh kambing sebanding dengan satu ekor unta. Syu'bah berkata; dan yang paling saya ketahui adalah bahwa saya mendengar hadits tersebut dari Sa'id bin Masruq, dan telah menceritakan kepadaku dengannya Sufyan darinya... wallahu a'lam."},"4100":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْعَزِيزِ بْنِ غَزْوَانَ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ حُسَيْنٍ يَعْنِي ابْنَ وَاقِدٍ عَنْ عِلْبَاءَ بْنِ أَحْمَرَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَحَضَرَ النَّحْرُ فَاشْتَرَكْنَا فِي الْبَعِيرِ عَنْ عَشْرَةٍ وَالْبَقَرَةِ عَنْ سَبْعَةٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul 'aziz bin Ghazwn], ia berkata; telah menceritakan kepada kami [Al Fadhl bin Musa] dari [Husain yaitu Ibnu Waqid] dari ['Ilba` bin Ahmar] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; kami bersama Rasulullah shallallahu 'alaihi wasallam ketika melakukan safar lalu datang hari Qurban, kemudian kami menyembelih seekor unta dari sepuluh orang dan seekor sapi dari tujuh orang."},"4101":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ يَحْيَى عَنْ عَبْدِ الْمَلِكِ عَنْ عَطَاءٍ عَنْ جَابِرٍ قَالَكُنَّا نَتَمَتَّعُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَذْبَحُ الْبَقَرَةَ عَنْ سَبْعَةٍ وَنَشْتَرِكُ فِيهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dari [Yahya] dari [Abdul Malik] dari ['Atho`] dari [Jabir], ia berkata; kami melakukan haji tamattu' bersama Nabi shallallahu 'alaihi wasallam, kemudian kami menyembelih sapi untuk orang tujuk dan kami berserikat padanya. "},"4102":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ ابْنِ أَبِي زَائِدَةَ قَالَ أَنْبَأَنَا أَبِي عَنْ فِرَاسٍ عَنْ عَامِرٍ عَنْ الْبَرَاءِ بْنِ عَازِبٍ ح وَأَنْبَأَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ عَنْ الْبَرَاءِ فَذَكَرَ أَحَدُهُمَا مَا لَمْ يَذْكُرْ الْآخَرُ قَالَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْأَضْحَى فَقَالَ مَنْ وَجَّهَ قِبْلَتَنَا وَصَلَّى صَلَاتَنَا وَنَسَكَ نُسُكَنَا فَلَا يَذْبَحْ حَتَّى يُصَلِّيَ فَقَامَ خَالِي فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي عَجَّلْتُ نُسُكِي لِأُطْعِمَ أَهْلِي وَأَهْلَ دَارِي أَوْ أَهْلِي وَجِيرَانِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعِدْ ذِبْحًا آخَرَ قَالَ فَإِنَّ عِنْدِي عَنَاقَ لَبَنٍ هِيَ أَحَبُّ إِلَيَّ مِنْ شَاتَيْ لَحْمٍ قَالَ اذْبَحْهَا فَإِنَّهَا خَيْرُ نَسِيكَتَيْكَ وَلَا تَقْضِي جَذَعَةٌ عَنْ أَحَدٍ بَعْدَكَ","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dari [Ibnu Abu Zaidah], ia berkata; telah memberitakan kepada kami [ayahku] dari [Firas] dari ['Amir] dari [Al Bara` bin 'Azib]. Telah menceritakan dan memberitakan kepada kami [Daud bin Abu Hindun] dari [Asy Sya'bi] dari [Al Bara`] kemudian salah seorang diantara mereka menyebutkan apa yang tidak disebutkan oleh yang lain, ia berkata; Rasulullah shallallahu 'alaihi wasallam berdiri pada hari raya Kurban dan bersabda: \"Barang siapa yang menghadap ke Kiblat kami, melakukan shalat kami, menyembelih sembelihan kami maka janganlah ia menyembelih hingga ia melakukan shalat.\" Kemudian pamanku berdiri dan berkata; wahai Rasulullah, sesungguhnya saya mempercepat sembelihanku agar dapat memberikan makan keluargaku dan penghuni rumahku atau keluargaku dan tetanggaku. Kemudian beliau bersabda: \"Ulangi sembelihan yang lain\", ia berkata; sesungguhnya saya memiliki anak kambing betina yang masih menyusu yang lebih saya cintai daripada dua ekor kambing pedaging. Beliau bersabda: \"Sembelihlah sesungguhnya itu penyembelihanmu yang terbaik, dan kambing yang berumur satu tahun tidak dapat menunaikan bagi seorangpun setelahmu.\""},"4103":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ مَنْصُورٍ عَنْ الشَّعْبِيِّ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ النَّحْرِ بَعْدَ الصَّلَاةِ ثُمَّ قَالَ مَنْ صَلَّى صَلَاتَنَا وَنَسَكَ نُسُكَنَا فَقَدْ أَصَابَ النُّسُكَ وَمَنْ نَسَكَ قَبْلَ الصَّلَاةِ فَتِلْكَ شَاةُ لَحْمٍ فَقَالَ أَبُو بُرْدَةَ يَا رَسُولَ اللَّهِ وَاللَّهِ لَقَدْ نَسَكْتُ قَبْلَ أَنْ أَخْرُجَ إِلَى الصَّلَاةِ وَعَرَفْتُ أَنَّ الْيَوْمَ يَوْمُ أَكْلٍ وَشُرْبٍ فَتَعَجَّلْتُ فَأَكَلْتُ وَأَطْعَمْتُ أَهْلِي وَجِيرَانِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تِلْكَ شَاةُ لَحْمٍ قَالَ فَإِنَّ عِنْدِي عَنَاقًا جَذَعَةً خَيْرٌ مِنْ شَاتَيْ لَحْمٍ فَهَلْ تُجْزِئُ عَنِّي قَالَ نَعَمْ وَلَنْ تَجْزِيَ عَنْ أَحَدٍ بَعْدَكَ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Abu Al Ahwash] dari [Manshur] dari [Asy Sya'bi] dari [Al Bara` bin 'Azib], ia berkata; Rasulullah shallallahu 'alaihi wasallam berkhutbah kepada kami pada hari Kurban setelah melakukan shalat kemudian bersabda: \"Barang siapa yang melakukan shalat kami dan menyembelih sembelihan kami sungguh ia telah benar dalam menyembelih dan barang siapa yang menyembelih sebelum shalat maka itu adalah kambing yang dimanfaatkan dagingnya bukan kurban.\" Kemudian Abu Burdah berkata; wahai Rasulullah, demi Allah saya telah menyembelih sebelum keluar melakukan shalat dan saya tahu bahwa hari ini adalah hari makan dan minum, sehingga saya mempercepat, kemudian saya makan dan memberikan makan kepada keluarga dan tetanggaku. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Itu adalah kambing yang dimanfaatkan dagingnya.\" Ia berkata; saya memiliki anak kambing betina, kambing yang berumur satu tahun lebih baik daripada dua kambing yang dimanfaatkan dagingnya saja, apakah itu mencukupi untukku? Beliau bersabda: \"ya, dan tidak mencukupi untuk seorangpun setelahmu.\""},"4104":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ مُحَمَّدٍ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ النَّحْرِ مَنْ كَانَ ذَبَحَ قَبْلَ الصَّلَاةِ فَلْيُعِدْ فَقَامَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ هَذَا يَوْمٌ يُشْتَهَى فِيهِ اللَّحْمُ فَذَكَرَ هَنَةً مِنْ جِيرَانِهِ كَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَّقَهُ قَالَ عِنْدِي جَذَعَةٌ هِيَ أَحَبُّ إِلَيَّ مِنْ شَاتَيْ لَحْمٍ فَرَخَّصَ لَهُ فَلَا أَدْرِي أَبَلَغَتْ رُخْصَتُهُ مَنْ سِوَاهُ أَمْ لَا ثُمَّ انْكَفَأَ إِلَى كَبْشَيْنِ فَذَبَحَهُمَا","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim], ia berkata; telah menceritakan kepada kami [Ibnu Ulayyah], ia berkata; telah menceritakan kepada kami [Ayyub] dari [Muhammad] dari [Anas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda pada hari Kurban: \"Barang siapa yang menyembelih sebelum shalat maka hendaknya ia mengulangi.\" Kemudian terdapat seorang laki-laki yang berdiri dan berkata; wahai Rasulullah, ini adalah hari memakan daging..... kemudian ia menyebutkan kebutuhan dari tetangganya, sepertinya Rasulullah shallallahu 'alaihi wasallam membenarkannya. Ia berkata; saya memiliki anak kambing yang berumur satu tahun itu lebih saya senangi daripada dua kambing yang hanya dimanfaatkan dagingnya saja bukan kurban. Kemudian beliau memberikan keringanan baginya. Saya tidak tahu apakah keringanan yang beliau berikan itu sampai kepada orang selainnya atau tidak. Kemudian beliau menuju kepada dua kambing kibasnya dan menyembelihnya."},"4105":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ يَحْيَى ح وَأَنْبَأَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ بُشَيْرِ بْنِ يَسَارٍ عَنْ أَبِي بُرْدَةَ بْنِ نِيَارٍأَنَّهُ ذَبَحَ قَبْلَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُعِيدَ قَالَ عِنْدِي عَنَاقُ جَذَعَةٍ هِيَ أَحَبُّ إِلَيَّ مِنْ مُسِنَّتَيْنِ قَالَ اذْبَحْهَا فِي حَدِيثِ عُبَيْدِ اللَّهِ فَقَالَ إِنِّي لَا أَجِدُ إِلَّا جَذَعَةً فَأَمَرَهُ أَنْ يَذْبَحَ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id], ia berkata; telah menceritakan kepada kami [Yahya] dari [Yahya]. Telah menceritakan dan memberitakan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Yahya] dari [Yahya bin Sa'id] dari [Busyair bin Yasar] dari [Abu Burdah bin Niyar] bahwa ia telah menyembelih sebelum Nabi shallallahu 'alaihi wasallam, kemudian Nabi shallallahu 'alaihi wasallam memerintahkannya agar mengulanginya. Ia berkata; saya memiliki anak kambing betina, kambing berumur satu tahun lebih saya senangi daripada dua kambing yang berumur dua tahun. Beliau bersabda: \"Sembelihlah kambing tersebut.\" Dalam hadits 'Ubaidullah; Kemudian ia berkata; sesungguhnya saya tidak mendapatkan kecuali kambing yang berumur satu tahun. Lalu beliau memerintahkannya untuk menyembelih. "},"4106":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ عَنْ جُنْدُبِ بْنِ سُفْيَانَ قَالَضَحَّيْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَضْحًى ذَاتَ يَوْمٍ فَإِذَا النَّاسُ قَدْ ذَبَحُوا ضَحَايَاهُمْ قَبْلَ الصَّلَاةِ فَلَمَّا انْصَرَفَ رَآهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُمْ ذَبَحُوا قَبْلَ الصَّلَاةِ فَقَالَ مَنْ ذَبَحَ قَبْلَ الصَّلَاةِ فَلْيَذْبَحْ مَكَانَهَا أُخْرَى وَمَنْ كَانَ لَمْ يَذْبَحْ حَتَّى صَلَّيْنَا فَلْيَذْبَحْ عَلَى اسْمِ اللَّهِ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Al Aswad bin Qais] dari [Jundub bin Sufyan], ia berkata; kami telah berkurban bersama Rasulullah shallallahu 'alaihi wasallam pada hari 'idul Adhha, ternyata terdapat beberapa orang yang telah menyembelih kurban mereka sebelum melakukan shalat, kemudian tatkala beliau pergi Nabi shallallahu 'alaihi wasallam melihat mereka telah menyembelih sebelum melakukan shalat, lalu beliau bersabda: \"Barang siapa yang menyembelih sebelum melakukan shalat maka hendaknya ia menyembelih yang lain sebagai gantinya dan barang siapa yang belum menyembelih hingga melakukan shalat maka hendaknya ia menyembelih dengan menyebut nama Allah 'azza wajalla.\""},"4107":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ حَدَّثَنَا دَاوُدُ عَنْ عَامِرٍ عَنْ مُحَمَّدِ بْنِ صَفْوَانَأَنَّهُ أَصَابَ أَرْنَبَيْنِ وَلَمْ يَجِدْ حَدِيدَةً يَذْبَحُهُمَا بِهِ فَذَكَّاهُمَا بِمَرْوَةٍ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي اصْطَدْتُ أَرْنَبَيْنِ فَلَمْ أَجِدْ حَدِيدَةً أُذَكِّيهِمَا بِهِ فَذَكَّيْتُهُمَا بِمَرْوَةٍ أَفَآكُلُ قَالَ كُلْ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna], ia berkata; telah menceritakan kepada kami [Yazid bin Harun], ia berkata; telah menceritakan kepada kami [Daud] dari ['Amir] dari [Muhammad bin Shafwan] bahwa ia telah menangkap dua ekor kelinci dan tidak mendapatkan besi untuk menyembelihnya. Kemudian ia menyembelihnya menggunakan batu putih yang dibuat seperti pisau, lalu datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; wahai Rasulullah, sesungguhnya saya telah memburu dua ekor kelinci dan tidak mendapatkan besi untuk menyembelihnya kemudian saya menyembelihnya menggunakan batu putih yang dibuat seperti pisau, apakah saya boleh memakannya? Beliau bersabda: \"Makanlah.\""},"4108":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ عَنْ مُحَمَّدِ بْنِ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا حَاضِرُ بْنُ الْمُهَاجِرِ الْبَاهِلِيُّ قَالَ سَمِعْتُ سُلَيْمَانَ بْنَ يَسَارٍ يُحَدِّثُ عَنْ زَيْدِ بْنِ ثَابِتٍأَنَّ ذِئْبًا نَيَّبَ فِي شَاةٍ فَذَبَحُوهَا بِالْمَرْوَةِ فَرَخَّصَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَكْلِهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dari [Muhammad bin Ja'far], ia berkata; telah menceritakan kepada kami [Syu'bah], ia berkata; telah menceritakan kepada kami [Hadhir bin Al Muhajir Al Bahili], ia berkata; saya mendengar [Sulaiman bin Yasar] menceritakan dari [Zaid bin Tsabit] bahwa terdapat seekor serigala yang menggigit seekor kambing, kemudian mereka menyembelihnya menggunakan menggunakan batu putih yang dibuat seperti pisau, kemudian Nabi shallallahu 'alaihi wasallam memberikan keringanan untuk memakannya."},"4109":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى وَإِسْمَعِيلُ بْنُ مَسْعُودٍ عَنْ خَالِدٍ عَنْ شُعْبَةَ عَنْ سِمَاكٍ قَالَ سَمِعْتُ مُرِّيَّ بْنَ قَطَرِيٍّ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي أُرْسِلُ كَلْبِي فَآخُذُ الصَّيْدَ فَلَا أَجِدُ مَا أُذَكِّيهِ بِهِ فَأَذْبَحُهُ بِالْمَرْوَةِ وَبِالْعَصَا قَالَ أَنْهِرْ الدَّمَ بِمَا شِئْتَ وَاذْكُرْ اسْمَ اللَّهِ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dan [Isma'il bin Mas'ud] dari [Khalid] dari [Syu'bah] dari [Simak], ia berkata; saya mendengar [Murri bin Qathari] dari ['Adi bin hatim], ia berkata; saya berkata; wahai Rasulullah, saya melepas anjingku berburu, lalu aku mengambil buruannya namun saya tidak mendapati sesuatu untuk menyembelihnya, maka saya menyembelihnya dengan batu putih yang dibentuk seperti pisau dan tongkat, beliau bersabda: \" Alirkan darah dengan apa yang engkau kehendaki dan sebutlah nama Allah 'azza wajalla.\""},"4110":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ مَعْمَرٍ قَالَ حَدَّثَنَا حَبَّانُ بْنُ هِلَالٍ قَالَ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ زَيْدِ بْنِ أَسْلَمَ فَلَقِيتُ زَيْدَ بْنَ أَسْلَمَ فَحَدَّثَنِي عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَكَانَتْ لِرَجُلٍ مِنْ الْأَنْصَارِ نَاقَةٌ تَرْعَى فِي قِبَلِ أُحُدٍ فَعُرِضَ لَهَا فَنَحَرَهَا بِوَتَدٍ فَقُلْتُ لِزَيْدٍ وَتَدٌ مِنْ خَشَبٍ أَوْ حَدِيدٍ قَالَ لَا بَلْ خَشَبٌ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ فَأَمَرَهُ بِأَكْلِهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'mar], ia berkata; telah menceritakan kepada kami [Habban bin Hilal], ia berkata; telah menceritakan kepada kami [Jarir bin Hazim], ia berkata; telah menceritakan kepada kami [Ayyub] dari [Zaid bin Aslam], dan saya bertemu dengan Zaid bin Aslam kemudian ia menceritakan kepadaku dari ['Atho' bin Yasar] dari [Abu Sa'd' Al Khudri] ia berkata; seorang Anshar memiliki seekor unta yang digembalakan disekitar Uhud, ketika nampak unta itu, ia menyembelihnya dengan pasak. Saya berkata kepada Zaid; pasak dari kayu atau besi? Ia menjawab; tidak, melainkan dari kayu. Kemudian ia datang kepada Nabi shallallahu 'alaihi wasallam dan bertanya kepada beliau, lalu beliau menyuruh untuk memakannya."},"4111":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عُمَرَ بْنِ سَعِيدٍ عَنْ أَبِيهِ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ عَنْ رَافِعِ بْنِ خَدِيجٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا أَنْهَرَ الدَّمَ وَذُكِرَ اسْمُ اللَّهِ فَكُلْ إِلَّا بِسِنٍّ أَوْ ظُفُرٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Umar bin Sa'id] dari [ayahnya] dari ['Abayah bin Rifa'ah] dari [Rafi' bin Khadij] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa yang dapat mengalirkan darah dan telah disebutkan nama Allah, maka makanlah, kecuali dengan gigi atau kuku.\""},"4112":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي الْأَحْوَصِ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ رَافِعِ بْنِ خَدِيجٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا نَلْقَى الْعَدُوَّ غَدًا وَلَيْسَ مَعَنَا مُدًى فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَنْهَرَ الدَّمَ وَذُكِرَ اسْمُ اللَّهِ عَزَّ وَجَلَّ فَكُلُوا مَا لَمْ يَكُنْ سِنًّا أَوْ ظُفُرًا وَسَأُحَدِّثُكُمْ عَنْ ذَلِكَ أَمَّا السِّنُّ فَعَظْمٌ وَأَمَّا الظُّفُرُ فَمُدَى الْحَبَشَةِ","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dari [Abu Al Ahwash] dari [Sa'id bin Masruq] dari ['Abayah bin Rifa'ah] dari [ayahnya] dari [kakeknya yaitu Rafi' bin Khadij], ia berkata; saya berkata; wahai Rasulullah, sesungguhnya kita akan bertemu musuh besok, dan kita tidak memiliki pisau. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa yang dapat mengalirkan darah dan telah disebutkan nama Allah, maka makanlah, selama bukan gigi atau kuku dan akan saya ceritakan mengenai hal tersebut; adapun gigi maka itu adalah tulang, adapun kuku maka itu adalah pisau orang-orang Habasyah.\""},"4113":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ عَنْ خَالِدٍ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْأَشْعَثِ عَنْ شَدَّادِ بْنِ أَوْسٍ قَالَاثْنَتَانِ حَفِظْتُهُمَا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ كَتَبَ الْإِحْسَانَ عَلَى كُلِّ شَيْءٍ فَإِذَا قَتَلْتُمْ فَأَحْسِنُوا الْقِتْلَةَ وَإِذَا ذَبَحْتُمْ فَأَحْسِنُوا الذِّبْحَةَ وَلْيُحِدَّ أَحَدُكُمْ شَفْرَتَهُ وَلْيُرِحْ ذَبِيحَتَهُ","id":"Telah mengabarkan kepada kami [Ali bin Hujr], ia berkata; telah menceritakan kepada kami [Isma'il] dari [Khalid] dari [Abu Qilabah] dari [Abu Al Asy'ats] dari [Syadad bin Aus], ia berkata; ada dua perkara yang saya hafal dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Allah telah mewajibkan berbuat baik kepada segala sesuatu, apabila kalian membunuh maka bunuhlah secara baik, dan apabila kalian menyembelih maka sembelihlah secara baik, dan hendaknya salah seorang diantara kalian menajamkan pisaunya serta memberikan kenyamanan kepada sembelihannya.\""},"4114":{"ar":"أَخْبَرَنَا عِيسَى بْنُ أَحْمَدَ الْعَسْقَلَانِيُّ عَسْقَلَانُ بَلْخٍ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ حَدَّثَنِي سُفْيَانُ عَنْ هِشَامِ بْنِ عُرْوَةَ حَدَّثَهُ عَنْ فَاطِمَةَ بِنْتِ الْمُنْذِرِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ قَالَتْنَحَرْنَا فَرَسًا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَ��َكَلْنَاهُ","id":"Telah mengabarkan kepada kami [Isa bin Ahmad Al 'Asqalani], ia berkata; telah menceritakan kepada kami [Ibnu Wahb], ia berkata; telah menceritakan kepadaku [Sufyan] dari [Hisyam bin 'Urwah] ia telah menceritakan kepadanya dari [Fathimah binti Al Mundzir] dari [Asma` binti Abu Bakar], ia berkata; kami menyembelih kuda pada zaman Rasulullah shallallahu 'alaihi wasallam kemudian kami memakannya. "},"4115":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ عَنْ مُحَمَّدِ بْنِ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ حَاضِرَ بْنَ الْمُهَاجِرِ الْبَاهِلِيَّ قَالَ سَمِعْتُ سُلَيْمَانَ بْنَ يَسَارٍ يُحَدِّثُ عَنْ زَيْدِ بْنِ ثَابِتٍأَنَّ ذِئْبًا نَيَّبَ فِي شَاةٍ فَذَبَحُوهَا بِمَرْوَةٍ فَرَخَّصَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَكْلِهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dari [Muhammad bin Ja'far], ia berkata; telah menceritakan kepada kami [Syu'bah], ia berkata; saya mendengar [Hadhir bin Al Muhajir Al Bahili], ia berkata; saya mendengar [Sulaiman bin Yasar] menceritakan dari [Zaid bin Tsabit] bahwa terdapat seekor serigala yang menggigit seekor kambing kemudian mereka menyembelihnya menggunakan batu putih yang dibuat seperti pisau, lalu Nabi shallallahu 'alaihi wasallam memberikan keringanan dan kami memakannya. "},"4116":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ أَبِي الْعُشَرَاءِ عَنْ أَبِيهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَمَا تَكُونُ الذَّكَاةُ إِلَّا فِي الْحَلْقِ وَاللَّبَّةِ قَالَ لَوْ طَعَنْتَ فِي فَخِذِهَا لَأَجْزَأَكَ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim], ia berkata; telah menceritakan kepada kami [Abdurrahman] dari [Hammad bin Salamah] dari [Abu Al 'Usyara`] dari [ayahnya], ia berkata; saya berkata; wahai Rasulullah, bukankah menyembelih itu hanya di tenggorokan dan leher bagian bawah? Beliau bersabda: \"Apabila engkau menusuk pada pahanya maka cukup bagimu.\""},"4117":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ عَنْ عَبَايَةَ بْنِ رَافِعٍ عَنْ رَافِعٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا لَاقُو الْعَدُوِّ غَدًا وَلَيْسَ مَعَنَا مُدًى قَالَ مَا أَنْهَرَ الدَّمَ وَذُكِرَ اسْمُ اللَّهِ عَزَّ وَجَلَّ فَكُلْ مَا خَلَا السِّنَّ وَالظُّفُرَ قَالَ فَأَصَابَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهْبًا فَنَدَّ بَعِيرٌ فَرَمَاهُ رَجُلٌ بِسَهْمٍ فَحَبَسَهُ فَقَالَ إِنَّ لِهَذِهِ النَّعَمِ أَوْ قَالَ الْإِبِلِ أَوَابِدَ كَأَوَابِدِ الْوَحْشِ فَمَا غَلَبَكُمْ مِنْهَا فَافْعَلُوا بِهِ هَكَذَا","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud], ia berkata; telah menceritakan kepada kami [Khalid] dari [Syu'bah] dari [Sa'id bin Masruq] dari ['Abayah bin Rafi'] dari [Rafi'], ia berkata; saya berkata; wahai Rasulullah, sesungguhnya kita akan bertemu musuh besok, dan kita tidak memiliki pisau. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa yang dapat mengalirkan darah dan telah disebutkan nama Allah, maka makanlah, selama bukan gigi dan kuku.\" Kemudian Rasulullah shallallahu 'alaihi wasallam mendapatkan rampasan, lalu terdapat unta yang lari, kemudian seorang laki-laki memanahnya dengan anak panah sehingga menghentikannya. Beliau bersabda: \"Sesungguhnya binatang ternak ini.. atau beliau bersabda: \"unta ini memiliki binanatang-binatang yang menjadi liar, seperti liarnya binatang liar, maka apa yang kalian mampu lakukan terhadapnya maka lakukanlah.\""},"4118":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ أَنْبَأَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي أَبِي عَنْ عَبَايَةَ بْنِ رِفَاعَةَ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا لَاقُو الْعَدُوِّ غَدًا وَلَيْسَتْ مَعَنَا مُدًى قَالَ مَا أَنْهَرَ الدَّمَ وَذُكِرَ اسْمُ اللَّهِ عَزَّ وَجَلَّ فَكُلْ لَيْسَ السِّنَّ وَالظُّفُرَ وَسَأُحَدِّثُكُمْ أَمَّا السِّنُّ فَعَظْمٌ وَأَمَّا الظُّفُرُ فَمُدَى الْحَبَشَةِ وَأَصَبْنَا نَهْبَةَ إِبِلٍ أَوْ غَنَمٍ فَنَدَّ مِنْهَا بَعِيرٌ فَرَمَاهُ رَجُلٌ بِسَهْمٍ فَحَبَسَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِهَذِهِ الْإِبِلِ أَوَابِدَ كَأَوَابِدِ الْوَحْشِ فَإِذَا غَلَبَكُمْ مِنْهَا شَيْءٌ فَافْعَلُوا بِهِ هَكَذَا","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah memberitakan kepada kami [Yahya bin Sa'id], ia berkata; telah menceritakan kepada kami [Sufyan], ia berkata; telah menceritakan kepadaku [ayahku] dari ['Abayah bin Rifa'ah] dari [Rafi' bin Khadij], ia berkata; saya mengatakan; wahai Rasulullah, sesungguhnya kita akan bertemu musuh besok, dan kita tidak memiliki pisau. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa yang dapat mengalirkan darah dan telah disebutkan nama Allah, maka makanlah, yang bukan gigi atau kuku dan akan saya ceritakan mengenai hal tersebut; adapun gigi maka itu adalah tulang, adapun kuku maka itu adalah pisau orang-orang Habasyah.\" Dan kami mendapatkan rampasan unta dan kambing, lalu terdapat unta yang lari, kemudian seorang laki-laki memanahnya dengan anak panah sehingga menghentikannya. Beliau bersabda: \"Sesungguhnya unta ini memiliki binanatang-binatang yang menjadi liar, seperti liarnya binatang liar, maka apa yang kalian mampu lakukan terhadapnya maka lakukanlah demikian.\""},"4119":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى قَالَ أَنْبَأَنَا إِسْرَائِيلُ عَنْ مَنْصُورٍ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي أَسْمَاءَ الرَّحَبِيِّ عَنْ أَبِي الْأَشْعَثِ عَنْ شَدَّادِ بْنِ أَوْسٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ عَزَّ وَجَلَّ كَتَبَ الْإِحْسَانَ عَلَى كُلِّ شَيْءٍ فَإِذَا قَتَلْتُمْ فَأَحْسِنُوا الْقِتْلَةَ وَإِذَا ذَبَحْتُمْ فَأَحْسِنُوا الذَّبْحَ وَلْيُحِدَّ أَحَدُكُمْ إِذَا ذَبَحَ شَفْرَتَهُ وَلْيُرِحْ ذَبِيحَتَهُ","id":"Telah mengabarkan kepada kami [Ibrahim bin Ya'qub], ia berkata; telah menceritakan kepada kami ['Ubaidullah bin Musa], ia berkata; telah memberitakan kepada kami [Israil] dari [Manshur] dari [Khalid Al Hadzdza`] dari [Abu Qilabah] dari [Abu Asma` Ar Rahabi] dari [Abu Al Asy'ats] dari [Syaddad bin Aus], ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah telah mewajibkan berbuat baik kepada segala sesuatu, apabila kalian membunuh maka bunuhlah secara baik, dan apabila kalian menyembelih maka sembelihlah secara baik, dan hendaknya salah seorang diantara kalian menajamkan pisaunya apabila ia menyembelih serta memberikan kenyamanan kepada sembelihannya.\""},"4120":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ أَبُو عَمَّارٍ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْأَشْعَثِ الصَّنْعَانِيِّ عَنْ شَدَّادِ بْنِ أَوْسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ كَتَبَ الْإِحْسَانَ عَلَى كُلِّ شَيْءٍ فَإِذَا قَتَلْتُمْ فَأَحْسِنُوا الْقِتْلَةَ وَإِذَا ذَبَحْتُمْ فَأَحْسِنُوا الذَّبْحَ وَلْيُحِدَّ أَحَدُكُمْ شَفْرَتَهُ وَلْيُرِحْ ذَبِيحَتَهُ","id":"Telah mengabarkan kepada kami [Al Husain bin Huraits Abu 'Ammar], ia berkata; telah memberitakan kepada kami [Jarir] dari [Manshur] dari [Khalid Al Hadzdza`] dari [Abu Qilabah] dari [Abu Al Asy'ats Ash Shan'ani] dari [Syaddad bin Aus], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah telah mewajibkan berbuat baik kepada segala sesuatu, apabila kalian membunuh maka bunuhlah secara baik, dan apabila kalian menyembelih maka sembelihlah secara baik, dan hendaknya salah seorang diantara kalian menajamkan pisaunya serta memberikan kenyamanan kepada sembelihannya.\""},"4121":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْأَشْعَثِ عَنْ شَدَّادِ بْنِ أَوْسٍ قَالَسَمِعْتُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اثْنَتَيْنِ فَقَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ كَتَبَ الْإِحْسَانَ عَلَى كُلِّ شَيْءٍ فَإِذَا قَتَلْتُمْ فَأَحْسِنُوا الْقِتْلَةَ وَإِذَا ذَبَحْتُمْ فَأَحْسِنُوا الذَّبْحَ وَلْيُحِدَّ أَحَدُكُمْ شَفْرَتَهُ ثُمَّ لِيُرِحْ ذَبِيحَتَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'], ia berkata; telah menceritakan kepada kami [Abdur Razzaq], ia berkata; telah memberitakan kepada kami [Ma'mar] dari [Ayyub] dari [Abu Qilabah] dari [Abu Al Asy'ats] dari [Syaddad bin Aus], ia berkata; saya telah mendengar dari Nabi shallallahu 'alaihi wasallam dua hal, beliau bersabda: \"\"Sesungguhnya Allah 'azza wajalla telah mewajibkan berbuat baik kepada segala sesuatu, apabila kalian membunuh maka bunuhlah secara baik, dan apabila kalian menyembelih maka sembelihlah secara baik, dan hendaknya salah seorang diantara kalian menajamkan pisaunya kemudian memberikan kenyamanan kepada sembelihannya.\""},"4122":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ بَزِيعٍ قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ زُرَيْعٍ قَالَ حَدَّثَنَا خَالِدٌ ح وَأَنْبَأَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ خَالِدٍ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْأَشْعَثِ عَنْ شَدَّادِ بْنِ أَوْسٍ قَالَثِنْتَانِ حَفِظْتُهُمَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ عَزَّ وَجَلَّ كَتَبَ الْإِحْسَانَ عَلَى كُلِّ شَيْءٍ فَإِذَا قَتَلْتُمْ فَأَحْسِنُوا الْقِتْلَةَ وَإِذَا ذَبَحْتُمْ فَأَحْسِنُوا الذِّبْحَةَ لِيُحِدَّ أَحَدُكُمْ شَفْرَتَهُ وَلْيُرِحْ ذَبِيحَتَهُ","id":"Telah mengabarkan kepada kami [Muhammad Abdullah bin Bazi'], ia berkata; telah menceritakan kepada kami [Yazid yaitu Ibnu Zurai'], ia berkata; telah menceritakan kepada kami [Khalid]. Telah menceritakan dan memberitakan kepada kami [Abdullah bin Muhammad bin Abdurrahman], ia berkata; telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari [Khalid] dari [Abu Qilabah] dari [Abu Al Asy'ats] dari [Syaddad bin Aus], ia berkata; dua perkara yang saya hafal Rasulullah shallallahu 'alaihi wasallam: \"Sesungguhnya Allah telah mewajibkan berbuat baik kepada segala sesuatu, apabila kalian membunuh maka bunuhlah secara baik, dan apabila kalian menyembelih maka sembelihlah secara baik, dan hendaknya salah seorang diantara kalian menajamkan pisaunya serta memberikan kenyamanan kepada sembelihannya.\""},"4123":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ أَخْبَرَنِي قَتَادَةُ قَالَ سَمِعْتُ أَنَسًا قَالَضَحَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِكَبْشَيْنِ أَمْلَحَيْنِ أَقْرَنَيْنِ يُكَبِّرُ وَيُسَمِّي وَلَقَدْ رَأَيْتُهُ يَذْبَحُهُمَا بِيَدِهِ وَاضِعًا عَلَى صِفَاحِهِمَا قَدَمَهُ قُلْتُ أَنْتَ سَمِعْتَهُ مِنْهُ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud], ia berkata; telah menceritakan kepada kami [Khalid] dari [Syu'bah] telah memberitakan kepadaku [Qatadah], ia berkata; saya mendengar [Anas], ia berkata; Rasulullah shallallahu 'alaihi wasallam berkurban dengan dua ekor kambing kibas yang gemuk dan bertanduk, beliau bertakbir dan menyebutkan nama Allah. Sungguh saya telah melihat beliau menyembelihnya dengan tangannya dan meletakkan kakinya di atas sebelah pipinya. Saya katakan; apakah engkau mendengarnya dari beliau? Ia berkata; ya."},"4124":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ نَاصِحٍ قَالَ حَدَّثَنَا هُشَيْمٌ عَنْ شُعْبَةَ عَنْ قَتَادَةَ قَالَ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُضَحِّي بِكَبْشَيْنِ أَمْلَحَيْنِ أَقْرَنَيْنِ وَكَانَ يُسَمِّي وَيُكَبِّرُ وَلَقَدْ رَأَيْتُهُ يَذْبَحُهُمَا بِيَدِهِ وَاضِعًا رِجْلَهُ عَلَى صِفَاحِهِمَا","id":"Telah mengabarkan kepada kami [Ahmad bin Nashih], ia berkata; telah menceritakan kepada kami [Husyaim] dari [Syu'bah] dari [Qatadah], ia berkata; telah menceritakan kepada kami [Anas bin Malik], ia berkata; Rasulullah shallallahu 'alaihi wasallam berkurban dengan dua ekor kambing kibas yang gemuk dan bertanduk, beliau bertakbir dan menyebutkan nama Allah. Sungguh saya telah melihat beliau menyembelihnya dengan tangannya dan meletakkan kakinya di atas sebelah pipinya."},"4125":{"ar":"أَخْبَرَنَا الْقَاسِمُ بْنُ زَكَرِيَّا بْنِ دِينَارٍ قَالَ حَدَّثَنَا مُصْعَبُ بْنُ الْمِقْدَامِ عَنْ الْحَسَنِ يَعْنِي ابْنَ صَالِحٍ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَلَقَدْ رَأَيْتُهُ يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَذْبَحُهُمَا بِيَدِهِ وَاضِعًا عَلَى صِفَاحِهِمَا قَدَمَهُ يُسَمِّي وَيُكَبِّرُ كَبْشَيْنِ أَمْلَحَيْنِ أَقْرَنَيْنِ","id":"Telah mengabarkan kepada kami [Al Qasim bin Zakariya bin Dinar], ia berkata; telah menceritakan kepada kami [Mush'ab bin Al Miqdam] dari [Al Hasan yaitu Ibnu Shalih] dari [Syu'bah] dari [Qatadah] dari [Anas], ia berkata; Sungguh saya telah melihat beliau menyembelihnya dengan tangannya dan meletakkan kakinya di atas sebelah pipinya."},"4126":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا يَزِيدُ يَعْنِي ابْنَ زُرَيْعٍ قَالَ حَدَّثَنَا سَعِيدٌ قَالَ حَدَّثَنَا قَتَادَةُ أَنَّ أَنَسَ بْنَ مَالِكٍ حَدَّثَهُمْأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَحَّى بِكَبْشَيْنِ أَقْرَنَيْنِ أَمْلَحَيْنِ يَطَؤُ عَلَى صِفَاحِهِمَا وَيَذْبَحُهُمَا وَيُسَمِّي وَيُكَبِّرُ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Yazid yaitu Ibnu Zurai'], ia berkata; telah menceritakan kepada kami [Sa'id], ia berkata; telah menceritakan kepada kami [Qatadah] bahwa [Anas bin Malik] telah menceritakan kepada mereka bahwa Nabi shallallahu 'alaihi wasallam telah berkurban dengan dua ekor kambing kibas yang bertanduk dan gemuk, beliau menginjak sebelah pipinya dan menyembelihnya serta menyebutkan nama Allah dan bertakbir. "},"4127":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحَرَ بَعْضَ بُدْنِهِ بِيَدِهِ وَنَحَرَ بَعْضَهَا غَيْرُهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] dengan membacakan riwayat sedang saya mendengar, dari [Ibnu Al Qasim], ia berkata; telah menceritakan kepadaku [Malik] dari [Ja'far bin Muhammad] dari [ayahnya] dari [Jabir bin Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam menyembelih kambingnya dengan tangan kanannya dan sebagiannya disembelih selain beliau."},"4128":{"ar":"أَخْبَرَنَا قُتَيْبَةُ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ فَاطِمَةَ عَنْ أَسْمَاءَ قَالَتْنَحَرْنَا فَرَسًا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَكَلْنَاهُ وَقَالَ قُتَيْبَةُ فِي حَدِيثِهِ فَأَكَلْنَا لَحْمَهُخَالَفَهُ عَبْدَةُ بْنُ سُلَيْمَانَ","id":"Telah mengabarkan kepada kami [Qutaibah] dan [Muhammad bin Abdullah bin Yazid] mereka berdua berkata; telah menceritakan kepada kami [Sufyan] dari [Hisyam bin 'Urwah] dari [Fathimah] dari [Asma`], ia berkata; kami menyembelih kuda pada zaman Rasulullah shallallahu 'alaihi wasallam, dan memakannya. Qutaibah berkata di dalam haditsnya; kemudian kami memakan dagingnya. ' Abdah bin Salman telah menyelisihinya. "},"4129":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ آدَمَ قَالَ حَدَّثَنَا عَبْدَةُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ فَاطِمَةَ عَنْ أَسْمَاءَ قَالَتْذَبَحْنَا عَلَى عَهْدِ رَسُول�� اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَسًا وَنَحْنُ بِالْمَدِينَةِ فَأَكَلْنَاهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Adam], ia berkata; telah menceritakan kepada kami ['Abdah] dari [Hisyam bin 'Urwah] dari [Fathimah] dari [Asma`], ia berkata; kami menyembelih kuda pada zaman Rasulullah shallallahu 'alaihi wasallam dan kami berada di Madinah, kemudian kami memakannya."},"4130":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا يَحْيَى وَهُوَ ابْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ ابْنِ حَيَّانَ يَعْنِي مَنْصُورًا عَنْ عَامِرِ بْنِ وَاثِلَةَ قَالَسَأَلَ رَجُلٌ عَلِيًّا هَلْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسِرُّ إِلَيْكَ بِشَيْءٍ دُونَ النَّاسِ فَغَضِبَ عَلِيٌّ حَتَّى احْمَرَّ وَجْهُهُ وَقَالَ مَا كَانَ يُسِرُّ إِلَيَّ شَيْئًا دُونَ النَّاسِ غَيْرَ أَنَّهُ حَدَّثَنِي بِأَرْبَعِ كَلِمَاتٍ وَأَنَا وَهُوَ فِي الْبَيْتِ فَقَالَ لَعَنَ اللَّهُ مَنْ لَعَنَ وَالِدَهُ وَلَعَنَ اللَّهُ مَنْ ذَبَحَ لِغَيْرِ اللَّهِ وَلَعَنَ اللَّهُ مَنْ آوَى مُحْدِثًا وَلَعَنَ اللَّهُ مَنْ غَيَّرَ مَنَارَ الْأَرْضِ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Yahya yaitu Zakariya bin Abu Zaidah] dari [Ibnu Hayyan yaitu Manshur] dari ['Amir bin Watsilah], ia berkata; seseorang telah bertanya kepada [Ali]; apakah Rasulullah shallallahu 'alaihi wasallam pernah merahasiakan sesuatu kepadamu tanpa orang lain? Kemudian Ali marah hingga wajahnya memerah, dan berkata; beliau tidak pernah merahasiakan sesuatu kepadaku tanpa orang lain, selain bahwa beliau telah menceritakan kepadaku empat perkataan, saya dan beliau berada dalam rumah. Beliau bersabda: \"Allah melaknat orang yang melaknat orang tuanya, Allah melaknat orang yang menyembelih untuk selain Allah dan Allah melaknat orang yang melindungi orang yang berbuat jahat, serta Allah melaknat orang yang mengubah patok tanah.\""},"4131":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ تُؤْكَلَ لُحُومُ الْأَضَاحِيِّ بَعْدَ ثَلَاثٍ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Abdur Razzaq], ia berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam melarang memakan daging kurban setelah tiga hari."},"4132":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ عَنْ غُنْدَرٍ قَالَ حَدَّثَنَا مَعْمَرٌ قَالَ حَدَّثَنَا الزُّهْرِيُّ عَنْ أَبِي عُبَيْدٍ مَوْلَى ابْنِ عَوْفٍ قَالَشَهِدْتُ عَلِيَّ بْنَ أَبِي طَالِبٍ كَرَّمَ اللَّهُ وَجْهَهُ فِي يَوْمِ عِيدٍ بَدَأَ بِالصَّلَاةِ قَبْلَ الْخُطْبَةِ ثُمَّ صَلَّى بِلَا أَذَانٍ وَلَا إِقَامَةٍ ثُمَّ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى أَنْ يُمْسِكَ أَحَدٌ مِنْ نُسُكِهِ شَيْئًا فَوْقَ ثَلَاثَةِ أَيَّامٍ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dari [Ghundar], ia berkata; telah menceritakan kepada kami [Ma'mar], ia berkata; telah menceritakan kepada kami [Az Zuhri] dari [Abu 'Ubaid mantan Ibnu 'Auf], ia berkata; saya menyaksikan [Ali bin Abu Thalib] semoga Allah memuliakan wajahnya pada hari raya memulai dengan melakukan shalat sebelum khutbah, ia melakukan shalat dengan tanpa adzan serta iqamah, kemudian ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam melarang seseorang menyimpan sebagian dari sembelihan kurbannya di atas tiga hari. "},"4133":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَنَّ أَبَا عُبَيْدٍ أَخْبَرَهُأَنَّ عَلِيَّ بْنَ أَبِي طَالِبٍ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ نَهَاكُمْ أَنْ تَأْكُلُوا لُحُومَ نُسُكِكُمْ فَوْقَ ثَلَاثٍ","id":"Telah mengabarkan kepada kami [Abu Daud], ia berkata; telah menceritakan kepada kami [Ya'qub], ia berkata; telah menceritakan kepada kami [ayahku] dari [Shalih] dari [Ibnu Syihab] bahwa [Abu 'Ubaid] telah mengabarkan kepadanya bahwa [Ali bin Abu Thalib] berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah melarang kalian makan daging kurban kalian di atas tiga hari. "},"4134":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ أَنَّهُ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ أَكْلِ لُحُومِ الضَّحَايَا بَعْدَ ثَلَاثٍ ثُمَّ قَالَ كُلُوا وَتَزَوَّدُوا وَادَّخِرُوا","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, lafazhnya adalah lafazh Al Harits, dari [Ibnu Al Qasim], ia berkata; telah menceritakan kepadaku [Malik] dari [Abu Az Zubair] dari [Jabir bin Abdullah] bahwa ia mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari memakan daging kurban setelah tiga hari kemudian beliau bersabda: \" Makanlah, berbekallah dan masaklah.\""},"4135":{"ar":"أَخْبَرَنَا عِيسَى بْنُ حَمَّادٍ زُغْبَةُ قَالَ أَنْبَأَنَا اللَّيْثُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ ابْنِ خَبَّابٍ هُوَ عَبْدُ اللَّهِ بْنُ خَبَّابٍ أَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّقَدِمَ مِنْ سَفَرٍ فَقَدَّمَ إِلَيْهِ أَهْلُهُ لَحْمًا مِنْ لُحُومِ الْأَضَاحِيِّ فَقَالَ مَا أَنَا بِآكِلِهِ حَتَّى أَسْأَلَ فَانْطَلَقَ إِلَى أَخِيهِ لِأُمِّهِ قَتَادَةَ بْنِ النُّعْمَانِ وَكَانَ بَدْرِيًّا فَسَأَلَهُ عَنْ ذَلِكَ فَقَالَ إِنَّهُ قَدْ حَدَثَ بَعْدَكَ أَمْرٌ نَقْضًا لِمَا كَانُوا نُهُوا عَنْهُ مِنْ أَكْلِ لُحُومِ الْأَضَاحِيِّ بَعْدَ ثَلَاثَةِ أَيَّامٍ","id":"Telah mengabarkan kepada kami [Isa bin Hammad Zughbah], ia berkata; telah memberitakan kepada kami [Al Laits] dari [Yahya bin Sa'id] dari [Al Qasim bin Muhammad] dari [Ibnu Khabbab yaitu Abdullah bin Khabbab] bahwa [Abu Sa'id Al Khudri] datang dari perjalanan kemudian keluarganya menghidangkan kepadanya daging kurban. Kemudian ia berkata; saya tidak akan memakannya hingga bertanya. Kemudian ia pergi kepada saudara seibunya [Qatadah bin An Nu'man] ia adalah orang Badr. Lalu ia bertanya kepadanya mengenai hal tersebut, kemudian Qatadah berakta; sesungguhnya telah terjadi setelahmu suatu perkara sebagai pembatal apa yang dahulu mereka dilarang darinya yaitu memakan daging kurban setelah tiga hari. "},"4136":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ سَعْدِ بْنِ إِسْحَقَ قَالَ حَدَّثَتْنِي زَيْنَبُ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ لُحُومِ الْأَضَاحِيِّ فَوْقَ ثَلَاثَةِ أَيَّامٍ فَقَدِمَ قَتَادَةُ بْنُ النُّعْمَانِ وَكَانَ أَخَا أَبِي سَعِيدٍ لِأُمِّهِ وَكَانَ بَدْرِيًّا فَقَدَّمُوا إِلَيْهِ فَقَالَ أَلَيْسَ قَدْ نَهَى عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو سَعِيدٍ إِنَّهُ قَدْ حَدَثَ فِيهِ أَمْرٌ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَانَا أَنْ نَأْكُلَهُ فَوْقَ ثَلَاثَةِ أَيَّامٍ ثُمَّ رَخَّصَ لَنَا أَنْ نَأْكُلَهُ وَنَدَّخِرَهُ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id], ia berkata; telah menceritakan kepada kami [Yahya] dari [Sa'd bin Ishaq], ia berkata; telah menceritakan kepadaku [Zainab] dari [Abu Sa'id Al Khudri] bahwa Rasulullah shallallahu 'alaihi wasallam telah melarang dari daging kurban di atas tiga hari. Kemudian Qatadah bin An Nu'man yang merupakan saudara Seibu Abu Sa'id datang dan ia adalah orang Badr. Lalu mereka menyuguhkan sesuatu kepadanya, kemudian ia berkata; bukankah Rasulullah shallallahu 'alaihi wasallam telah melarang darinya? Abu Sa'id berkata; sesungguhnya telah terjadi perkara dalam hal itu, bahwa Rasulullah shallallahu 'alaihi wasallam telah melarang kita untuk memakannya di atas tiga hari kemudian beliau memberikan keringanan kepada kita untuk makan dan menyimpannya. "},"4137":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ وَهُوَ النُّفَيْلِيُّ قَالَ حَدَّثَنَا زُهَيْرٌ ح وَأَنْبَأَنَا مُحَمَّدُ بْنُ مَعْدَانَ بْنِ عِيسَى قَالَ حَدَّثَنَا الْحَسَنُ بْنُ أَعْيَنَ قَالَ حَدَّثَنَا زُهَيْرٌ قَالَ حَدَّثَنَا زُبَيْدُ بْنُ الْحَارِثِ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي كُنْتُ نَهَيْتُكُمْ عَنْ ثَلَاثٍ عَنْ زِيَارَةِ الْقُبُورِ فَزُورُوهَا وَلْتَزِدْكُمْ زِيَارَتُهَا خَيْرًا وَنَهَيْتُكُمْ عَنْ لُحُومِ الْأَضَاحِيِّ بَعْدَ ثَلَاثٍ فَكُلُوا مِنْهَا وَأَمْسِكُوا مَا شِئْتُمْ وَنَهَيْتُكُمْ عَنْ الْأَشْرِبَةِ فِي الْأَوْعِيَةِ فَاشْرَبُوا فِي أَيِّ وِعَاءٍ شِئْتُمْ وَلَا تَشْرَبُوا مُسْكِرًا وَلَمْ يَذْكُرْ مُحَمَّدٌ وَأَمْسِكُوا","id":"Telah mengabarkan kepada kami ['Amr bin Manshur], ia berkata; telah menceritakan kepada kami [Abdullah bin Muhammad yaitu An Nufaili], ia berkata; telah menceritakan kepada kami [Zuhair]; telah menceritakan dan memberitakan kepada kami [Muhammad bin Ma'dan bin Isa], ia berkata; telah menceritakan kepada kami [Al Hasan bin A'yan], ia berkata; telah menceritakan kepada kami [Zuhair], ia berkata; telah menceritakan kepada kami [Zubaid bin Al Harits] dari [Muharib bin Ditsar] dari [Ibnu Buraidah] dari [ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dahulu saya telah melarang kalian dari tiga perkara; dari berziarah kubur, sekarang berziarahlah dan hendaknya ziarahnya memberikan tambahan kebaikan kepadanya, dan saya telah melarang kalian dari daging kurban setelah tiga hari, sekarang makanlah sebagian darinya dan simpanlah semaumu, dan saya telah melarang kalian dari minuman dalam bejana, sekarang minumlah dalam bejana apapun, dan janganlah minum sesuatu yang memabukkan.\" Muhammad tidak menyebutkan; dan simpanlah "},"4138":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ الْعَنْبَرِيُّ عَنْ الْأَحْوَصِ بْنِ جَوَّابٍ عَنْ عَمَّارِ بْنِ رُزَيْقٍ عَنْ أَبِي إِسْحَقَ عَنْ الزُّبَيْرِ بْنِ عَدِيٍّ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي كُنْتُ نَهَيْتُكُمْ عَنْ لُحُومِ الْأَضَاحِيِّ بَعْدَ ثَلَاثٍ وَعَنْ النَّبِيذِ إِلَّا فِي سِقَاءٍ وَعَنْ زِيَارَةِ الْقُبُورِ فَكُلُوا مِنْ لُحُومِ الْأَضَاحِيِّ مَا بَدَا لَكُمْ وَتَزَوَّدُوا وَادَّخِرُوا وَمَنْ أَرَادَ زِيَارَةَ الْقُبُورِ فَإِنَّهَا تُذَكِّرُ الْآخِرَةَ وَاشْرَبُوا وَاتَّقُوا كُلَّ مُسْكِرٍ","id":"Telah mengabarkan kepada kami [Al Abbas bin Abdul 'Azhim Al 'Anbari] dari [Al Ahwash bin Jawwab] dari ['Ammar bin Ruzaiq] dari [Abu Ishaq] dari [Az Zubair bin 'Adi] dari [Ibnu Buraidah] dari [ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya saya telah melarang kalian dari daging kurban Setelah tiga hari dan dari rendaman anggur kecuali dalam wadah air dari kulit dan dari menziarahi kuburan, sekarang makanlah daging kurban semau kalian dan berbekallah serta simpanlah, dan barang siapa yang ingin berziarah kubur maka sesungguhnya hal itu akan mengingatkannya kepada Akherat, dan minumlah serta jauhi segala yang memabukkan.\" "},"4139":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ مَالِكٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي بَكْرٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْدَفَّتْ دَافَّةٌ مِنْ أَهْلِ الْبَادِيَةِ حَضْرَةَ الْأَضْحَى فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُوا وَادَّخِرُوا ثَلَاثًا فَلَمَّا كَانَ بَعْدَ ذَلِكَ قَالُوا يَا رَسُولَ اللَّهِ إِنَّ النَّاسَ كَانُوا يَنْتَفِعُونَ مِنْ أَضَاحِيِّهِمْ يَجْمُلُونَ مِنْهَا الْوَدَكَ وَيَتَّخِذُونَ مِنْهَا الْأَسْقِيَةَ قَالَ وَمَا ذَاكَ قَالَ الَّذِي نَهَيْتَ مِنْ إِمْسَاكِ لُحُومِ الْأَضَاحِيِّ قَالَ إِنَّمَا نَهَيْتُ لِلدَّافَّةِ الَّتِي دَفَّتْ كُلُوا وَادَّخِرُوا وَتَصَدَّقُوا","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id], ia berkata; telah menceritakan kepada kami [Yahya] dari [Malik], ia berkata; telah menceritakan kepadaku [Abdullah bin Abu Bakar] dari ['Amrah] dari [Aisyah], ia berkata; sekelompok orang dari penduduk badui datang dengan terburu-buru pada waktu idul adhha, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Makan dan dan simpanlah selama tiga hari.\" Kemudian setelah itu mereka berkata; wahai Rasulullah, sesungguhnya orang-orang memanfaatkan dari kurban mereka mencairkan lemaknya dan darinya mereka membuat geriba. Beliau bersabda: \"Ada apa dengan hal tersebut?\" Ia berkata; yang telah anda larang yaitu menyimpan daging kurban. Beliau bersabda: \"Sesungguhnya saya melarang sekelompok orang yang datang terburu-buru, makan, simpan dan bersedekahlah.\""},"4140":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَابِسٍ عَنْ أَبِيهِ قَالَدَخَلْتُ عَلَى عَائِشَةَ فَقُلْتُ أَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ لُحُومِ الْأَضَاحِيِّ بَعْدَ ثَلَاثٍ قَالَتْ نَعَمْ أَصَابَ النَّاسَ شِدَّةٌ فَأَحَبَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُطْعِمَ الْغَنِيُّ الْفَقِيرَ ثُمَّ قَالَ لَقَدْ رَأَيْتُ آلَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُونَ الْكُرَاعَ بَعْدَ خَمْسَ عَشْرَةَ قُلْتُ مِمَّ ذَاكَ فَضَحِكَتْ فَقَالَتْ مَا شَبِعَ آلُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ خُبْزٍ مَأْدُومٍ ثَلَاثَةَ أَيَّامٍ حَتَّى لَحِقَ بِاللَّهِ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dari [Abdurrahman] dari [Sufyan] dari [Abdurrahman bin 'Abis] dari [ayahnya], ia berkata; saya menemui [Aisyah] kemudian berkata; apakah dahulu Rasulullah shallallahu 'alaihi wasallam melarang dari daging kurban setelah tiga hari? Ia berkata; ya, orang-orang tertimpa kesusahan kemudian Rasulullah shallallahu 'alaihi wasallam ingin agar orang kaya memberi makan orang yang miskin. 'Abis berkata; sungguh saya telah melihat keluarga Muhammad shallallahu 'alaihi wasallam memakan betis kambing setelah lima belas hari. Saya bertanya; apa sebab hal itu? Aisyah tertawa dan berkata; keluarga Muhammad tidaklah kenyang roti Yang diberi lauk sejak tiga hari hingga beliau menemui Allah 'azza wajalla. "},"4141":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ عِيسَى قَالَ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ زِيَادِ بْنِ أَبِي الْجَعْدِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَابِسٍ عَنْ أَبِيهِ قَالَسَأَلْتُ عَائِشَةَ عَنْ لُحُومِ الْأَضَاحِيِّ قَالَتْ كُنَّا نَخْبَأُ الْكُرَاعَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَهْرًا ثُمَّ يَأْكُلُهُ","id":"Telah mengabarkan kepada kami [Yusuf bin Isa], ia berkata; telah menceritakan kepada kami [Al Fhadhl bin Musa], ia berkata; telah menceritakan kepada kami [Yazid yaitu Ibnu Ziyad bin Abu Al Ja'd] dari [Abdurrahman bin 'Abis] dari [ayahnya], ia berkata; saya bertanya kepada [Aisyah] mengenai daging kurban. Ia berkata; dahulu kami menyimpan betis kambing untuk Rasulullah shallallahu 'alaihi wasallam selama satu bulan, kemudian beliau memakannya."},"4142":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ ابْنِ عَوْنٍ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ إِمْسَاكِ الْأُضْحِيَّةِ فَوْقَ ثَلَاثَةِ أَيَّامٍ ثُمَّ قَالَ كُلُوا وَأَطْعِمُوا","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr], ia berkata; telah memberitakan kepada kami [Abdullah] dari [Ibnu 'Aun] dari [Ibnu Sirin] dari [Abu Sa'id Al Khudri], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari menyimpan kurban di atas tiga hari kemudian beliau bersabda: \"Makan dan berilah makan.\""},"4143":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُلَيْمَانَ بْنِ مُغِيرَةَ قَالَ حَدَّثَنَا حُمَيْدُ بْنُ هِلَالٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُغَفَّلٍ قَالَدُلِّيَ جِرَابٌ مِنْ شَحْمٍ يَوْمَ خَيْبَرَ فَالْتَزَمْتُهُ قُلْتُ لَا أُعْطِي أَحَدًا مِنْهُ شَيْئًا فَالْتَفَتُّ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَبَسَّمُ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim], ia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sulaiman bin Mughirah], ia berkata; telah menceritakan kepada kami [Humaid bin Hilal], ia berkata; telah menceritakan kepada kami [Abdullah bin Mughaffal], ia berkata; sekantong lemak telah digantungkan pada saat perang Khaibar, dan saya menungguinya dan mengatakan; tidak akan saya berikan sedikitpun darinya kepada seseorang. Kemudian saya menoleh ternyata Rasulullah shallallahu 'alaihi wasallam tersenyum. "},"4144":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ نَاسًا مِنْ الْأَعْرَابِ كَانُوا يَأْتُونَا بِلَحْمٍ وَلَا نَدْرِي أَذَكَرُوا اسْمَ اللَّهِ عَلَيْهِ أَمْ لَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اذْكُرُوا اسْمَ اللَّهِ عَزَّ وَجَلَّ عَلَيْهِ وَكُلُوا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah menceritakan kepada kami [An Nadhr bin Syumail], ia berkata; telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [ayahnya] dari ['Aisyah] bahwa orang-orang Badui menemui kami dengan membawa daging yang kami tidak mengetahui apakah mereka menyebut nama Allah ketika menyembelih atau tidak, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebutlah nama Allah Azza wa jalla lalu makanlah.\""},"4145":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي هَارُونُ بْنُ أَبِي وَكِيعٍ وَهُوَ هَارُونُ بْنُ عَنْتَرَةَ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ عَزَّ وَجَلَّ{ وَلَا تَأْكُلُوا مِمَّا لَمْ يُذْكَرْ اسْمُ اللَّهِ عَلَيْهِ }قَالَ خَاصَمَهُمْ الْمُشْرِكُونَ فَقَالُوا مَا ذَبَحَ اللَّهُ فَلَا تَأْكُلُوهُ وَمَا ذَبَحْتُمْ أَنْتُمْ أَكَلْتُمُوهُ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Yahya], ia berkata; telah menceritakan kepada kami [Sufyan], ia berkata; telah menceritakan kepadaku [Harun bin Abu Waki'] yaitu Harun bin 'Antarah dari [ayahnya] dari [Ibnu Abbas] mengenai firman Allah 'azza wajalla: Dan janganlah kamu memakan binatang-binatang yang tidak disebut nama Allah ketika menyembelihnya, ia berkata; orang-orang musyrikin mempermasalahkan hal itu dan mereka berkata; apa yang disembelih Allah janganlah kalian memakan sedangkan apa yang kalian sembelih boleh kalian memakannya."},"4146":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا بَقِيَّةُ عَنْ بَحِيرٍ عَنْ خَالِدٍ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِي ثَعْلَبَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَحِلُّ الْمُجَثَّمَةُ","id":"Telah mengabarkan kepada kami ['Amr bin Utsman], ia berkata; telah menceritakan kepada kami [Baqiyah] dari [Bahir] dari [Khalid] dari [Jubair bin Nufair] dari [Abu Tsa'labah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal menjadikan hewan sebagai sasaran memanah.\" "},"4147":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ عَنْ هِشَامِ بْنِ زَيْدٍ قَالَدَخَلْتُ مَعَ أَنَسٍ عَلَى الْحَكَمِ يَعْنِي ابْنَ أَيُّوبَ فَإِذَا أُنَاسٌ يَرْمُونَ دَجَاجَةً فِي دَارِ الْأَمِيرِ فَقَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُصْبَرَ الْبَهَائِمُ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud], ia berkata; telah menceritakan kepada kami [Khalid] dari [Syu'bah] dari [Hisyam bin Zaid], ia berkata; saya bersama [Anas] menemui Al Hakam yaitu Ibnu Ayyub, ternyata orang-orang sedang membidik ayam di rumah Al Amir, kemudian ia berkata; Rasulullah shallallahu 'alaihi wasallam telah melarang hewan-hewan ternak dijadikan sasaran."},"4148":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ زُنْبُورٍ الْمَكِّيُّ قَالَ حَدَّثَنَا ابْنُ أَبِي حَازِمٍ عَنْ يَزِيدَ وَهُوَ ابْنُ الْهَادِ عَنْ مُعَاوِيَةَ بْنِ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ قَالَمَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أُنَاسٍ وَهُمْ يَرْمُونَ كَبْشًا بِالنَّبْلِ فَكَرِهَ ذَلِكَ وَقَالَ لَا تَمْثُلُوا بِالْبَهَائِمِ","id":"Telah mengabarkan kepada kami [Muhammad bin Zunbur Al Makki], dia berkata; telah menceritakan kepada kami [Ibnu Abu Hazim] dari [Yazid dan dia adalah Ibnu Al Had] dai [Mu'awiyyah bin Abdullah bin Ja'far] dari [Abdullah bin Ja'far] ia berkata Rasulullah shallallahu 'alaihi wasallam melewati sekelompok orang yang sedang melempari seekor kambing dengan tombak, beliau membenci hal itu dan bersabda: \" Janganlah kalian mencincang hewan.\""},"4149":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا هُشَيْمٌ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عُمَرَ قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اتَّخَذَ شَيْئًا فِيهِ الرُّوحُ غَرَضًا","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id], ia berkata; telah menceritakan kepada kami [Husyaim] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam melaknat orang yang orang yang menjadikan sesuatu yang bernyawa sebagai sasaran."},"4150":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنِي الْمِنْهَالُ بْنُ عَمْرٍو عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عُمَرَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَعَنَ اللَّهُ مَنْ مَثَّلَ بِالْحَيَوَانِ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Yahya], ia berkata; telah menceritakan kepada kami [Syu'bah], ia berkata; telah menceritakan kepadaku [Al Minhal bin 'Amr] dari [Sa'id bin Jubair] dari [Ibnu Umar], ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \" Allah melaknat orang yang mencincang hewan.\""},"4151":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ شُعْبَةَ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَتَّخِذُوا شَيْئًا فِيهِ الرُّوحُ غَرَضًا","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr], ia berkata; telah memberitakan kepada kami [Abdullah] dari [Syu'bah] dari ['Adi bin Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian jadikan sesuatu yang bernyawa sebagai sasaran.\""},"4152":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُبَيْدٍ الْكُوفِيُّ قَالَ حَدَّثَنَا عَلِيُّ بْنُ هَاشِمٍ عَنْ الْعَلَاءِ بْنِ صَالِحٍ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَتَّخِذُوا شَيْئًا فِيهِ الرُّوحُ غَرَضًا","id":"Telah mengabarkan kepada kami [Muhammad bin 'Ubaid Al Kufi], ia berkata; telah menceritakan kepada kami [Ali bin Hasyim] dari [Al 'Ala` bin Shalih] dari ['Adi bin Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menjadikan sesuatu yang bernyawa sebagai sasaran.\""},"4153":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ صُهَيْبٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍويَرْفَعُهُ قَالَ مَنْ قَتَلَ عُصْفُورًا فَمَا فَوْقَهَا بِغَيْرِ حَقِّهَا سَأَلَ اللَّهُ عَزَّ وَجَلَّ عَنْهَا يَوْمَ الْقِيَامَةِ قِيلَ يَا رَسُولَ اللَّهِ فَمَا حَقُّهَا قَالَ حَقُّهَا أَنْ تَذْبَحَهَا فَتَأْكُلَهَا وَلَا تَقْطَعْ رَأْسَهَا فَيُرْمَى بِهَا","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id], ia berkata; telah menceritakan kepada kami [Sufyan] dari ['Amr] dari [Shuhaib] dari [Abdullah bin 'Amr] dan ia memarfu'kannya: \"Barang siapa yang membunuh burung pipit tanpa hak, maka Allah 'azza wajalla akan menanyakan mengenainya pada hari Kiamat.\" Dikatakan kepada Rasulullah shallallahu 'alaihi wasallam; wahai Rasulullah, apakah haknya? Beliau bersabda: \"Menyembelihnya dan memakannya serta tidak memotong kepalanya kemudia membuangnya.\""},"4154":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ دَاوُدَ الْمِصِّيصِيُّ قَالَ حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ قَالَ حَدَّثَنَا أَبُو عُبَيْدَةَ عَبْدُ الْوَاحِدِ بْنُ وَاصِلٍ عَنْ خَلَفٍ يَعْنِي ابْنَ مِهْرَانَ قَالَ حَدَّثَنَا عَامِرٌ الْأَحْوَلُ عَنْ صَالِحِ بْنِ دِينَارٍ عَنْ عَمْرِو بْنِ الشَّرِيدِ قَالَ سَمِعْتُ الشَّرِيدَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ قَتَلَ عُصْفُورًا عَبَثًا عَجَّ إِلَى اللَّهِ عَزَّ وَجَلَّ يَوْمَ الْقِيَامَةِ يَقُولُ يَا رَبِّ إِنَّ فُلَانًا قَتَلَنِي عَبَثًا وَلَمْ يَقْتُلْنِي لِمَنْفَعَةٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Daud Al Mishshishi], ia berkata; telah menceritakan kepada kami [Ahmad bin Hanbal], ia berkata; telah menceritakan kepada kami [Abu 'Ubaidah Abdul Wahid bin Washil] dari [Khalaf yaitu Ibnu Mahran], ia berkata; telah menceritakan kepada kami ['Amir Al Ahwal] dari [Shalih bin Dinar] dari ['Amr bin Asy Syarid], ia berkata; saya mendengar [Asy Syarid] berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang membunuh burung pipit dengan sia-sia maka burung tersebut akan berteriak kepada Allah, dan mengatakan; wahai Tuhanku, sesungguhnya Fulan telah membunuhku dengan sia-sia dan tidak membunuhku untuk suatu manfaat.\""},"4155":{"ar":"أَخْبَرَنِي عُثْمَانُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي سَهْلُ بْنُ بَكَّارٍ قَالَ حَدَّثَنَا وُهَيْبُ بْنُ خَالِدٍ عَنْ ابْنِ طَاوُسٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ أَبِيهِ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ مَرَّةً عَنْ أَبِيهِ وَقَالَ مَرَّةً عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى يَوْمَ خَيْبَرَ عَنْ لُحُومِ الْحُمُرِ الْأَهْلِيَّةِ وَعَنْ الْجَلَّالَةِ وَعَنْ رُكُوبِهَا وَعَنْ أَكْلِ لَحْمِهَا","id":"Telah mengabarkan kepada kami [Utsman bin Abdullah], ia berkata; telah menceritakan kepadaku [Sahl bin Bakkar], ia berkata; telah menceritakan kepada kami [Wuhaib bin Khalid] dari [Ibnu Thawus] dari ['Amr bin Syu'aib] dari [ayahnya] dari [ayahnya yaitu Muhammad bin Abdullah bin 'Amr], sesekali, ia berkata; dari ayahnya, dan sesekali, ia berkata; dari [kakeknya]. Bahwa Rasulullah shallallahu 'alaihi wasallam telah melarang pada saat perang Khaibar dari daging keledai jinak, dan dari hewan yang diberi makan kotoran, dan dari menaikinya serta memakan dagingnya."},"4156":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا هِشَامٌ قَالَ حَدَّثَنَا قَتَادَةُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُجَثَّمَةِ وَلَبَنِ الْجَلَّالَةِ وَالشُّرْبِ مِنْ فِي السِّقَاءِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud], ia berkata; telah menceritakan kepada kami [Khalid], ia berkata; telah menceritakan kepada kami [Hisyam], ia berkata; telah menceritakan kepada kami [Qatadah] dari [Ikrimah] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari menjadikan binatang sebagai sasaran, dan susu binatang yang diberi makan kotoran serta minum dari geriba."},"4157":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ أَبُو قُدَامَةَ السَّرْخَسِيُّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ عَمَّتِهِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَطْيَبَ مَا أَكَلَ الرَّجُلُ مِنْ كَسْبِهِ وَإِنَّ وَلَدَ الرَّجُلِ مِنْ كَسْبِهِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id Abu Qudamah As Sarkhasi], ia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan] dari [Manshur] dari [Ibrahim] dari ['Umarah bin 'Umair] dari [bibinya] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya sebaik-baik apa yang dimakan seseorang adalah yang berasal dari usahanya, dan sesungguhnya anak seseorang adalah berasal dari usahanya.\""},"4158":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ عَمَّةٍ لَهُ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَوْلَادَكُمْ مِنْ أَطْيَبِ كَسْبِكُمْ فَكُلُوا مِنْ كَسْبِ أَوْلَادِكُمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur], ia berkata; telah menceritakan kepada kami [Sufyan], ia berkata; telah menceritakan kepada kami [Al A'masy] dari [Ibrahim] dari ['Umarah bin 'Umair] dari [bibinya] dari [Aisyah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya anak-anak kalian adalah merupakan usaha kalian yang terbaik. Maka makanlah dari usaha anak-anakmu.\""},"4159":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ عِيسَى قَالَ أَنْبَأَنَا الْفَضْلُ بْنُ مُوسَى قَالَ أَنْبَأَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَطْيَبَ مَا أَكَلَ الرَّجُلُ مِنْ كَسْبِهِ وَوَلَدُهُ مِنْ كَسْبِهِ","id":"Telah mengabarkan kepada kami [Yusuf bin Isa], ia berkata; telah memberitakan kepada kami [Al Fadhl bin Musa], ia berkata; telah memberitakan kepada kami [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Sesungguhnya sebaik-baik apa yang dimakan oleh seseorang adalah yang berasal dari usahanya, dan anaknya adalah berasal dari usahanya.\""},"4160":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَفْصِ بْنِ عَبْدِ اللَّهِ النَّيْسَابُورِيُّ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ عُمَرَ بْنِ سَعِيدٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَطْيَبَ مَا أَكَلَ الرَّجُلُ مِنْ كَسْبِهِ وَإِنَّ وَلَدَهُ مِنْ كَسْبِهِ","id":"Telah mengabarkan kepada kami [Ahmad bin Hafsh bin Abdullah An Naisaburi], ia berkata; telah menceritakan kepadaku [ayahku], ia berkata; telah menceritakan kepadaku [Ibrahim bin Thahman] dari [Umar bin Sa'id] dari [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Sesungguhnya sebaik-baik apa yang dimakan seseorang adalah yang berasal dari usahanya dan anaknya adalah berasal dari usahanya.\""},"4161":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الصَّنْعَانِيُّ قَالَ حَدَّثَنَا خَالِدٌ وَهُوَ ابْنُ الْحَارِثِ قَالَ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ الشَّعْبِيِّ قَالَ سَمِعْتُ النُّعْمَانَ بْنَ بَشِيرٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَاللَّهِ لَا أَسْمَعُ بَعْدَهُ أَحَدًا يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الْحَلَالَ بَيِّنٌ وَإِنَّ الْحَرَامَ بَيِّنٌ وَإِنَّ بَيْنَ ذَلِكَ أُمُورًا مُشْتَبِهَاتٍ وَرُبَّمَا قَالَ وَإِنَّ بَيْنَ ذَلِكَ أُمُورًا مُشْتَبِهَةً قَالَ وَسَأَضْرِبُ لَكُمْ فِي ذَلِكَ مَثَلًا إِنَّ اللَّهَ عَزَّ وَجَلَّ حَمَى حِمًى وَإِنَّ حِمَى اللَّهِ عَزَّ وَجَلَّ مَا حَرَّمَ وَإِنَّهُ مَنْ يَرْتَعُ حَوْلَ الْحِمَى يُوشِكُ أَنْ يُخَالِطَ الْحِمَى وَرُبَّمَا قَالَ إِنَّهُ مَنْ يَرْعَى حَوْلَ الْحِمَى يُوشِكُ أَنْ يُرْتِعَ فِيهِ وَإِنَّ مَنْ يُخَالِطُ الرِّيبَةَ يُوشِكُ أَنْ يَجْسُرَ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la Ash Shan'ani], ia berkata; telah menceritakan kepada kami [Khalid yaitu Ibnu Al Harits], ia berkata; telah menceritakan kepada kami [Ibnu 'Aun] dari [Asy Sya'bi], ia berkata; saya mendengar [An Nu'man bin Basyir], ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam, demi Allah saya tidak mendengar seorangpun setelahnya, ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya yang halal itu jelas dan yang haram itu jelas. Dan diantara hal itu terdapat perkara-perkara yang tidak jelas dan akan saya berikan permisalan kepadamu dalam hal tersebut; sesungguhnya alla 'azza wajalla telah membuat daerah larangan dan sesungguhnya daerah larangan Allah 'azza wajalla adalah apa yang Dia haramkan. Sesunggunya orang yang menggembala di sekitar daerah larangan akan memasuki daerah larangan.\" Dan terkadang beliau bersabda: \"Barang siapa yang menggembala di sekitar daerah larangan akan menggembala di dalamnya, dan orang yang memasuki sesuatu yang meragukan maka ia akan menyeberanginya.\" "},"4162":{"ar":"حَدَّثَنَا الْقَاسِمُ بْنُ زَكَرِيَّا بْنِ دِينَارٍ قَالَ حَدَّثَنَا أَبُو دَاوُدَ الْحَفَرِيُّ عَنْ سُفْيَانَ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْتِي عَلَى النَّاسِ زَمَانٌ مَا يُبَالِي الرَّجُلُ مِنْ أَيْنَ أَصَابَ الْمَالَ مِنْ حَلَالٍ أَوْ حَرَامٍ","id":"Telah mengabarkan kepada kami [Al Qasim bin Zakariya bin Dinar], ia berkata; telah menceritakan kepada kami [Abu Daud Al Hafari] dari [Sufyan] dari [Muhammad bin Abdurrahman] dari [Al Maqburi] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan datang kepada manusia suatu zaman dimana seseorang tidak peduli darimana ia mendapatkan harta, dari yang halal atau yang haram.\""},"4163":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ سَعِيدِ بْنِ أَبِي خَيْرَةَ عَنْ الْحَسَنِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَأْتِي عَلَى النَّاسِ زَمَانٌ يَأْكُلُونَ الرِّبَا فَمَنْ لَمْ يَأْكُلْهُ أَصَابَهُ مِنْ غُبَارِهِ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Daud bin Abu Hindun] dari [Sa'id bin Abu Khubairah] dari [Al Hasan] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan datang kepada manusia suatu zaman, dimana mereka makan riba, dan orang yang tidak memakannya ia akan mendapatkan debunya.\""},"4164":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ أَنْبَأَنَا وَهْبُ بْنُ جَرِيرٍ قَالَ حَدَّثَنِي أَبِي عَنْ يُونُسَ عَنْ الْحَسَنِ عَنْ عَمْرِو بْنِ تَغْلِبَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ أَشْرَاطِ السَّاعَةِ أَنْ يَفْشُوَ الْمَالُ وَيَكْثُرَ وَتَفْشُوَ التِّجَارَةُ وَيَظْهَرَ الْعِلْمُ وَيَبِيعَ الرَّجُلُ الْبَيْعَ فَيَقُولَ لَا حَتَّى أَسْتَأْمِرَ تَاجِرَ بَنِي فُلَانٍ وَيُلْتَمَسَ فِي الْحَيِّ الْعَظِيمِ الْكَاتِبُ فَلَا يُوجَدُ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah memberitakan kepada kami [Wahb bin Jarir], ia berkata; telah menceritakan kepadaku [ayahku] dari [Yunus] dari [Al Hasan] dari ['Amr bin Taghlib], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya diantara tanda-tanda Hari Kiamat adalah semakin banyaknya harta dan menyebarnya perdagangan, munculnya pengetahuan, seseorang menjual barang dan berkata; jangan engkau jual hingga aku meminta pertimbangan penjual dari Bani Fulan dan dicari seorang penulis yang adal disuatu kampung yang besar namun tidak ditemukan.\""},"4165":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ عَنْ يَحْيَى قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنِي قَتَادَةُ عَنْ أَبِي الْخَلِيلِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ حَكِيمِ بْنِ حِزَامٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَيِّعَانِ بِالْخِيَارِ مَا لَمْ يَفْتَرِقَا فَإِنْ صَدَقَا وَبَيَّنَا بُورِكَ فِي بَيْعِهِمَا وَإِنْ كَذَبَا وَكَتَمَا مُحِقَ بَرَكَةُ بَيْعِهِمَا","id":"Telah mengabarkan kepada kami ['Amr bin Ali] dari [Yahya], ia berkata; telah menceritakan kepada kami [Syu'bah], ia berkata; telah menceritakan kepadaku [Qatadah] dari [Abu Al Khalil] dari [Abdullah bin Al Harits] dari [Hakim bin Hizam], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua orang yang berjual beli memiliki hak memilih selama mereka belum berpisah, apabila keduanya berbuat jujur dan memberikan penjelasan maka jual beli mereka akan mendapatkan berkah, dan apabila mereka berdusta dan menyembunyikan aib maka akan dihapuskan berkah jual beli mereka.\""},"4166":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ عَنْ مُحَمَّدٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَلِيِّ بْنِ مُدْرِكٍ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ خَرَشَةَ بْنِ الْحُرِّ عَنْ أَبِي ذَرٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثَلَاثَةٌ لَا يُكَلِّمُهُمْ اللَّهُ يَوْمَ الْقِيَامَةِ وَلَا يَنْظُرُ إِلَيْهِمْ وَلَا يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ فَقَرَأَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو ذَرٍّ خَابُوا وَخَسِرُوا قَالَ الْمُسْبِلُ إِزَارَهُ وَالْمُنَفِّقُ سِلْعَتَهُ بِالْحَلِفِ الْكَاذِبِ وَالْمَنَّانُ عَطَاءَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dari [Muhammad], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Ali bin Mudrik] dari [Abu Zur'ah bin 'Amr bin Jarir] dari [Kharasyah bin Al Hurr] dari [Abu Dzar] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tiga orang yang tidak akan diajak bicara Allah pada Hari Kiamat dan Allah tidak akan melihatnya serta mensucikannya dan mereka mendapatkan adzab yang pedih kemudian Rasulullah shallallahu 'alaihi wasallam membacakannya. Abu Dzar berkata; mereka telah binasa dan merugi. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang memanjangkan kainya melebihi mata kaki, orang yang menjual barangnya dengan sumpah palsu, serta orang yang mengungkit-ungkit pemberiannya.\" "},"4167":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي سُلَيْمَانُ الْأَعْمَشُ عَنْ سُلَيْمَانَ بْنِ مُسْهِرٍ عَنْ خَرَشَةَ بْنِ الْحُرِّ عَنْ أَبِي ذَرٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثَلَاثَةٌ لَا يَنْظُرُ اللَّهُ إِلَيْهِمْ يَوْمَ الْقِيَامَةِ وَلَا يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ الَّذِي لَا يُعْطِي شَيْئًا إِلَّا مَنَّهُ وَالْمُسْبِلُ إِزَارَهُ وَالْمُنَفِّقُ سِلْعَتَهُ بِالْكَذِبِ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Yahya], ia berkata; telah menceritakan kepada kami [Sufyan], ia berkata; telah menceritakan kepadaku [Sulaiman Al A'masy] dari [Sulaiman bin Mushir] dari [Kharasyah bin Al Hurr] dari [Abu Dzar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: Tiga orang yang tidak akan diajak bicara Allah pada Hari Kiamat dan Allah tidak akan melihatnya serta mensucikannya dan mereka mendapatkan adzab yang pedih yaitu; orang yang tidak memberi sesuatu melainkan ia mengungkitnya, orang yang memanjangkan kainnya hingga melebihi mata kaki, dan orang yang menjual barangnya dengan sumpah palsu.\" "},"4168":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ قَالَ أَخْبَرَنِي الْوَلِيدُ يَعْنِي ابْنَ كَثِيرٍ عَنْ مَعْبَدِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِي قَتَادَةَ الْأَنْصَارِيِّأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِيَّاكُمْ وَكَثْرَةَ الْحَلِفِ فِي الْبَيْعِ فَإِنَّهُ يُنَفِّقُ ثُمَّ يَمْحَقُ","id":"Telah mengabarkan kepada kami [Harun bin Abdullah], ia berkata; telah menceritakan kepada kami [Abu Usamah], ia berkata; telah memberitakan kepadaku [Al Walid yaitu Ibnu Katsir] dari [Ma'bad bin Ka'b bin Malik] dari [Abu Qatadah Al Anshari] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berhati-hatilah kalian dari sering bersumpah dalam berjual beli, karena sesungguhnya bisa jadi ia menjual kemudian dihilangkan berkahnya.\" "},"4169":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْحَلِفُ مَنْفَقَةٌ لِلسِّلْعَةِ مَمْحَقَةٌ لِلْكَسْبِ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amr bin As Sarh], ia berkata; telah menceritakan kepada kami [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sumpah akan melariskan barang dagangan dan menghilangkan kelarisannya dalam sangkaan orang yang bersumpah.\" "},"4170":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثَلَاثَةٌ لَا يُكَلِّمُهُمْ اللَّهُ عَزَّ وَجَلَّ وَلَا يَنْظُرُ إِلَيْهِمْ يَوْمَ الْقِيَامَةِ وَلَا يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ رَجُلٌ عَلَى فَضْلِ مَاءٍ بِالطَّرِيقِ يَمْنَعُ ابْنَ السَّبِيلِ مِنْهُ وَرَجُلٌ بَايَعَ إِمَامًا لِدُنْيَا إِنْ أَعْطَاهُ مَا يُرِيدُ وَفَّى لَهُ وَإِنْ لَمْ يُعْطِهِ لَمْ يَفِ لَهُ وَرَجُلٌ سَاوَمَ رَجُلًا عَلَى سِلْعَةٍ بَعْدَ الْعَصْرِ فَحَلَفَ لَهُ بِاللَّهِ لَقَدْ أُعْطِيَ بِهَا كَذَا وَكَذَا فَصَدَّقَهُ الْآخَرُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Tiga orang yang tidak akan diajak bicara Allah 'azza wajalla dan Allah tidak akan melihat mereka pada Hari Kiamat serta tidak akan mensucikan mereka dan bagi mereka siksaan yang pedih, yaitu; orang yang memiliki kelebihan air dijalan dan ia melarang orang yang dalam perjalan untuk mengambilnya, seseorang yang membai'at imam karena urusan dunia, apabila ia memberi apa yang ia inginkan maka ia akan menunaikan haknya dan apabila ia tidak memberinya maka ia tidak memenuhi haknya, dan seseorang yang menawar barang orang lain setelah Ashar dan bersumpah kepadanya dengan nama Allah sungguh ia telah diberi dengan harga sekian dan sekian, kemudian orang lain mempercayainya.\" "},"4171":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ قُدَامَةَ عَنْ جَرِيرٍ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ قَيْسِ بْنِ أَبِي غَرَزَةَ قَالَكُنَّا بِالْمَدِينَةِ نَبِيعُ الْأَوْسَاقَ وَنَبْتَاعُهَا وَنُسَمِّي أَنْفُسَنَا السَّمَاسِرَةَ وَيُسَمِّينَا النَّاسُ فَخَرَجَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمَّانَا بِاسْمٍ هُوَ خَيْرٌ لَنَا مِنْ الَّذِي سَمَّيْنَا بِهِ أَنْفُسَنَا فَقَالَ يَا مَعْشَرَ التُّجَّارِ إِنَّهُ يَشْهَدُ بَيْعَكُمْ الْحَلِفُ وَاللَّغْوُ فَشُوبُوهُ بِالصَّدَقَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] dari [Jarir] dari [Manshur] dari [Abu Wail] dari [Qais bin Abu Gharazah], ia berkata; dahulu kami di Madinah menjual beberapa wasaq makanan dan juga membelinya, kami kami serta orang-orang menamai diri kami para calo, kemudian Rasulullah shallallahu 'alaihi wasallam mendatangi kami dan menamai kami dengan nama yang lebih baik bagi kami daripada apa yang telah kami namai diri kami dengannya. Beliau bersabda: \"Wahai para pedagang, sesungguhnya jual beli kalian disaksikan oleh orang bersumpah dan sesuatu yang sia-sia, maka campurlah dengan sedekah.\""},"4172":{"ar":"أَخْبَرَنَا أَبُو الْأَشْعَثِ عَنْ خَالِدٍ قَالَ حَدَّثَنَا سَعِيدٌ وَهُوَ ابْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ صَالِحٍ أَبِي الْخَلِيلِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ حَكِيمِ بْنِ حِزَامٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْبَيِّعَانِ بِالْخِيَارِ مَا لَمْ يَفْتَرِقَا فَإِنْ بَيَّنَا وَصَدَقَا بُورِكَ لَهُمَا فِي بَيْعِهِمَا وَإِنْ كَذَبَا وَكَتَمَا مُحِقَ بَرَكَةُ بَيْعِهِمَا","id":"Telah mengabarkan kepada kami [Abu Al Asy'ats] dari [Khalid], ia berkata; telah menceritakan kepada kami [Sa'id yaitu Ibnu Abu 'Arubah] dari [Qatadah] dari [Shalih Abu Al Khalil] dari [Abdullah bin Al Harits] dari [Hakim bin Hizam] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua orang yang berjual beli memiliki hak memilih selama mereka belum berpisah, apabila keduanya berbuat jujur dan memberikan penjelasan maka jual beli mereka akan mendapatkan berkah, dan apabila mereka berdusta dan menyembunyikan aib maka akan dihapuskan berkah jual beli mereka.\""},"4173":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُتَبَايِعَانِ كُلُّ وَاحِدٍ مِنْهُمَا بِالْخِيَارِ عَلَى صَاحِبِهِ مَا لَمْ يَفْتَرِقَا إِلَّا بَيْعَ الْخِيَارِ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, lafazh hadits ini adalah lafazh Al Harits, dari [Al Qasim], ia berkata; telah menceritakan kepadaku [Malik] dari [Nafi'] dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua orang yang berjual beli setiap mereka memiliki hak memilih atas sahabatnya selama mereka belum berpisah, kecuali jual beli dengan syarat ada hak memilih.\""},"4174":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْبَيِّعَانِ بِالْخِيَارِ مَا لَمْ يَفْتَرِقَا أَوْ يَكُونَ خِيَارًا","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Yahya] dari ['Ubaidullah], ia berkata; telah menceritakan kepadaku [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua orang yang berjual beli memiliki hak memilih selama mereka belum berpisah, atau merupakan jual beli dengan syarat memiliki hak memilih.\""},"4175":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَلِيٍّ الْمَرْوَزِيُّ قَالَ حَدَّثَنَا مُحْرِزٌ بُنُ الْوَضَّاحُ عَنْ إِسْمَعِيلَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُتَبَايِعَانِ بِالْخِيَارِ مَا لَمْ يَفْتَرِقَا إِلَّا أَنْ يَكُونَ الْبَيْعُ كَانَ عَنْ خِيَارٍ فَإِنْ كَانَ الْبَيْعُ عَنْ خِيَارٍ فَقَدْ وَجَبَ الْبَيْعُ","id":"Telah mengabarkan kepada kami [Muhammad bin Ali Al Marwazi], ia berkata; telah menceritakan kepada kami [Muhriz bin Al Wadhdhah] dari [Isma'il] dari [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua orang yang berjual beli memiliki hak memilih selama mereka belum berpisah, kecuali jual beli tersebut dengan syarat adanya hak memilih, apabila jual beli tersebut dengan syarat adanya hak memilih maka jual beli tersebut telah tetap.\""},"4176":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ مَيْمُونٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ جُرَيْجٍ قَالَ أَمْلَى عَلَيَّ نَافِعٌ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَبَايَعَ الْبَيِّعَانِ فَكُلُّ وَاحِدٍ مِنْهُمَا بِالْخِيَارِ مِنْ بَيْعِهِ مَا لَمْ يَفْتَرِقَا أَوْ يَكُونَ بَيْعُهُمَا عَنْ خِيَارٍ فَإِنْ كَانَ عَنْ خِيَارٍ فَقَدْ وَجَبَ الْبَيْعُ","id":"Telah mengabarkan kepada kami [Ali bin Maimun], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Ibnu Juraij], ia berkata; Ali mendektekan kepada [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila dua orang yang berjual beli telah melakukan jual beli maka setiap mereka memiliki hak memilih dalam jual belinya selama mereka belum berpisah, atau jual beli mereka dengan syarat adanya hak memilih, apabila dengan syarat adanya hak memilih maka jual beli tersebut telah tetap.\""},"4177":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الْأَعْلَى قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْبَيِّعَانِ بِالْخِيَارِ مَا لَمْ يَفْتَرِقَا أَوْ يَقُولَ أَحَدُهُمَا لِلْآخَرِ اخْتَرْ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Abdul A'la], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Penjual dan pembali memiliki hak memilih selama mereka belum berpisah, atau salah seorang dari mereka mengatakan kepada yang lain; pilihlah.\""},"4178":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ قَالَ أَنْبَأَنَا أَيُّوبُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَيِّعَانِ بِالْخِيَارِ حَتَّى يَفْتَرِقَا أَوْ يَكُونَ بَيْعَ خِيَارٍ وَرُبَّمَا قَالَ نَافِعٌ أَوْ يَقُولَ أَحَدُهُمَا لِلْآخَرِ اخْتَرْ","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub], ia berkata; telah menceritakan kepada kami [Ibnu Ulayyah], ia berkata; telah memberitakan kepada kami [Ayyub] dari [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pedagang dan pembeli memiliki hak memilih hingga mereka memilih, atau jual beli tersebut adalah jual beli dengan syarat adanya hak memilih.\""},"4179":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَيِّعَانِ بِالْخِيَارِ حَتَّى يَفْتَرِقَا أَوْ يَكُونَ بَيْعَ خِيَارٍ وَرُبَّمَا قَالَ نَافِعٌ أَوْ يَقُولَ أَحَدُهُمَا لِلْآخَرِ اخْتَرْ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu Umar] dari Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pedagang dan pembeli memiliki hak memilih atau merupakan jual beli dengan syarat adanya hak memilih.\" Dan terkadang Nafi' mengatakan; atau salahj seorang dari mereka berkata kepada yang lain; pilihlah."},"4180":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا تَبَايَعَ الرَّجُلَانِ فَكُلُّ وَاحِدٍ مِنْهُمَا بِالْخِيَارِ حَتَّى يَفْتَرِقَا وَقَالَ مَرَّةً أُخْرَى مَا لَمْ يَتَفَرَّقَا وَكَانَا جَمِيعًا أَوْ يُخَيِّرَ أَحَدُهُمَا الْآخَرَ فَإِنْ خَيَّرَ أَحَدُهُمَا الْآخَرَ فَتَبَايَعَا عَلَى ذَلِكَ فَقَدْ وَجَبَ الْبَيْعُ فَإِنْ تَفَرَّقَا بَعْدَ أَنْ تَبَايَعَا وَلَمْ يَتْرُكْ وَاحِدٌ مِنْهُمَا الْبَيْعَ فَقَدْ وَجَبَ الْبَيْعُ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu Umar] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Apabila dua orang saling berjaul beli maka setiap mereka memiliki hak memilih hingga mereka berpisah\" dan berkata sekali lagi; selama mereka belum berpisah atau salah seorang diantara mereka memberikan hak memilih kepada yang lain, maka apabila salah seorang diantara mereka memberikan hak memilih kepada kepada yang lain kemudian mereka berjual beli atas dasar hal tersebut maka jual beli mereka telah tetap, kemudian apabila mereka berpisah setelah melakukan jual beli dan salah seorang diantara mereka tidak meninggalkan jual beli maka jual beli tersebut telah tetap\" "},"4181":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الْوَهَّابِ قَالَ سَمِعْتُ يَحْيَى بْنَ سَعِيدٍ يَقُولُ سَمِعْتُ نَافِعًا يُحَدِّثُ عَنْ ابْنِ عُمَرَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْمُتَبَايِعَيْنِ بِالْخِيَارِ فِي بَيْعِهِمَا مَا لَمْ يَفْتَرِقَا إِلَّا أَنْ يَكُونَ الْبَيْعُ خِيَارًاقَالَ نَافِعٌ فَكَانَ عَبْدُ اللَّهِ إِذَا اشْتَرَى شَيْئًا يُعْجِبُهُ فَارَقَ صَاحِبَهُ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Abdul Wahhab], ia berkata; saya mendengar [Yahya bin Sa'id] berkata; saya mendengar [Nafi'] menceritakan dari [Ibnu Umar] dari Rasulullah shallallahu 'alaihi wasallam; sesungguhnya dua orang yang berjual beli memiliki hak memilih dalam jual beli selama mereka belum berpisah kecuali jual beli tersebut berdasarkan atas hak memilih. Nafi' berkata; dan Abdullah apabila membeli sesuatu yang menarik baginya maka ia cepat meninggalkan pemiliknya."},"4182":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا هُشَيْمٌ عَنْ يَحْيَى بْنِ سَعِيدٍ قَالَ حَدَّثَنَا نَافِعٌ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُتَبَايِعَانِ لَا بَيْعَ بَيْنَهُمَا حَتَّى يَتَفَرَّقَا إِلَّا بَيْعَ الْخِيَارِ","id":"Telah mengabarkan kepada kami [Ali bin Hujr], ia berkata; telah menceritakan kepada kami [Husyaim] dari [Yahya bin Sa'id], ia berkata; telah menceritakan kepada kami [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua orang yang berjual beli tidak ada jual beli antara mereka berdua hingga mereka berpisah, kecuali jual beli dengah syarat adanya hak memilih.\""},"4183":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ عَنْ إِسْمَعِيلَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ بَيِّعَيْنِ لَا بَيْعَ بَيْنَهُمَا حَتَّى يَتَفَرَّقَا إِلَّا بَيْعَ الْخِيَارِ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] dari [Isma'il] dari [Abdullah bin Dinar] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap dua orang yang berjual beli tidak ada jual beli diantara mereka hingga mereka berpisah kecuali jual beli dengan syarat adanya hak memilih.\""},"4184":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ عَنْ شُعَيْبٍ عَنْ اللَّيْثِ عَنْ ابْنِ الْهَادِ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كُلُّ بَيِّعَيْنِ فَلَا بَيْعَ بَيْنَهُمَا حَتَّى يَتَفَرَّقَا إِلَّا بَيْعَ الْخِيَارِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Abdul Hakam] dari [Syu'aib] dari [Al Laits] dari [Ibnu Al Had] dari [Abdullah bin Dinar] dari [Abdullah bin Umar] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap dua orang yang berjual beli tidak ada jual beli diantara mereka hingga mereka berpisah kecuali jual beli dengan syarat adanya hak memilih.\""},"4185":{"ar":"أَخْبَرَنَا عَبْدُ الْحَمِيدِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا مَخْلَدٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ بَيِّعَيْنِ لَا بَيْعَ بَيْنَهُمَا حَتَّى يَتَفَرَّقَا إِلَّا بَيْعَ الْخِيَارِ","id":"Telah mengabarkan kepada kami [Abdul Hamid bin Muhammad], ia berkata; telah menceritakan kepada kami [Makhlad], ia berkata; telah menceritakan kepada kami [Sufyan] dari ['Amr bin Dinar] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap dua orang yang berjual beli tidak ada jual beli diantara mereka hingga mereka berpisah kecuali jual beli dengan syarat adanya hak memilih.\""},"4186":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ بْنِ دَاوُدَ قَالَ حَدَّثَنَا إِسْحَقُ بْنُ بَكْرٍ قَالَ حَدَّثَنَا أَبِي عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كُلُّ بَيِّعَيْنِ لَا بَيْعَ بَيْنَهُمَا حَتَّى يَتَفَرَّقَا إِلَّا بَيْعَ الْخِيَارِ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman bin Daud], ia berkata; telah menceritakan kepada kami [Ishaq bin Bakr], ia berkata; telah menceritakan kepada kami [ayahku] dari [Yazid] dari [Abdullah bin Dinar] dari [Ibnu Umar] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap dua orang yang berjual beli tidak ada jual beli diantara mereka hingga mereka berpisah kecuali jual beli dengan syarat adanya hak memilih.\""},"4187":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَزِيدَ عَنْ بَهْزِ بْنِ أَسَدٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ بَيِّعَيْنِ فَلَا بَيْعَ بَيْنَهُمَا حَتَّى يَتَفَرَّقَا إِلَّا بَيْعَ الْخِيَارِ","id":"Telah mengabarkan kepada kami ['Amr bin Yazid] dari [Bahz bin Asad], ia berkata; telah menceritakan kepada kami [Syu'bah], ia berkata; telah menceritakan kepada kami [Abdullah bin Dinar] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap dua orang yang berjual beli tidak ada jual beli diantara mereka hingga mereka berpisah kecuali jual beli dengan syarat adanya hak memilih.\""},"4188":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْبَيِّعَانِ بِالْخِيَارِ مَا لَمْ يَتَفَرَّقَا أَوْ يَكُونَ بَيْعُهُمَا عَنْ خِيَارٍ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Dinar] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Setiap dua orang yang berjual beli memiliki hak memilih selama mereka belum berpisah atau jual beli mereka dengan syarat adanya hak memilih.\""},"4189":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْبَيِّعَانِ بِالْخِيَارِ حَتَّى يَتَفَرَّقَا أَوْ يَأْخُذَ كُلُّ وَاحِدٍ مِنْهُمَا مِنْ الْبَيْعِ مَا هَوِيَ وَيَتَخَايَرَانِ ثَلَاثَ مَرَّاتٍ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Mu'adz bin Hisyam], ia berkata; telah menceritakan kepadaku [ayahku] dari [Qatadah] dari [Al Hasan] dari [Samrah] bahwasanya Nabi shallallahu 'alaihi wasallam bersabda: \"Penjual dan pembeli mempunyai hak memilih hingga mereka berpisah atau setiap mereka mengambil yang ia inginkan dari jual beli tersebut dan saling memilih sebanyak tiga kali.\""},"4190":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَزِيدُ قَالَ أَنْبَأَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَيِّعَانِ بِالْخِيَارِ مَا لَمْ يَتَفَرَّقَا وَيَأْخُذْ أَحَدُهُمَا مَا رَضِيَ مِنْ صَاحِبِهِ أَوْ هَوِيَ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim], ia berkata; telah menceritakan kepada kami [Yazid], ia berkata; telah memberitakan kepada kami [Hammam] dari [Qatadah] dari [Al Hasan] dari [Samurah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua orang yang berjual beli memiliki hak memilih selama mereka belum berpisah dan sebelum salah seorang dari mereka mengambil apa yang ia ridhai dari sahabatnya atau ia inginkan.\""},"4191":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ أَنْبَأَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُتَبَايِعَانِ بِالْخِيَارِ مَا لَمْ يَتَفَرَّقَا إِلَّا أَنْ يَكُونَ صَفْقَةَ خِيَارٍ وَلَا يَحِلُّ لَهُ أَنْ يُفَارِقَ صَاحِبَهُ خَشْيَةَ أَنْ يَسْتَقِيلَهُ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id], ia berkata; telah memberitakan kepada kami [Al Laits] dari [Ibnu 'Ajlan] dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \" Dua orang yang berjual beli memiliki hak memilih selama mereka belum berpisah kecuali jika ada kesepakatan hak memilih, dan tidak halal baginya untuk meninggalkan sahabatnya karena takut jika ia membatalkan jual beli tersebut.\""},"4192":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَأَنَّ رَجُلًا ذَكَرَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ يُخْدَعُ فِي الْبَيْعِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا بِعْتَ فَقُلْ لَا خِلَابَةَ فَكَانَ الرَّجُلُ إِذَا بَاعَ يَقُولُ لَا خِلَابَةَ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Abdullah bin Dinar] dari [Ibnu Umar] bahwa seorang laki-laki menyebutkan kepada Nabi shallallahu 'alaihi wasallam bahwa ia tertipu dalam berjual beli. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Apabila engkau menjual maka katakanlah; tidak boleh ada penipuan.\" Kemudian orang tersebut apabila hendak menjual maka ia mengatakan; tidak boleh ada penipuan. "},"4193":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ حَمَّادٍ قَالَ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ رَجُلًا كَانَ فِي عُقْدَتِهِ ضَعْفٌ كَانَ يُبَايِعُ وَأَنَّ أَهْلَهُ أَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا يَا نَبِيَّ اللَّهِ احْجُرْ عَلَيْهِ فَدَعَاهُ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَهَاهُ فَقَالَ يَا نَبِيَّ اللَّهِ إِنِّي لَا أَصْبِرُ عَنْ الْبَيْعِ قَالَ إِذَا بِعْتَ فَقُلْ لَا خِلَابَةَ","id":"Telah mengabarkan kepada kami [Yusuf bin Hammad], ia berkata; telah menceritakan kepada kami [Abdul A'la] dari [Sa'id] dari [Qatadah] dari [Anas] bahwa ada seseorang yang memiliki kelemahan pada lisannya, keluarganya mendatangi Nabi shallallahu 'alaihi wasallam dan berkata; wahai Nabi Allah, laranglah ia berjualan, lalu Nabi shallallahu 'alaihi wasallam memanggilnya dan melarangnya, ia berkata; wahai Rasulullah, sesungguhnya saya tidak sabar untuk berjual beli. Beliau bersabda: \"Jika engkau berjualan maka katakanlah tidak boleh ada tipuan.\""},"4194":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو كَثِيرٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا بَاعَ أَحَدُكُمْ الشَّاةَ أَوْ اللَّقْحَةَ فَلَا يُحَفِّلْهَا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Abdur Razzaq] telah menceritakan kepada kami [Ma'mar] dari [Yahya bin Abu Katsir], ia berkata; telah menceritakan kepadaku [Abu Katsir] bahwa ia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian menjual kambing atau unta perah maka janganlah engkau menahan air susunya.\""},"4195":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَلَقَّوْا الرُّكْبَانَ لِلْبَيْعِ وَلَا تُصَرُّوا الْإِبِلَ وَالْغَنَمَ مَنْ ابْتَاعَ مِنْ ذَلِكَ شَيْئًا فَهُوَ بِخَيْرِ النَّظَرَيْنِ فَإِنْ شَاءَ أَمْسَكَهَا وَإِنْ شَاءَ أَنْ يَرُدَّهَا رَدَّهَا وَمَعَهَا صَاعُ تَمْرٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Janganlah kalian menyambut orang-orang yang membawa barang dagangan ke kota untuk berjual beli, dan jangan kalian menahan air susu unta dan kambing dalam kantongnya. Barang siapa yang membeli sesuatu dari hal tersebut maka ia berhak memilih yang terbaik dari dua pendapatnya, apabila ia mau maka ia bisa menahannya dan apabila ia mau ingin mengembalikannya maka ia mengembalikannya disertai dengan satu sha' kurma.\" "},"4196":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْحَارِثِ قَالَ حَدَّثَنِي دَاوُدُ بْنُ قَيْسٍ عَنْ ابْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اشْتَرَى مُصَرَّاةً فَإِنْ رَضِيَهَا إِذَا حَلَبَهَا فَلْيُمْسِكْهَا وَإِنْ كَرِهَهَا فَلْيَرُدَّهَا وَمَعَهَا صَاعٌ مِنْ تَمْرٍ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah menceritakan kepada kami [Abdullah bin Al Harits], ia berkata; telah menceritakan kepada kami [Daud bin Qais], dari [Ibnu Yasar] dari [Abu Hurairah] dari Rasulullah beliau bersabda: \"Barang siapa yang membeli hewan yang ditahan ais susu yang ada dalam kantongnya kemudian apabila ia ridha terhadapnya ketika memerahnya maka hendaknya ia menahannya dan apabila ia tidak menyukainya maka hendaknya ia mengembalikannya di sertai satu sha' kurma.\" "},"4197":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ أَبُو الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ ابْتَاعَ مُحَفَّلَةً أَوْ مُصَرَّاةً فَهُوَ بِالْخِيَارِ ثَلَاثَةَ أَيَّامٍ إِنْ شَاءَ أَنْ يُمْسِكَهَا أَمْسَكَهَا وَإِنْ شَاءَ أَنْ يَرُدَّهَا رَدَّهَا وَصَاعًا مِنْ تَمْرٍ لَا سَمْرَاءَ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Ayyub] dari [Muhammad], ia berkata; saya mendengar [Abu Hurairah] berkata; Abu Al Qasim shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang membeli hewan yang ditahan air susu yang ada dalam kantongnya maka ia memiliki hak memilih selama tiga hari, apabila ia ingin menahannya maka ia menahannya dan apabila ia ingin mengembalikannya maka ia mengembalikannya disertai satu sha' kurma tidak harus yang berwarna sawo matang.\" "},"4198":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عِيسَى بْنُ يُونُسَ وَوَكِيعٌ قَالَا حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ مَخْلَدِ بْنِ خُفَافٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ الْخَرَاجَ بِالضَّمَانِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah menceritakan kepada kami [Isa bin Yunus] dan [Waki'] mereka berkata; telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Makhlad bin Khufaf] dari ['Urwah] dari ['Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam menetapkan bahwa manfaat yang di dapat disertai dengan tanggungan."},"4199":{"ar":"أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ تَمِيمٍ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنِي شُعْبَةُ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ التَّلَقِّي وَأَنْ يَبِيعَ مُهَاجِرٌ لِلْأَعْرَابِيِّ وَعَنْ التَّصْرِيَةِ وَالنَّجْشِ وَأَنْ يَسْتَامَ الرَّجُلُ عَلَى سَوْمِ أَخِيهِ وَأَنْ تَسْأَلَ الْمَرْأَةُ طَلَاقَ أُخْتِهَا","id":"Telah mengabarkan kepadaku [Abdullah bin Muhammad bin Tamim], ia berkata; telah menceritakan kepada kami [Hajjaj], ia berkata; telah menceritakan kepadaku [Syu'bah] dari ['Adi bin Tsabit] dari [Abu Hazim] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari menyambut orang-orang yang membawa dagangan sebelum sampai pasar, dan seorang muhajir menjualkan barang untuk orang badui, dan dari menahan air susu hewan dalam kantongnya, serta seseorang menawar atas penawaran saudaranya dan seorang wanita meminta agar saudaranya dicerai."},"4200":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ الزِّبْرِقَانِ قَالَ حَدَّثَنَا يُونُسُ بْنُ عُبَيْدٍ عَنْ الْحَسَنِ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يَبِيعَ حَاضِرٌ لِبَادٍ وَإِنْ كَانَ أَبَاهُ أَوْ أَخَاهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar], ia berkata; telah menceritakan kepadaku [Muhammad bin Az Zibriqan], ia berkata; telah menceritakan kepada kami [Yunus bin 'Ubaid] dari [Al Hasan] dari [Anas] bahwasanya Nabi shallallahu 'alaihi wasallam melarang orang yang tinggal di kota menjualkan untuk orang yang di pelosok walaupun ia adalah bapak atau saudaranya."},"4201":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنِي سَالِمُ بْنُ نُوحٍ قَالَ أَنْبَأَنَا يُونُسُ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَنُهِينَا أَنْ يَبِيعَ حَاضِرٌ لِبَادٍ وَإِنْ كَانَ أَخَاهُ أَوْ أَبَاهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna], ia berkata; telah menceritakan kepadaku [Salim bin Nuh], ia berkata; telah memberitakan kepada kami [Yunus] dari [Muhammad bin Sirin] dari [Anas bin Malik], ia berkata; kita dilarang orang yang tinggal di kota menjualkan untuk orang yang tinggal di pelosok walaupun ia adalah saudara atau bapaknya."},"4202":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ مُحَمَّدٍ عَنْ أَنَسٍ قَالَنُهِينَا أَنْ يَبِيعَ حَاضِرٌ لِبَادٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Khalid], ia berkata; telah menceritakan kepada kami [Ibnu 'Aun] dari [Muhammad] dari [Anas], ia berkata; kita dilarang orang yang tinggal di kota menjualkan untuk orang yang tinggal di pelosok."},"4203":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْحَسَنِ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرًا يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَبِيعُ حَاضِرٌ لِبَادٍ دَعُوا النَّاسَ يَرْزُقُ اللَّهُ بَعْضَهُمْ مِنْ بَعْضٍ","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Hasan], ia berkata; telah menceritakan kepada kami [Hajjaj], ia berkata; [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Abu Az Zubair] bahwa ia telah mendengar [Jabir] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh orang yang tinggal di kota menjualkan untuk orang yang tinggal di desa, biarkan manusia Allah memberi rizki sebagian mereka dengan sebagian yang lain.\""},"4204":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَلَقَّوْا الرُّكْبَانَ لِلْبَيْعِ وَلَا يَبِعْ بَعْضُكُمْ عَلَى بَيْعِ بَعْضٍ وَلَا تَنَاجَشُوا وَلَا يَبِيعُ حَاضِرٌ لِبَادٍ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah menyambut orang yang membawa barang dagangan sebelum sampai pasar dan janganlah sebagian kalian menjual di atas jual beli sebagian yang lainnya dan janganlah berpura-pura menawar agar mengecoh pembeli yang lain, dan janganlah orang yang tinggal di kota menjualkan untuk orang yang tinggal di pelosok.\""},"4205":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ بْنِ أَعْيَنَ قَالَ حَدَّثَنَا شُعَيْبُ بْنُ اللَّيْثِ عَنْ أَبِيهِ عَنْ كَثِيرِ بْنِ فَرْقَدٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ النَّجْشِ وَالتَّلَقِّي وَأَنْ يَبِيعَ حَاضِرٌ لِبَادٍ","id":"Telah mengabarkan kepada kami [Abdurrahman bin Abdullah bin Abdul Hakam bin A'yan], ia berkata; telah menceritakan kepada kami [Syu'aib bin Al Laits] dari [ayahnya] dari [Katsir bin Farqad] dari [Nafi'] dari [Abdullah] dari Rasulullah shallallahu 'alaihi wasallam bahwa beliau melarang dari menawar barang tidak untuk membelinya tapi agar harganya naik, menyambut orang yang membawa barang dagangan sebelum sampai ke pasar, serta orang yang tinggal di kota menjualkan untuk orang yang tinggal di pelosok."},"4206":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ التَّلَقِّي","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id], ia berkata; telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari menyambut orang yang membawa barang dagang sebelum sampai pasar."},"4207":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ قُلْتُ لِأَبِي أُسَامَةَ أَحَدَّثَكُمْ عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ تَلَقِّي الْجَلْبِ حَتَّى يَدْخُلَ بِهَا السُّوقَ فَأَقَرَّ بِهِ أَبُو أُسَامَةَ وَقَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; saya berkata kepada [Abu Usamah]; apakah ['Ubaidullah] menceritakan kepadamu dari [Nafi'] dari [Ibnu Umar], Ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari menyambut orang yang membawa dagangan sebelum masuk pasar hingga ia masuk pasar. Kemudian Abu Usamah mengakui dan mengatakan; ya. "},"4208":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُتَلَقَّى الرُّكْبَانُ وَأَنْ يَبِيعَ حَاضِرٌ لِبَادٍقُلْتُ لِابْنِ عَبَّاسٍ مَا قَوْلُهُ حَاضِرٌ لِبَادٍ قَالَ لَا يَكُونُ لَهُ سِمْسَارٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'], ia berkata; telah memberitakan kepada kami [Abdur Razzaq], ia berkata; telah memberitakan kepada kami [Ma'mar] dari [Ibnu Thawus] dari [ayahnya] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang menyambut orang yang membawa dagangan sebelum masuk pasar dan orang yang tinggal di kota menjualkan barang untuk orang yang tinggal di pelosok. Saya berkata kepada Ibnu Abbas; apa maksud perkataan orang yang tinggal di kota untuk orang yang tinggal di pelosok? Ia berkata; tidak boleh menjadi calo untuknya. "},"4209":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْحَسَنِ قَالَ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ قَالَ أَنْبَأَنَا ابْنُ جُرَيْجٍ قَالَ أَنْبَأَنَا هِشَامُ بْنُ حَسَّانَ الْقُرْدُوسِيُّ أَنَّهُ سَمِعَ ابْنَ سِيرِينَ يَقُولُ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَلَقَّوْا الْجَلْبَ فَمَنْ تَلَقَّاهُ فَاشْتَرَى مِنْهُ فَإِذَا أَتَى سَيِّدُهُ السُّوقَ فَهُوَ بِالْخِيَارِ","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Hasan], ia berkata; telah menceritakan kepada kami [Hajjaj bin Muhammad], ia berkata; telah memberitakan kepada kami [Ibnu Juraij], ia berkata; telah memberitakan kepada kami [Hisyam bin Hassan Al Qurdusi] bahwa ia mendengar [Ibnu Sirin] berkata; saya mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menyambut orang yang membawa barang dagangan sebelum sampai pasar, barang siapa yang menyambutnya kemudian membeli darinya kemudian apabila pemiliknya datang ke pasar maka ia memiliki hak untuk memilih. "},"4210":{"ar":"حَدَّثَنَا مُجَاهِدُ بْنُ مُوسَى قَالَ حَدَّثَنَا إِسْمَعِيلُ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَبِيعَنَّ حَاضِرٌ لِبَادٍ وَلَا تَنَاجَشُوا وَلَا يُسَاوِمْ الرَّجُلُ عَلَى سَوْمِ أَخِيهِ وَلَا يَخْطُبْ عَلَى خِطْبَةِ أَخِيهِ وَلَا تَسْأَلْ الْمَرْأَةُ طَلَاقَ أُخْتِهَا لِتَكْتَفِئَ مَا فِي إِنَائِهَا وَلِتُنْكَحَ فَإِنَّمَا لَهَا مَا كَتَبَ اللَّهُ لَهَا","id":"Telah mengabarkan kepada kami [Mujahid bin Musa], ia berkata; telah menceritakan kepada kami [Isma'il] dari [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah orang yang tinggal di kota menjualkan barang untuk orang yang tinggal di pelosok, dan janganlah menawar untuk mengecohkan pembeli yang lain, janganlah seseorang menawar penawaran saudaranya dan janganlah ia meminang atas pinangan saudaranya dan janganlah seorang wanita meminta agar saudaranya dicerai agar ia mendapatkan apa yang ada dalam periuknya dan agar ia dinikahi, karena sesungguhnya ia mendapatkan apa yang telah Allah tetapkan baginya.\" "},"4211":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ وَاللَّيْثُ وَاللَّفْظُ لَهُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَا يَبِيعُ أَحَدُكُمْ عَلَى بَيْعِ أَخِيهِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dan [Al Laits], lafazhnya adalah lafazh Al Laits, dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Janganlah salah seorang diantara kalian menjual atas penjualan saudaranya.\""},"4212":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَبِيعُ الرَّجُلُ عَلَى بَيْعِ أَخِيهِ حَتَّى يَبْتَاعَ أَوْ يَذَرَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah menceritakan kepada kami [Abu Mu'awiyah], ia berkata; telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Janganlah seseorang menjual atas penjualan saudaranya hingga ia membeli atau meninggalkan.\""},"4213":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ النَّجْشِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam melarang dari menawar barang untuk mengecoh pembeli yang lain."},"4214":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى قَالَ حَدَّثَنَا بِشْرُ بْنُ شُعَيْبٍ قَالَ حَدَّثَنَا أَبِي عَنْ الزُّهْرِيِّ أَخْبَرَنِي أَبُو سَلَمَةَ وَسَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَبِيعُ الرَّجُلُ عَلَى بَيْعِ أَخِيهِ وَلَا يَبِيعُ حَاضِرٌ لِبَادٍ وَلَا تَنَاجَشُوا وَلَا يَزِيدُ الرَّجُلُ عَلَى بَيْعِ أَخِيهِ وَلَا تَسْأَلْ الْمَرْأَةُ طَلَاقَ الْأُخْرَى لِتَكْتَفِئَ مَا فِي إِنَائِهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya], ia berkata; telah menceritakan kepada kami [Bisyr bin Syu'aib], ia berkata; telah menceritakan kepada kami [ayahku] dari [Az Zuhri] telah mengabarkan kepadaku [Abu Salamah] dan [Sa'id bin Al Musayyab] bahwa [Abu Hurairah] berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seseorang menjual di atas jualan saudaranya dan janganlah orang yang tinggal di kota menjual barang untuk orang yang tinggal di pelosok, dan janganlah menawar barang untuk mengecoh pembeli, janganlah seseorang menambah atas penjualan saudaranya, dan janganlah seorang wanita meminta wanita yang lain dicerai agar ia mendapatkan apa yang ada dalam periuknya. "},"4215":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا يَزِيدُ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَبِيعُ حَاضِرٌ لِبَادٍ وَلَا تَنَاجَشُوا وَلَا يَزِيدُ الرَّجُلُ عَلَى بَيْعِ أَخِيهِ وَلَا تَسْأَلْ الْمَرْأَةُ طَلَاقَ أُخْتِهَا لِتَسْتَكْفِئَ بِهِ مَا فِي صَحْفَتِهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Yazid], ia berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tidak boleh orang yang tinggal di kota menjualkan barang untuk orang yang tinggal di pelosok, dan janganlah menawar barang untuk mengecoh pembeli, janganlah seseorang menambah atas penjualan saudaranya, dan janganlah seorang wanita meminta saudarinya dicerai agar ia mendapatkan apa yang ada dalam periuknya. "},"4216":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا الْمُعْتَمِرُ وَعِيسَى بْنُ يُونُسَ قَالَا حَدَّثَنَا الْأَخْضَرُ بْنُ عَجْلَانَ عَنْ أَبِي بَكْرٍ الْحَنَفِيِّ عَنْ أَنَسِ ��ْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَاعَ قَدَحًا وَحِلْسًا فِيمَنْ يَزِيدُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah menceritakan kepada kami [Al Mu'tamir] dan [Isa bin Yunus] mereka berkata; telah menceritakan kepada kami [Al Akhdhar bin 'Ajlan] dari [Abu Bakar Al Hanafi] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam menjual gelas dan alas pelana kepada orang yang menambahkan harga. "},"4217":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ وَأَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْمُلَامَسَةِ وَالْمُنَابَذَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, lafazhnya adalah lafazh Al Harits, dari [Ibnu Al Qasim], ia berkata; telah menceritakan kepadaku [Malik] dari [Muhammad bin Yahya bin Habban] serta [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari mulamasah (yaitu barang dagangan apapun yang disentuh wajib untuk dibayar tanpa mengetahui kondisi barang tersebut), serta munabadzah (yaitu jual beli dengan saling melemparkan barang yang akan dijual tanpa diketahui barangnya)."},"4218":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ يَعْقُوبَ بْنِ إِسْحَقَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عَامِرُ بْنُ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْمُلَامَسَةِ لَمْسِ الثَّوْبِ لَا يَنْظُرُ إِلَيْهِ وَعَنْ الْمُنَابَذَةِ وَهِيَ طَرْحُ الرَّجُلِ ثَوْبَهُ إِلَى الرَّجُلِ بِالْبَيْعِ قَبْلَ أَنْ يُقَلِّبَهُ أَوْ يَنْظُرَ إِلَيْهِ","id":"Telah mengabarkan kepada kami [Ibrahim bin Ya'qub bin Ishaq], ia berkata; telah menceritakan kepada kami [Abdullah bin Yusuf], ia berkata; telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab], ia berkata; telah memberitakan kepadaku ['Amir bin Sa'd bin Abu Waqqash] dari [Abu Sa'id Al Khudri] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari mulamasah yaitu menyentuh pakaian dan tidak melihatnya. Dan beliau melarang dari munabadzah yaitu seseorang melempar pakaiannya kepada seseorang untuk dijual kepadanya sebelum ia membalik baju tersebut atau melihat kepadanya."},"4219":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُلَامَسَةِ وَالْمُنَابَذَةِ فِي الْبَيْعِ","id":"Telah mengabarkan kepada kami [Yunus bin Abdul A'la] serta [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, dari [Ibnu Wahb], ia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari ['Amir bin Sa'd] dari [Abu Sa'id Al Khudri], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari mulamasah, dan munabadzah dalam berjual beli. "},"4220":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ الْمَرْوَزِيُّ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعَتَيْنِ عَنْ الْمُلَامَسَةِ وَالْمُنَابَذَةِ","id":"Telah mengabarkan kepada kami [Al Husain bin Huraits Al Marwazi], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Atho` bin Yazid] dari [Abu Sa'id Al Kudri], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari dua macam jual beli yaitu mulamasah dan munbadzah."},"4221":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُصَفَّى بْنِ بَهْلُولٍ عَنْ مُحَمَّدِ بْنِ حَرْبٍ عَنْ الزُّبَيْدِيِّ عَنْ الزُّهْرِيِّ قَالَ سَمِعْتُ سَعِيدًا يَقُولُ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُلَامَسَةِ وَالْمُنَابَذَةِ وَالْمُلَامَسَةُ أَنْ يَتَبَايَعَ الرَّجُلَانِ بِالثَّوْبَيْنِ تَحْتَ اللَّيْلِ يَلْمِسُ كُلُّ رَجُلٍ مِنْهُمَا ثَوْبَ صَاحِبِهِ بِيَدِهِ وَالْمُنَابَذَةُ أَنْ يَنْبِذَ الرَّجُلُ إِلَى الرَّجُلِ الثَّوْبَ وَيَنْبِذَ الْآخَرُ إِلَيْهِ الثَّوْبَ فَيَتَبَايَعَا عَلَى ذَلِكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mushaffa bin Bahlul] dari [Muhammad bin Harb] dari [Az Zubaidi] dari [Az Zuhri], ia berkata; saya mendengar [Sa'id] berkata; saya mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari mulamasah dan menabadzah. Dan mulamasah adalah dua orang melakukan jual beli dengan dua pakaian dimalam hari setiap orang dari mereka menyentuh pakaian temannya dengan tangannya, sedangkan munabadzah adalah seseorang melemparkan pakaian kepada orang lain dan orang yang lain melemparkan baju kepadanya dan mereka berjual beli atas dasar seperti itu. "},"4222":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَنَّ عَامِرَ بْنَ سَعْدٍ أَخْبَرَهُ أَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّ رَضِيَ اللَّهُ عَنْهُ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُلَامَسَةِ وَالْمُلَامَسَةُ لَمْسُ الثَّوْبِ لَا يَنْظُرُ إِلَيْهِ وَعَنْ الْمُنَابَذَةِ وَالْمُنَابَذَةُ طَرْحُ الرَّجُلِ ثَوْبَهُ إِلَى الرَّجُلِ قَبْلَ أَنْ يُقَلِّبَهُ","id":"Telah mengabarkan kepada kami [Abu Daud], ia berkata; telah menceritakan kepada kami [Ya'qub bin Ibrahim], ia berkata; telah menceritakan kepada kami [ayahku] dari [Shalih] dari [Ibnu Syihab] bahwa ['Amir bin Sa'd] telah mengabarkan kepadanya bahwa [Abu Sa'id Al Khudri] radliallahu 'anhu berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari mulamasah, dan mulamasah adalah menyentuh baju dan tidak melihat kepadanya, dan dari munabadzah. Munabadzah adalah seseorang melemparkan baju kepada orang lain sebelum ia membaliknya. "},"4223":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لُبْسَتَيْنِ وَعَنْ بَيْعَتَيْنِ أَمَّا الْبَيْعَتَانِ فَالْمُلَامَسَةُ وَالْمُنَابَذَةُ وَالْمُنَابَذَةُ أَنْ يَقُولَ إِذَا نَبَذْتُ هَذَا الثَّوْبَ فَقَدْ وَجَبَ يَعْنِي الْبَيْعَ وَالْمُلَامَسَةُ أَنْ يَمَسَّهُ بِيَدِهِ وَلَا يَنْشُرَهُ وَلَا يُقَلِّبَهُ إِذَا مَسَّهُ فَقَدْ وَجَبَ الْبَيْعُ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'], ia berkata; telah menceritakan kepada kami [Abdur Razzaq], ia berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Atho` bin Yazid] dari [Abu Sa'id Al Khudri], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari dua pakaian dan dari dua macam jual beli. Adapun dua macam jual beli yaitu mulamasah dan munabadzah, yaitu berkata; apabila saya melempar baju ini maka telah terjadi jual beli. Sedangkan mulamasah yaitu memegang dengan tangannya dan tidak membukanya serta membalikkannya, apabila ia memegangnya maka telah terjadi jual beli. "},"4224":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ زَيْدِ بْنِ أَبِي الزَّرْقَاءِ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا جَعْفَرُ بْنُ بُرْقَانَ قَالَ بَلَغَنِي عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لُبْسَتَيْنِ وَنَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعَتَيْنِ عَنْ الْمُنَابَذَةِ وَالْمُلَامَسَةِ وَهِيَ بُيُوعٌ كَانُوا يَتَبَايَعُونَ بِهَا فِي الْجَاهِلِيَّةِ","id":"Telah mengabarkan kepada kami [Harun bin Zaid bin Abu Az Zarqa`], ia berkata; telah menceritakan kepada kami [ayahku], ia berkata; telah menceritakan kepada kami [Ja'far bin Burqan], ia berkata; telah sampai kepadaku dari [Az Zuhri] dari [Salim] dari [ayahnya] ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari dua pakaian dan Rasulullah shallallahu 'alaihi wasallam melarang kita dari dua jual beli yaitu munabadzah dan mulamasah itu adalah jual beli yang mereka lakukan pada masa Jahiliyah."},"4225":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ عُبَيْدَ اللَّهِ عَنْ خُبَيْبٍ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ بَيْعَتَيْنِ أَمَّا الْبَيْعَتَانِ فَالْمُنَابَذَةُ وَالْمُلَامَسَةُوَزَعَمَ أَنَّ الْمُلَامَسَةَ أَنْ يَقُولَ الرَّجُلُ لِلرَّجُلِ أَبِيعُكَ ثَوْبِي بِثَوْبِكَ وَلَا يَنْظُرُ وَاحِدٌ مِنْهُمَا إِلَى ثَوْبِ الْآخَرِ وَلَكِنْ يَلْمِسُهُ لَمْسًا وَأَمَّا الْمُنَابَذَةُ أَنْ يَقُولُ أَنْبِذُ مَا مَعِي وَتَنْبِذُ مَا مَعَكَ لِيَشْتَرِيَ أَحَدُهُمَا مِنْ الْآخَرِ وَلَا يَدْرِي كُلُّ وَاحِدٍ مِنْهُمَا كَمْ مَعَ الْآخَرِ وَنَحْوًا مِنْ هَذَا الْوَصْفِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Al Mu'tamir], ia berkata; saya mendengar ['Ubaidullah] dari [Khubaib] dari [Hafsh bin 'Ashim] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bahwa beliau melarang dari dua macam jual beli, yaitu munabadzah dan mulamasah. Dan ia mengatakan bahwa mulamasah adalah seseorang berkata kepada orang lain; saya jual kepadamu bajuku dengan bajumu dan setiap mereka tidak melihat kepada baju orang lain akan tetapi ia menyentuhnya sekali. Adapun munabadzah adalah mengatakan saya lemparkan apa yang ada padaku dan engkau melemparkan apa yang ada padamu, agar keduanya saling membeli dari yang lainnya, dan setiap mereka tidak mengetahui berapa yang ada pada orang lain. Dan yang serupa dengan sifat ini."},"4226":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ أَخْبَرَنِي أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الْحَصَاةِ وَعَنْ بَيْعِ الْغَرَرِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id], ia berkata; telah menceritakan kepada kami [Yahya] dari ['Ubaidullah], ia berkata; telah mengabarkan kepadaku [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari menjual dengan cara hashah (jual beli, dan jual beli gharar (tidak jelas)."},"4227":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَبِيعُوا الثَّمَرَ حَتَّى يَبْدُوَ صَلَاحُهُ نَهَى الْبَائِعَ وَالْمُشْتَرِيَ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu Umar] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Janganlah menjual buah hingga kelihatan layaknya\", beliau melarang penjual dan pembeli. "},"4228":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الثَّمَرِ حَتَّى يَبْدُوَ صَلَاحُهُ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Salim] dari [ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari menjual buah hingga kelihatan kelayakannya. "},"4229":{"ar":"أَخْبَرَنِي يُونُسُ بْنُ عَبْدِ الْأَعْلَى وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي سَعِيدٌ وَأَبُو سَلَمَةَ أَنَّ أَبَا هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَبِيعُوا الثَّمَرَ حَتَّى يَبْدُوَ صَلَاحُهُ وَلَا تَبْتَاعُوا الثَّمَرَ بِالتَّمْرِقَالَ ابْنُ شِهَابٍ حَدَّثَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ عَنْ أَبِيهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ مِثْلِهِ سَوَاءً","id":"Telah mengabarkan kepadaku [Yunus bin Abdul A'la] serta [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, dari [Ibnu Wahb], telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab], ia berkata; telah menceritakan kepadaku [Sa'id] dan [Abu Salamah] bahwa [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian jual buah hingga terlihat kelayakannya, dan janganlah kalian beli buah dengan buah.\" [Ibnu Syihab] berkata; telah menceritakan kepadaku [Salim bin Abdullah] dari [ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari hal seperti itu. "},"4230":{"ar":"أَخْبَرَنَا عَبْدُ الْحَمِيدِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا مَخْلَدُ بْنُ يَزِيدَ قَالَ حَدَّثَنَا حَنْظَلَةُ قَالَ سَمِعْتُ طَاوُسًا يَقُولُ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عُمَرَ يَقُولُقَامَ فِينَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا تَبِيعُوا الثَّمَرَ حَتَّى يَبْدُوَ صَلَاحُهُ","id":"Telah mengabarkan kepada kami [Abdul Hamid bin Muhammad], ia berkata; telah menceritakan kepada kami [Makhlad bin Yazid], ia berkata; telah menceritakan kepada kami [Hanzhalah], ia berkata; saya mendengar [Thawus] berkata; saya mendengar [Ibnu Umar] berkata; Rasulullah shallallahu 'alaihi wasallam berdiri diantara kami dan bersabda: \"Janganlah kalian jual buah hingga nampak kelayakannya.\""},"4231":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ الْمُخَابَرَةِ وَالْمُزَابَنَةِ وَالْمُحَاقَلَةِ وَأَنْ يُبَاعَ الثَّمَرُ حَتَّى يَبْدُوَ صَلَاحُهُ وَأَنْ لَا يُبَاعَ إِلَّا بِالدَّنَانِيرِ وَالدَّرَاهِمِ وَرَخَّصَ فِي الْعَرَايَا","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Ibnu Juraij] dari ['Atho`] saya mendengar [Jabir bin Abdullah] dari Nabi shallallahu 'alaihi wasallam bahwa beliau melarang dari mukhabarah, muzabanah dan muhaqalah serta menjual buah hingga nampak kelayakannya, dan agar tidak dijual kecuali dengan dinar dan dirham. dan beliau memberikan keringanan dalam hal 'araya (membeli pohon kurma dengan kurma). "},"4232":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا الْمُفَضَّلُ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ وَأَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْمُخَابَرَةِ وَالْمُزَابَنَةِ وَالْمُحَاقَلَةِ وَبَيْعِ الثَّمَرِ حَتَّى يُطْعَمَ إِلَّا الْعَرَايَا","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Mufadhdhal] dari [Ibnu Juraij] dari ['Atho`] dan [Abu Az Zubair] dari [Jabir] bahwa Nabi shallallahu 'alaihi wasallam melarang dari mukhabarah, muzabanah dan muhaqalah, serta menjual buah hingga dapat dimakan kecuali 'araya. "},"4233":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا هِشَامٌ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ النَّخْلِ حَتَّى يُطْعَمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Khalid], ia berkata; telah menceritakan kepada kami [Hisyam] dari [Abu Zubair] dari [Jabir], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari menjual kurma hingga dapat dimakan."},"4234":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الثِّمَارِ حَتَّى تُزْهِيَ قِيلَ يَا رَسُولَ اللَّهِ وَمَا تُزْهِيَ قَالَ حَتَّى تَحْمَرَّ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَأَيْتَ إِنْ مَنَعَ اللَّهُ الثَّمَرَةَ فَبِمَ يَأْخُذُ أَحَدُكُمْ مَالَ أَخِيهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, lafazhnya adalah lafazh Al Harits, dari [Ibnu Al Qasim], ia berkata; telah menceritakan kepadaku [Malik] dari [Humaid Atha Thawil] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari menjual buah hingga layak, Rasulullah ditanya; wahai Rasulullah, apakah yang dimaksud dengan layak itu? Beliau bersabda: \"Hingga memerah.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bagaimana pendapatmu apabila Allah menolak tumbuhnya buah maka dengan apakah salah seorang dari kalian mengambil harta saudaranya?\""},"4235":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْحَسَنِ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرًا يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ بِعْتَ مِنْ أَخِيكَ ثَمَرًا فَأَصَابَتْهُ جَائِحَةٌ فَلَا يَحِلُّ لَكَ أَنْ تَأْخُذَ مِنْهُ شَيْئًا بِمَ تَأْخُذُ مَالَ أَخِيكَ بِغَيْرِ حَقٍّ","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Hasan], ia berkata; telah menceritakan kepada kami [Hajjaj], ia berkata; telah berkata; [Ibnu Juraij]; telah mengabarkan kepadaku [Abu Az Zubair] bahwa ia mendengar [Jabir] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila engkau menjual buah kepada saudaramu kemudian buah tersebut tertimpa bencana maka tidak halal bagimu untuk mengambil sebagian darinya, dengan apakah engkau mengambil harta saudaramu dengan tanpa hak?\""},"4236":{"ar":"أَخْبَرَنَا هِشَامُ بْنُ عَمَّارٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ قَالَ حَدَّثَنَا ثَوْرُ بْنُ يَزِيدَ أَنَّهُ سَمِعَ ابْنَ جُرَيْجٍ يُحَدِّثُ عَنْ أَبِي الزُّبَيْرِ الْمَكِّيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ بَاعَ ثَمَرًا فَأَصَابَتْهُ جَائِحَةٌ فَلَا يَأْخُذْ مِنْ أَخِيهِ وَذَكَرَ شَيْئًا عَلَى مَا يَأْكُلُ أَحَدُكُمْ مَالَ أَخِيهِ الْمُسْلِمِ","id":"Telah mengabarkan kepada kami [Hisyam bin 'Ammar], ia berkata; telah menceritakan kepada kami [Yahya bin Hamzah], ia berkata; telah menceritakan kepada kami [Tsaur bin Yazid] bahwa ia mendengar [Ibnu Juraij] bercerita dari [Abu Az Zubair Al Makki] dari [Jabir bin Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: barang siapa yang menjual buah kemudian terkena bencana maka janganlah ia mengambil dari saudaranya sesuatupun, atas dasar apakah salah seorang dari kalian memakan harta saudaranya?\""},"4237":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ حُمَيْدٍ وَهُوَ الْأَعْرَجُ عَنْ سُلَيْمَانَ بْنِ عَتِيقٍ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَضَعَ الْجَوَائِحَ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Yazid], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Humaid yaitu Al A'raj] dari [Sulaiman bin 'Atiq] dari [Jabir] bahwa Nabi shallallahu 'alaihi wasallam meletakkan sebagian tanggungan karena adanya musibah yang menimpa."},"4238":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ بُكَيْرٍ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَأُصِيبَ رَجُلٌ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ثِمَارٍ ابْتَاعَهَا فَكَثُرَ دَيْنُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَصَدَّقُوا عَلَيْهِ فَتَصَدَّقَ النَّاسُ عَلَيْهِ فَلَمْ يَبْلُغْ ذَلِكَ وَفَاءَ دَيْنِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُذُوا مَا وَجَدْتُمْ وَلَيْسَ لَكُمْ إِلَّا ذَلِكَ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Bukair] dari ['Iyadh bin Abdullah] dari [Abu Sa'id Al Khudri], ia berkata; seorang laki-laki tertimpa musibah pada zaman Nabi shallallahu 'alaihi wasallam pada buah-buahan yang ia beli, sehingga hutangnya menjadi banyak. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bersedekahlah kepadanya.\" Maka orang-orang bersedekah kepadanya namun belum bisa melunasi hutang. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ambillah apa yang kalian dapatkan dan kalian tidak memiliki selain itu.\" "},"4239":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ حُمَيْدٍ الْأَعْرَجِ عَنْ سُلَيْمَانَ بْنِ عَتِيكٍ قَالَ قُتَيْبَةُ عَتِيكٌ بِالْكَافِ وَالصَّوَابُ عَتِيقٌ عَنْ جَابِرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الثَّمَرِ سِنِينَ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Humaid Al A'raj] dari [Sulaiman bin 'Atik], ia mengatakan; Qutaibah bin 'Atik dengan huruf kaf, yang benar adalah 'Atiq. Dari [Jabir] dari Nabi shallallahu 'alaihi wasallam, beliau melarang dari menjual buah beberapa tahun yang akan datang. "},"4240":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الثَّمَرِ بِالتَّمْرِو قَالَ ابْنُ عُمَرَ حَدَّثَنِي زَيْدُ بْنُ ثَابِتٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ فِي الْعَرَايَا","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Salim] dari [ayahnya] bahwa Nabi shallallahu 'alaihi wasallam melarang dari menjual buah dengan kurma. [Ibnu Umar] berkata; telah menceritakan kepadaku [Zaid bin Tsabit] bahwa Rasulullah shallallahu 'alaihi wasallam memberikan keringanan dalam hal 'araya."},"4241":{"ar":"أَخْبَرَنِي زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْمُزَابَنَةِ وَالْمُزَابَنَةُ أَنْ يُبَاعَ مَا فِي رُءُوسِ النَّخْلِ بِتَمْرٍ بِكَيْلٍ مُسَمًّى إِنْ زَادَ لِي وَإِنْ نَقَصَ فَعَلَيَّ","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub], ia berkata; telah menceritakan kepada kami [Ibnu 'Ulaiyah], ia berkata; telah menceritakan kepada kami [Ayyub] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari muzabanah, dan muzabanah adalah menjual apa yang ada di atas pohon kurma dengan kurma dengan takaran tertentu, ia mengatakan; apabila lebih maka untukku dan apabila kurang maka menjadi tanggunganku."},"4242":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْمُزَابَنَةِ وَالْمُزَابَنَةُ بَيْعُ الثَّمَرِ بِالتَّمْرِ كَيْلًا وَبَيْعُ الْكَرْمِ بِالزَّبِيبِ كَيْلًا","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari muzabanah, dan muzabanah adalah menjual kurma dengan kurma dengan takaran, serta menjual anggur dengan kismis dengan takaran. "},"4243":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ طَارِقٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُحَاقَلَةِ وَالْمُزَابَنَةِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id], ia berkata; telah menceritakan kepada kami [Abu Al Ahwash] dari [Thariq] dari [Sa'id bin Al Musayyab] dari [Rafi' bin Khadij], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari muhaqalah dan muzabanah."},"4244":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْ��ُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَ حَدَّثَنِي زَيْدُ بْنُ ثَابِتٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ فِي الْعَرَايَا","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Salim] dari [ayahnya], ia berkata; telah menceritakan kepadaku [Zaid bin Tsabit] bahwa Rasulullah shallallahu 'alaihi wasallam memberikan keringanan dalam hal 'araya."},"4245":{"ar":"قَالَ الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي خَارِجَةُ بْنُ زَيْدِ بْنِ ثَابِتٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ فِي الْعَرَايَا بِالتَّمْرِ وَالرُّطَبِ","id":"Telah berkata [Al Harits bin Miskin] dengan membacakan riwayat, dan saya mendengar, dari [Ibnu Wahb], ia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab], ia berkata; telah menceritakan kepadaku [Kharijah bin Zaid bin Tsabit] dari [ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam memberikan keringanan dalam hal membeli pohon kurma dengan buah kurma atau ruthab. "},"4246":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ أَخْبَرَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِ عَنْ زَيْدِ بْنِ ثَابِتٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ فِي بَيْعِ الْعَرَايَا تُبَاعُ بِخِرْصِهَا","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id], ia berkata; telah menceritakan kepada kami [Yahya] dari ['Ubaidullah], ia berkata; telah mengabarkan kepadaku [Nafi'] dari [Abdullah] dari [Zaid bin Tsabit] bahwa Rasulullah shallallahu 'alaihi wasallam memberikan keringanan dalam menjual 'araya dijual dengan taksirannya. "},"4247":{"ar":"حَدَّثَنَا عِيسَى بْنُ حَمَّادٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ حَدَّثَنِي زَيْدُ بْنُ ثَابِتٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ فِي بَيْعِ الْعَرِيَّةِ بِخِرْصِهَا تَمْرًا","id":"Telah mengabarkan kepada kami [Isa bin Hammad], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Yahya bin Sa'id] dari [Nafi'] dari [Ibnu Umar], ia berkata; telah menceritakan kepadaku [Zaid bin Tsabit] bahwa Rasulullah shallallahu 'alaihi wasallam memberikan keringanan dalam menjual 'araya dengan kurma secara taksiran. "},"4248":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَنَّ سَالِمًا أَخْبَرَهُ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عُمَرَ يَقُولُ إِنَّ زَيْدَ بْنَ ثَابِتٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ فِي بَيْعِ الْعَرَايَا بِالرُّطَبِ وَبِالتَّمْرِ وَلَمْ يُرَخِّصْ فِي غَيْرِ ذَلِكَ","id":"Telah mengabarkan kepada kami [Abu Daud], ia berkata; telah menceritakan kepada kami [Ya'qub bin Ibrahim], ia berkata; telah menceritakan kepada kami [ayahku] dari [Shalih] dari [Ibnu Syihab] bahwa [Salim] telah mengabarkan kepadanya bahwa ia mendengar [Abdullah bin Umar] berkata; sesungguhnya [Zaid bin Tsabit] telah mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam memberikan keringanan untuk menjual pohon kurma dengan ruthab dan kurma dan tidak memberikan keringanan dalam perkara selain itu. "},"4249":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ وَيَعْقُوبُ بْنُ إِبْرَاهِيمَ وَاللَّفْظُ لَهُ عَنْ عَبْدِ الرَّحْمَنِ عَنْ مَالِكٍ عَنْ دَاوُدَ بْنِ الْحُصَيْنِ عَنْ أَبِي سُفْيَانَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ فِي الْعَرَايَا أَنْ تُبَاعَ بِخِرْصِهَا فِي خَمْسَةِ أَوْسُقٍ أَوْ مَا دُونَ خَمْسَةِ أَوْسُقٍ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dan [Ya'qub bin Ibrahim], lafazhnya adalah lafazh Ya'qub, dari [Abdurrahman] dari [Malik] dari [Daud bin Al Hushain] dari [Abu Sufyan] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam memberikan keringanan dalam 'araya agar dijual dengan penaksirannya, lima wasaq atau kurang dari lima wasaq. "},"4250":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ يَحْيَى عَنْ بُشَيْرِ بْنِ يَسَارٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الثَّمَرِ حَتَّى يَبْدُوَ صَلَاحُهُ وَرَخَّصَ فِي الْعَرَايَا أَنْ تُبَاعَ بِخِرْصِهَا يَأْكُلُهَا أَهْلُهَا رُطَبًا","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad bin Abdurrahman], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Yahya] dari [Busyair bin Yasar] dari [Sahl bin Abu Hatsmah] bahwa Nabi shallallahu 'alaihi wasallam melarang dari menjual buah hingga nampak kelayakannya, dan memberikan keringanan dalalm hal 'araya di beli dengan perkiraannya, dan dimakan pemiliknya dalam bentuk ruthab. "},"4251":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ عِيسَى قَالَ حَدَّثَنَا أَبُو أُسَامَةَ قَالَ حَدَّثَنِي الْوَلِيدُ بْنُ كَثِيرٍ قَالَ أَخْبَرَنِي بُشَيْرُ بْنُ يَسَارٍ أَنَّ رَافِعَ بْنَ خَدِيجٍ وَسَهْلَ بْنَ أَبِي حَثْمَةَ حَدَّثَاهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْمُزَابَنَةِ بَيْعُ الثَّمَرِ بِالتَّمْرِ إِلَّا لِأَصْحَابِ الْعَرَايَا فَإِنَّهُ أَذِنَ لَهُمْ","id":"Telah mengabarkan kepada kami [Al Husain bin Isa], ia berkata; telah menceritakan kepada kami [Abu Usamah], ia berkata; telah menceritakan kepadaku [Al Walid bin Katsir], ia berkata; telah mengabarkan kepadaku [Busyair bin Yasar] bahwa [Rafi' bin Khadij] serta [Sahl bin Abu Hatsmah] telah menceritakan kepdanya bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari muzabanah yaitu menjual buah dengan kurma, kecuali bagi pemilik 'araya, sesungguhnya beliau mengizinkannya. "},"4252":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَحْيَى عَنْ بُشَيْرِ بْنِ يَسَارٍ عَنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُمْ قَالُوارَخَّصَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْعِ الْعَرَايَا بِخَرْصِهَا","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Yahya] dari [Busyair bin Yasar] dari [para sahabat] Rasulullah shallallahu 'alaihi wasallam bahwa mereka berkta; Rasulullah shallallahu 'alaihi wasallam memberikan keringanan untuk menjual 'araya dengan penaksirannya. "},"4253":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا مَالِكٌ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ يَزِيدَ عَنْ زَيْدِ بْنِ أَبِي عَيَّاشٍ عَنْ سَعْدٍ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ التَّمْرِ بِالرُّطَبِ فَقَالَ لِمَنْ حَوْلَهُ أَيَنْقُصُ الرُّطَبُ إِذَا يَبِسَ قَالُوا نَعَمْ فَنَهَى عَنْهُ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Yahya], ia berkata; telah menceritakan kepada kami [Malik], ia berkata; telah menceritakan kepadaku [Abdullah bin Yazid] dari [Zaid bin Abu 'Ayyasy] dari [Sa'd], ia berkata; Rasulullah shallallahu 'alaihi wasallam ditanya mengenai menjual kurma dengan ruthab kemudian beliau bertanya kepada orang di sekitarnya: \"Apakah ruthab akan berkurang apabila mongering?\" mereka berkata; ya. Kemudian beliau melarangnya. "},"4254":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَلِيِّ بْنِ مَيْمُونٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ الْفِرْيَابِيُّ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ زَيْدٍ عَنْ سَعْدِ بْنِ مَالِكٍ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الرُّطَبِ بِالتَّمْرِ فَقَالَ أَيَنْقُصُ إِذَا يَبِسَ قَالُوا نَعَمْ فَنَهَى عَنْهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Ali bin Maimun], ia berkata; telah menceritakan kepada kami [Muhammad bin Yusuf Al Firyabi], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Isma'il bin Umayyah] dari [Abdullah bin Yazid] dari [Zaid] dari [Sa'd bin Malik], ia berkata; Rasulullah shallallahu 'alaihi wasallam ditanya mengenai jual beli ruthab dengan kurma. Lalu beliau bertanya: \"Apakah ruthab akan berkurang apabila mengering?\" mereka berkata; ya. Kemudian beliau melarang. "},"4255":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْحَسَنِ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الصُّبْرَةِ مِنْ التَّمْرِ لَا يُعْلَمُ مَكِيلُهَا بِالْكَيْلِ الْمُسَمَّى مِنْ التَّمْرِ","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Hasan], ia berkata; telah menceritakan kepada kami [Hajjaj], telah berkata [Ibnu Juraij] telah mengabarkan kepadaku [Abu Az Zubair] berkata bahwa ia mendengar [Jabir bin Abdullah] berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari menjual kumpulan kurma yang tidak diketahui takarannya dengan kurma dengan takaran tertentu. "},"4256":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْحَسَنِ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُبَاعُ الصُّبْرَةُ مِنْ الطَّعَامِ بِالصُّبْرَةِ مِنْ الطَّعَامِ وَلَا الصُّبْرَةُ مِنْ الطَّعَامِ بِالْكَيْلِ الْمُسَمَّى مِنْ الطَّعَامِ","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Hasan], ia berkata; telah menceritakan kepada kami [Hajjaj], ia berkata; [Ibnu Juraij] telah mengabarkan kepadaku [Abu Az Zubair] bahwa ia mendengar [Jabir bin Abdullah] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak boleh menjual sekumpulan makanan dengan sekumpulan makanan dan sekumpulan makanan dengan makanan dengan takaran tertentu.\""},"4257":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُزَابَنَةِ أَنْ يَبِيعَ ثَمَرَ حَائِطِهِ وَإِنْ كَانَ نَخْلًا بِتَمْرٍ كَيْلًا وَإِنْ كَانَ كَرْمًا أَنْ يَبِيعَهُ بِزَبِيبٍ كَيْلًا وَإِنْ كَانَ زَرْعًا أَنْ يَبِيعَهُ بِكَيْلِ طَعَامٍ نَهَى عَنْ ذَلِكَ كُلِّهِ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari muzabanah dengan menjual buah kebunnya apabila berupa pohon kurma dengan kurma dalam bentuk takaran, apabila pohon anggur menjualnya dengan kismis dalam bentuk takaran, dan apabila tanaman menjualnya dengan makanan dalam bentuk takaran. Beliau melarang dari semua itu. "},"4258":{"ar":"حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا مَخْلَدُ بْنُ يَزِيدَ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْمُخَابَرَةِ وَالْمُزَابَنَةِ وَالْمُحَاقَلَةِ وَعَنْ بَيْعِ الثَّمَرِ قَبْلَ أَنْ يُطْعَمَ وَعَنْ بَيْعِ ذَلِكَ إِلَّا بِالدَّنَانِيرِ وَالدَّرَاهِمِ","id":"Telah mengabarkan kepada kami [Abdul Hamid bin Muhammad], ia berkata; telah menceritakan kepada kami [Makhlad bin Yazid], ia berkata; telah menceritakan kepada kami [Ibnu Juraij] dari ['Atho`] dari [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari mukhabarah, muzabanah, muhaqalah dan dari menjual buah sebelum bisa dimakan dan dari menjual hal tersebut kecuali dengan dinar dan dirham. "},"4259":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ النَّخْلَةِ حَتَّى تَزْهُوَ وَعَنْ السُّنْبُلِ حَتَّى يَبْيَضَّ وَيَأْمَنَ الْعَاهَةَ نَهَى الْبَائِعَ وَالْمُشْتَرِيَ","id":"Telah mengabarkan kepada kami [Ali bin Hujr], ia berkata; telah menceritakan kepada kami [Isma'il] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari menjual kurma yang masih di pohon hingga memerah dan dari bulir hingga mengeras bijinya, dan aman dari bencana. Beliau melarang penjual dan pembeli. "},"4260":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ الْأَعْمَشِ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ أَبِي صَالِحٍأَنَّ رَجُلًا مَنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَهُ قَالَ يَا رَسُولَ اللَّهِ إِنَّا لَا نَجِدُ الصَّيْحَانِيَّ وَلَا الْعِذْقَ بِجَمْعِ التَّمْرِ حَتَّى نَزِيدَهُمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعْهُ بِالْوَرِقِ ثُمَّ اشْتَرِ بِهِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id], ia berkata; telah menceritakan kepada kami [Abu Al Ahwash] dari [Al A'masy] dari [Habib bin Abu Tsabit] dari [Abu Shalih] bahwa [seseorang dari sahabat] Nabi shallallahu 'alaihi wasallam telah mengabarkan kepadanya bahwa ia mengatakan; wahai Rasulullah, kami tidak mendapatkan Shaihani (jenis kurma yang baik) atau Al 'Idzq dengan kurma Jam' kecuali kami menambahkan mereka, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Juallah kurma dengan uang perak lalu belilah dengannya.\""},"4261":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ عَبْدِ الْمَجِيدِ بْنِ سُهَيْلٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ وَعَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَعْمَلَ رَجُلًا عَلَى خَيْبَرَ فَجَاءَ بِتَمْرٍ جَنِيبٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكُلُّ تَمْرِ خَيْبَرَ هَكَذَا قَالَ لَا وَاللَّهِ يَا رَسُولَ اللَّهِ إِنَّا لَنَأْخُذُ الصَّاعَ مِنْ هَذَا بِصَاعَيْنِ وَالصَّاعَيْنِ بِالثَّلَاثِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَفْعَلْ بِعْ الْجَمْعَ بِالدَّرَاهِمِ ثُمَّ ابْتَعْ بِالدَّرَاهِمِ جَنِيبًا","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] dengan membacakan riwayat, dan saya mendengar, lafazhnya adalah lafazh Al Harits, dari [Ibnu Al Qasim], ia berkata; telah menceritakan kepadaku [Malik] dari [Abdul Majid bin Suhail] dari [Sa'id bin Al Musayyab] dari [Abu Sa'id Al Khudri] dan dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam menggunakan tenaga orang untuk menggarap lahan Khaibar, kemudian orang tersebut datang membawa kurma Janih. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah seluruh kurma Khaibar seperti ini?\" orang tersebut berkata; tidak, demi Allah wahai Rasulullah, sesungguhnya kami mengambil satu sha' dengan dua sha', mengambil dua sha' dengan tiga sha'. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jangan kalian lakukan, juallah kurma jam' dengan uang dirham kemudian belilah dengan dirham tersebut kurma Janih.\" "},"4262":{"ar":"أَخْبَرَنَا نَصْرُ بْنُ عَلِيٍّ وَإِسْمَعِيلُ بْنُ مَسْعُودٍ وَاللَّفْظُ لَهُ عَنْ خَالِدٍ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِتَمْرٍ رَيَّانَ وَكَانَ تَمْرُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْلًا فِيهِ يُبْسٌ فَقَالَ أَنَّى لَكُمْ هَذَا قَالُوا ابْتَعْنَاهُ صَاعًا بِصَاعَيْنِ مِنْ تَمْرِنَا فَقَالَ لَا تَفْعَلْ فَإِنَّ هَذَا لَا يَصِحُّ وَلَكِنْ بِعْ تَمْرَكَ وَاشْتَرِ مِنْ هَذَا حَاجَتَكَ","id":"Telah mengabarkan kepada kami [Nashr bin Ali] dan [Isma'il bin Mas'ud] dan lafazhnya adalah lafazh Isma'il, dari [Khalid], ia berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Sa'id bin Al Musayyab] dari [Abu Sa'id Al Khudri] bahwa Rasulullah shallallahu 'alaihi wasallam diberi kurman Rayyan sedangkan kurma Rasulullah shallallahu 'alaihi wasallam adalah kurma Ba'l yang basah, kemudian beliau bersabda: \"Dari manakah kalian mendapatkan hal ini?\" mereka berkata; kami membelinya satu sha' dengan dua sha' dari kurma kami. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jangan engkau lakukan, sesungguhnya hal tidaklah sah, akan tetapi juallah kurmamu dan belilah dari penjualan ini apa yang engkau kehendaki.\""},"4263":{"ar":"حَدَّثَنِي إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا أَبُو سَعِيدٍ الْخُدْرِيُّ قَالَكُنَّا نُرْزَقُ تَمْرَ الْجَمْعِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَبِيعُ الصَّاعَيْنِ بِالصَّاعِ فَبَلَغَ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا صَاعَيْ تَمْرٍ بِصَاعٍ وَلَا صَاعَيْ حِنْطَةٍ بِصَاعٍ وَلَا دِرْهَمًا بِدِرْهَمَيْنِ","id":"Telah mengabarkan kepadaku [Isma'il bin Mas'ud], ia berkata; telah menceritakan kepada kami [Khalid], ia berkata; telah menceritakan kepada kami [Hisyam] dari [Yahya bin Abu Katsir] dari [Abu Salamah bin Abdurrahman], ia berkata; telah menceritakan kepada kami [Abu Sa'id Al Khudri], ia berkata; dahulu kami mendapatkan rizqi kurma Jam' pada zaman Rasulullah shallallahu 'alaihi wasallam, kemudian kami menjual dua sha' dengan satu sha'. Kemudian hal tersebut sampai kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Jangan engkau jual dua sha' kurma dengan satu sha' dan dua sha' gandum dengan satu sha', serta satu dirham dengan dua dirham.\""},"4264":{"ar":"أَخْبَرَنَا هِشَامُ بْنُ عَمَّارٍ عَنْ يَحْيَى وَهُوَ ابْنُ حَمْزَةَ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى قَالَ حَدَّثَنِي أَبُو سَلَمَةَ قَالَ حَدَّثَنِي أَبُو سَعِيدٍ قَالَكُنَّا نَبِيعُ تَمْرَ الْجَمْعِ صَاعَيْنِ بِصَاعٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا صَاعَيْ تَمْرٍ بِصَاعٍ وَلَا صَاعَيْ حِنْطَةٍ بِصَاعٍ وَلَا دِرْهَمَيْنِ بِدِرْهَمٍ","id":"Telah mengabarkan kepada kami [Hisyam bin 'Ammar] dari [Yahya yaitu Ibnu Hamzah], ia berkata; telah menceritakan kepada kami [Al Auza'i] dari [Yahya], ia berkata; telah menceritakan kepadaku [Abu Salamah], ia berkata; telah menceritakan kepadaku [Abu Sa'id], ia berkata; dahulu kami menjual kurma Jam' dua Sha' dengan satu sha'. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Jangan engkau jual dua sha' kurma dengan satu sha' dan dua sha' gandum dengan satu sha', serta satu dirham dengan dua dirham.\""},"4265":{"ar":"أَخْبَرَنَا هِشَامُ بْنُ عَمَّارٍ عَنْ يَحْيَى وَهُوَ ابْنُ حَمْزَةَ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي يَحْيَى قَالَ حَدَّثَنِي عُقْبَةُ بْنُ عَبْدِ الْغَافِرِ قَالَ حَدَّثَنِي أَبُو سَعِيدٍ قَالَأَتَى بِلَالٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِتَمْرٍ بَرْنِيٍّ فَقَالَ مَا هَذَا قَالَ اشْتَرَيْتُهُ صَاعًا بِصَاعَيْنِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوِّهْ عَيْنُ الرِّبَا لَا تَقْرَبْهُ","id":"Telah mengabarkan kepada kami [Hisyam bin 'Ammar] dari [Yahya yaitu Ibnu Hamzah], ia berkata; telah menceritakan kepada kami [Al Auza'i], ia berkata; telah menceritakan kepadaku [Yahya], ia berkata; telah menceritakan kepadaku ['Uqbah bin Abdul Ghafir], ia berkata; telah menceritakan kepadaku [Abu Sa'id], ia berkata; telah datang Bilal kepada Rasulullah shallallahu 'alaihi wasallam membawa kurma Barni, kemudian beliau bersabda: \"Apa ini?\" Ia berkata; saya membelinya satu sha' dengan dua sha'. Lalu beliau bersabda: \"Aduh, bentuk riba, janganlah engkau dekati.\""},"4266":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ مَالِكِ بْنِ أَوْسِ بْنِ الْحَدَثَانِ أَنَّهُ سَمِعَ عُمَرَ بْنَ الْخَطَّابِ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الذَّهَبُ بِالْوَرِقِ رِبًا إِلَّا هَاءَ وَهَاءَ وَالتَّمْرُ بِالتَّمْرِ رِبًا إِلَّا هَاءَ وَهَاءَ وَالْبُرُّ بِالْبُرِّ رِبًا إِلَّا هَاءَ وَهَاءَ وَالشَّعِيرُ بِالشَّعِيرِ رِبًا إِلَّا هَاءَ وَهَاءَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Malik bin Aus bin Al Hadatsan] bahwa Ia mendengar [Umar bin Al Khathab] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Menjual emas dengan perak adalah riba, kecuali serah terima secara langsung, kurma dengan kurma adalah riba kecuali serah terima secara langsung, gandum dengan gandum adalah riba kecuali serah terima secara langsung, jewawut dengan jewawut adalah riba kecuali serah terima secara langsung.\""},"4267":{"ar":"أَخْبَرَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ التَّمْرُ بِالتَّمْرِ وَالْحِنْطَةُ بِالْحِنْطَةِ وَالشَّعِيرُ بِالشَّعِيرِ وَالْمِلْحُ بِالْمِلْحِ يَدًا بِيَدٍ فَمَنْ زَادَ أَوْ ازْدَادَ فَقَدْ أَرْبَى إِلَّا مَا اخْتَلَفَتْ أَلْوَانُهُ","id":"Telah mengabarkan kepada kami [Washil bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Ibnu Fudhail] dari [ayahnya] dari [Abu Zur'ah] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kurma dengan kurma, gandum dengan gandum, jewawut dengan jewawut, garam dengan garam dengan serah terima secara langsung, barang siapa menambah atau meminta tambahan maka sungguh ia telah melakukan riba kecuali yang berbeda warnanya.\""},"4268":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ بَزِيعٍ قَالَ حَدَّثَنَا يَزِيدُ قَالَ حَدَّثَنَا سَلَمَةُ وَهُوَ ابْنُ عَلْقَمَةَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ مُسْلِمِ بْنِ يَسَارٍ وَعَبْدِ اللَّهِ بْنِ عَتِيكٍ قَالَا جَمَعَ الْمَنْزِلُ بَيْنَ عُبَادَةَ بْنِ الصَّامِتِ وَمُعَاوِيَةَ حَدَّثَهُمْ عُبَادَةُ قَالَنَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الذَّهَبِ بِالذَّهَبِ وَالْوَرِقِ بِالْوَرِقِ وَالْبُرِّ بِالْبُرِّ وَالشَّعِيرِ بِالشَّعِيرِ وَالتَّمْرِ بِالتَّمْرِ قَالَ أَحَدُهُمَا وَالْمِلْحِ بِالْمِلْحِ وَلَمْ يَقُلْهُ الْآخَرُ إِلَّا مِثْلًا بِمِثْلٍ يَدًا بِيَدٍ وَأَمَرَنَا أَنْ نَبِيعَ الذَّهَبَ بِالْوَرِقِ وَالْوَرِقَ بِالذَّهَبِ وَالْبُرَّ بِالشَّعِيرِ وَالشَّعِيرَ بِالْبُرِّ يَدًا بِيَدٍ كَيْفَ شِئْنَا قَالَ أَحَدُهُمَا فَمَنْ زَادَ أَوْ ازْدَادَ فَقَدْ أَرْبَى","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Bazi'], ia berkata; telah menceritakan kepada kami [Yazid], ia berkata; telah menceritakan kepada kami [Salamah yaitu Ibnu 'Alqamah] dari [Muhammad bin Sirin] dari [Muslim bin Yasar] dan [Abdullah bin 'Atik] mereka berkata; di dalam rumah terdapat 'Ubadah bin Ash Shamit dan Mu'awiyah, ['Ubadah] menceritakan kepada mereka, ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang kita dari menjual emas dengan emas, perak dengan perak, gandum dengan gandum, jewawut dengan jewawut dan kurma dengan kurma. Salah seorang dari mereka berdua berkata; dan garam dengan garam, sedangkan yang lain tidak mengatakan hal tersebut. Kecuali dengan semisal dengan yang semisal, dan dengan serah terima secara langsung. Dan beliau memerintahkan agar kami menjual emas dengan perak, dan perak dengan emas, gandum dengan jewawut dengan serah terima secara langsung bagaimanapun yang kami kehendaki. Barang siapa menambah atau meminta tambahan maka sungguh ia telah melakukan riba."},"4269":{"ar":"أَخْبَرَنَا الْمُؤَمَّلُ بْنُ هِشَامٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ وَهُوَ ابْنُ عُلَيَّةَ عَنْ سَلَمَةَ بْنِ عَلْقَمَةَ عَنْ ابْنِ سِيرِينَ قَالَ حَدَّثَنِي مُسْلِمُ بْنُ يَسَارٍ وَعَبْدُ اللَّهِ بْنُ عُبَيْدٍ وَقَدْ كَانَ يُدْعَى ابْنَ هُرْمُزَ قَالَ جَمَعَ الْمَنْزِلُ بَيْنَ عُبَادَةَ بْنِ الصَّامِتِ وَبَيْنَ مُعَاوِيَةَ حَدَّثَهُمْ عُبَادَةُ قَالَنَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الذَّهَبِ بِالذَّهَبِ وَالْفِضَّةِ بِالْفِضَّةِ وَالتَّمْرِ بِالتَّمْرِ وَالْبُرِّ بِالْبُرِّ وَالشَّعِيرِ بِالشَّعِيرِ قَالَ أَحَدُهُمَا وَالْمِلْحِ بِالْمِلْحِ وَلَمْ يَقُلْهُ الْآخَرُ إِلَّا سَوَاءً بِسَوَاءٍ مِثْلًا بِمِثْلٍ قَالَ أَحَدُهُمَا مَنْ زَادَ أَوْ ازْدَادَ فَقَدْ أَرْبَى وَلَمْ يَقُلْهُ الْآخَرُ وَأَمَرَنَا أَنْ نَبِيعَ الذَّهَبَ بِالْفِضَّةِ وَالْفِضَّةَ بِالذَّهَبِ وَالْبُرَّ بِالشَّعِيرِ وَالشَّعِيرَ بِالْبُرِّ يَدًا بِيَدٍ كَيْفَ شِئْنَا","id":"Telah mengabarkan kepada kami [Al Muammal bin Hisyam], ia berkata; telah menceritakan kepada kami [Isma'il yaitu Ibnu 'Ulayyah] dari [Salamah bin 'Alqamah] dari [Ibnu Sirin], ia berkata; telah menceritakan kepadaku [Muslim bin Yasar] dan [Abdullah bin Atik] dan ia dahulu dipanggil dengan nama Ibnu Hurmuz, ia berkata; sementara di dalam rumah terdapat 'Ubadah bin Ash Shamit dan Mu'awiyah, ['Ubadah] menceritakan kepada mereka, ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang kita dari menjual emas dengan emas, perak dengan perak, kurma dengan kurma, gandum dengan gandum, jewawut dengan jewawut. Salah seorang dari mereka berdua berkata; dan garam dengan garam, sedangkan yang lain tidak mengatakan hal tersebut. Kecuali secara sama-sama, semisal dengan yang semisal. Salah seorang diantara mereka berdua mengatakan; Barang siapa menambah atau meminta tambahan maka sungguh ia telah melakukan riba. Dan yang lainnya tidak mengatakannya. Dan beliau memerintahkan agar kami menjual emas dengan perak, dan perak dengan emas, gandum dengan jewawut dan jewawut dengan gandum, dengan serah terima secara langsung bagaimanapun yang kami kehendaki. "},"4270":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ قَالَ حَدَّثَنَا سَلَمَةُ بْنُ عَلْقَمَةَ عَنْ مُحَمَّدٍ قَالَ حَدَّثَنِي مُسْلِمُ بْنُ يَسَارٍ وَعَبْدُ اللَّهِ بْنُ عُبَيْدٍ قَالَا جَمَعَ الْمَنْزِلُ بَيْنَ عُبَادَةَ بْنِ الصَّامِتِ وَبَيْنَ مُعَاوِيَةَ فَقَالَ عُبَادَةُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَبِيعَ الذَّهَبَ بِالذَّهَبِ وَالْوَرِقَ بِالْوَرِقِ وَالْبُرَّ بِالْبُرِّ وَالشَّعِيرَ بِالشَّعِيرِ وَالتَّمْرَ بِالتَّمْرِ قَالَ أَحَدُهُمَا وَالْمِلْحَ بِالْمِلْحِ وَلَمْ يَقُلْ الْآخَرُ إِلَّا سَوَاءً بِسَوَاءٍ مِثْلًا بِمِثْلٍ قَالَ أَحَدُهُمَا مَنْ زَادَ أَوْ ازْدَادَ فَقَدْ أَرْبَى وَلَمْ يَقُلْ الْآخَرُ وَأَمَرَنَا أَنْ نَبِيعَ الذَّهَبَ بِالْوَرِقِ وَالْوَرِقَ بِالذَّهَبِ وَالْبُرَّ بِالشَّعِيرِ وَالشَّعِيرَ بِالْبُرِّ يَدًا بِيَدٍ كَيْفَ شِئْنَافَبَلَغَ هَذَا الْحَدِيثُ مُعَاوِيَةَ فَقَامَ فَقَالَ مَا بَالُ رِجَالٍ يُحَدِّثُونَ أَحَادِيثَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ صَحِبْنَاهُ وَلَمْ نَسْمَعْهُ مِنْهُ فَبَلَغَ ذَلِكَ عُبَادَةَ بْنَ الصَّامِتِ فَقَامَ فَأَعَادَ الْحَدِيثَ فَقَالَ لَنُحَدِّثَنَّ بِمَا سَمِعْنَاهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنْ رَغِمَ مُعَاوِيَةُ خَالَفَهُ قَتَادَةُ رَوَاهُ عَنْ مُسْلِمِ بْنِ يَسَارٍ عَنْ أَبِي الْأَشْعَثِ عَنْ عُبَادَةَ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud], ia berkata; telah menceritakan kepada kami [Bisyr bin Al Mufadhdhal], ia berkata; telah menceritakan kepada kami [Salamah bin 'Alqamah] dari [Muhammad], ia berkata; telah menceritakan kepadaku [Muslim bin Yasar] dan [Abdullah bin Atik], mereka mengatakan; sementara di dalam rumah terdapat 'Ubadah bin Ash Shamit dan Mu'awiyah, kemudian ['Ubadah] berkata; Rasulullah shallallahu 'alaihi wasallam melarang kami dari menjual emas dengan emas, perak dengan perak, gandum dengan gandum, jewawut dengan jewawut, dan kurma dengan kurma. Salah seorang dari mereka berdua berkata; dan garam dengan garam, sedangkan yang lain tidak mengatakan hal tersebut. Kecuali secara sama-sama, semisal dengan yang semisal. Salah seorang diantara mereka berdua mengatakan; Barang siapa menambah atau meminta tambahan maka sungguh ia telah melakukan riba. Dan yang lainnya tidak mengatakannya. Dan beliau memerintahkan agar kami menjual emas dengan perak, dan perak dengan emas, gandum dengan jewawut dan jewawut dengan gandum, dengan serah terima secara langsung bagaimanapun yang kami kehendaki. Kemudian hadits ini sampai kepada Mu'awiyah, kemudian ia berdiri dan berkata; bagaimana keadaan orang-orang yang meriwayatkan hadits-hadits dari Rasulullah shallallahu 'alaihi wasallam, dan kami telah menemani beliau dan belum mendengarnya dari beliau. Kemudian hal tersebut sampai kepada Ubadah bin Ash Shamit, lalu ia berdiri dan mengulangi hadits tersebut. Kemudian berkata; sungguh kami akan ceritakan apa yang telah kami dengar dari Rasulullah shallallahu 'alaihi wasallam walaupun Mu'awiyah tidak menyukainya. Qatadah menyelisinya, ia meriwayatkannya dari Muslim bin Yasar dari Abu Al Asy'ats dari Ubadah. "},"4271":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ آدَمَ عَنْ عَبْدَةَ عَنْ ابْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ مُسْلِمِ بْنِ يَسَارٍ عَنْ أَبِي الْأَشْعَثِ الصَّنْعَانِيِّ عَنْ عُبَادَةَ بْنِ الصَّامِتِ وَكَانَ بَدْرِيًّا وَكَانَ بَايَعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ لَا يَخَافَ فِي اللَّهِ لَوْمَةَ لَائِمٍ أَنَّ عُبَادَةَقَامَ خَطِيبًا فَقَالَ أَيُّهَا النَّاسُ إِنَّكُمْ قَدْ أَحْدَثْتُمْ بُيُوعًا لَا أَدْرِي مَا هِيَ أَلَا إِنَّ الذَّهَبَ بِالذَّهَبِ وَزْنًا بِوَزْنٍ تِبْرُهَا وَعَيْنُهَا وَإِنَّ الْفِضَّةَ بِالْفِضَّةِ وَزْنًا بِوَزْنٍ تِبْرُهَا وَعَيْنُهَا وَلَا بَأْسَ بِبَيْعِ الْفِضَّةِ بِالذَّهَبِ يَدًا بِيَدٍ وَالْفِضَّةُ أَكْثَرُهُمَا وَلَا تَصْلُحُ النَّسِيئَةُ أَلَا إِنَّ الْبُرَّ بِالْبُرِّ وَالشَّعِيرَ بِالشَّعِيرِ مُدْيًا بِمُدْيٍ وَلَا بَأْسَ بِبَيْعِ الشَّعِيرِ بِالْحِنْطَةِ يَدًا بِيَدٍ وَالشَّعِيرُ أَكْثَرُهُمَا وَلَا يَصْلُحُ نَسِيئَةً أَلَا وَإِنَّ التَّمْرَ بِالتَّمْرِ مُدْيًا بِمُدْيٍ حَتَّى ذَكَرَ الْمِلْحَ مُدًّا بِمُدٍّ فَمَنْ زَادَ أَوْ اسْتَزَادَ فَقَدْ أَرْبَى","id":"Telah mengabarkan kepada kami [Muhammad bin Adam] dari ['Abdah] dari [Ibnu Abu 'Arubah] dari [Qatadah] dari [Muslim bin Yasar] dari [Al Asy'ats Ash Shan'ani] dari ['Ubadah bin Ash Shamit] yang merupakan orang Badr, dan telah membai'at Nabi shallallahu 'alaihi wasallam untuk tidak takut karena Allah kepada celaan orang yang mencela. Bahwa 'Ubadah berdiri melakukan ceramah, ia berkata; wahai manusia, sungguh kalian telah mengadakan jual beli, saya tidak tahu apa itu, ketahuilah sesungguhnya emas dengan emas satu timbangan dengan satu timbangan, baik yang masih murni atau mata uangnya, dan perak dengan perak, satu timbangan dengan satu timbangan, baik yang masih murni atau mata uangnya. Dan tidak mengapa menjual perak dengan emas dengan serah terima secara langsung dan perak lebih banyak, tidak boleh ditunda. Ketahuilah sesungguhnya gandum dengan gandum, dan jewawut-dengan jewawut satu mudyun (jenis takaran penduduk Syam) dengan satu mudyun dan tidak mengapa menjual jewawut dengan gandum dengan serah terima secara langsung, dan jewawut lebih banyak, dan tidak boleh menunda. Ketahuilah sesungguhnya kurma dengan kurma satu mudyun dengan satu mudyun....hingga ia menyebutkan garam satu mud dengan satu mud. Barang siapa yang menambah atau meminta tambahan maka sungguh ia telah melakukan riba. "},"4272":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَإِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَا حَدَّثَنَا عَمْرُو بْنُ عَاصِمٍ قَالَ حَدَّثَنَا هَمَّامٌ قَالَ حَدَّثَنَا قَتَادَةُ عَنْ أَبِي الْخَلِيلِ عَنْ مُسْلِمٍ الْمَكِّيِّ عَنْ أَبِي الْأَشْعَثِ الصَّنْعَانِيِّ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الذَّهَبُ بِالذَّهَبِ تِبْرُهُ وَعَيْنُهُ وَزْنًا بِوَزْنٍ وَالْفِضَّةُ بِالْفِضَّةِ تِبْرُهُ وَعَيْنُهُ وَزْنًا بِوَزْنٍ وَالْمِلْحُ بِالْمِلْحِ وَالتَّمْرُ بِالتَّمْرِ وَالْبُرُّ بِالْبُرِّ وَالشَّعِيرُ بِالشَّعِيرِ سَوَاءً بِسَوَاءٍ مِثْلًا بِمِثْلٍ فَمَنْ زَادَ أَوْ ازْدَادَ فَقَدْ أَرْبَى وَاللَّفْظُ لِمُحَمَّدٍ لَمْ يَذْكُرْ ابْنُ يَعْقُوبَ وَالشَّعِيرُ بِالشَّعِيرِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dan [Ibrahim bin Ya'qub] mereka berkata; telah menceritakan kepada kami ['Amr bin 'Ashim], ia berkata; telah menceritakan kepada kami [Hammam], ia berkata; telah menceritakan kepada kami [Qatadah] dari [Abu Al Khalil] dari [Muslim Al Makki] dari [Abu Al Asy'ats Ash Shan'ani] dari ['Ubadah bin Ash Shamit], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Emas dengan emas yang murni dan mata uangnya satu timbangan dengan satu timbangan, perak dengan perak yang murni dan mata uangnya satu timbangan dengan satu timbangan, garam dengan garam, kurma dengan kurma, gandum dengan gandum, dan jewawut dengan jewawut secara sama-sama dan semisal dengan semisal. Barang siapa yang menambah atau minta tambahan maka sungguh ia telah melakukan riba.\" Lafazhnya adalah lafazh Muhammad, Ibnu Ya'qub tidak menyebutkan; dan jewawut dengan jewawut."},"4273":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ عَنْ سُلَيْمَانَ بْنِ عَلِيٍّ أَنَّ أَبَا الْمُتَوَكِّلِ مَرَّ بِهِمْ فِي السُّوقِ فَقَامَ إِلَيْهِ قَوْمٌ أَنَا مِنْهُمْ قَالَ قُلْنَا أَتَيْنَاكَ لِنَسْأَلَكَ عَنْ الصَّرْفِ قَالَ سَمِعْتُ أَبَا سَعِيدٍ الْخُدْرِيَّقَالَ لَهُ رَجُلٌ مَا بَيْنَكَ وَبَيْنَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرُ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ لَيْسَ بَيْنِي وَبَيْنَهُ غَيْرُهُ قَالَ فَإِنَّ الذَّهَبَ بِالذَّهَبِ وَالْوَرِقَ بِالْوَرِقِ قَالَ سُلَيْمَانُ أَوْ قَالَ وَالْفِضَّةَ بِالْفِضَّةِ وَالْبُرَّ بِالْبُرِّ وَالشَّعِيرَ بِالشَّعِيرِ وَالتَّمْرَ بِالتَّمْرِ وَالْمِلْحَ بِالْمِلْحِ سَوَاءً بِسَوَاءٍ فَمَنْ زَادَ عَلَى ذَلِكَ أَوْ ازْدَادَ فَقَدْ أَرْبَى وَالْآخِذُ وَالْمُعْطِي فِيهِ سَوَاءٌ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud], ia berkata; telah menceritakan kepada kami [Khalid] dari [Sulaiman bin Ali] bahwa [Abu Al Mutawalli] melewati orang-orang di pasar kemudian beberapa orang datang kepadanya dan saya termasuk diantara mereka. Sulaiman mengatakan; kami mengatakan; kami datang kepadamu untuk bertanya mengenai barter. Ia berkata; saya mendengar [Abu Sa'id Al Khudri].... kemudian seorang laki-laki berkata kepadanya; apakah tidak ada orang antara engkau dan Rasulullah shallallahu 'alaihi wasallam selain Abu Sa'id Al Khudri? Abu Al Mutawalli berkata; tidak ada orang antara saya dengan Rasulullah shallallahu 'alaihi wasallam selain dia. Ia berkata; sesungguhnya emas dengan emas, perak dengan perak, gandum dengan gandum, jewawut dengan jewawut, kurma dengan kurma dan garam dengan garam secara sama-sama, barang siapa menambah hal itu atau minta tambahan maka ia telah melakukan riba, orang yang mengambil dan yang memberi adalah sama. "},"4274":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ قَالَ قَالَ إِسْمَعِيلُ حَدَّثَنَا حَكِيمُ بْنُ جَابِرٍ ح وَأَنْبَأَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَحْيَى عَنْ إِسْمَعِيلَ قَالَ حَدَّثَنَا حَكِيمُ بْنُ جَابِرٍ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الذَّهَبُ الْكِفَّةُ بِالْكِفَّةِ وَلَمْ يَذْكُرْ يَعْقُوبُ الْكِفَّةُ بِالْكِفَّةِفَقَالَ مُعَاوِيَةُ إِنَّ هَذَا لَا يَقُولُ شَيْئًا قَالَ عُبَادَةُ إِنِّي وَاللَّهِ مَا أُبَالِي أَنْ لَا أَكُونَ بِأَرْضٍ يَكُونُ بِهَا مُعَاوِيَةُ إِنِّي أَشْهَدُ أَنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ ذَلِكَ","id":"Telah mengabarkan kepada kami [Harun bin Abdullah], ia berkata; telah menceritakan kepada kami [Abu Usamah], ia berkata; telah berkata [Isma'il]; telah menceritakan kepada kami [Hakim bin Jabir]. Dari jalur lain; Telah menceritakan dan memberitakan kepada kami [Ya'qub bin Ibrahim], ia berkata; telah menceritakan kepada kami [Yahya] dari [Isma'il], ia berkata; telah menceritakan kepada kami [Hakim bin Jabir] dari ['Ubadah bin Ash Shamit], ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Emas dengan emas satu timbangan dengan satu timbangan Ya'qub tidak menyebutkan; \"satu timbangan dengan satu timbangan\". Mu'awiyah berkata; sesungguhnya orang ini tidak mengatakan sesuatupun. 'Ubadah berkata; demi Allah sesungguhnya saya tidak peduli untuk tidak berada di negeri yang padanya terdapat Mu'awiyah, sesungguhnya saya bersaksi bahwa saya mendengar Rasulullah shallallahu 'alaihi wasallam mengatakan hal tersebut."},"4275":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ مُوسَى بْنِ أَبِي تَمِيمٍ عَنْ سَعِيدِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الدِّينَارُ بِالدِّينَارِ وَالدِّرْهَمُ بِالدِّرْهَمِ لَا فَضْلَ بَيْنَهُمَا","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Musa bin Abu Tamim] dari [Sa'id bin Yasar] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dinar dengan dinar, dan dirham dengan dirham, tidak boleh ada lebih diantara keduanya.\""},"4276":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ حُمَيْدِ بْنِ قَيْسٍ الْمَكِّيِّ عَنْ مُجَاهِدٍ قَالَ قَالَ عُمَرُالدِّينَارُ بِالدِّينَارِ وَالدِّرْهَمُ بِالدِّرْهَمِ لَا فَضْلَ بَيْنَهُمَا هَذَا عَهْدُ نَبِيِّنَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْنَا","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Humaid bin Qais Al Makki] dari [Mujahid], ia berkata; [Umar] berkata; dinar dengan dinar, dirham dengan dirham tidak boleh ada kelebihan diantara keduanya. Hal ini adalah janji Nabi kita kepada kita. "},"4277":{"ar":"أَخْبَرَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ أَبِيهِ عَنْ ابْنِ أَبِي نُعْمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الذَّهَبُ بِالذَّهَبِ وَزْنًا بِوَزْنٍ مِثْلًا بِمِثْلٍ وَالْفِضَّةُ بِالْفِضَّةِ وَزْنًا بِوَزْنٍ مِثْلًا بِمِثْلٍ فَمَنْ زَادَ أَوْ ازْدَادَ فَقَدْ أَرْبَى","id":"Telah mengabarkan kepada kami [Washil bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Muhammad bin Fudhail] dari [ayahnya] dari [Ibnu Abu Nu'aim] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Emas dengan emas, satu timbangan dengan satu timbangan dan semisal dengan yang semisalnya, perak dengan perak satu timbangan dengan satu timbangan, semisalnya dengan semisalnya. Barang siapa yang menambah atau meminta tambahan maka ia telah melakukan riba.\""},"4278":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَبِيعُوا الذَّهَبَ بِالذَّهَبِ إِلَّا مِثْلًا بِمِثْلٍ وَلَا تُشِفُّوا بَعْضَهَا عَلَى بَعْضٍ وَلَا تَبِيعُوا الْوَرِقَ بِالْوَرِقِ إِلَّا مِثْلًا بِمِثْلٍ وَلَا تَبِيعُوا مِنْهَا شَيْئًا غَائِبًا بِنَاجِزٍ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Nafi'] dari [Abu Sa'id Al Khudri] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menjual emas dengan emas kecuali semisalnya dengan yang semisalnya, dan janganlah kalian melebihkan sedikitpun darinya, baik dengan ditunda atau secara kuntan. "},"4279":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ وَإِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَا حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ زُرَيْعٍ قَالَ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ نَافِعٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَبَصُرَ عَيْنِي وَسَمِعَ أُذُنِي مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ النَّهْيَ عَنْ الذَّهَبِ بِالذَّهَبِ وَالْوَرِقِ بِالْوَرِقِ إِلَّا سَوَاءً بِسَوَاءٍ مِثْلًا بِمِثْلٍ وَلَا تَبِيعُوا غَائِبًا بِنَاجِزٍ وَلَا تُشِفُّوا أَحَدَهُمَا عَلَى الْآخَرِ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dan [Isma'il bin Mas'ud] mereka berkata; telah menceritakan kepada kami [Yazid yaitu Ibnu Zurai'], ia berkata; telah menceritakan kepada kami [Ibnu 'Aun] dari [Nafi'] dari [Abu Sa'id Al Khudri], ia berkata; mataku telah melihat dan telingaku mendengar dari Rasulullah shallallahu 'alaihi wasallam dan beliau menyebutkan larangan dari menjual emas dengan emas, perak dengan perak kecuali secara sama - sama, dan semisalnya dengan yang semisalnya, dan janganlah kalian menjual yang tidak kuntan dengan yang kuntan, dan janganlah kalian melebihkan salah satu dari keduanya atas yang lainnya."},"4280":{"ar":"حَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ أَنَّ مُعَاوِيَةَ بَاعَ سِقَايَةً مِنْ ذَهَبٍ أَوْ وَرِقٍ بِأَكْثَرَ مِنْ وَزْنِهَا فَقَالَ أَبُو الدَّرْدَاءِسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ مِثْلِ هَذَا إِلَّا مِثْلًا بِمِثْلٍ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Zaid bin Aslam] dari ['Atho` bin Yasar] bahwa Mu'awiyah menjual geriba dari emas atau perak dengan lebih dari timbanganya, kemudian [Abu Ad Darda`] berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam melarang hal seperti ini kecuali semisalnya dengan yang semisalnya."},"4281":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ أَبِي شُجَاعٍ سَعِيدِ بْنِ يَزِيدَ عَنْ خَالِدِ بْنِ أَبِي عِمْرَانَ عَنْ حَنَشٍ الصَّنْعَانِيِّ عَنْ فَضَالَةَ بْنِ عُبَيْدٍ قَالَاشْتَرَيْتُ يَوْمَ خَيْبَرَ قِلَادَةً فِيهَا ذَهَبٌ وَخَرَزٌ بِاثْنَيْ عَشَرَ دِينَارًا فَفَصَّلْتُهَا فَوَجَدْتُ فِيهَا أَكْثَرَ مِنْ اثْنَيْ عَشَرَ دِينَارًا فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا تُبَاعُ حَتَّى تُفَصَّلَ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Abu Syuja' Sa'id bin Yazid] dari [Khalid bin Abu Imran] dari [Hanasy Ash Shan'ani] dari [Fadhalah bin 'Ubaid], ia berkata; saya membeli kalung yang mengandung emas serta mutiara padanya saat Perang Khaibar, dengan harga dua belas dinar. Kemudian saya memisahkannya dan mendapatinya lebih dari dua belas dinar, kemudian hal tersebut disebutkan kepada Nabi shallallahu 'alaihi wasallam lalu beliau bersabda: \"Tidak boleh dijual hingga emas tersebut dipisahkan.\""},"4282":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ مَحْبُوبٍ قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ أَبِي عِمْرَانَ عَنْ حَنَشٍ الصَّنْعَانِيِّ عَنْ فَضَالَةَ بْنِ عُبَيْدٍ قَالَأَصَبْتُ يَوْمَ خَيْبَرَ قِلَادَةً فِيهَا ذَهَبٌ وَخَرَزٌ فَأَرَدْتُ أَنْ أَبِيعَهَا فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ افْصِلْ بَعْضَهَا مِنْ بَعْضٍ ثُمَّ بِعْهَا","id":"Telah mengabarkan kepada kami ['Amr bin Manshur], ia berkata; telah menceritakan kepada kami [Muhammad bin Mahbub], ia berkata; telah menceritakan kepada kami [Husyaim], ia berkata; telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Khalid bin Abu Imran] dari [Hanasy Ash Shan'ani] dari [Fadhalah bin 'Ubaid], ia berkata; pada saat perang Khaibar saya mendapatkan kalung yang mengandung emas dan mutiara, kemudian saya hendak menjualnya, kemudian hal tersebut diutarakan kepada Nabi shallallahu 'alaihi wasallam, kemudian beliau bersabda: \"Pisahkan sebagian dari sebagiannya kemudian juallah.\" "},"4283":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ عَنْ سُفْيَانَ عَنْ عَمْرٍو عَنْ أَبِي الْمِنْهَالِ قَالَبَاعَ شَرِيكٌ لِي وَرِقًا بِنَسِيئَةٍ فَجَاءَنِي فَأَخْبَرَنِي فَقُلْتُ هَذَا لَا يَصْلُحُ فَقَالَ قَدْ وَاللَّهِ بِعْتُهُ فِي السُّوقِ وَمَا عَابَهُ عَلَيَّ أَحَدٌ فَأَتَيْتُ الْبَرَاءَ بْنَ عَازِبٍ فَسَأَلْتُهُ فَقَالَ قَدِمَ عَلَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ وَنَحْنُ نَبِيعُ هَذَا الْبَيْعَ فَقَالَ مَا كَانَ يَدًا بِيَدٍ فَلَا بَأْسَ وَمَا كَانَ نَسِيئَةً فَهُوَ رِبًاثُمَّ قَالَ لِي ائْتِ زَيْدَ بْنَ أَرْقَمَ فَأَتَيْتُهُ فَسَأَلْتُهُ فَقَالَ مِثْلَ ذَلِكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dari [Sufyan] dari ['Amr] dari [Abu Al Minhal], ia berkata; Syarik menjualkan perak untukku dengan tidak tunai, kemudian ia datang dan mengabarkan kepadaku, maka saya katakan; ini tidak boleh. Lalu ia berkata; cukup, demi Allah, saya telah menjualnya di pasar dan tidak ada seorang seorangpun yang mencelaku. Kemudian saya datang kepada [Al Barra` bin 'Azib] dan bertanya kepadanya, lalu ia berkata; Nabi shallallahu 'alaihi wasallam datang kepada kami di Madinah dan kami sedang berjual beli seperti ini, kemudian beliau bersabda: \"Selama serah terima secara langsung maka tidak mengapa, dan yang tidak tunai maka itu Adalah riba.\" Kemudian ia berkata kepadaku; datanglah kepada [Zaid bin Arqam]. Kemudian saya datang kepada dan bertanya kepadanya, lalu ia mengatakan seperti itu. "},"4284":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ الْحَسَنِ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي عَمْرُو بْنُ دِينَارٍ وَعَامِرُ بْنُ مُصْعَبٍ أَنَّهُمَا سَمِعَا أَبَا الْمِنْهَالِ يَقُولُ سَأَلْتُ الْبَرَاءَ بْنَ عَازِبٍ وَزَيْدَ بْنَ أَرْقَمَ فَقَالَاكُنَّا تَاجِرَيْنِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْنَا نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّرْفِ فَقَالَ إِنْ كَانَ يَدًا بِيَدٍ فَلَا بَأْسَ وَإِنْ كَانَ نَسِيئَةً فَلَا يَصْلُحُ","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Hasan], ia berkata; telah menceritakan kepada kami [Hajjaj], ia berkata; telah berkata [Ibnu Juraij]; telah mengabarkan kepadaku ['Amr bin Dinar] serta ['Amir bin Mush'ab] bahwa mereka telah mendengar [Abu Al Minhal] berkata; saya mendengar [Al Bara` bin 'Azib] dan [Zaid bin Arqam] berkata; dahulu kami adalah pedagang pada zaman Rasulullah shallallahu 'alaihi wasallam kemudian kami bertanya kepada Nabi Allah shallallahu 'alaihi wasallam mengenai barter, lalu beliau bersabda: \"Apabila serah terima secara langsung maka tidak mengapa dan apabila tidak tunai maka tidak boleh.\""},"4285":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ الْحَكَمِ عَنْ مُحَمَّدٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ حَبِيبٍ قَالَ سَمِعْتُ أَبَا الْمِنْهَالِ قَالَسَأَلْتُ الْبَرَاءَ بْنَ عَازِبٍ عَنْ الصَّرْفِ فَقَالَ سَلْ زَيْدَ بْنَ أَرْقَمَ فَإِنَّهُ خَيْرٌ مِنِّي وَأَعْلَمُ فَسَأَلْتُ زَيْدًا فَقَالَ سَلْ الْبَرَاءَ فَإِنَّهُ خَيْرٌ مِنِّي وَأَعْلَمُ فَقَالَا جَمِيعًا نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْوَرِقِ بِالذَّهَبِ دَيْنًا","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah bin Al Hakam] dari [Muhammad] telah menceritakan kepada kami [Syu'bah] dari [Habib], dia berkata; \"Saya mendengar [Abu Al Minhal] berkata; \"Saya bertanya kepada [Al Bara` bin 'Azib] mengenai barter, kemudian dia berkata; \"Tanyakan kepada [Zaid bin Arqam], sesungguhnya dia lebih baik dariku dan lebih mengetahui.\" Lalu saya bertanya kepada Zaid kemudian dia berkata; \"Tanyakan kepada Al Bara` sesungguhnya dia lebih baik dariku dan lebih mengetahui.\" Kemudian mereka berdua berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang menjual perak dengan emas dengan cara dihutang.\" "},"4286":{"ar":"وَفِيمَا قُرِئَ عَلَيْنَا أَحْمَدُ بْنُ مَنِيعٍ قَالَ حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي إِسْحَقَ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي بَكْرَةَ عَنْ أَبِيهِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الْفِضَّةِ بِالْفِضَّةِ وَالذَّهَبِ بِالذَّهَبِ إِلَّا سَوَاءً بِسَوَاءٍ وَأَمَرَنَا أَنْ نَبْتَاعَ الذَّهَبَ بِالْفِضَّةِ كَيْفَ شِئْنَا وَالْفِضَّةَ بِالذَّهَبِ كَيْفَ شِئْنَا","id":"Dan di antara yang dibacakan kepada kami oleh [Ahmad bin Mani'], dia berkata; telah menceritakan kepada kami ['Abbad bin Al 'Awwab] telah menceritakan kepada kami [Yahya bin Abu Ishaq] telah menceritakan kepada kami [Abdur Rahman bin Abu Bakrah] dari [ayahnya], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang menjual perak dengan perak dan emas dengan emas kecuali bila sama ukuran/beratnya, dan beliau memerintahkan kami agar menjual emas dengan perak semau kami serta perak dengan emas semau kami.\" "},"4287":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ مُحَمَّدِ بْنِ كَثِيرٍ الْحَرَّانِيُّ قَالَ حَدَّثَنَا أَبُو تَوْبَةَ قَالَ حَدَّثَنَا مُعَاوِيَةُ بْنُ سَلَّامٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِ قَالَنَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَبِيعَ الْفِضَّةَ بِالْفِضَّةِ إِلَّا عَيْنًا بِعَيْنٍ سَوَاءً بِسَوَاءٍ وَلَا نَبِيعَ الذَّهَبَ بِالذَّهَبِ إِلَّا عَيْنًا بِعَيْنٍ سَوَاءً بِسَوَاءٍ بِسَوَاءٍ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَبَايَعُوا الذَّهَبَ بِالْفِضَّةِ كَيْفَ شِئْتُمْ وَالْفِضَّةَ بِالذَّهَبِ كَيْفَ شِئْتُمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya bin Muhammad bin Katsir Al Harrani] telah menceritakan kepada kami [Abu Taubah] telah menceritakan kepada kami [Mu'awiyah bin Sallam] dari [Yahya bin Abu Katsir] dari [Abdur Rahman bin Abu Bakrah] dari [ayahnya], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang kami untuk menjual perak dengan perak kecuali secara kontan dan keduanya sama beratnya. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Juallah emas dengan perak bagaimanapun kalian mau, dan perak dengan emas bagaimanapun kalian mau.\""},"4288":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي يَزِيدَ سَمِعَ ابْنَ عَبَّاسٍ يَقُولُ حَدَّثَنِي أُسَامَةُ بْنُ زَيْدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا رِبًا إِلَّا فِي النَّسِيئَةِ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] telah menceritakan kepada kami [Sufyan] dari ['Ubaidullah bin Abu Yazid], dia telah mendengar [Ibnu Abbas] berkata; \"Telah menceritakan kepadaku [Usamah bin Zaid] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada riba kecuali di dalam kredit.\""},"4289":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ أَبِي صَالِحٍ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُقُلْتُ لِابْنِ عَبَّاسٍ أَرَأَيْتَ هَذَا الَّذِي تَقُولُ أَشَيْئًا وَجَدْتَهُ فِي كِتَابِ اللَّهِ عَزَّ وَجَلَّ أَوْ شَيْئًا سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا وَجَدْتُهُ فِي كِتَابِ اللَّهِ عَزَّ وَجَلَّ وَلَا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَكِنْ أُسَامَةُ بْنُ زَيْدٍ أَخْبَرَنِي أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا الرِّبَا فِي النَّسِيئَةِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Sufyan] dari ['Amru] dari [Abu Shalih], dia mendengar [Abu Sa'id Al Khudri] berkata; saya berkata kepada [Ibnu Abbas]; \"Bagaimana pendapatmu mengenai sesuatu yang engkau katakan ini, apakah itu adalah sesuatu yang engkau dapatkan di dalam Kitab Allah 'azza wajalla atau sesuatu yang engkau dengar dari Rasulullah shallallahu 'alaihi wasallam?\" Ibnu Abbas berkata; \"Saya tidak mendapatkannya dalam Kitab Allah 'azza wajalla dan tidak pula mendengarnya dari Rasulullah shallallahu 'alaihi wasallam akan tetapi [Usamah bin Zaid] telah mengabarkan kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya riba itu hanya ada dalam pembayaran yang ditangguhkan.\""},"4290":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ يَحْيَى عَنْ أَبِي نُعَيْمٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عُمَرَ قَالَكُنْتُ أَبِيعُ الْإِبِلَ بِالْبَقِيعِ فَأَبِيعُ بِالدَّنَانِيرِ وَآخُذُ الدَّرَاهِمَ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِ حَفْصَةَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي أُرِيدُ أَنْ أَسْأَلَكَ إِنِّي أَبِيعُ الْإِبِلَ بِالْبَقِيعِ فَأَبِيعُ بِالدَّنَانِيرِ وَآخُذُ الدَّرَاهِمَ قَالَ لَا بَأْسَ أَنْ تَأْخُذَهَا بِسِعْرِ يَوْمِهَا مَا لَمْ تَفْتَرِقَا وَبَيْنَكُمَا شَيْءٌ","id":"Telah mengabarkan kepada kami [Ahmad bin Yahya] dari [Abu Nu'aim] telah menceritakan kepada kami [Hammad bin Salamah] dari [Simak bin Harb] dari [Sa'id bin Jubair] dari [Ibnu Umar], dia berkata; \"Saya pernah menjual unta di Baqi' saya menjualnya dengan beberapa dinar, dan kuambil beberapa dirham, kemudian saya datang menemui Nabi shallallahu 'alaihi wasallam di rumah Hafshah, saya berkata; \"Wahai Rasulullah, saya ingin bertanya. Sesungguhnya saya menjual unta di Baqi', saya menjualnya dengan dinar dan mengambil dirham.\" Beliau bersabda: \"Tidak mengapa engkau mengambilnya dengan harga pada hari itu, selama kalian berdua belum berpisah sementara (ketika itu) di antara kalian ada sesuatu.\""},"4291":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ ابْنِ جُبَيْرٍ عَنْ ابْنِ عُمَرَ قَالَكُنْتُ أَبِيعُ الذَّهَبَ بِالْفِضَّةِ أَوْ الْفِضَّةَ بِالذَّهَبِ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ بِذَلِكَ فَقَالَ إِذَا بَايَعْتَ صَاحِبَكَ فَلَا تُفَارِقْهُ وَبَيْنَكَ وَبَيْنَهُ لَبْسٌ","id":"Telah mengabarkan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak] dari [Ibnu Jubair] dari [Ibnu Umar], dia berkata; \"Saya pernah menjual emas dengan perak atau perak dengan emas kemudian saya datang menemui Rasulullah shallallahu 'alaihi wasallam dan mengabarkan kepada beliau mengenai hal tersebut. Lalu beliau bersabda: \"Apabila engkau menjual kepada sahabatmu maka janganlah engkau meninggalkannya sedang diantara kalian ada ketidak jelasan.\""},"4292":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ أَنْبَأَنَا مُوسَى بْنُ نَافِعٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍأَنَّهُ كَانَ يَكْرَهُ أَنْ يَأْخُذَ الدَّنَانِيرَ مِنْ الدَّرَاهِمِ وَالدَّرَاهِمَ مِنْ الدَّنَانِيرِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Waki'] telah memberitakan kepada kami [Musa bin Nafi'] dari [Sa'id bin Jubair] bahwa dia membenci untuk mengambil dinar sebagai ganti dari dirham dan mengambil dirham sebagai ganti dari dinar."},"4293":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ أَنْبَأَنَا مُؤَمَّلٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي هَاشِمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عُمَرَأَنَّهُ كَانَ لَا يَرَى بَأْسًا يَعْنِي فِي قَبْضِ الدَّرَاهِمِ مِنْ الدَّنَانِيرِ وَالدَّنَانِيرِ مِنْ الدَّرَاهِمِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] telah memberitakan kepada kami [Muammal] telah menceritakan kepada kami [Sufyan] dari [Abu Hasyim] dari [Sa'id bin Jubair] dari [Ibnu Umar] bahwa dia berpendapat, tidak mengapa mengenai pengambilan dirham sebagai ganti dari dinar dan mengambil dinar sebagai ganti dari dirham."},"4294":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الْهُذَيْلِ عَنْ إِبْرَاهِيمَفِي قَبْضِ الدَّنَانِيرِ مِنْ الدَّرَاهِمِ أَنَّهُ كَانَ يَكْرَهُهَا إِذَا كَانَ مِنْ قَرْضٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abdur Rahman] telah menceritakan kepada kami [Sufyan] dari [Abu Al Hudzail] dari [Ibrahim] mengenai pengambilan dinar sebagai ganti dari dirham bahwa dia membencinya apabila berasal dari hutang."},"4295":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مُوسَى أَبِي شِهَابٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍأَنَّهُ كَانَ لَا يَرَى بَأْسًا وَإِنْ كَانَ مِنْ قَرْضٍأَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا مُوسَى بْنُ نَافِعٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ بِمِثْلِهِ قَالَ أَبُو عَبْد الرَّحْمَنِ كَذَا وَجَدْتُهُ فِي هَذَا الْمَوْضِعِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abdur Rahman] telah menceritakan kepada kami [Sufyan] dari [Musa Abu Syihab] dari [Sa'id bin Jubair] bahwa dia melihat tidak mengapa walaupun berasal dari hutang. Telah mengabarkan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Musa bin Nafi'] dari [Sa'id bin Jubair] dengan hadits yang semisal. Abu Abdurrahman berkata; \"Demikianlah yang saya dapatkan pada permasalahan ini."},"4296":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَمَّارٍ قَالَ حَدَّثَنَا الْمُعَافَى عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عُمَرَ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ رُوَيْدَكَ أَسْأَلُكَ إِنِّي أَبِيعُ الْإِبِلَ بِالْبَقِيعِ بِالدَّنَانِيرِ وَآخُذُ الدَّرَاهِمَ قَالَ لَا بَأْسَ أَنْ تَأْخُذَ بِسِعْرِ يَوْمِهَا مَا لَمْ تَفْتَرِقَا وَبَيْنَكُمَا شَيْءٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Ammar] telah menceritakan kepada kami [Al Mu'afa] dari [Hammad bin Salamah] dari [Simak bin Harb] dari [Sa'id bin Jubair] dari [Ibnu Umar], dia berkata; \"Saya datang menemui Nabi shallallahu 'alaihi wasallam dan mengatakan; \"Perlahan, saya akan bertanya kepada Tuan. Sesungguhnya saya menjual unta di Baqi' dengan dinar dan mengambil dirham.\" Beliau bersabda: \"Tidak mengapa engkau mengambil harga pada hari itu selama belum berpisah sementara diantara kalian terdapat sesuatu.\" "},"4297":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ قَالَ أَخْبَرَنِي مُحَارِبُ بْنُ دِثَارٍ عَنْ جَابِرٍ قَالَلَمَّا قَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ دَعَا بِمِيزَانٍ فَوَزَنَ لِي وَزَادَنِي","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] telah menceritakan kepada kami [Khalid] dari [Syu'bah] telah memberitakan kepadaku [Muharib bin Ditsar] dari [Jabir], dia berkata; \"Tatkala Nabi shallallahu 'alaihi wasallam datang ke Madinah, beliau meminta timbangan, kemudian beliau menimbang untukku dan menambahiku.\""},"4298":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ سُفْيَانَ عَنْ مِسْعَرٍ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ جَابِرٍ قَالَقَضَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَزَادَنِي","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dan [Muhammad bin Abdullah bin Yazid] dari [Sufyan] dari [Mis'ar] dari [Muharib bin Ditsar] dari [Jabir], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam membayarku dan beliau menambahiku.\""},"4299":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ سِمَاكٍ عَنْ سُوَيْدِ بْنِ قَيْسٍ قَالَجَلَبْتُ أَنَا وَمَخْرَفَةُ الْعَبْدِيُّ بَزًّا مِنْ هَجَرَ فَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ بِمِنًى وَوَزَّانٌ يَزِنُ بِالْأَجْرِ فَاشْتَرَى مِنَّا سَرَاوِيلَ فَقَالَ لِلْوَزَّانِ زِنْ وَأَرْجِحْ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Abdur Rahman] dari [Sufyan] dari [Simak] dari [Suwaid bin Qais], dia berkata; \"Saya dan Makhrafah Al 'Abdi mendatangkan kain sutera dari Hajar, kemudian Rasulullah shallallahu 'alaihi wasallam mendatangi kami ketika kami berada di Mina, dan terdapat seorang penimbang yang menimbang dengan upah, kemudian beliau membeli beberapa celana panjang dari kami, kemudian beliau berkata kepada penimbang tersebut: \"Timbanglah dan lebihkan.\""},"4300":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ عَنْ مُحَمَّدٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكِ بْنِ حَرْبٍ قَالَ سَمِعْتُ أَبَا صَفْوَانَ قَالَبِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرَاوِيلَ قَبْلَ الْهِجْرَةِ فَأَرْجَحَ لِي","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] dari [Muhammad] telah menceritakan kepada kami [Syu'bah] dari [Simak bin Harb], dia berkata; \"Saya mendengar [Abu Shafwan] berkata; \"Saya menjual beberapa celana panjang kepada Rasulullah shallallahu 'alaihi wasallam sebelum berhijrah dan beliau melebihkan berat timbangannya untukku.\" "},"4301":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ عَنْ الْمُلَائِيِّ عَنْ سُفْيَانَ ح وَأَنْبَأَنَا مُحَمَّدُ بْنُ إِسْمَاعِيلَ قَالَ أَنْبَأَنَا أَبُو نُعَيْمٍ عَنْ سُفْيَانَ عَنْ حَنْظَلَةَ عَنْ طَاوُسٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمِكْيَالُ عَلَى مِكْيَالِ أَهْلِ الْمَدِينَةِ وَالْوَزْنُ عَلَى وَزْنِ أَهْلِ مَكَّةَوَاللَّفْظُ لِإِسْحَقَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dari [Al Mulai] dari [Sufyan]. Dalam jalur lain disebutkan: telah memberitakan kepada kami [Muhammad bin Isma'il] telah memberitakan kepada kami [Abu Nu'aim] dari [Sufyan] dari [Hanzhalah] dari [Thawus] dari [Ibnu Umar], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Takaran itu menyesuaikan dengan takaran penduduk Madinah, sedang timbangan menyesuaikan dengan timbangan penduduk Makkah, \" lafazh hadits tersebut adalah lafazh Ishaq.\""},"4302":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ ابْتَاعَ طَعَامًا فَلَا يَبِعْهُ حَتَّى يَسْتَوْفِيَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, dari [Ibnu Al Qasim] dari [Malik] dari [Nafi'] dari [Ibnu Umar], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang membeli makanan maka janganlah dia menjualnya hingga mengambilnya.\""},"4303":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ أَنْبَأَنَا ابْنُ الْقَاسِمِ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ ابْتَاعَ طَعَامًا فَلَا يَبِعْهُ حَتَّى يَقْبِضَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] telah memberitakan kepada kami [Ibnu Al Qasim] dari [Malik] dari [Abdullah bin Dinar] dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang membeli makanan maka janganlah dia menjualnya hingga mengambilnya.\""},"4304":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا قَاسِمٌ عَنْ سُفْيَانَ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ ابْتَاعَ طَعَامًا فَلَا يَبِيعُهُ حَتَّى يَكْتَالَهُأَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ أَنْبَأَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ عَمْرٍو عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ وَالَّذِي قَبْلَهُ حَتَّى يَقْبِضَهُ","id":"Telah mengabarkan kepada kami [Ahmad bin Harb] telah menceritakan kepada kami [Qasim] dari [Sufyan] dari [Ibnu Thawus] dari [ayahnya] dari [Ibnu Abbas], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang membeli makanan maka janganlah dia menjualnya hingga menakarnya.\" Telah mengabarkan kepada kami [Ishaq bin Manshur] telah memberitakan kepada kami [Abdur Rahman] dari [Sufyan] dari ['Amru] dari [Thawus] dari [Ibnu Abbas], dia berkata; \"Saya mendengar Nabi shallallahu 'alaihi wasallam (bersabda) dengan hadits seperti itu dan yang sebelumnya hingga dia mengambilnya.\""},"4305":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ طَاوُسٍ عَنْ طَاوُسٍ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُأَمَّا الَّذِي نَهَى عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُبَاعَ حَتَّى يُسْتَوْفَى الطَّعَامُ","id":"Telah mengabarkan kepada kami [Qutaibah] telah menceritakan kepada kami [Sufyan] dari [Ibnu Thawus] dari [Thawus], dia berkata; \"Saya mendengar [Ibnu Abbas] berkata; \"Adapun yang dilarang Rasulullah shallallahu 'alaihi wasallam untuk dijual hingga diambil adalah makanan.\""},"4306":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ ابْتَاعَ طَعَامًا فَلَا يَبِيعُهُ حَتَّى يَقْبِضَهُقَالَ ابْنُ عَبَّاسٍ فَأَحْسَبُ أَنَّ كُلَّ شَيْءٍ بِمَنْزِلَةِ الطَّعَامِ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdur Razzaq] telah menceritakan kepada kami [Ma'mar] dari [Ibnu Thawus] dari [ayahnya] dari [Ibnu Abbas], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang membeli makanan maka janganlah dia menjualnya hingga mengambilnya.\" Ibnu Abbas berkata; \"Saya mengira bahwa segala sesuatu sama dengan makanan.\" "},"4307":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ الْحَسَنِ عَنْ حَجَّاجِ بْنِ مُحَمَّدٍ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي عَطَاءٌ عَنْ صَفْوَانَ بْنِ مَوْهَبٍ أَنَّهُ أَخْبَرَهُ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ صَيْفِيٍّ عَنْ حَكِيمِ بْنِ حِزَامٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَبِعْ طَعَامًا حَتَّى تَشْتَرِيَهُ وَتَسْتَوْفِيَهُأَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْحَسَنِ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ قَالَ ابْنُ جُرَيْجٍ وَأَخْبَرَنِي عَطَاءٌ ذَلِكَ عَنْ عَبْدِ اللَّهِ بْنِ عِصْمَةَ الْجُشَمِيِّ عَنْ حَكِيمِ بْنِ حِزَامٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepadaku [Ibrahim bin Al Hasan] dari [Hajjaj bin Muhammad] telah berkata [Ibnu Juraij] telah mengabarkan kepadaku ['Atho`] dari [Shafwan bin Mauhab] bahwa dia telah dikabarkan kepadanya dari [Abdullah bin Muhammad bin Shaifi] dari [Hakim bin Hizam], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah engkau menjual makanan hingga engkau membeli dan mengambilnya.\" Telah mengabarkan kepada kami [Ibrahim bin Al Hasan], ia berkata; telah menceritakan kepada kami [Hajjaj], ia berkata; telah berkata [Ibnu Juraij] dan telah mengabarkan kepadaku ['Atho`] dari [Abdullah bin 'Ishmah Al Jusyami] dari [Hakim bin Hizam] dari Nabi shallallahu 'alaihi wasallam. "},"4308":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ حِزَامِ بْنِ حَكِيمٍ قَالَ قَالَ حَكِيمُ بْنُ حِزَامٍابْتَعْتُ طَعَامًا مِنْ طَعَامِ الصَّدَقَةِ فَرَبِحْتُ فِيهِ قَبْلَ أَنْ أَقْبِضَهُ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ لَا تَبِعْهُ حَتَّى تَقْبِضَهُ","id":"Telah mengabarkan kepada kami [Sulaiman bin Manshur], ia berkata; telah menceritakan kepada kami [Abu Al Ahwash] dari [Abdul 'Aziz bin Rufai'] dari ['Atho` bin Abu Rabah] dari [Hizam bin Hakim], ia berkata; telah berkata [Hakim bin Hizam]; saya membeli makanan dari makanan sedekah kemudian mendapatkan keuntungan padanya sebelum mengambilnya, kemudian saya datang kepada Rasulullah shallallahu 'alaihi wasallam dan menyebutkan hal tersebut kepada beliau. Kemudian beliau bersabda: \"Janganlah engkau menjualnya hingga engkau mengambilnya.\""},"4309":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ الْمُنْذِرِ بْنِ عُبَيْدٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يَبِيعَ أَحَدٌ طَعَامًا اشْتَرَاهُ بِكَيْلٍ حَتَّى يَسْتَوْفِيَهُ","id":"Telah mengabarkan kepada kami [Sulaiman bin Daud] dan [Al Harits bin Miskin] dengan membacakan riwayat, dan saya mendengar, dari [Ibnu Wahb], ia berkata; telah mengabarkan kepadaku ['Amru bin Al Harits] dari [Al Mundzir bin 'Ubaid] dari [Al Qasim bin Muhammad] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam melarang seseorang menjual makanan yang ia beli dengan takaran hingga ia mengambilnya."},"4310":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَكُنَّا فِي زَمَانِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَبْتَاعُ الطَّعَامَ فَيَبْعَثُ عَلَيْنَا مَنْ يَأْمُرُنَا بِانْتِقَالِهِ مِنْ الْمَكَانِ الَّذِي ابْتَعْنَا فِيهِ إِلَى مَكَانٍ سِوَاهُ قَبْلَ أَنْ نَبِيعَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, dari [Ibnu Al Qasim], ia berkata; telah menceritakan kepadaku [Malik] dari [Nafi'] dari [Abdullah bin Umar], ia berkata; kami pada zaman Rasulullah shallallahu 'alaihi wasallam membeli makanan kemudian diutus kepada kami orang yang memerintahkan kami untuk memindahnya dari tempat kami membelinya ke tempat lainnya sebelum menjualnya."},"4311":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَأَنَّهُمْ كَانُوا يَبْتَاعُونَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَعْلَى السُّوقِ جُزَافًا فَنَهَاهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَبِيعُوهُ فِي مَكَانِهِ حَتَّى يَنْقُلُوهُ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id], ia berkata; telah menceritakan kepada kami [Yahya] dari ['Ubaidullah], ia berkata; telah mengabarkan kepadaku [Nafi'] dari [Ibnu Umar] bahwa mereka dahulu membeli pada zaman Rasulullah shallallahu 'alaihi wasallam di atas pasar tanpa diketahui kadarnya, kemudian Rasulullah shallallahu 'alaihi wasallam melarang mereka untuk menjualnya di tempatnya hingga ia memindahnya. "},"4312":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ قَالَ حَدَّثَنَا شُعَيْبُ بْنُ اللَّيْثِ عَنْ أَبِيهِ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَ حَدَّثَهُمْأَنَّهُمْ كَانُوا يَبْتَاعُونَ الطَّعَامَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الرُّكْبَانِ فَنَهَاهُمْ أَنْ يَبِيعُوا فِي مَكَانِهِمْ الَّذِي ابْتَاعُوا فِيهِ حَتَّى يَنْقُلُوهُ إِلَى سُوقِ الطَّعَامِ","id":"Telah mengabarkan kepada kami [Abdur Rahman bin Abdullah bin Abdullah bin Abdul Hakam], ia berkata; telah menceritakan kepada kami [Syu'aib bin Al Laits] dari [ayahnya] dari [Muhammad bin Abdur Rahman] dari [Nafi'] bahwa [Ibnu Umar] telah menceritakan kepada mereka bahwa mereka membeli makanan pada zaman Rasulullah shallallahu 'alaihi wasallam dari orang-orang membawa dagangan ke pasar kemudian beliau melarang mereka untuk menjual di tempat mereka membelinya hingga memindahnya ke pasar makanan. "},"4313":{"ar":"أَخْبَرَنَا نَصْرُ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَزِيدُ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَرَأَيْتُ النَّاسَ يُضْرَبُونَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اشْتَرَوْا الطَّعَامَ جُزَافًا أَنْ يَبِيعُوهُ حَتَّى يُؤْوُوهُ إِلَى رِحَالِهِمْ","id":"Telah mengabarkan kepada kami [Nashr bin Ali], ia berkata; telah menceritakan kepada kami [Yazid] dari [Ma'mar] dari [Az Zuhri] dari [Salim] dari [ayahnya], ia berkata; saya melihat manusia pada zaman Rasulullah shallallahu 'alaihi wasallam mendapatkan hukuman apabila mereka membeli makanan tidak diketahui kadarnya dan menjualnya kecuali mereka mengambilnya ada memindahkannya ke tempat tinggal mereka. "},"4314":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ آدَمَ عَنْ حَفْصِ بْنِ غِيَاثٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْاشْتَرَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ يَهُودِيٍّ طَعَامًا إِلَى أَجَلٍ وَرَهَنَهُ دِرْعَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Adam] dari [Hafsh bin Ghiyats] dari [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam membeli makanan dari seorang Yahudi hingga suatu tempo dan beliau menggadaikan baju zirahnya kepadanya. "},"4315":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا هِشَامٌ قَالَ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّهُ مَشَى إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِخُبْزِ شَعِيرٍ وَإِهَالَةٍ سَنِخَةٍ قَالَ وَلَقَدْ رَهَنَ دِرْعًا لَهُ عِنْدَ يَهُودِيٍّ بِالْمَدِينَةِ وَأَخَذَ مِنْهُ شَعِيرًا لِأَهْلِهِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud], ia berkata; telah menceritakan kepada kami [Khalid], ia berkata; telah menceritakan kepada kami [Hisyam], ia berkata; telah menceritakan kepada kami [Qatadah] dari [Anas bin Malik] bahwa ia berjalan kepada Rasulullah shallallahu 'alaihi wasallam membawa roti dari gandum dan lemak cair yang telah berubah baunya. Ia berkata; sungguh beliau telah menggadaikan baju zirahnya pada seorang Yahudi di Madinah dan darinya ia mengambil gandum untuk keluarganya. "},"4316":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ وَحُمَيْدُ بْنُ مَسْعَدَةَ عَنْ يَزِيدَ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ سَلَفٌ وَبَيْعٌ وَلَا شَرْطَانِ فِي بَيْعٍ وَلَا بَيْعُ مَا لَيْسَ عِنْدَكَ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] dan [Humaid bin Mas'adah] dari [Yazid], ia berkata; telah menceritakan kepada kami [Ayyub] dari ['Amru bin Syu'aib] dari [ayahnya] dari [kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal jual beli dengan syarat diberi hutang, serta dua syarat dalam jual beli serta menjual apa yang tidak kamu miliki.\""},"4317":{"ar":"أَخْبَرَنَا عُثْمَانُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ عَنْ عَبَّادِ بْنِ الْعَوَّامِ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ أَبِي رَجَاءٍ قَالَ عُثْمَانُ هُوَ مُحَمَّدُ بْنُ سَيْفٍ عَنْ مَطَرٍ الْوَرَّاقِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ عَلَى رَجُلٍ بَيْعٌ فِيمَا لَا يَمْلِكُ","id":"Telah mengabarkan kepada kami [Utsman bin Abdullah], ia berkata; telah menceritakan kepada kami [Sa'id bin Sulaiman] dari ['Abbad bin Al 'Awwam] dari [Sa'id bin Abu 'Arubah] dari [Abu Raja`], Utsman berkata dia adalah Muhammad bin Saif dari [Mathar] dari ['Amru bin Syu'aib] dari [ayahnya] dari [kakeknya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh seseorang menjual sesuatu yang tidak ia miliki.\" "},"4318":{"ar":"حَدَّثَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ حَدَّثَنَا أَبُو بِشْرٍ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ حَكِيمِ بْنِ حِزَامٍ قَالَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ يَأْتِينِي الرَّجُلُ فَيَسْأَلُنِي الْبَيْعَ لَيْسَ عِنْدِي أَبِيعُهُ مِنْهُ ثُمَّ أَبْتَاعُهُ لَهُ مِنْ السُّوقِ قَالَ لَا تَبِعْ مَا لَيْسَ عِنْدَكَ","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub], ia berkata; telah menceritakan kepada kami [Husyaim], ia berkata; telah menceritakan kepada kami [Abu Bisyr] dari [Yusuf bin Mahak] dari [Hakim bin Hizam], ia berkata; saya bertanya kepada Nabi shallallahu 'alaihi wasallam, saya katakan; wahai Rasulullah, datang kepadaku seorang laki-laki dan meminta kepadaku untuk menjual apa yang tidak ada padaku, saya jual kepadanya kemudian saya membeli membeli untuknya dari pasar. Beliau bersabda: \"Janganlah engkau menjual apa yang tidak engkau miliki.\""},"4319":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي الْمُجَالِدِ قَالَ سَأَلْتُ ابْنَ أَبِي أَوْفَىعَنْ السَّلَفِ قَالَ كُنَّا نُسْلِفُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَعُمَرَ فِي الْبُرِّ وَالشَّعِيرِ وَالتَّمْرِ إِلَى قَوْمٍ لَا أَدْرِي أَعِنْدَهُمْ أَمْ لَاوَابْنُ أَبْزَى قَالَ مِثْلَ ذَلِكَ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id], ia berkata; telah menceritakan kepada kami [Yahya] dari [Syu'bah] dari [Abdullah bin Abu Al Mujalid], ia berkata; saya bertanya kepada [Ibnu Abu Aufa] mengenai jual beli secara salaf. Ia berkata; dahulu kami melakukan salaf pada zaman Rasulullah shallallahu 'alaihi wasallam, Abu Bakr dan Umar dalam gandum dan jewawut serta kurma kepada suatu kaum yang saya tidak mengetahui apakah mereka memiliki atau tidak. Dan [Ibnu Abzaa] mengatakan seperti itu. "},"4320":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ أَنْبَأَنَا شُعْبَةُ قَالَ حَدَّثَنَا ابْنُ أَبِي الْمُجَالِدِ وَقَالَ مَرَّةً عَبْدُ اللَّهِ وَقَالَ مَرَّةً مُحَمَّدٌ قَالَتَمَارَى أَبُو بُرْدَةَ وَعَبْدُ اللَّهِ بْنُ شَدَّادٍ فِي السَّلَمِ فَأَرْسَلُونِي إِلَى ابْنِ أَبِي أَوْفَى فَسَأَلْتُهُ فَقَالَ كُنَّا نُسْلِمُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَى عَهْدِ أَبِي بَكْرٍ وَعَلَى عَهْدِ عُمَرَ فِي الْبُرِّ وَالشَّعِيرِ وَالزَّبِيبِ وَالتَّمْرِ إِلَى قَوْمٍ مَا نُرَى عِنْدَهُمْوَسَأَلْتُ ابْنَ أَبْزَى فَقَالَ مِثْلَ ذَلِكَ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan], ia berkata; telah menceritakan kepada kami [Abu Daud], ia berkata; telah memberitakan kepada kami [Syu'bah], ia berkata; telah menceritakan kepada kami [Ibnu Abu Al Mujalid] dan ia mengatakan terkadang Abdullah dan terkadang Muhammad, ia berkata; Abu Burdah Abdullah bin Syaddad berselisih menganai jual belia secara salam. Kemudian mereka mengutusku kepada [Ibnu Abu Aufa] kemudian saya bertanya kepadanya. Lalu ia berkata; dahulu kami melakukan jual beli dengan cara dihutang pada zaman Rasulullah shallallahu 'alaihi wasallam, dan zaman Abu Bakr serta Umar pada gandum dan jewawut, kismis serta kurma kepada beberapa orang yang kami lihat memiliki barang tersebut. Dan saya bertanya kepada [Ibnu Abza] kemudian ia berkata seperti itu. "},"4321":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ عَبْدِ اللَّهِ بْنِ كَثِيرٍ عَنْ أَبِي الْمِنْهَالِ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ قَالَقَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ وَهُمْ يُسْلِفُونَ فِي التَّمْرِ السَّنَتَيْنِ وَالثَّلَاثَ فَنَهَاهُمْ وَقَالَ مَنْ أَسْلَفَ سَلَفًا فَلْيُسْلِفْ فِي كَيْلٍ مَعْلُومٍ وَوَزْنٍ مَعْلُومٍ إِلَى أَجَلٍ مَعْلُومٍ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Najih] dari [Abdullah bin Katsir] dari [Abu Al Minhal], ia berkata; saya mendengar [Ibnu Abbas] berkata; Rasulullah shallallahu 'alaihi wasallam datang ke Madinah dan mereka melakukan jual beli secara salaf pada kurma selama dalam jangka dua tahun dan tiga tahun. Kemudian beliau melarang mereka dan bersabda: \"Barang siapa yang memberikan hutang maka hendaknya ia menghutangi pada takaran yang diketahui, timbangan yang diketahui hingga jangka yang diketahui.\" "},"4322":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي رَافِعٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَسْلَفَ مِنْ رَجُلٍ بَكْرًا فَأَتَاهُ يَتَقَاضَاهُ بَكْرَهُ فَقَالَ لِرَجُلٍ انْطَلِقْ فَابْتَعْ لَهُ بَكْرًا فَأَتَاهُ فَقَالَ مَا أَصَبْتُ إِلَّا بَكْرًا رَبَاعِيًا خِيَارًا فَقَالَ أَعْطِهِ فَإِنَّ خَيْرَ الْمُسْلِمِينَ أَحْسَنُهُمْ قَضَاءً","id":"Telah mengabarkan kepada kami ['Amru bin Ali], ia berkata; telah menceritakan kepada kami [Abdur Rahman], ia berkata; telah menceritakan kepada kami [Malik] dari [Zaid bin Aslam] dari ['Atho` bin Yasar] dari [Abu Rafi'] bahwa Rasulullah shallallahu 'alaihi wasallam menghutang unta muda kepada seseorang, kemudian orang tersebut datang kepada beliau menuntut unta mudanya, maka Rasulullah shallallahu 'alaihi wasallam bersabda kepada seseorang: \"Pergilah dan belikan untuknya unta muda.\" Kemudian orang tersebut datang kepada beliau dan berkata; saya tidak mendapatkan kecuali unta muda yang berumur empat tahun. Kemudian beliau bersabda: \"Berikan kepadanya sesungguhnya sebaik-baik orang muslim adalah orang yang paling baik dalam membayar.\""},"4323":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ لِرَجُلٍ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِنٌّ مِنْ الْإِبِلِ فَجَاءَ يَتَقَاضَاهُ فَقَالَ أَعْطُوهُ فَلَمْ يَجِدُوا إِلَّا سِنًّا فَوْقَ سِنِّهِ قَالَ أَعْطُوهُ فَقَالَ أَوْفَيْتَنِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ خِيَارَكُمْ أَحْسَنُكُمْ قَضَاءً","id":"Telah mengabarkan kepada kami ['Amru bin Manshur], ia berkata; telah menceritakan kepada kami [Abu Nu'aim], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Salamah bin Kuhail] dari [Abu Salamah] dari [Abu Hurairah], ia berkata; dahulu terdapat seseorang yang memiliki hak atas Rasulullah shallallahu 'alaihi wasallam berupa unta satu tahun, lalu ia datang kepada beliau menuntut, kemudian beliau bersabda: \"Berilah ia.\" Kemudian mereka tidak mendapatkan kecuali yang berumur di atas umur unta tersebut. Beliau bersabda: \"Berikan kepadanya.\" Orang tersebut berkata; engkau telah memenuhi hakku. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya sebaik-baik kalian adalah yang paling baik membayarnya.\" "},"4324":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ قَالَ سَمِعْتُ سَعِيدَ بْنَ هَانِئٍ يَقُولُ سَمِعْتُ عِرْبَاضَ بْنَ سَارِيَةَ يَقُولُبِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَكْرًا فَأَتَيْتُهُ أَتَقَاضَاهُ فَقَالَ أَجَلْ لَا أَقْضِيكَهَا إِلَّا نَجِيبَةً فَقَضَانِي فَأَحْسَنَ قَضَائِي وَجَاءَهُ أَعْرَابِيٌّ يَتَقَاضَاهُ سِنَّهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطُوهُ سِنًّا فَأَعْطَوْهُ يَوْمَئِذٍ جَمَلًا فَقَالَ هَذَا خَيْرٌ مِنْ سِنِّي فَقَالَ خَيْرُكُمْ خَيْرُكُمْ قَضَاءً","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Abdur Rahman bin Mahdi], ia berkata; telah menceritakan kepada kami [Mu'awiyah bin Shalih] ia berkata; saya mendengar [Sa'id bin Hani'] berkata; saya mendengar ['Irbadh bin Sariyah] berkata; saya menjual kepada Rasulullah shallallahu 'alaihi wasallam seekor unta muda. Lalu saya mendatangi beliau menuntut anak unta itu, beliau bersabda: \" Baiklah aku tidak akan membayarnya kepadamu kecuali dengan seekor unta yang berharga, \" lalu beliau membayarku dengan pembayaran yang terbaik, kemudian datanglah kepada beliau seorang badui menuntut seekor unta yang berumur kepada beliau, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \" berikan unta kepadanya, \" lalu mereka pada hari itu memberikan unta, lalu ia berkata; ini lebih baik dari untaku, kemudian beliau bersabda: \" sebaik-baik kalian adalah yang paling baik membayarnya.\""},"4325":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَيَزِيدُ بْنُ زُرَيْعٍ وَخَالِدُ بْنُ الْحَارِثِ قَالُوا حَدَّثَنَا شُعْبَةُ و أَخْبَرَنِي أَحْمَدُ بْنُ فَضَالَةَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى قَالَ حَدَّثَنَا الْحَسَنُ بْنُ صَالِحٍ عَنْ ابْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الْحَيَوَانِ بِالْحَيَوَانِ نَسِيئَةً","id":"Telah mengabarkan kepada kami ['Amru bin Ali], ia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dan [Yazid bin Zurai'] dan [Khalid bin Al Harits] mereka berkata; telah menceritakan kepada kami [Syu'bah] dan telah mengabarkan kepadaku [Ahmad bin Fadhalah bin Ibrahim], ia berkata; telah menceritakan kepada kami ['Ubaidullah bin Musa], ia berkata; telah menceritakan kepada kami [Al Hasan bin Shalih] dari [Ibnu Abu 'Arubah] dari [Qatadah] dari [Al Hasan] dari [Samurah] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari menjual hewan dengan hewan secara kredit."},"4326":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَجَاءَ عَبْدٌ فَبَايَعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْهِجْرَةِ وَلَا يَشْعُرُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ عَبْدٌ فَجَاءَ سَيِّدُهُ يُرِيدُهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعْنِيهِ فَاشْتَرَاهُ بِعَبْدَيْنِ أَسْوَدَيْنِ ثُمَّ لَمْ يُبَايِعْ أَحَدًا بَعْدُ حَتَّى يَسْأَلَهُ أَعَبْدٌ هُوَ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Abu Az Zubair] dari [Jabir], ia berkata; telah datang seorang budak kemudian membai'at Rasulullah shallallahu 'alaihi wasallam untuk melakukan hijrah, dan Nabi shallallahu 'alaihi wasallam tidak merasakan bahwa ia adalah seorang budak. Kemudian tuannya datang menginginkannya. Lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Juallah dia kepadaku.\" Kemudian beliau membelinya dengan dua orang budak hitam, kemudian beliau tidak membai'at seseorang hingga bertanya kepadanya apakah ia budak? "},"4327":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَكِيمٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَيُّوبَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ السَّلَفُ فِي حَبَلِ الْحَبَلَةِ رِبًا","id":"Telah mengabarkan kepada kami [Yahya bin Hakim], ia berkata; telah menceritakan kepada kami [Muhammad bin Ja'far], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Ayyub] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari Nabi beliau bersabda: \"salaf (mendahulukan pembayaran dan mengakhirkan barang pembelian) dalam hablil hablah (menjual janin yang nantinya ada dalam janin unta) adalah riba.\""},"4328":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ حَبَلِ الْحَبَلَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Ayyub] dari [Sa'id bin Jubair] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam melarang dari menjual janin yang ada dalam janin unta. "},"4329":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ حَبَلِ الْحَبَلَةِ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam melarang dari menjual janin yang ada dalam janin unta."},"4330":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ حَبَلِ الْحَبَلَةِ وَكَانَ بَيْعًا يَتَبَايَعُهُ أَهْلُ الْجَاهِلِيَّةِ كَانَ الرَّجُلُ يَبْتَاعُ جَزُورًا إِلَى أَنْ تُنْتِجَ النَّاقَةُ ثُمَّ تُنْتِجُ الَّتِي فِي بَطْنِهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, lafazhnya adalah lafazh Al Harits, dari [Ibnu Al Qasim], ia berkata; telah menceritakan kepadaku [Malik] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam melarang dari melarang dari menjual hablul hablah, dan hal itu merupakan jual beli yang dilakukan orang-orang ahli Jahiliyah, yaitu seseorang membeli unta sembelihan hingga waktu unta melahirkan dan anaknya yang ada dalam perutnya itupun melahirkan"},"4331":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ السِّنِينَ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Az Zubair] dari [Jabir], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari menjual hingga beberapa tahun. "},"4332":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ حُمَيْدٍ الْأَعْرَجِ عَنْ سُلَيْمَانَ وَهُوَ ابْنُ عَتِيقٍ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ السِّنِينَ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Humaid Al A'raj] dari [Sulaiman yaitu Ibnu 'Atiq] dari [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari menjual hingga beberapa tahun. "},"4333":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا عُمَارَةُ بْنُ أَبِي حَفْصَةَ قَالَ أَنْبَأَنَا عِكْرِمَةُ عَنْ عَائِشَةَ قَالَتْكَانَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بُرْدَيْنِ قِطْرِيَّيْنِ وَكَانَ إِذَا جَلَسَ فَعَرِقَ فِيهِمَا ثَقُلَا عَلَيْهِ وَقَدِمَ لِفُلَانٍ الْيَهُودِيِّ بَزٌّ مِنْ الشَّأْمِ فَقُلْتُ لَوْ أَرْسَلْتَ إِلَيْهِ فَاشْتَرَيْتَ مِنْهُ ثَوْبَيْنِ إِلَى الْمَيْسَرَةِ فَأَرْسَلَ إِلَيْهِ فَقَالَ قَدْ عَلِمْتُ مَا يُرِيدُ مُحَمَّدٌ إِنَّمَا يُرِيدُ أَنْ يَذْهَبَ بِمَالِي أَوْ يَذْهَبَ بِهِمَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَذَبَ قَدْ عَلِمَ أَنِّي مِنْ أَتْقَاهُمْ لِلَّهِ وَآدَاهُمْ لِلْأَمَانَةِ","id":"Telah mengabarkan kepada kami ['Amru bin Ali], ia berkata; telah menceritakan kepada kami [Yazid bin Zurai'], ia berkata; telah menceritakan kepada kami ['Umarah bin Abu Hafshah], ia berkata; telah memberitakan kepada kami ['Ikrimah] dari ['Aisyah] ia berkata; dulu Rasulullah shallallahu 'alaihi wasallam mengenakan dua kain burdah yang tebal, jika beliau duduk lalu berkeringat maka kain itu memberatkannya, dan telah datang kepada seorang Yahudi sejenis pakaian sutera, lalu saya katakan; seandainya anda mengutus seseorang kemudian membeli darinya dua pakaian hingga waktu mendapatkan kemudaha. Lalu beliau mengutus seseorang kepadanya, kemudian orang Yahudi itu berkata; aku tahu apa yang diinginkan Muhammad, ia hanya ingin untuk pergi dengan hartaku atau ia pergi dengan keduanya. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \" ia dusta, sesungguhnya ia telah mengetahui bahwa aku adalah yang paling takut kepada Allah dari mereka dan yang paling menjaga amanat.\""},"4334":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ عَنْ خَالِدٍ عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ سَلَفٍ وَبَيْعٍ وَشَرْطَيْنِ فِي بَيْعٍ وَرِبْحِ مَا لَمْ يُضْمَنْ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dari [Khalid] dari [Husain Al Mu'allim] dari ['Amru bin Syu'aib] dari [ayahnya] dari [kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari jual beli dengan syarat diberi hutang, dua syarat dalam jual beli dan keuntungan sesuatu yang belum ditanggung."},"4335":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ قَالَ حَدَّثَنَا أَيُّوبُ قَالَ حَدَّثَنَا عَمْرُو بْنُ شُعَيْبٍ قَالَ حَدَّثَنِي أَبِي عَنْ أَبِيهِ حَتَّى ذَكَرَ عَبْدَ اللَّهِ بْنَ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحِلُّ سَلَفٌ وَبَيْعٌ وَلَا شَرْطَانِ فِي بَيْعٍ وَلَا رِبْحُ مَا لَمْ يُضْمَنْ","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub], ia berkata; telah menceritakan kepada kami [Ibnu 'Ulayyah], ia berkata; telah menceritakan kepada kami [Ayyub], ia berkata; telah menceritakan kepada kami ['Amru bin Syu'aib], ia berkata; telah menceritakan kepadaku [ayahku] dari [ayahnya] hingga ia menyebutkan [Abdullah bin 'Amru], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal jual beli dengan syarat diberi hutang, dua syarat dalam jual beli dan keuntungan sesuatu yang belum ditanggung.\""},"4336":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ سَلَفٍ وَبَيْعٍ وَعَنْ شَرْطَيْنِ فِي بَيْعٍ وَاحِدٍ وَعَنْ بَيْعِ مَا لَيْسَ عِنْدَكَ وَعَنْ رِبْحِ مَا لَمْ يُضْمَنْ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'], ia berkata; telah menceritakan kepada kami [Abdur Razzaq], ia berkata; telah menceritakan kepada kami [Ma'mar] dari [Ayyub] dari ['Amru bin Syu'aib] dari [ayahnya] dari [kakeknya], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari jual beli dengan syarat diberi hutang, dua syarat dalam satu akad jual beli, dan menjual sesuatu yang tidak engkau miliki."},"4337":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ وَيَعْقُوبُ بْنُ إِبْرَاهِيمَ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالُوا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو قَالَ حَدَّثَنَا أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعَتَيْنِ فِي بَيْعَةٍ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] dan [Ya'qub bin Ibrahim] dan [Muhammad bin Al Mutsanna] mereka berkata; telah menceritakan kepada kami [Yahya bin Sa'id], ia berkata; telah menceritakan kepada kami [Muhammad bin 'Amru], ia berkata; telah menceritakan kepada kami [Abu Salamah] dari [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari dua jual beli dalam satu akad jual beli."},"4338":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ قَالَ حَدَّثَنَا سُفْيَانُ بْنُ حُسَيْنٍ قَالَ حَدَّثَنَا يُونُسُ عَنْ عَطَاءٍ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْمُحَاقَلَةِ وَالْمُزَابَنَةِ وَالْمُخَابَرَةِ وَعَنْ الثُّنْيَا إِلَّا أَنْ تُعْلَمَ","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub], ia berkata; telah menceritakan kepada kami ['Abbad bin Al Awwam], ia berkata; telah menceritakan kepada kami [Sufyan bin Husain], ia berkata; telah menceritakan kepada kami [Yunus] dari ['Atho`] dari [Jabir] bahwa Nabi shallallahu 'alaihi wasallam melarang dari muhaqalah, muzabanah dan mukhabarah serta pengecualian kecuali diketahui."},"4339":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ أَيُّوبَ و أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ قَالَ أَنْبَأَنَا أَيُّوبُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُحَاقَلَةِ وَالْمُزَابَنَةِ وَالْمُخَابَرَةِ وَالْمُعَاوَمَةِ وَالثُّنْيَا وَرَخَّصَ فِي الْعَرَايَا","id":"Telah mengabarkan kepada kami [Ali bin Hujr], ia berkata; telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Ayyub] dan telah mengabarkan kepada kami [Ziyad bin Ayyub], ia berkata; telah menceritakan kepada kami [Ibnu 'Ulayyah], ia berkata; telah memberitakan kepada kami [Ayyub] dari [Abu Az Zubair] dari [Jabir], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari muhaqalah, muzabanah dan mukhabarah dan mu'awamah (menjual buah yang ada di atas pohon beberapa tahun sebelum nampak buah tersebut) serta pengecualian dan beliau memberikan keringanan dalam hal 'araya."},"4340":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا امْرِئٍ أَبَّرَ نَخْلًا ثُمَّ بَاعَ أَصْلَهَا فَلِلَّذِي أَبَّرَ ثَمَرُ النَّخْلِ إِلَّا أَنْ يَشْتَرِطَ الْمُبْتَاعُ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Siapapun orang yang mengawinkan pohon kurma kemudian menjual pokoknya maka bagi orang yang mengawinkan mendapatkan buah pohon kurma kecuali apabila orang yang membeli mensyaratkan buah tersebut untuknya.\""},"4341":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ ابْتَاعَ نَخْلًا بَعْدَ أَنْ تُؤَبَّرَ فَثَمَرَتُهَا لِلْبَائِعِ إِلَّا أَنْ يَشْتَرِطَ الْمُبْتَاعُ وَمَنْ بَاعَ عَبْدًا وَلَهُ مَالٌ فَمَالُهُ لِلْبَائِعِ إِلَّا أَنْ يَشْتَرِطَ الْمُبْتَاعُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Sufyan] dari [Az Zuhri] dari [Salim] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang membeli pohon kurma setelah dikawinkan maka buahnya untuk orang yang membeli kecuali orang yang membeli mensyaratkan buah tersebut untuknya, dan barang siapa yang membeli budak dan ia memiliki harta maka hartanya milik orang yang menjual kecuali orang yang membeli mensyaratkannya.\""},"4342":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا سَعْدَانُ بْنُ يَحْيَى عَنْ زَكَرِيَّا عَنْ عَامِرٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَأَعْيَا جَمَلِي فَأَرَدْتُ أَنْ أُسَيِّبَهُ فَلَحِقَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَدَعَا لَهُ فَضَرَبَهُ فَسَارَ سَيْرًا لَمْ يَسِرْ مِثْلَهُ فَقَالَ بِعْنِيهِ بِوُقِيَّةٍ قُلْتُ لَا قَالَ بِعْنِيهِ فَبِعْتُهُ بِوُقِيَّةٍ وَاسْتَثْنَيْتُ حُمْلَانَهُ إِلَى الْمَدِينَةِ فَلَمَّا بَلَغْنَا الْمَدِينَةَ أَتَيْتُهُ بِالْجَمَلِ وَابْتَغَيْتُ ثَمَنَهُ ثُمَّ رَجَعْتُ فَأَرْسَلَ إِلَيَّ فَقَالَ أَتُرَانِي إِنَّمَا مَاكَسْتُكَ لِآخُذَ جَمَلَكَ خُذْ جَمَلَكَ وَدَرَاهِمَكَ","id":"Telah mengabarkan kepada kami [Ali bin Hujr], ia berkata; telah memberitakan kepada kami [Sa'dan bin Yahya] dari [Zakariya] dari ['Amir] dari [Jabir bin Abdullah], ia berkata; saya pernah bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan kemudian untaku tidak mampu untuk berjalan, lalu saya hendak meninggalkannya kemudian Rasulullah shallallahu 'alaihi wasallam menyusulku dan memanggil kemudian memukul unta tersebut sehingga ia berjalan yang sebelumnya tidak berjalan seperti itu. Lalu beliau bersabda: 'Juallah unta tersebut kepadaku dengan satu uqiyah.\" Maka saya katakan; tidak. Beliau bersabda: 'Juallah unta tersebut kepadaku.\" Kemudian saya menjual kepadanya dengan satu uqiyah dan saya mensyaratkan untuk membawaku ke Madinah. Setelah kami sampai Madinah maka saya mendatangi beliau dengan membawa unta tersebut, dan saya mengambil harganya, kemudian kembali. Lalu beliau mengirim utusan kepadaku dan beliau bersabda: \"Apakah engkau mengira bahwa saya menawarmu agar untuk mengambil untamu? Ambillah unta dan uang dirhammu.\""},"4343":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى بْنِ الطَّبَّاعِ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مُغِيرَةَ عَنْ الشَّعْبِيِّ عَنْ جَابِرٍ قَالَغَزَوْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى نَاضِحٍ لَنَا ثُمَّ ذَكَرْتُ الْحَدِيثَ بِطُولِهِ ثُمَّ ذَكَرَ كَلَامًا مَعْنَاهُ فَأُزْحِفَ الْجَمَلُ فَزَجَرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْتَشَطَ حَتَّى كَانَ أَمَامَ الْجَيْشِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا جَابِرُ مَا أَرَى جَمَلَكَ إِلَّا قَدْ انْتَشَطَ قُلْتُ بِبَرَكَتِكَ يَا رَسُولَ اللَّهِ قَالَ بِعْنِيهِ وَلَكَ ظَهْرُهُ حَتَّى تَقْدَمَ فَبِعْتُهُ وَكَانَتْ لِي إِلَيْهِ حَاجَةٌ شَدِيدَةٌ وَلَكِنِّي اسْتَحْيَيْتُ مِنْهُ فَلَمَّا قَضَيْنَا غَزَاتَنَا وَدَنَوْنَا اسْتَأْذَنْتُهُ بِالتَّعْجِيلِ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي حَدِيثُ عَهْدٍ بِعُرْسٍ قَالَ أَبِكْرًا تَزَوَّجْتَ أَمْ ثَيِّبًا قُلْتُ بَلْ ثَيِّبًا يَا رَسُولَ اللَّهِ إِنَّ عَبْدَ اللَّهِ بْنَ عَمْرٍو أُصِيبَ وَتَرَكَ جَوَارِيَ أَبْكَارًا فَكَرِهْتُ أَنْ آتِيَهُنَّ بِمِثْلِهِنَّ فَتَزَوَّجْتُ ثَيِّبًا تُعَلِّمُهُنَّ وَتُؤَدِّبُهُنَّ فَأَذِنَ لِي وَقَالَ لِي ائْتِ أَهْلَكَ عِشَاءً فَلَمَّا قَدِمْتُ أَخْبَرْتُ خَالِي بِبَيْعِي الْجَمَلَ فَلَامَنِي فَلَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَدَوْتُ بِالْجَمَلِ فَأَعْطَانِي ثَمَنَ الْجَمَلِ وَالْجَمَلَ وَسَهْمًا مَعَ النَّاسِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya bin Abdullah], ia berkata; telah menceritakan kepada kami [Muhammad bin Isa bin Ath Thabba'], ia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Mughirah] dari [Asy Sya'bi] dari [Jabir], ia berkata; saya berperang bersama Nabi shallallahu 'alaihi wasallam di atas unta kami, kemudian saya menyebutkan peristiwa tersebut. Kemudian unta tersebut mengalami keletihan lalu Nabi shallallahu 'alaihi wasallam menghardiknya sehingga ia menjadi semangat kembali hingga berada di hadapan pasukan. Lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Jabir, saya tidak melihat kecuali telah bersemangat kembali.\" Maka saya katakan; karena berkahmu wahai Rasulullah! Beliau bersabda: \"Juallah kepadaku, dan engkau mendapatkan tunggangannya hingga engkau sampai Madinah.\" Kemudian saya menjualnya padahal saya sangat membutuhkannya, akan tetapi saya malu dari beliau. Kemudian tatkala kami telah menyelesaikan perang kami dan kami telah dekat dengan Madinah, maka saya meminta izin untuk mendahului. Saya katakan; wahai Rasulullah, saya adalah orang yang baru menikah. Beliau bersabda: \"Engkau menikahi gadis atau janda?\" Saya mengatakan; janda wahai Rasulullah, sesungguhnya Abdullah bin 'Amru telah terbunuh dan ia meninggalkan beberapa orang anak wanita yang masih gadis, dan saya tidak suka untuk mendatangi mereka dengan wanita yang seperti mereka, sehingga saya menikahi janda yang akan mengajari dan mendidik mereka. Kemudian beliau mengizinkan saya, dan bersabda: \"Datanglah kepada keluargamu pada saat isya`.\" Kemudian tatkala saya telah sampai maka saya khabarkan penjualan ont a tesebut kepada bibiku, lalu ia mencelaku. Tatkala Rasulullah shallallahu 'alaihi wasallam telah sampai maka saya datang kepada beliau membawa unta. Kemudian beliau memberiku harga unta serta unta itu sendiri, dan saham saya bersama orang-orang."},"4344":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكُنْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ وَكُنْتُ عَلَى جَمَلٍ فَقَالَ مَا لَكَ فِي آخِرِ النَّاسِ قُلْتُ أَعْيَا بَعِيرِي فَأَخَذَ بِذَنَبِهِ ثُمَّ زَجَرَهُ فَإِنْ كُنْتُ إِنَّمَا أَنَا فِي أَوَّلِ النَّاسِ يُهِمُّنِي رَأْسُهُ فَلَمَّا دَنَوْنَا مِنْ الْمَدِينَةِ قَالَ مَا فَعَلَ الْجَمَلُ بِعْنِيهِ قُلْتُ لَا بَلْ هُوَ لَكَ يَا رَسُولَ اللَّهِ قَالَ لَا بَلْ بِعْنِيهِ قُلْتُ لَا بَلْ هُوَ لَكَ قَالَ لَا بَلْ بِعْنِيهِ قَدْ أَخَذْتُهُ بِوُقِيَّةٍ ارْكَبْهُ فَإِذَا قَدِمْتَ الْمَدِينَةَ فَأْتِنَا بِهِ فَلَمَّا قَدِمْتُ الْمَدِينَةَ جِئْتُهُ بِهِ فَقَالَ لِبِلَالٍ يَا بِلَالُ زِنْ لَهُ أُوقِيَّةً وَزِدْهُ قِيرَاطًا قُلْتُ هَذَا شَيْءٌ زَادَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يُفَارِقْنِي فَجَعَلْتُهُ فِي كِيسٍ فَلَمْ يَزَلْ عِنْدِي حَتَّى جَاءَ أَهْلُ الشَّامِ يَوْمَ الْحَرَّةِ فَأَخَذُوا مِنَّا مَا أَخَذُوا","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala`], ia berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Salim bin Abu Al Ja'd] dari [Jabir bin Abdullah], ia berkata; kami pernah bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu safar, dan saya berada di atas unta. Kemudian beliau bersabda: \"Kenapa engkau berada di bagian belakang?\" Saya katakan; untaku keletihan. Kemudian beliau memegang ekornya dan menghardiknya, lalu saya berada di depan orang-orang dan kepala unta tersebut membuatkan merasa khawatir. Kemudian tatkala kami telah mendekati Madinah beliau bersabda: \"Apa yang dilakukan unta tersebut? Juallah kepadaku.\" Saya mengatakan; tidak, melainkan unta tersebut untukmu wahai Rasulullah. Beliau bersabda: \"Tidak, juallah kepadaku.\" Saya mengatakan; tidak, melainkan unta tersebut untukmu. Beliau bersabda: \"Tidak, julallah kepadaku, saya beli dengan satu uqiyah, naiklah kemudian apabila engkau telah sampai Madinah maka datanglah kepada kami membawa unta tersebut.\" Tatkala saya telah sampai Madinah maka saya mendatanginya membawa unta tersebut. Kemudian beliau bersabda kepada Bilal: \"Wahai Bilal, timbanglah untuknya satu uqiyah dan tambahlah satu qirath.\" Ini adalah sesuatu yang dilebihkan Rasulullah shallallahu 'alaihi wasallam untukku, dan beliau tidak meninggalkanku. Kemudian saya meletakkannya di sebuah kantong, dan tetap ada padaku hingga penduduk Syam datang menyerang pada saat perang Harrah, dan mereka mengambil dari kami apa yang telah mereka ambil."},"4345":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَأَدْرَكَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكُنْتُ عَلَى نَاضِحٍ لَنَا سَوْءٍ فَقُلْتُ لَا يَزَالُ لَنَا نَاضِحُ سَوْءٍ يَا لَهْفَاهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَبِيعُنِيهِ يَا جَابِرُ قُلْتُ بَلْ هُوَ لَكَ يَا رَسُولَ اللَّهِ قَالَ اللَّهُمَّ اغْفِرْ لَهُ اللَّهُمَّ ارْحَمْهُ قَدْ أَخَذْتُهُ بِكَذَا وَكَذَا وَقَدْ أَعَرْتُكَ ظَهْرَهُ إِلَى الْمَدِينَةِ فَلَمَّا قَدِمْتُ الْمَدِينَةَ هَيَّأْتُهُ فَذَهَبْتُ بِهِ إِلَيْهِ فَقَالَ يَا بِلَالُ أَعْطِهِ ثَمَنَهُ فَلَمَّا أَدْبَرْتُ دَعَانِي فَخِفْتُ أَنْ يَرُدَّهُ فَقَالَ هُوَ لَكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Az Zubair] dari [Jabir], ia berkata; Rasulullah shallallahu 'alaihi wasallam menemuiku dan saya berada di atas unta kami yang lemah. Kemudian saya katakan; aduh, kami senantiasa memiliki unta yang lemah. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Apakah engkau akan menjualnya kepadaku wahai Jabir?\" Maka saya katakan; unta itu untukmu wahai Rasulullah! Beliau bersabda: \"Ya Allah, ampunilah dia. Ya Allah, rahmatilah dia, sungguh saya telah membelinya dengan sekian dan sekian. Dan saya telah meminjamkan punggungnya hingga sampai Madinah.\" Kemudian setelah saya sampai Madinah, saya mempersiapkan unta tersebut dan pergi membawanya kepada beliau. Kemudian beliau bersabda: \"Wahai Bilal, berikan hartanya kepadanya.\" Kemudian setelah saya pergi maka beliau memanggilku, maka saya khawatir beliau mengembalikannya. Beliau bersabda: \"Unta itu untukmu.\" "},"4346":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ أَبِي قَالَ حَدَّثَنَا أَبُو نَضْرَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا نَسِيرُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا عَلَى نَاضِحٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَبِيعُنِيهِ بِكَذَا وَكَذَا وَاللَّهُ يَغْفِرُ لَكَ قُلْتُ نَعَمْ هُوَ لَكَ يَا نَبِيَّ اللَّهِ قَالَ أَتَبِيعُنِيهِ بِكَذَا وَكَذَا وَاللَّهُ يَغْفِرُ لَكَ قُلْتُ نَعَمْ هُوَ لَكَ يَا نَبِيَّ اللَّهِ قَالَ أَتَبِيعُنِيهِ بِكَذَا وَكَذَا وَاللَّهُ يَغْفِرُ لَكَ قُلْتُ نَعَمْ هُوَ لَكَقَالَ أَبُو نَضْرَةَ وَكَانَتْ كَلِمَةً يَقُولُهَا الْمُسْلِمُونَ افْعَلْ كَذَا وَكَذَا وَاللَّهُ يَغْفِرُ لَكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Al Mu'tamir], ia berkata; saya mendengar [ayahku] berkata; telah menceritakan kepada kami [Abu Nadhrah] dari [Jabir bin Abdullah], ia berkata; kami pernah berjalan bersama Rasulullah shallallahu 'alaihi wasallam dan saya berada di atas unta. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: 'Apakah engkau menjualnya kepadaku dengan sekian serta sekian dan Allah mengampuni dosamu?\" Maka saya katakan; ya, unta itu untukmu wahai Nabi Allah. Beliau bersabda: 'Apakah engkau menjualnya kepadaku dengan sekian serta sekian dan Allah mengampuni dosamu?\" Maka saya katakan; ya, unta itu untukmu wahai Nabi Allah. 'Apakah engkau menjualnya kepadaku dengan sekian serta sekian dan Allah mengampuni dosamu?\" Maka saya katakan; ya, unta itu untukmu wahai Nabi Allah. Abu Nadhrah mengatakan; dan hal itu menjadi perkataan yang dikatakan oleh orang-orang muslim; lakukanlah demikian dan demikian dan semoga Allah mengampunimu."},"4347":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْاشْتَرَيْتُ بَرِيرَةَ فَاشْتَرَطَ أَهْلُهَا وَلَاءَهَا فَذَكَرْتُ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَعْتِقِيهَا فَإِنَّ الْوَلَاءَ لِمَنْ أَعْطَى الْوَرِقَ قَالَتْ فَأَعْتَقْتُهَا قَالَتْ فَدَعَاهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَيَّرَهَا مِنْ زَوْجِهَا فَاخْتَارَتْ نَفْسَهَا وَكَانَ زَوْجُهَا حُرًّا","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id], ia berkata; telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari [Aisyah], ia berkata; saya membeli Barirah kemudian pemiliknya mensyaratkan perwaliannya. Lalu hal tersebut saya utarakan kepada Nabi shallallahu 'alaihi wasallam kemudian beliau bersabda: \"Bebaskan dia, sesungguhnya perwalian itu untuk orang yang memberikan perak (pembeli).\" Aisyah berkata; kemudian Rasulullah shallallahu 'alaihi wasallam memanggil Barirah dan memberikan pilihan kepadanya terhadap suaminya, maka ia memilih dirinya. Suaminya pada saat itu adalah orang merdeka. "},"4348":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ الْقَاسِمِ قَالَ سَمِعْتُ الْقَاسِمَ يُحَدِّثُ عَنْ عَائِشَةَأَنَّهَا أَرَادَتْ أَنْ تَشْتَرِيَ بَرِيرَةَ لِلْعِتْقِ وَأَنَّهُمْ اشْتَرَطُوا وَلَاءَهَا فَذَكَرَتْ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَرِيهَا فَأَعْتِقِيهَا فَإِنَّ الْوَلَاءَ لِمَنْ أَعْتَقَ وَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَحْمٍ فَقِيلَ هَذَا تُصُدِّقَ بِهِ عَلَى بَرِيرَةَ فَقَالَ هُوَ لَهَا صَدَقَةٌ وَلَنَا هَدِيَّةٌ وَخُيِّرَتْ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar], ia berkata; telah menceritakan kepada kami [Muhammad], ia berkata; telah menceritakan kepada kami [Syu'bah], ia berkata; telah menceritakan kepada kami [Abdur Rahman bin Al Qasim], ia berkata; saya mendengar [Al Qasim] bercerita dari [Aisyah] bahwa ia ingin membeli Barirah untuk di merdekakan. Dan mereka mensyaratkan perwaliannya, lalu Aisyah mengutarakan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Belilah dia dan merdekakan, sesungguhnya perwalian adalah untuk orang yang memerdekakan.\" Dan Rasulullah shallallahu 'alaihi wasallam telah diberi daging kemudian dikatakan; daging ini disedekahkan kepada Barirah. Kemudian beliau bersabda: \"Itu sedekah baginya dan bagi kita sebagai hadiah.\" Kemudian Barirah diminta untuk memilih."},"4349":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ عَائِشَةَ أَرَادَتْ أَنْ تَشْتَرِيَ جَارِيَةً تَعْتِقُهَا فَقَالَ أَهْلُهَا نَبِيعُكِهَا عَلَى أَنَّ الْوَلَاءَ لَنَا فَذَكَرَتْ ذَلِكِ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا يَمْنَعُكِ ذَلِكِ فَإِنَّ الْوَلَاءَ لِمَنْ أَعْتَقَ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Nafi'] dari [Abdullah bin Umar] bahwa Aisyah ingin membeli seorang budak wanita yang akan ia merdekakan, kemudian pemiliknya berkata; kami akan menjualnya kepadamu dengan syarat perwalian untuk kami. Kemudian Aisyah mengutarakan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Hal itu tidak menghalangimu, sesungguhnya perwalian adalah untuk orang yang memerdekakan.\""},"4350":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَفْصِ بْنِ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي إِبْرَاهِيمُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الْمَغَانِمِ حَتَّى تُقْسَمَ وَعَنْ الْحَبَالَى أَنْ يُوطَأْنَ حَتَّى يَضَعْنَ مَا فِي بُطُونِهِنَّ وَعَنْ لَحْمِ كُلِّ ذِي نَابٍ مِنْ السِّبَاعِ","id":"Telah mengabarkan kepada kami [Ahmad bin Hafsh bin Abdullah], ia berkata; telah menceritakan kepadaku [ayahku], ia berkata; telah menceritakan kepadaku [Ibrahim] dari [Yahya bin Sa'id] dari ['Amru bin Syu'aib] dari [Abdullah bin Abu Najih] dari [Mujahid] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari menjual harta rampasan perang hingga dibagikan, dan dari wanita-wanita hamil untuk digauli hingga melahirkan kandungannya, dan dari daging setiap yang memiliki taring dari binatang buas."},"4351":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ زُرَارَةَ قَالَ أَنْبَأَنَا إِسْمَعِيلُ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشُّفْعَةُ فِي كُلِّ شِرْكٍ رَبْعَةٍ أَوْ حَائِطٍ لَا يَصْلُحُ لَهُ أَنْ يَبِيعَ حَتَّى يُؤْذِنَ شَرِيكَهُ فَإِنْ بَاعَ فَهُوَ أَحَقُّ بِهِ حَتَّى يُؤْذِنَهُ","id":"Telah mengabarkan kepada kami ['Amru bin Zurarah], ia berkata; telah memberitakan kepada kami [Isma'il] dari [Ibnu Juraij], ia berkata; telah mengabarkan kepadaku [Abu Az Zubair] dari [Jabir], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hak membeli terlebih dahulu ada dalam setiap rumah yang dimiliki bersama, atau kebun dan tidak boleh ia menjual hingga memberi tahu sekutunya, kemudian apabila ia menjual maka sekutunya tersebut lebih berhak terhadapnya hingga ia memberi izin untuk menjualnya.\""},"4352":{"ar":"أَخْبَرَنَا الْهَيْثَمُ بْنُ مَرْوَانَ بْنِ الْهَيْثَمِ بْنِ عِمْرَانَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ بَكَّارٍ قَالَ حَدَّثَنَا يَحْيَى وَهُوَ ابْنُ حَمْزَةَ عَنْ الزُّبَيْدِيِّ أَنَّ الزُّهْرِيَّ أَخْبَرَهُ عَنْ عُمَارَةَ بْنِ خُزَيْمَةَ أَنَّ عَمَّهُ حَدَّثَهُ وَهُوَ مِنْ أَص��حَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْتَاعَ فَرَسًا مِنْ أَعْرَابِيٍّ وَاسْتَتْبَعَهُ لِيَقْبِضَ ثَمَنَ فَرَسِهِ فَأَسْرَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبْطَأَ الْأَعْرَابِيُّ وَطَفِقَ الرِّجَالُ يَتَعَرَّضُونَ لِلْأَعْرَابِيِّ فَيَسُومُونَهُ بِالْفَرَسِ وَهُمْ لَا يَشْعُرُونَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْتَاعَهُ حَتَّى زَادَ بَعْضُهُمْ فِي السَّوْمِ عَلَى مَا ابْتَاعَهُ بِهِ مِنْهُ فَنَادَى الْأَعْرَابِيُّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنْ كُنْتَ مُبْتَاعًا هَذَا الْفَرَسَ وَإِلَّا بِعْتُهُ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ سَمِعَ نِدَاءَهُ فَقَالَ أَلَيْسَ قَدْ ابْتَعْتُهُ مِنْكَ قَالَ لَا وَاللَّهِ مَا بِعْتُكَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ ابْتَعْتُهُ مِنْكَ فَطَفِقَ النَّاسُ يَلُوذُونَ بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِالْأَعْرَابِيِّ وَهُمَا يَتَرَاجَعَانِ وَطَفِقَ الْأَعْرَابِيُّ يَقُولُ هَلُمَّ شَاهِدًا يَشْهَدُ أَنِّي قَدْ بِعْتُكَهُ قَالَ خُزَيْمَةُ بْنُ ثَابِتٍ أَنَا أَشْهَدُ أَنَّكَ قَدْ بِعْتَهُ قَالَ فَأَقْبَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى خُزَيْمَةَ فَقَالَ لِمَ تَشْهَدُ قَالَ بِتَصْدِيقِكَ يَا رَسُولَ اللَّهِ قَالَ فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَهَادَةَ خُزَيْمَةَ شَهَادَةَ رَجُلَيْنِ","id":"Telah mengabarkan kepada kami [Al Haitsam bin Marwan bin Imran], ia berkata; telah menceritakan kepada kami [Muhammad bin Bakkar], ia berkata; telah menceritakan kepada kami [Yahya yaitu Ibnu Hamzah] dari [Az Zubaidi] bahwa [Az Zuhri] telah mengabarkan kepadanya dari ['Umarah bin Khuzaimah] bahwa [pamannya] berkata kepadanya yang termasuk seorang sahabat Nabi shallallahu 'alaihi wasallam telah menceritakan kepadanya bahwa Nabi shallallahu 'alaihi wasallam membeli seekor kuda dari seorang badui dan ia mengikuti beliau untuk mengambil uangnya, lalu Nabi shallallahu 'alaihi wasallam mempercepat jalannya sedangkan orang badui itu memperlambat jalannya, lalu orang-orang mulai mendatangi badui itu dan menawarnya, mereka tidak mengetahui jika Nabi shallallahu 'alaihi wasallam telah membelinya hingga salah seorang dari mereka menambah harganya melebihi harga yang telah dibeli beliau, lalu orang badui itu memanggil Nabi shallallahu 'alaihi wasallam dan berkata apakah engkau jadi membeli kudaku ini jika tidak maka aku akan menjualnya, Nabi shallallahu 'alaihi wasallam berdiri begitu mendengar panggilan orang badui itu, beliau bersabda: \"Bukankah aku telah membelinya darimu?\" Ia menjawab tidak, demi Allah aku tidak menjualnya kepadamu, lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Aku telah membelinya darimu, \" lalu orang-orang mulai mengerumunin Nabi shallallahu 'alaihi wasallam dan orang badui itu, kemudian mereka berdua kembali, orang badui itu berkata datangkan seorang saksi bahwa aku telah menjualnya kepadamu, Khuzaimah bin Tasbit berkata aku bersaksi bahwa engkau telah menjualnya, lalu Nabi shallallahu 'alaihi wasallam menerima persaksian Kuzaimah dan bersabda: \"Karena apa engkau bersaksi, \" ia berkata dengan mempercayaimu ya Rasulullah ia berkata lalu Rasulullah shallallahu 'alaihi wasallam menjadikan persaksian Khuzaimah dengan dua orang saksi."},"4353":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِدْرِيسَ قَالَ حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ قَالَ حَدَّثَنَا أَبِي عَنْ أَبِي عُمَيْسٍ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدِ بْنِ الْأَشْعَثِ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ عَبْدُ اللَّهِسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا اخْتَلَفَ الْبَيِّعَانِ وَلَيْسَ بَيْنَهُمَا بَيِّنَةٌ فَهُوَ مَا يَقُولُ رَبُّ السِّلْعَةِ أَوْ يَتْرُكَا","id":"Telah mengabarkan kepada kami [Muhammad bin Idris], ia berkata; telah menceritakan kepada kami [Umar bin Hafsh bin Ghiyats], ia berkata; telah menceritakan kepada kami [ayahku] dari [Abu 'Umais] ia berkata; telah menceritakan kepadaku [Abdur Rahman bin Qais bin Muhammad bin Al Asy'ats] dari [ayahnya] dari [kakekknya], [Abdullah] berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika dua orang yang berjual beli berselisih dan tidak ada bukti diantara keduanya maka yang diambil adalah perkataan pemilik barang atau mereka berdua meninggalkannya.\""},"4354":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ الْحَسَنِ وَيُوسُفُ بْنُ سَعِيدٍ وَعَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ وَاللَّفْظُ لِإِبْرَاهِيمَ قَالُوا حَدَّثَنَا حَجَّاجٌ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي إِسْمَعِيلُ بْنُ أُمَيَّةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُبَيْدٍ قَالَ حَضَرْنَا أَبَا عُبَيْدَةَ بْنَ عَبْدِ اللَّهِ بْنِ مَسْعُودٍأَتَاهُ رَجُلَانِ تَبَايَعَا سِلْعَةً فَقَالَ أَحَدُهُمَا أَخَذْتُهَا بِكَذَا وَبِكَذَا وَقَالَ هَذَا بِعْتُهَا بِكَذَا وَكَذَا فَقَالَ أَبُو عُبَيْدَةَ أُتِيَ ابْنُ مَسْعُودٍ فِي مِثْلِ هَذَا فَقَالَ حَضَرْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِمِثْلِ هَذَا فَأَمَرَ الْبَائِعَ أَنْ يَسْتَحْلِفَ ثُمَّ يَخْتَارَ الْمُبْتَاعُ فَإِنْ شَاءَ أَخَذَ وَإِنْ شَاءَ تَرَكَ","id":"Telah mengabarkan kepadaku [Ibrahim bin Al Hasan] dan [Yusuf bin Sa'id] dan [Abdur Rahman bin Khalid], lafazhnya adalah lafazh Ibrahim, mereka berkata; telah menceritakan kepada kami [Hajjaj], ia berkata; telah berkata [Ibnu Juraij]; telah mengabarkan kepadaku [Isma'il bin Umayyah] dari [Abdul Malik bin 'Ubaid], ia berkata; kami bersama 'Ubaidah bin Abdullah bin Mas'ud, telah datang kepadanya dua orang yang berjual beli suatu barang. Kemudian salah seorang diantara mereka berkata; saya membelinya dengan sekian dan sekian. Dan yang lain berkata; saya menjualnya dengan sekian dan sekian. Lalu [Abu 'Ubaidah] berkata; [Ibnu Mas'ud] dihadapkan pada permasalahan seperti ini, kemudian ia berkata; saya bersama Rasulullah shallallahu 'alaihi wasallam dan beliau dihadapkan pada permasalahan seperti ini kemudian beliau memerintahkan penjual agar bersumpah kemudian pembeli memilih, apabila mau maka ia mengambilnya dan apabila mau maka ia meninggalkannya."},"4355":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْاشْتَرَى رَسُولُ اللَّهِ ��َلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ يَهُودِيٍّ طَعَامًا بِنَسِيئَةٍ وَأَعْطَاهُ دِرْعًا لَهُ رَهْنًا","id":"Telah mengabarkan kepada kami [Ahmad bin Harb], ia berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam membeli makanan dengan kredit dari seorang Yahudi, dan beliau memberikan kepadanya baju zirah beliau sebagai gadaian. "},"4356":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ حَمَّادٍ قَالَ حَدَّثَنَا سُفْيَانُ بْنُ حَبِيبٍ عَنْ هِشَامٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَتُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَدِرْعُهُ مَرْهُونَةٌ عِنْدَ يَهُودِيٍّ بِثَلَاثِينَ صَاعًا مِنْ شَعِيرٍ لِأَهْلِهِ","id":"Telah mengabarkan kepada kami [Yusuf bin Hammad], ia berkata; telah menceritakan kepada kami [Sufyan bin Habib] dari [Hisyam] dari [Ikrimah] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam meninggal dan baju zirahnya tergadaikan pada seorang Yahudi dengan tiga pulu sha' jewawut untuk keluarganya. "},"4357":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَأَعْتَقَ رَجُلٌ مِنْ بَنِي عُذْرَةَ عَبْدًا لَهُ عَنْ دُبُرٍ فَبَلَغَ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلَكَ مَالٌ غَيْرُهُ قَالَ لَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يَشْتَرِيهِ مِنِّي فَاشْتَرَاهُ نُعَيْمُ بْنُ عَبْدِ اللَّهِ الْعَدَوِيُّ بِثَمَانِ مِائَةِ دِرْهَمٍ فَجَاءَ بِهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَفَعَهَا إِلَيْهِ ثُمَّ قَالَ ابْدَأْ بِنَفْسِكَ فَتَصَدَّقْ عَلَيْهَا فَإِنْ فَضَلَ شَيْءٌ فَلِأَهْلِكَ فَإِنْ فَضَلَ مِنْ أَهْلِكَ شَيْءٌ فَلِذِي قَرَابَتِكَ فَإِنْ فَضَلَ مِنْ ذِي قَرَابَتِكَ شَيْءٌ فَهَكَذَا وَهَكَذَا وَهَكَذَا يَقُولُ بَيْنَ يَدَيْكَ وَعَنْ يَمِينِكَ وَعَنْ شِمَالِكَ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Abu Az Zubair] dari [Jabir], ia berkata; seseorang dari Bani 'Udzrah telah memerdekakan seorang budaknya apabila ia telah meninggal. Kemudian hal tersebut sampai kepada Rasulullah shallallahu 'alaihi wasallam, kemudian beliau bersabda: \"Apakah engkau memiliki harta selainnya?\" Ia berkata; tidak. Kemudian beliau bersabda: \"Siapakah yang akan membelinya dariku?\" Lalu budak tersebut dibeli Nu'aim bin Abdullah Al 'Adawi dengan harga delapan ratus dirham. kemudian ia membawanya kepada Rasulullah shallallahu 'alaihi wasallam. Lalu Rasulullah shallallahu 'alaihi wasallam menyerahkannya kepada orang tersebut kemudian bersabda: \"Mulailah dari dirimu, dan bersedekahlah kepadanya, kemudian apabila tersisa maka sisa tersebut untuk keluargamu, apabila tersisa dari keluargamu maka untuk kerabatmu, apabila tersisa dari kerabatmu maka demikian, demikian dan demikian.\" Beliau bersabda; untuk orang yang dihadapanmu, di sebelah kananmu dn sebelah kirimu.\" "},"4358":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ رَجُلًا مِنْ الْأَنْصَارِ يُقَالُ لَهُ أَبُو مَذْكُورٍ أَعْتَقَ غُلَامًا لَهُ عَنْ دُبُرٍ يُقَالُ لَهُ يَعْقُوبُ لَمْ يَكُنْ لَهُ مَالٌ غَيْرُهُ فَدَعَا بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ يَشْتَرِيهِ فَاشْتَرَاهُ نُعَيْمُ بْنُ عَبْدِ اللَّهِ بِثَمَانِ مِائَةِ دِرْهَمٍ فَدَفَعَهَا إِلَيْهِ وَقَالَ إِذَا كَانَ أَحَدُكُمْ فَقِيرًا فَلْيَبْدَأْ بِنَفْسِهِ فَإِنْ كَانَ فَضْلًا فَعَلَى عِيَالِهِ فَإِنْ كَانَ فَضْلًا فَعَلَى قَرَابَتِهِ أَوْ عَلَى ذِي رَحِمِهِ فَإِنْ كَانَ فَضْلًا فَهَا هُنَا وَهَا هُنَا","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub], ia berkata; telah menceritakan kepada kami [Isma'il], ia berkata; telah menceritakan kepada kami [Ayyub] dari [Abu Az Zubair] dari [Jabir] bahwa seorang laki-laki dari Anshar yang dipanggil Abu Madzkur memerdekakan budaknya yang bernama Ya'qub apabila ia meninggal, ia tidak memiliki harta selainnya. Lalu Rasulullah shallallahu 'alaihi wasallam meminta agar budak tersebut didatangkan, kemudian beliau bersabda: \"Siapakah yang akan membelinya?\" kemudian ia dibeli Nu'aim bin Abdullah dengan harga delapan ratus dirham. kemudian beliau menyerahkannya kepada orang Anshar tersebut dan bersabda: Apabila salah seorang diantara kalian fakir maka hendaknya ia memulai dari dirinya, kemudian apabila tersisa maka diberikan kepada keluarganya, kemudian apabila tersisa maka diberikan kepada kerabatnya kemudian apabila tersisa maka diberikan ke sini dan ke sini.\""},"4359":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا سُفْيَانُ وَابْنُ أَبِي خَالِدٍ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ عَطَاءٍ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَاعَ الْمُدَبَّرَ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan], ia berkata; telah menceritakan kepada kami [Waki'], ia berkata; telah menceritakan kepada kami [Sufyan] dan [Ibnu Abu Khalid] dari [Salamah bin Khuhail] dari ['Atho`] dari [Jabir] bahwa Nabi shallallahu 'alaihi wasallam menjual budak yang dimerdekakan apabila tuannya meninggal. "},"4360":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَخْبَرَتْهُأَنَّ بَرِيرَةَ جَاءَتْ عَائِشَةَ تَسْتَعِينُهَا فِي كِتَابَتِهَا شَيْئًا فَقَالَتْ لَهَا عَائِشَةُ ارْجِعِي إِلَى أَهْلِكِ فَإِنْ أَحَبُّوا أَنْ أَقْضِيَ عَنْكِ كِتَابَتَكِ وَيَكُونَ وَلَاؤُكِ لِي فَعَلْتُ فَذَكَرَتْ ذَلِكَ بَرِيرَةُ لِأَهْلِهَا فَأَبَوْا وَقَالُوا إِنْ شَاءَتْ أَنْ تَحْتَسِبَ عَلَيْكِ فَلْتَفْعَلْ وَيَكُونَ لَنَا وَلَاؤُكِ فَذَكَرَتْ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْتَاعِي وَأَعْتِقِي فَإِنَّ الْوَلَاءَ لِمَنْ أَعْتَقَ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا بَالُ أَقْوَامٍ يَشْتَرِطُونَ شُرُوطًا لَيْسَتْ فِي كِتَابِ اللَّهِ فَمَنْ اشْتَرَطَ شَيْئًا لَيْسَ فِي كِتَابِ اللَّهِ فَلَيْسَ لَهُ وَإِنْ اشْتَرَطَ مِائَةَ شَرْطٍ وَشَرْطُ اللَّهِ أَحَقُّ وَأَوْثَقُ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari ['Urwah] dari [Aisyah], ia telah mengabarkan kepadanya bahwa Barirah datang kepada Aisyah meminta bantuan dalam menyelesaikan perjanjian pembebasannya. Kemudian Aisyah berkata kepadanya; kembalilah kepada tuanmu, apabila mereka ingin saya membayar perjanjian pembebasanmu dan perwaliannya untukku maka saya akan melakukannya. Kemudian Barirah menyebutkan hal tersebut kepada tuannyada mereka menolak, dan mengatakan; apabila ia ingin mengharapkan pahala dan perwaliannya untuk kami maka silahkan ia melakukannya. Kemudian Aisyah mengungkan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam dan beliau bersabda kepadanya: \"Belilah dan merdekakan, sesungguhnya perwalian itu untuk orang yang memerdekakan.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bagaimana keadaan suatu kaum, mereka memberikan syarat yang tidak ada dalam Kitab Allah, barang siapa yang memberi syarat yang tidak ada dalam Kitab Allah, maka ia tidak berhak atas syarat tersebut walaupun ia telah memberikan syarat seratus syarat. Syarat Allah lebih berhak dan lebih kuat. "},"4361":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي رِجَالٌ مِنْ أَهْلِ الْعِلْمِ مِنْهُمْ يُونُسُ وَاللَّيْثُ أَنَّ ابْنَ شِهَابٍ أَخْبَرَهُمْ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّهَا قَالَتْجَاءَتْ بَرِيرَةُ إِلَيَّ فَقَالَتْ يَا عَائِشَةُ إِنِّي كَاتَبْتُ أَهْلِي عَلَى تِسْعِ أَوَاقٍ فِي كُلِّ عَامٍ أُوقِيَّةٌ فَأَعِينِينِي وَلَمْ تَكُنْ قَضَتْ مِنْ كِتَابَتِهَا شَيْئًا فَقَالَتْ لَهَا عَائِشَةُ وَنَفِسَتْ فِيهَا ارْجِعِي إِلَى أَهْلِكِ فَإِنْ أَحَبُّوا أَنْ أُعْطِيَهُمْ ذَلِكَ جَمِيعًا وَيَكُونَ وَلَاؤُكِ لِي فَعَلْتُ فَذَهَبَتْ بَرِيرَةُ إِلَى أَهْلِهَا فَعَرَضَتْ ذَلِكَ عَلَيْهِمْ فَأَبَوْا وَقَالُوا إِنْ شَاءَتْ أَنْ تَحْتَسِبَ عَلَيْكِ فَلْتَفْعَلْ وَيَكُونَ ذَلِكِ لَنَا فَذَكَرَتْ ذَلِكَ عَائِشَةُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا يَمْنَعُكِ ذَلِكِ مِنْهَا ابْتَاعِي وَأَعْتِقِي فَإِنَّ الْوَلَاءَ لِمَنْ أَعْتَقَ فَفَعَلَتْ وَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي النَّاسِ فَحَمِدَ اللَّهَ تَعَالَى ثُمَّ قَالَ أَمَّا بَعْدُ فَمَا بَالُ النَّاسِ يَشْتَرِطُونَ شُرُوطًا لَيْسَتْ فِي كِتَابِ اللَّهِ مَنْ اشْتَرَطَ شَرْطًا لَيْسَ فِي كِتَابِ اللَّهِ فَهُوَ بَاطِلٌ وَإِنْ كَانَ مِائَةَ شَرْطٍ قَضَاءُ اللَّهِ أَحَقُّ وَشَرْطُ اللَّهِ أَوْثَقُ وَإِنَّمَا الْوَلَاءُ لِمَنْ أَعْتَقَ","id":"Telah mengabarkan kepada kami [Yunus bin Abdul A'la], ia berkata; telah memberitakan kepada kami [Ibnu Wahb], ia berkata; telah memberitakan kepadaku beberapa orang dari ulama, diantara mereka adalah [Yunus] dan [Al Laits] bahwa [Ibnu Syihab] telah mengabarkan kepada mereka dari ['Urwah] dari [Aisyah] bahwa ia berkata; telah datang Barirah kepadaku dan berkata; wahai Aisyah, sesungguhnya saya telah mengadakan janji dengan tuanku untuk memerdekakan diriku, dengan sembila uqiyah pada setiap tahun satu uqiyah, maka bantulah saya. Dan ia belum membayar sedikitpun dari perjanjian pembebasannya itu. Kemudian Aisyah berkata kepadanya; kembalilah kepada taunmu, apabila mereka ingin saya memberikan itu semua kepada mereka dan perwaliannya untukku maka saya akan melakukannya. Kemudian Barirah pergi menemui tuannya dan menawarkan kepada mereka hal tersebut, namun mereka menolak, dan mengatakan; apabila ia mau mengharapkan pahala maka hendaknya silahkan ia melakukan dan perwalian itu untuk kami. Kemudian Aisyah menyampaikan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam. Lalu beliau bersabda: \"Hal itu tidak menghalangimu darinya. Belilah dan merdekakan, sesungguhnya perwalian untuk orang yang memerdekakan.\" Kemudian Aisyah melakukannya, dan Rasulullah shallallahu 'alaihi wasallam berdiri diantara manusia kemudian memuji Allah ta'la kemudian bersabda: \"Adapun selanjutnya, bagaimana keadaan orang-orang yang memberikan syarat-syarat yang tidak ada dalam Kitab Allah. Barang siapa yang memberikan syarat yang tidak ada dalam Kitab Allah maka syarat tersebut adalah batil, walaupun seratus syarat. Keputusan Allah lebih berhak dan syarat Allah lebih kuat, sesungguhnya perwalian adalah untuk orang yang memerdekakan.\""},"4362":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الْوَلَاءِ وَعَنْ هِبَتِهِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud], ia berkata; telah menceritakan kepada kami [Khalid], ia berkata; telah menceritakan kepada kami ['Ubaidullah] dari [Abdullah bin Dinar] dari [Abdullah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari menjual perwalian dan memberikannya. "},"4363":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الْوَلَاءِ وَعَنْ هِبَتِهِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id], ia berkata; telah menceritakan kepada kami [Malik] dari [Abdullah bin Dinar] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari menjual perwalian dan memberikannya."},"4364":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ شُعْبَةَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الْوَلَاءِ وَعَنْ هِبَتِهِ","id":"Telah mengabarkan kepada kami [Ali bin Hujr], ia berkata; telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Syu'bah] dari [Abdullah bin Dinar] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari menjual perwalian dan memberikannya."},"4365":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى السِّينَانِيُّ عَنْ حُسَيْنِ بْنِ وَاقِدٍ عَنْ أَيُّوبَ السَّخْتِيَانِيِّ عَنْ عَطَاءٍ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الْمَاءِ","id":"Telah mengabarkan kepada kami [Al Husain bin Huraits], ia berkata; telah menceritakan kepada kami [Al Fadhl bin Musa As Sinani] dari [Husain bin Waqid] dari [Ayyub As Sakhtiyani] dari ['Atho`] dari [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari menjual air. "},"4366":{"ar":"أَخْبَرَنَا قُتَيْبَةُ وَعَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ وَاللَّفْظُ لَهُ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ قَالَ سَمِعْتُ أَبَا الْمِنْهَالِ يَقُولُ سَمِعْتُ إِيَاسَ بْنَ عُمَرَ وَقَالَ مَرَّةً ابْنَ عَبْدٍ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ بَيْعِ الْمَاءِقَالَ قُتَيْبَةُ لَمْ أَفْقَهْ عَنْهُ بَعْضَ حُرُوفِ أَبِي الْمِنْهَالِ كَمَا أَرَدْتُ","id":"Telah mengabarkan kepada kami [Qutaibah] dan [Abdullah bin Muhammad bin Abdur Rahman] dan lafazhnya adalah lafazh Abdullah, mereka berkata; telah menceritakan kepada kami [Sufyan] dari ['Amru bin Dinar], ia berkata; saya mendengar [Abu Al Minhal] berkata; saya mendengar [Iyas bin Umar]... (terkadang ia mengatakan; Ibnu ' Abd) berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam melarang dari menjual air. Qutaibah berkata; saya tidak memahami sebagian yang dikatakan Abu Al Minhal sebagaimana yang saya inginkan. "},"4367":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا دَاوُدُ عَنْ عَمْرٍو عَنْ أَبِي الْمِنْهَالِ عَنْ إِيَاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ فَضْلِ الْمَاءِوَبَاعَ قَيِّمُ الْوَهَطِ فَضْلَ مَاءِ الْوَهَطِ فَكَرِهَهُ عَبْدُ اللَّهِ بْنُ عَمْرٍو","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id], ia berkata; telah menceritakan kepada kami [Daud] dari ['Amru] dari [Abu Al Minhal] dari [Iyas] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari menjual kelebihan air. Dan penjaga Al Wahth telah menjual kelebihan air dan Abdullah bin 'Amru tidak menyukainya. "},"4368":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْحَسَنِ عَنْ حَجَّاجٍ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي عَمْرُو بْنُ دِينَارٍ أَنَّ أَبَا الْمِنْهَالِ أَخْبَرَهُ أَنَّ إِيَاسَ بْنَ عَبْدٍ صَاحِبَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَلَا تَبِيعُوا فَضْلَ الْمَاءِ فَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ فَضْلِ الْمَاءِ","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Hasan] dari [Hajjaj], ia berkata; telah berkata [Ibnu Juraij] berkata; telah mengabarkan kepadaku ['Amru bin Dinar] bahwa [Abu Al Minhal] telah mengabarkan kepadanya bahwa [Iyas bin 'Abd] seorang sahabat Nabi berkata; janganlah kalian menjual kelebihan air, sesungguhnya Nabi melarang dari menjual kelebihan air. "},"4369":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ ابْنِ وَعْلَةَ الْمِصْرِيِّ أَنَّهُ سَأَلَ ابْنَ عَبَّاسٍعَمَّا يُعْصَرُ مِنْ الْعِنَبِ قَالَ ابْنُ عَبَّاسٍ أَهْدَى رَجُلٌ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَاوِيَةَ خَمْرٍ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ عَلِمْتَ أَنَّ اللَّهَ عَزَّ وَجَلَّ حَرَّمَهَا فَسَارَّ وَلَمْ أَفْهَمْ مَا سَارَّ كَمَا أَرَدْتُ فَسَأَلْتُ إِنْسَانًا إِلَى جَنْبِهِ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَ سَارَرْتَهُ قَالَ أَمَرْتُهُ أَنْ يَبِيعَهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الَّذِي حَرَّمَ شُرْبَهَا حَرَّمَ بَيْعَهَا فَفَتَحَ الْمَزَادَتَيْنِ حَتَّى ذَهَبَ مَا فِيهِمَا","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Zaid bin Aslam] dari [Ibnu Wa'lah Al Mishri] bahwa ia bertanya kepada Ibnu Abbas mengenai apa yang diperas dari anggur, [Ibnu Abbas] berkata; seseorang telah memberikan hadiah kepada Rasulullah shallallahu 'alaihi wasallam geriba yang penuh dengan minuman keras, kemudian Nabi shallallahu 'alaihi wasallam bersabda kepadanya; \"Tidakkah engkau mengetahui bahwa Allah 'azza wajalla telah mengharamkannya?\" kemudian orang tersebut membisikkan dan saya tidak memahami apa yang ia bisikkan seperti saya menginginkan. Kemudian saya bertanya kepada seseorang disampingnya. Lalu Nabi shallallahu 'alaihi wasallam bertanya kepadanya: \"Apa yang engkau bisikkan?\" Orang tersebut berkata; saya memerintahkannya agar menjualnya. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Yang mengharamkannya mengharamkan penjualannya.\" Kemudian beliau membuka dua bejana besar yang terbuat dari kulit hingga terbuang isinya. "},"4370":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْلَمَّا نَزَلَتْ آيَاتُ الرِّبَا قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ فَتَلَاهُنَّ عَلَى النَّاسِ ثُمَّ حَرَّمَ التِّجَارَةَ فِي الْخَمْرِ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan], ia berkata; telah menceritakan kepada kami [Waki'], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Abu Adh Dhuha] dari [Masruq] dari [Aisyah], ia berkata; tatkala turun ayat mengenai riba Rasulullah shallallahu 'alaihi wasallam berdiri di atas mimbar kemudian membacakan ayat tersebut kepada manusia, kemudian beliau mengharamkan penjualan minuman keras. "},"4371":{"ar":"حَدَّثَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ أَنَّهُ سَمِعَ أَبَا مَسْعُودٍ عُقْبَةَ بْنَ عَمْرٍو قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ثَمَنِ الْكَلْبِ وَمَهْرِ الْبَغِيِّ وَحُلْوَانِ الْكَاهِنِ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Abu Bakr bin Abdur Rahman bin Al Harits bin Hisyam] bahwa ia mendengar [Abu Mas'ud 'Uqbah bin 'Amru], ia berkata; Rasulullah shallallahu 'alaihi wasallam telah melarang dari menjual anjing upah pelacur dan bayaran dukun. "},"4372":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ قَالَ حَدَّثَنَا سَعِيدُ بْنُ عِيسَى قَالَ أَنْبَأَنَا الْمُفَضَّلُ بْنُ فَضَالَةَ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَشْيَاءَ حَرَّمَهَا وَثَمَنُ الْكَلْبِ","id":"Telah mengabarkan kepada kami [Abdur Rahman bin Abdullah bin Abdul Hakam], ia berkata; telah menceritakan kepada kami [Sa'id bin Isa], ia berkata; telah memberitakan kepada kami [Al Mufadhdhal bin Fadhalah] dari [Ibnu Juraij] dari ['Atho` bin Abu Rabah] dari [Ibn Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda mengenai apa saja yang diharamkan: \" Dan menjual anjing.\""},"4373":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ الْحَسَنِ قَالَ أَنْبَأَنَا حَجَّاجُ بْنُ مُحَمَّدٍ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ ثَمَنِ الْكَلْبِ وَالسِّنَّوْرِ إِلَّا كَلْبِ صَيْدٍقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا مُنْكَرٌ","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Hasan], ia berkata; telah memberitakan kepada kami [Hajjaj bin Muhammad] dari [Hammad bin Salamah] dari [Abu Az Zubair] dari [Jabir bin Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari menjual anjing dan kucing kecuali anjing pemburu. Abdur Rahman berkata; hadits ini adalah mungkar. "},"4374":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عَامَ الْفَتْحِ وَهُوَ بِمَكَّةَ إِنَّ اللَّهَ وَرَسُولَهُ حَرَّمَ بَيْعَ الْخَمْرِ وَالْمَيْتَةِ وَالْخِنْزِيرِ وَالْأَصْنَامِ فَقِيلَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ شُحُومَ الْمَيْتَةِ فَإِنَّهُ يُطْلَى بِهَا السُّفُنُ وَيُدَّهَنُ بِهَا الْجُلُودُ وَيَسْتَصْبِحُ بِهَا النَّاسُ فَقَالَ لَا هُوَ حَرَامٌ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ ذَلِكَ قَاتَلَ اللَّهُ الْيَهُودَ إِنَّ اللَّهَ عَزَّ وَجَلَّ لَمَّا حَرَّمَ عَلَيْهِمْ شُحُومَهَا جَمَّلُوهُ ثُمَّ بَاعُوهُ فَأَكَلُوا ثَمَنَهُ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari ['Atho` bin Abu Rabah] dari [Jabir bin Abdullah] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda pada saat penaklukan Mekkah dan beliau berada di Mekkah: \"Sesungguhnya Allah dan RasulNya telah mengharamkan menjual minuman keras, bangkai, babi dan patung.\" Beliau ditanya; wahai Rasulullah, bagaimana pendapat anda mengenai lemak bangkai, sesungguhnya lemak itu bisa digunakan untuk mengecat kapal, dan meminyaki kulit serta digunakan manusia untuk penerangan. Kemudian beliau bersabda: \"Tidak, itu adalah haram.\" Rasulullah shallallahu 'alaihi wasallam pada saat demikian bersabda: \"Semoga Allah 'azza wajalla memerangi orang-orang Yahudi, Allah telah mengharamkan atas mereka lemaknya lalu mereka mencairkannya, kemudian menjualnya dan memakan uangnya.\""},"4375":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ الْحَسَنِ عَنْ حَجَّاجٍ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرًا يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ ضِرَابِ الْجَمَلِ وَعَنْ بَيْعِ الْمَاءِ وَبَيْعِ الْأَرْضِ لِلْحَرْثِ يَبِيعُ الرَّجُلُ أَرْضَهُ وَمَاءَهُ فَعَنْ ذَلِكَ نَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Hasan] dari [Hajjaj], ia berkata; telah berkata [Ibnu Juraij]; telah mengabarkan kepadaku [Abu Az Zubair] bahwa ia telah mendengar [Jabir] berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari menjual pengawinan unta, dan dari menjual air, menjual tanah bercocok tanam, yaitu seseorang menjual tanahnya dan airnya. Maka dari hal tersebut Nabi shallallahu 'alaihi wasallam melarang. "},"4376":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ عَلِيِّ بْنِ الْحَكَمِ ح وَأَنْبَأَنَا حُمَيْدُ بْنُ مَسْعَدَةَ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ عَلِيِّ بْنِ الْحَكَمِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ عَسْبِ الْفَحْلِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Ali bin Al Hakam], telah menceritakan dan memberikatakan kepada kami [Humaid bin Mas'adah], ia berkata; telah menceritakan kepada kami [Abdul Warits] dari [Ali bin Al Hakam] dari [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari penyewaan pejantan."},"4377":{"ar":"أَخْبَرَنَا عِصْمَةُ بْنُ الْفَضْلِ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ إِبْرَاهِيمَ بْنِ حُمَيْدٍ الرُّوَاسِيِّ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَجَاءَ رَجُلٌ مِنْ بَنِي الصَّعْقِ أَحَدِ بَنِي كِلَابٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ عَنْ عَسْبِ الْفَحْلِ فَنَهَاهُ عَنْ ذَلِكَ فَقَالَ إِنَّا نُكْرِمُ عَلَى ذَلِكَ","id":"Telah mengabarkan kepada kami ['Ishmah bin Al Fadhl], ia berkata; telah menceritakan kepada kami [Yahya bin Adam] dari [Ibrahim bin Humaid Ar Ruwasi], ia berkata; telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Muhammad bin Ibrahim bin Al Harits] dari [Anas bin Malik] ia berkata; seorang laki-laki dari Bani Sha'q salah satu dari Bani Kilab mendatangi Rasulullah shallallahu 'alaihi wasallam dan bertanya kepada beliau; mengenai penyewakan pejantan. Maka beliau melarang hal itu dan bersabda: \"Sesungguhnya kami memuliakan hal itu.\""},"4378":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ عَنْ مُحَمَّدٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْمُغِيرَةِ قَالَ سَمِعْتُ ابْنَ أَبِي نُعْمٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ كَسْبِ الْحَجَّامِ وَعَنْ ثَمَنِ الْكَلْبِ وَعَنْ عَسْبِ الْفَحْلِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dari [Muhammad], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Al Mughirah], ia berkata; saya mendengar [Ibnu Abu Nu'm], ia berkata; saya mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari usaha tukang bekam, menjual anjing serta penyewaan pejantan. "},"4379":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ عَلِيِّ بْنِ مَيْمُونٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامٍ عَنْ ابْنِ أَبِي نُعْمٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ عَسْبِ الْفَحْلِ","id":"Telah mengabarkan kepada kami [Muhammad bin Ali bin Maimun], ia berkata; telah menceritakan kepada kami [Muhammad], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Hisyam] dari [Ibnu Abu Nu'm] dari [Abu Sa'id Said Alkhudri] ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari penyewakan pejantan."},"4380":{"ar":"أَخْبَرَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ الْأَعْمَشِ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ثَمَنِ الْكَلْبِ وَعَسْبِ الْفَحْلِ","id":"Telah mengabarkan kepada kami [Washil bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Ibnu Fudhail] dari [Al A'masy] dari [Abu Hazim] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari jual beli anjing dan penyewaan pejantan."},"4381":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَحْيَى عَنْ أَبِي بَكْرِ بْنِ حَزْمٍ عَنْ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا امْرِئٍ أَفْلَسَ ثُمَّ وَجَدَ رَجُلٌ عِنْدَهُ سِلْعَتَهُ بِعَيْنِهَا فَهُوَ أَوْلَى بِهِ مِنْ غَيْرِهِ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Yahya] dari [Abu Bakr bin Hazm] dari [Umar bin Abdul Aziz] dari [Abu Bakr bin Abdur Rahman bin Al Harits bin Hisyam] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Siapapun orang yang bangkrut kemudian seseorang mendapati barangnya ada padanya maka ia lebih berhak daripada selainnya.\""},"4382":{"ar":"أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ وَإِبْرَاهِيمُ بْنُ الْحَسَنِ وَاللَّفْظُ لَهُ قَالَ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي ابْنُ أَبِي حُسَيْنٍ أَنَّ أَبَا بَكْرِ بْنَ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ أَخْبَرَهُ أَنَّ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ حَدَّثَهُ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ حَدِيثِ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الرَّجُلِ يُعْدِمُ إِذَا وُجِدَ عِنْدَهُ الْمَتَاعُ بِعَيْنِهِ وَعَرَفَهُ أَنَّهُ لِصَاحِبِهِ الَّذِي بَاعَهُ","id":"Telah mengabarkan kepada kami [Abdur Rahman bin Khalid] dan [Ibrahim bin Al Hasan], lafazhnya adalah lafazh Ibrahim, ia berkata; telah menceritakan kepada kami [Hajjaj bin Muhammad], ia berkata; telah berkata [Ibnu Juraij]; telah mengabarkan kepadaku [Ibnu Abu Husain] bahwa [Abu Bakr bin Muhammad bin 'Amru bin Hazm] telah mengabarkan kepadanya bahwa [Umar bin Abdul Aziz] telah menceritakan kepadanya dari [Abu Bakr bin Abdur Rahman] dari hadits [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam mengenai seorang laki-laki yang menjadi miskin, apabila didapatkan bersamanya sebuah barang dan ia mengetahuinya, bahwa barang tersebut adalah untuk pemiliknya yang telah menjualnya."},"4383":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ حَدَّثَنِي اللَّيْثُ بْنُ سَعْدٍ وَعَمْرُو بْنُ الْحَارِثِ عَنْ بُكَيْرِ بْنِ الْأَشَجِّ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَأُصِيبَ رَجُلٌ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ثِمَارٍ ابْتَاعَهَا وَكَثُرَ دَيْنُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَصَدَّقُوا عَلَيْهِ فَتَصَدَّقُوا عَلَيْهِ وَلَمْ يَبْلُغْ ذَلِكَ وَفَاءَ دَيْنِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُذُوا مَا وَجَدْتُمْ وَلَيْسَ لَكُمْ إِلَّا ذَلِكَ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amru bin As Sarh], ia berkata; telah memberitakan kepada kami [Ibnu Wahb], ia berkata; telah menceritakan kepadaku [Al Laits bin Sa'd] dan ['Amru bin Al Harits] dari [Bukair bin Al Asyajj] dari ['Iyadh bin Abdullah] dari [Abu Sa'id Al Khudri], ia berkata; seeorang pada zaman Rasulullah shallallahu 'alaihi wasallam tertimpa musibah pada buah-buahan yang ia beli sehingga hutangnya menjadi banyak. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bersedekahlah kepadanya.\" Kemudian mereka bersedekah kepadanya dan hal itu belum bisa menutup hutannya, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ambillah apa yang kalian dapatkan, dan kalian tidak memiliki hak kecuali hal itu.\""},"4384":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا حَمَّادُ بْنُ مَسْعَدَةَ عَنْ ابْنِ جُرَيْجٍ عَنْ عِكْرِمَةَ بْنِ خَالِدٍ قَالَ حَدَّثَنِي أُسَيْدُ بْنُ حُضَيْرِ بْنِ سِمَاكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى أَنَّهُ إِذَا وَجَدَهَا فِي يَدِ الرَّجُلِ غَيْرِ الْمُتَّهَمِ فَإِنْ شَاءَ أَخَذَهَا بِمَا اشْتَرَاهَا وَإِنْ شَاءَ اتَّبَعَ سَارِقَهُ وَقَضَى بِذَلِكَ أَبُو بَكْرٍ وَعُمَرُ","id":"Telah mengabarkan kepada kami [Harun bin Abdullah], ia berkata; telah menceritakan kepada kami [Hammad bin Mas'adah] dari [Ibnu Juraij] dari [Ikrimah bin Khalid], ia berkata; telah menceritakan kepadaku [Usaid bin Hudhair bin Simak] bahwa Rasulullah shallallahu 'alaihi wasallam memutuskan jika ia mendapatkan barangnya ditangan laki-laki yang tidak tertuduh, maka jika mau ia boleh mengambil dengan memberikan harga belinya, dan jika mau ia boleh menuntut orang yang mencurinya. Dan Abu Bakar serta Umar memutuskan hal seperti itu."},"4385":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سَعِيدُ بْنُ ذُؤَيْبٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ ابْنِ جُرَيْجٍ وَلَقَدْ أَخْبَرَنِي عِكْرِمَةُ بْنُ خَالِدٍ أَنَّ أُسَيْدَ بْنَ حُضَيْرٍ الْأَنْصَارِيَّ ثُمَّ أَحَدَ بَنِي حَارِثَةَ أَخْبَرَهُأَنَّهُ كَانَ عَامِلًا عَلَى الْيَمَامَةِ وَأَنَّ مَرْوَانَ كَتَبَ إِلَيْهِ أَنَّ مُعَاوِيَةَ كَتَبَ إِلَيْهِ أَنَّ أَيَّمَا رَجُلٍ سُرِقَ مِنْهُ سَرِقَةٌ فَهُوَ أَحَقُّ بِهَا حَيْثُ وَجَدَهَا ثُمَّ كَتَبَ بِذَلِكَ مَرْوَانُ إِلَيَّ فَكَتَبْتُ إِلَى مَرْوَانَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِأَنَّهُ إِذَا كَانَ الَّذِي ابْتَاعَهَا مِنْ الَّذِي سَرَقَهَا غَيْرُ مُتَّهَمٍ يُخَيَّرُ سَيِّدُهَا فَإِنْ شَاءَ أَخَذَ الَّذِي سُرِقَ مِنْهُ بِثَمَنِهَا وَإِنْ شَاءَ اتَّبَعَ سَارِقَهُ ثُمَّ قَضَى بِذَلِكَ أَبُو بَكْرٍ وَعُمَرُ وَعُثْمَانُ فَبَعَثَ مَرْوَانُ بِكِتَابِي إِلَى مُعَاوِيَةَ وَكَتَبَ مُعَاوِيَةُ إِلَى مَرْوَانَ إِنَّكَ لَسْتَ أَنْتَ وَلَا أُسَيْدٌ تَقْضِيَانِ عَلَيَّ وَلَكِنِّي أَقْضِي فِيمَا وُلِّيتُ عَلَيْكُمَا فَأَنْفِذْ لِمَا أَمَرْتُكَ بِهِ فَبَعَثَ مَرْوَانُ بِكِتَابِ مُعَاوِيَةَ فَقُلْتُ لَا أَقْضِي بِهِ مَا وُلِّيتُ بِمَا قَالَ مُعَاوِيَةُ","id":"Telah mengabarkan kepada kami ['Amru bin Manshur] telah menceritakan kepada kami [Sa'id bin Dzuaib] telah menceritakan kepada kami [Abdur Razzaq] dari [Ibnu Juraij] sungguh telah mengabarkan kepadaku [Ikrimah bin Khalid] bahwa [Usaid bin Hudhair Al Anshari] kemudian salah seorang Bani Haritsah mengabarkan kepadanya bahwa dia adalah seorang gubernur di daerah Yamamah dan bahwa Marwan telah menulis surat kepadanya bahwa Mu'awiyah telah menulis surat kepadanya bahwa siapapun laki-laki yang kecurian suatu barang curian maka dia lebih berhak terhadap barang tersebut, ketika dia mendapatkannya (kembali). Kemudian Marwan menulis surat tersebut kepadaku, saya pun menulis surat kepada Marwan bahwa Nabi shallallahu 'alaihi wasallam memutuskan bahwasanya apabila orang yang membeli barang dari orang yang mencuri bukanlah orang yang tertuduh maka pemiliknya diberi pilihan, apabila mau dia boleh mengambil barang yang dicuri dengan memberikan harganya, dan apabila dia mau maka dia bisa menuntut orang yang mencurinya. Kemudian Abu Bakar, Umar dan Utsman memutuskan dengan hal tersebut. Lalu Marwan mengirim utusan dengan membawa suratku kepada Mu'awiyah. Dan Mu'awiyah menulis kepada Marwan; \"Sesungguhnya bukan engkau dan bukan Usaid yang memutuskan suatu perkara atas diriku, akan tetapi sayalah yang memutuskan perkara yang dikuasakan kepadaku atas kalian, maka lakukanlah apa yang aku perintahkan kepadamu.\" Kemudian Marwan mengirim surat Mu'awiyah kepadaku, lalu saya katakan; \"Selagi saya menjabat, saya tidak akan memutuskan dengan apa yang dikatakan Mu'awiyah.\""},"4386":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ دَاوُدَ قَالَ حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ قَالَ حَدَّثَنَا هُشَيْمٌ عَنْ مُوسَى بْنِ السَّائِبِ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرَّجُلُ أَحَقُّ بِعَيْنِ مَالِهِ إِذَا وَجَدَهُ وَيَتْبَعُ الْبَائِعُ مَنْ بَاعَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Daud] telah menceritakan kepada kami ['Amru bin 'Aun] telah menceritakan kepada kami [Husyaim] dari [Musa bin As Saib] dari [Qatadah] dari [Al Hasan] dari [Samurah], Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seseorang itu lebih berhak terhadap hartanya jika ia mendapatinya, dan seorang penjual menuntut orang yang menjualnya.\""},"4387":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا امْرَأَةٍ زَوَّجَهَا وَلِيَّانِ فَهِيَ لِلْأَوَّلِ مِنْهُمَا وَمَنْ بَاعَ بَيْعًا مِنْ رَجُلَيْنِ فَهُوَ لِلْأَوَّلِ مِنْهُمَا","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari [Qatadah] dari [Al Hasan] dari [Samurah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapapun wanita yang dinikahkan oleh dua orang wali maka ia adalah milik orang yang lebih dahulu dari keduanya, dan barang siapa yang menjual sesuatu kepada dua orang maka sesuatu tersebut milik orang yang lebih dahulu dari keduanya.\""},"4388":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي رَبِيعَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَاسْتَقْرَضَ مِنِّي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعِينَ أَلْفًا فَجَاءَهُ مَالٌ فَدَفَعَهُ إِلَيَّ وَقَالَ بَارَكَ اللَّهُ لَكَ فِي أَهْلِكَ وَمَالِكَ إِنَّمَا جَزَاءُ السَّلَفِ الْحَمْدُ وَالْأَدَاءُ","id":"Telah menceritakan kepada kami ['Amru bin Ali] telah menceritakan kepada kami [Abdur Rahman] dari [Sufyan] dari [Ismail bin Ibrahim bin Abdullah bin Abu Rabi'ah] dari [ayahnya] dari [kakeknya], dia berkata; \"Nabi shallallahu 'alaihi wasallam meminjam uang kepadaku sebanyak empat puluh ribu, lalu ketika beliau memiliki harta beliau menyerahkannya kepadaku dan bersabda: \"Semoga Allah memberkahi keluarga dan hartamu, sesungguhnya balasan bagi peminjaman itu adalah pujian dan pemenuhan (pelunasan).\""},"4389":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ عَنْ إِسْمَعِيلَ قَالَ حَدَّثَنَا الْعَلَاءُ عَنْ أَبِي كَثِيرٍ مَوْلَى مُحَمَّدِ بْنِ جَحْشٍ عَنْ مُحَمَّدِ بْنِ جَحْشٍ قَالَكُنَّا جُلُوسًا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَفَعَ رَأْسَهُ إِلَى السَّمَاءِ ثُمَّ وَضَعَ رَاحَتَهُ عَلَى جَبْهَتِهِ ثُمَّ قَالَ سُبْحَانَ اللَّهِ مَاذَا نُزِّلَ مِنْ التَّشْدِيدِ فَسَكَتْنَا وَفَزِعْنَا فَلَمَّا كَانَ مِنْ الْغَدِ سَأَلْتُهُ يَا رَسُولَ اللَّهِ مَا هَذَا التَّشْدِيدُ الَّذِي نُزِّلَ فَقَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَوْ أَنَّ رَجُلًا قُتِلَ فِي سَبِيلِ اللَّهِ ثُمَّ أُحْيِيَ ثُمَّ قُتِلَ ثُمَّ أُحْيِيَ ثُمَّ قُتِلَ وَعَلَيْهِ دَيْنٌ مَا دَخَلَ الْجَنَّةَ حَتَّى يُقْضَى عَنْهُ دَيْنُهُ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] dari [Isma'il] telah menceritakan kepada kami [Al 'Ala`] dari [Abu Katsir], budak Muhammad bin Jahsy dari [Muhammad bin Jahsy], dia berkata; \"Kami pernah duduk-duduk bersama Rasulullah shallallahu 'alaihi wasallam kemudian beliau mendongakkan kepala beliau ke langit kemudian beliau meletakkan telapak tangan beliau pada kening beliau kemudian bersabda: \"Subhanallah, apakah yang telah diturunkan dari sikap keras?\" kemudian kami diam dan terkejut. Kemudian setelah besok harinya saya bertanya kepada beliau; \"Wahai Rasulullah, sikap keras apakah yang telah diturunkan ini? Beliau bersabda: \"Demi Dzat yang jiwaku ada di tanganNya, seandainya seseorang terbunuh di jalan Allah, kemudian dihidupkan, kemudian terbunuh, kemudian dihidupkan, kemudian terbunuh dan ia memiliki tanggungan hutang maka ia tidak akan masuk Surga hingga terbayarkan hutangnya.\""},"4390":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا الثَّوْرِيُّ عَنْ أَبِيهِ عَنْ الشَّعْبِيِّ عَنْ سَمْعَانَ عَنْ سَمُرَةَ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جِنَازَةٍ فَقَالَ أَهَا هُنَا مِنْ بَنِي فُلَانٍ أَحَدٌ ثَلَاثًا فَقَامَ رَجُلٌ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مَنَعَكَ فِي الْمَرَّتَيْنِ الْأُولَيَيْنِ أَنْ لَا تَكُونَ أَجَبْتَنِي أَمَا إِنِّي لَمْ أُنَوِّهْ بِكَ إِلَّا بِخَيْرٍ إِنَّ فُلَانًا لِرَجُلٍ مِنْهُمْ مَاتَ مَأْسُورًا بِدَيْنِهِ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abdur Razzaq] telah menceritakan kepada kami [Ats Tsauri] dari [ayahnya] dari [Asy Sya'bi] dari [Sam'an] dari [Samurah], dia berkata; \"Kami bersama Rasulullah shallallahu 'alaihi wasallam ketika mengurusi jenazah, lalu beliau bersabda: \"Apakah disini ada seseorang yang berasal dari Bani Fulan, \" sebanyak tiga kali, lalu berdirilah seseorang, kemudian Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Apa yang menghalangimu untuk menjawabku pada kedua panggilan pertama, aku tidak bermaksud kepadamu selain kebaikan, sesungguhnya Fulan (yaitu seseorang diantara mereka) meninggal dalam keadaan tertahan oleh hutangnya.\""},"4391":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ قُدَامَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ زِيَادِ بْنِ عَمْرِو بْنِ هِنْدٍ عَنْ عِمْرَانَ بْنِ حُذَيْفَةَ قَالَكَانَتْ مَيْمُونَةُ تَدَّانُ وَتُكْثِرُ فَقَالَ لَهَا أَهْلُهَا فِي ذَلِكَ وَلَامُوهَا وَوَجَدُوا عَلَيْهَا فَقَالَتْ لَا أَتْرُكُ الدَّيْنَ وَقَدْ سَمِعْتُ خَلِيلِي وَصَفِيِّي صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ أَحَدٍ يَدَّانُ دَيْنًا فَعَلِمَ اللَّهُ أَنَّهُ يُرِيدُ قَضَاءَهُ إِلَّا أَدَّاهُ اللَّهُ عَنْهُ فِي الدُّنْيَا","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ziyad bin 'Amru bin Hindun] dari [Imran bin Hudzaifah], dia berkata; \" [Maimunah] adalah orang yang banyak berhutang, keluarganya memperingatkan akan hal itu, mencelanya dan marah kepadanya. Dia lalu berkata; \"Aku tidak akan meninggalkan hutang, sungguh aku telah mendengar kekasihku dan pilihanku shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang yang banyak berhutang dan Allah mengetahui bahwa ia ingin membayarnya kecuali Allah akan membayarkannya di dunia.\""},"4392":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ قَالَ حَدَّثَنَا أَبِي عَنْ الْأَعْمَشِ عَنْ حُصَيْنِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَأَنَّ مَيْمُونَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَدَانَتْ فَقِيلَ لَهَا يَا أُمَّ الْمُؤْمِنِينَ تَسْتَدِينِينَ وَلَيْسَ عِنْدَكِ وَفَاءٌ قَالَتْ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَخَذَ دَيْنًا وَهُوَ يُرِيدُ أَنْ يُؤَدِّيَهُ أَعَانَهُ اللَّهُ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [ayahku] dari [Al A'masy] dari [Hushain bin Abdur Rahman] dari ['Ubaidullah bin Abdullah bin 'Utbah] bahwa [Maimunah] isteri Nabi shallallahu 'alaihi wasallam berhutang, kemudian dikatakan kepadanya; \"Wahai Ummul Mukminin, engkau berhutang sedangkan engkau tidak mampu melunasi?\" Dia berkata; \"Sesungguhnya saya telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang mengambil hutang dan dia ingin membayarnya maka Allah 'azza wajalla akan membantunya.\""},"4393":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أُتْبِعَ أَحَدُكُمْ عَلَى مَلِيءٍ فَلْيَتْبَعْ وَالظُّلْمُ مَطْلُ الْغَنِيِّ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Sufyan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila seseorang diantara kalian dipindahkan kepada orang yang kaya maka hendaknya ia mengikuti, kezhaliman adalah orang kaya yang menunda pembayaran hutang tanpa adanya udzur (syar'i).\""},"4394":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ آدَمَ قَالَ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ وَبْرِ بنِ أَبِي دُلَيْلَةَ عَنْ مُحَمَّدِ بْنِ مَيْمُونٍ عَنْ عَمْرِو بْنِ الشَّرِيدِ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيُّ الْوَاجِدِ يُحِلُّ عِرْضَهُ وَعُقُوبَتَهُ","id":"Telah mengabarkan kepadaku [Muhammad bin Adam] telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Wabr bin Abu Dulailah] dari [Muhammad bin Maimun] dari ['Amru bin Asy Syarid] dari [ayahnya], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Penundaan pembayaran hutan yang dilakukan oleh orang yang mampu membayarnya menghalalkan kehormatan (untuk dighibah) dan hukumannya.\" "},"4395":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا وَبْرُ بْنُ أَبِي دُلَيْلَةَ الطَّائِفِيُّ عَنْ مُحَمَّدِ بْنِ مَيْمُونِ ابْنِ مُسَيْكَةَ وَأَثْنَى عَلَيْهِ خَيْرًا عَنْ عَمْرِو بْنِ الشَّرِيدِ عَنْ أَبِيهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيُّ الْوَاجِدِ يُحِلُّ عِرْضَهُ وَعُقُوبَتَهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Wabr bin Abu Dulailah Ath Thaify] dari [Muhammad bin Maimun bin Musaikah] dan dia memujinya dengan kebaikan dari ['Amru bin Asy Syarid] dari [ayahnya] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Penundaan pembayaran hutan yang dilakukan oleh orang yang mampu membayarnya menghalalkan kehormatan (untuk dighibah) dan hukumannya.\" "},"4396":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَطْلُ الْغَنِيِّ ظُلْمٌ وَإِذَا أُتْبِعَ أَحَدُكُمْ عَلَى مَلِيءٍ فَلْيَتْبَعْ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] dengan membacakan riwayat sedang saya mendengar, lafazhnya adalah lafazh Al Harits, dari [Ibnu Al Qasim] telah menceritakan kepadaku [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Penundaan pembayaran hutang yang dilakukan oleh orang yang kaya adalah kezhaliman. Apabila seseorang diantara kalian dipindahkan kepada orang yang kaya maka hendaknya dia mengikuti.\""},"4397":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ عُثْمَانَ بْنِ عَبْدِ اللَّهِ بْنِ مَوْهَبٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِأَنَّ رَجُلًا مِنْ الْأَنْصَارِ أُتِيَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصَلِّيَ عَلَيْهِ فَقَالَ إِنَّ عَلَى صَاحِبِكُمْ دَيْنًا فَقَالَ أَبُو قَتَادَةَ أَنَا أَتَكَفَّلُ بِهِ قَالَ بِالْوَفَاءِ قَالَ بِالْوَفَاءِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] telah menceritakan kepada kami [Khalid] telah menceritakan kepada kami [Sa'id] dari [Utsman bin Abdullah bin Mauhab] dari [Abdullah bin Abu Qatadah] dari [ayahnya] bahwa seseorang dari kalangan Anshar dihadapkan kepada Nabi shallallahu 'alaihi wasallam agar beliau menshalatinya, kemudian beliau bersabda: \"Sesungguhnya sahabat kalian ini memiliki hutang.\" Kemudian Abu Qatadah berkata; \"Saya yang akan menanggungnya.\" Beliau bersabda: \"Dengan membayarnya?\" Dia berkata; \"Dengan membayarnya.\""},"4398":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ عَنْ وَكِيعٍ قَالَ حَدَّثَنِي عَلِيُّ بْنُ صَالِحٍ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خِيَارُكُمْ أَحْسَنُكُمْ قَضَاءً","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dari [Waki'] telah menceritakan kepadaku [Ali bin Shalih] dari [Salamah bin Kuhail] dari [Abu Salamah] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sebaik-baik kalian adalah yang paling baik dalam membayar (hutang).\""},"4399":{"ar":"أَخْبَرَنَا عِيسَى بْنُ حَمَّادٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ رَجُلًا لَمْ يَعْمَلْ خَيْرًا قَطُّ وَكَانَ يُدَايِنُ النَّاسَ فَيَقُولُ لِرَسُولِهِ خُذْ مَا تَيَسَّرَ وَاتْرُكْ مَا عَسُرَ وَتَجَاوَزْ لَعَلَّ اللَّهَ تَعَالَى أَنْ يَتَجَاوَزَ عَنَّا فَلَمَّا هَلَكَ قَالَ اللَّهُ عَزَّ وَجَلَّ لَهُ هَلْ عَمِلْتَ خَيْرًا قَطُّ قَالَ لَا إِلَّا أَنَّهُ كَانَ لِي غُلَامٌ وَكُنْتُ أُدَايِنُ النَّاسَ فَإِذَا بَعَثْتُهُ لِيَتَقَاضَى قُلْتُ لَهُ خُذْ مَا تَيَسَّرَ وَاتْرُكْ مَا عَسُرَ وَتَجَاوَزْ لَعَلَّ اللَّهَ يَتَجَاوَزُ عَنَّا قَالَ اللَّهُ تَعَالَى قَدْ تَجَاوَزْتُ عَنْكَ","id":"Telah mengabarkan kepada kami [Isa bin Hammad] telah menceritakan kepada kami [Al Laits] dari [Ibnu 'Ajlan] dari [Zaid bin Aslam] dari [Abu Shalih] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya terdapat seorang laki-laki yang belum pernah berbuat kebaikan sama sekali, dan dia biasa memberikan hutang kepada orang-orang. Kemudian dia berkata kepada utusannya; \"Ambillah apa yang mudah dan tinggalkan apa yang sulit dan maafkan semoga Allah ta'ala mengampuni kita.\" Kemudian tatkala dia meninggal, Allah 'azza wajalla berfirman kepadanya: \"Apakah engkau pernah mengerjakan kebaikan?\" Dia berkata; \"Tidak, hanya saja saya memiliki seorang pembantu dan saya biasa memberikan hutang kepada orang-orang kemudian apabila saya mengutusnya untuk menagih hutang, saya katakan kepadanya; 'Ambillah apa yang mudah dan tinggalkan apa yang sulit dan maafkan, semoga Allah memaafkan kita.\" Allah ta'ala berfirman: sungguh Aku telah memaafkanmu.\""},"4400":{"ar":"أَخْبَرَنَا هِشَامُ بْنُ عَمَّارٍ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا الزُّبَيْدِيُّ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَ رَجُلٌ ��ُدَايِنُ النَّاسَ وَكَانَ إِذَا رَأَى إِعْسَارَ الْمُعْسِرِ قَالَ لِفَتَاهُ تَجَاوَزْ عَنْهُ لَعَلَّ اللَّهَ تَعَالَى يَتَجَاوَزُ عَنَّا فَلَقِيَ اللَّهَ فَتَجَاوَزَ عَنْهُ","id":"Telah mengabarkan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Az Zubaidi] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] bahwa dia mendengar [Abu Hurairah] berkata; \"Sesungguhnya Nabi shallallahu 'alaihi wasallam bersabda: \"Dahulu terdapat seorang laki-laki yang biasa memberikan hutang kepada orang-orang dan apabila ia melihat orang yang dihutangi mengalami kesulitan maka dia berkata kepada pembantunya; \"Maafkan dia, semoga Allah ta'ala memaafkan kita. Kemudian dia bertemu dengan Allah dan Dia pun memaafkannya.\""},"4401":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ إِسْمَعِيلَ ابْنِ عُلَيَّةَ عَنْ يُونُسَ عَنْ عَطَاءِ بْنِ فَرُّوخَ عَنْ عُثْمَانَ بْنِ عَفَّانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَدْخَلَ اللَّهُ عَزَّ وَجَلَّ رَجُلًا كَانَ سَهْلًا مُشْتَرِيًا وَبَائِعًا وَقَاضِيًا وَمُقْتَضِيًا الْجَنَّةَ","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad bin Ishaq] dari [Isma'il bin 'Ulayyah] dari [Yunus] dari ['Atho` bin Farrukh] dari [Utsman bin Affan] dia berkata; \"Allah shallallahu 'alaihi wasallam bersabda: \"Allah Azza wa jalla memasukkan kedalam surga seseorang yang memudahkan (dalam) menjual dan membeli, memberikan hutang, dan menagih pembayaran hutangnya.\""},"4402":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنِي أَبُو إِسْحَقَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ قَالَاشْتَرَكْتُ أَنَا وَعَمَّارٌ وَسَعْدٌ يَوْمَ بَدْرٍ فَجَاءَ سَعْدٌ بِأَسِيرَيْنِ وَلَمْ أَجِئْ أَنَا وَعَمَّارٌ بِشَيْءٍ","id":"Telah mengabarkan kepadaku ['Amru bin Ali] telah menceritakan kepada kami [Yahya] dari [Sufyan] telah menceritakan kepadaku [Abu Ishaq] dari [Abu 'Ubaidah] dari [Abdullah], dia berkata; \"Saya, 'Ammar dan Sa'd berserikat pada saat perang Badr, kemudian Sa'd datang membawa dua orang tawanan sedang saya dan 'Ammar tidak membawa sesuatupun."},"4403":{"ar":"أَخْبَرَنَا نُوحُ بْنُ حَبِيبٍ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَعْتَقَ شِرْكًا لَهُ فِي عَبْدٍ أُتِمَّ مَا بَقِيَ فِي مَالِهِ إِنْ كَانَ لَهُ مَالٌ يَبْلُغُ ثَمَنَ الْعَبْدِ","id":"Telah mengabarkan kepada kami [Nuh bin Habib] telah memberitakan kepada kami [Abdur Razzaq] telah memberitakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [ayahnya] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang memerdekakan bagiannya pada seorang budak maka bagian yang tersisa dari hartanya akan disempurnakan apabila dia memiliki harta yang mencapai harga budak tersebut.\""},"4404":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ زُرَيْعٍ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَعْتَقَ شِرْكًا لَهُ فِي مَمْلُوكٍ وَكَانَ لَهُ مِنْ الْمَالِ مَا يَبْلُغُ ثَمَنَهُ بِقِيمَةِ الْعَبْدِ فَهُوَ عَتِيقٌ مِنْ مَالِهِ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] telah menceritakan kepada kami [Yazid yaitu Ibnu Zurai'] telah menceritakan kepada kami [Ayyub] dari [Nafi'] dari [Ibnu Umar] Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang memerdekakan bagiannya pada seorang budak padahal dia memiliki harta yang tidak mencapai seluruh harga budak tersebut maka dia dibebaskan dari hartanya tersebut.\""},"4405":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّكُمْ كَانَتْ لَهُ أَرْضٌ أَوْ نَخْلٌ فَلَا يَبِعْهَا حَتَّى يَعْرِضَهَا عَلَى شَرِيكِهِ","id":"Telah mengabarkan kepada kami [Qutaibah] telah menceritakan kepada kami [Sufyan] dari [Abu Az Zubair] dari [Jabir] bahwa Nabi shallallahu 'alaihi wasallam bersabda: 'Siapapun di antara kalian yang memiliki tanah atau pohon kurma maka janganlah dia menjualnya hingga menawarkannya kepada sekutunya.\""},"4406":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ أَنْبَأَنَا ابْنُ إِدْرِيسَ عَنْ ابْنِ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالشُّفْعَةِ فِي كُلِّ شَرِكَةٍ لَمْ تُقْسَمْ رَبْعَةٍ وَحَائِطٍ لَا يَحِلُّ لَهُ أَنْ يَبِيعَهُ حَتَّى يُؤْذِنَ شَرِيكَهُ فَإِنْ شَاءَ أَخَذَ وَإِنْ شَاءَ تَرَكَ وَإِنْ بَاعَ وَلَمْ يُؤْذِنْهُ فَهُوَ أَحَقُّ بِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala`] telah memberitakan kepada kami [Ibnu Idris] dari [Ibnu Juraij] dari [Abu Az Zubair] dari [Jabir], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam memutuskan dengan hak syuf'ah pada setiap serikat yang belum dibagi, rumah dan kebun. Tidak halal baginya untuk menjualnya hingga dia memberitahukan kepada sekutunya jika mau maka dia mengambilnya dan jika mau maka dia meninggalkannya, dan apabila dia menjual tanpa persetujuan sekutunya maka sekutunya lebih berhak terhadapnya.\""},"4407":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ إِبْرَاهِيمَ بْنِ مَيْسَرَةَ عَنْ عَمْرِو بْنِ الشَّرِيدِ عَنْ أَبِي رَافِعٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجَارُ أَحَقُّ بِسَقَبِهِ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] telah menceritakan kepada kami [Sufyan] dari [Ibrahim bin Maisarah] dari ['Amru bin Asy Syarid] dari [Abu Rafi'], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tetangga lebih berhak terhadap apa yang dekat dengan rumahnya.\""},"4408":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عِيسَى بْنُ يُونُسَ قَالَ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ عَمْرِو بْنِ الشَّرِيدِ عَنْ أَبِيهِأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ أَرْضِي لَيْسَ لِأَحَدٍ فِيهَا شَرِكَةٌ وَلَا قِسْمَةٌ إِلَّا الْجُوَارَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجَارُ أَحَقُّ بِسَقَبِهِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah menceritakan kepada kami ['Isa bin Yunus] telah menceritakan kepada kami [Husain Al Mu'allim] dari ['Amru bin Syu'aib] dari ['Amru bin Asy Syarid] dari [ayahnya] bahwa seseorang berkata; \"Wahai Rasulullah, tidak ada yang berserikat dalam kepemilikan tanahku dan tidak ada yang mendapatkan bagian kecuali hanya tetangga.\" Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang tetangga itu lebih berhak terhadap apa yang dekat dengannya.\""},"4409":{"ar":"أَخْبَرَنَا هِلَالُ بْنُ بِشْرٍ قَالَ حَدَّثَنَا صَفْوَانُ بْنُ عِيسَى عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الشُّفْعَةُ فِي كُلِّ مَالٍ لَمْ يُقْسَمْ فَإِذَا وَقَعَتْ الْحُدُودُ وَعُرِفَتْ الطُّرُقُ فَلَا شُفْعَةَ","id":"Telah mengabarkan kepada kami [Hilal bin Bisyr] telah menceritakan kepada kami [Shafwan bin 'Isa] dari [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hak untuk membeli terlebih dahulu ada pada setiap harta yang belum dibagi, apabila telah dibuat batasan dan telah diketahui jalannya maka tidak ada hak membeli terlebih dahulu.\""},"4410":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْعَزِيزِ بْنِ أَبِي رِزْمَةَ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ حُسَيْنٍ وَهُوَ ابْنُ وَاقِدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالشُّفْعَةِ وَالْجِوَارِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul Aziz bin Abu Rizmah] telah menceritakan kepada kami [Al Fadhl bin Musa] dari [Husain yaitu Ibnu Waqid] dari [Abu Az Zubair] dari [Jabir], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam telah memutuskan dengan hak membeli terlebih dahulu dan hak tetangga.\""},"4411":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى قَالَ حَدَّثَنَا أَبُو مَعْمَرٍ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا قَطَنٌ أَبُو الْهَيْثَمِ قَالَ حَدَّثَنَا أَبُو يَزِيدَ الْمَدَنِيُّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَأَوَّلُ قَسَامَةٍ كَانَتْ فِي الْجَاهِلِيَّةِ كَانَ رَجُلٌ مِنْ بَنِي هَاشِمٍ اسْتَأْجَرَ رَجُلًا مِنْ قُرَيْشٍ مِنْ فَخِذِ أَحَدِهِمْ قَالَ فَانْطَلَقَ مَعَهُ فِي إِبِلِهِ فَمَرَّ بِهِ رَجُلٌ مِنْ بَنِي هَاشِمٍ قَدْ انْقَطَعَتْ عُرْوَةُ جُوَالِقِهِ فَقَالَ أَغِثْنِي بِعِقَالٍ أَشُدُّ بِهِ عُرْوَةَ جُوَالِقِي لَا تَنْفِرُ الْإِبِلُ فَأَعْطَاهُ عِقَالًا يَشُدُّ بِهِ عُرْوَةَ جُوَالِقِهِ فَلَمَّا نَزَلُوا وَعُقِلَتْ الْإِبِلُ إِلَّا بَعِيرًا وَاحِدًا فَقَالَ الَّذِي اسْتَأْجَرَهُ مَا شَأْنُ هَذَا الْبَعِيرِ لَمْ يُعْقَلْ مِنْ بَيْنِ الْإِبِلِ قَالَ لَيْسَ لَهُ عِقَالٌ قَالَ فَأَيْنَ عِقَالُهُ قَالَ مَرَّ بِي رَجُلٌ مِنْ بَنِي هَاشِمٍ قَدْ انْقَطَعَتْ عُرْوَةُ جُوَالِقِهِ فَاسْتَغَاثَنِي فَقَالَ أَغِثْنِي بِعِقَالٍ أَشُدُّ بِهِ عُرْوَةَ جُوَالِقِي لَا تَنْفِرُ الْإِبِلُ فَأَعْطَيْتُهُ عِقَالًا فَحَذَفَهُ بِعَصًا كَانَ فِيهَا أَجَلُهُ فَمَرَّ بِهِ رَجُلٌ مِنْ أَهْلِ الْيَمَنِ فَقَالَ أَتَشْهَدُ الْمَوْسِمَ قَالَ مَا أَشْهَدُ وَرُبَّمَا شَهِدْتُ قَالَ هَلْ أَنْتَ مُبَلِّغٌ عَنِّي رِسَالَةً مَرَّةً مِنْ الدَّهْرِ قَالَ نَعَمْ قَالَ إِذَا شَهِدْتَ الْمَوْسِمَ فَنَادِ يَا آلَ قُرَيْشٍ فَإِذَا أَجَابُوكَ فَنَادِ يَا آلَ هَاشِمٍ فَإِذَا أَجَابُوكَ فَسَلْ عَنْ أَبِي طَالِبٍ فَأَخْبِرْهُ أَنَّ فُلَانًا قَتَلَنِي فِي عِقَالٍ وَمَاتَ الْمُسْتَأْجَرُ فَلَمَّا قَدِمَ الَّذِي اسْتَأْجَرَهُ أَتَاهُ أَبُو طَالِبٍ فَقَالَ مَا فَعَلَ صَاحِبُنَا قَالَ مَرِضَ فَأَحْسَنْتُ الْقِيَامَ عَلَيْهِ ثُمَّ مَاتَ فَنَزَلْتُ فَدَفَنْتُهُ فَقَالَ كَانَ ذَا أَهْلَ ذَاكَ مِنْكَ فَمَكُثَ حِينًا ثُمَّ إِنَّ الرَّجُلَ الْيَمَانِيَّ الَّذِي كَانَ أَوْصَى إِلَيْهِ أَنْ يُبَلِّغَ عَنْهُ وَافَى الْمَوْسِمَ قَالَ يَا آلَ قُرَيْشٍ قَالُوا هَذِهِ قُرَيْشٌ قَالَ يَا آلَ بَنِي هَاشِمٍ قَالُوا هَذِهِ بَنُو هَاشِمٍ قَالَ أَيْنَ أَبُو طَالِبٍ قَالَ هَذَا أَبُو طَالِبٍ قَالَ أَمَرَنِي فُلَانٌ أَنْ أُبَلِّغَكَ رِسَالَةً أَنَّ فُلَانًا قَتَلَهُ فِي عِقَالٍ فَأَتَاهُ أَبُو طَالِبٍ فَقَالَ اخْتَرْ مِنَّا إِحْدَى ثَلَاثٍ إِنْ شِئْتَ أَنْ تُؤَدِّيَ مِائَةً مِنْ الْإِبِلِ فَإِنَّكَ قَتَلْتَ صَاحِبَنَا خَطَأً وَإِنْ شِئْتَ يَحْلِفْ خَمْسُونَ مِنْ قَوْمِكَ أَنَّكَ لَمْ تَقْتُلْهُ فَإِنْ أَبَيْتَ قَتَلْنَاكَ بِهِ فَأَتَى قَوْمَهُ فَذَكَرَ ذَلِكَ لَهُمْ فَقَالُوا نَحْلِفُ فَأَتَتْهُ امْرَأَةٌ مِنْ بَنِي هَاشِمٍ كَانَتْ تَحْتَ رَجُلٍ مِنْهُمْ قَدْ وَلَدَتْ لَهُ فَقَالَتْ يَا أَبَا طَالِبٍ أُحِبُّ أَنْ تُجِيزَ ابْنِي هَذَا بِرَجُلٍ مِنْ الْخَمْسِينَ وَلَا تُصْبِرْ يَمِينَهُ فَفَعَلَ فَأَتَاهُ رَجُلٌ مِنْهُمْ فَقَالَ يَا أَبَا طَالِبٍ أَرَدْتَ خَمْسِينَ رَجُلًا أَنْ يَحْلِفُوا مَكَانَ مِائَةٍ مِنْ الْإِبِلِ يُصِيبُ كُلَّ رَجُلٍ بَعِيرَانِ فَهَذَانِ بَعِيرَانِ فَاقْبَلْهُمَا عَنِّي وَلَا تُصْبِرْ يَمِينِي حَيْثُ تُصْبَرُ الْأَيْمَانُ فَقَبِلَهُمَا وَجَاءَ ثَمَانِيَةٌ وَأَرْبَعُونَ رَجُلًا حَلَفُوا قَالَ ابْنُ عَبَّاسٍ فَوَالَّذِي نَفْسِي بِيَدِهِ مَا حَالَ الْحَوْلُ وَمِنْ الثَّمَانِيَةِ وَالْأَرْبَعِينَ عَيْنٌ تَطْرِفُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami [Abdul Warits] telah menceritakan kepada kami [Qathan Abu Al Haitsam] telah menceritakan kepada kami [Abu Yazid Al Madani] dari [Ikrimah] dari [Ibnu Abbas], dia berkata; \"Qosamah (limapuluh orang bersumpah untuk menghilangkan tuduhan membunuh) yang pertama kali dilakukan pada masa Jahiliyah adalah terhadap seorang dari Bani Hasyim yang mempekerjakan seorang Quraisy dari salah kabilah mereka. Ibnu Abbas berkata; \"Lalu dia pergi bersamanya mengendarai untanya, lalu lewatlah seseorang dari Bani Hasyim yang gagang bejananya yang terbuat dari kulit putus, dia berkata; \"Bantulah aku dengan tali agar aku bisa mengikat gagang bejanaku, unta itu tidak akan kabur.\" Lalu dia memberinya tali untuk mengikat gagang bejananya, ketika mereka singgah dan unta-unta diikat kecuali seekor, majikannya berkata; \"Ada apa dengan unta ini, kenapa dia tidak diikat seperti unta yang lain?\" Pekerjanya menjawab; \"Dia tidak memiliki tali pengikat.\" Majikan berkata; \"Dimana tali pengikatnya?\" Pekerja menjawab; \"Seseorang dari Bani Hasyim yang gagang bejananya putus lewat di depanku. Dia meminta tolong kepadaku dan berkata tolonglah aku dengan sebuah tali hingga aku ikat gagang bejanaku, unta itu tidak akan kabur, lalu aku memberinya. Kemudian majikan itu memukulnya dengan tongkat yang dia bawa yang menjadi penyebab kematiannya. Lalu datanglah seorang penduduk Yaman, sang pekerja berkata; \"Apakah engkau pernah menghadiri Mausim (musim haji)?\" Penduduk Yaman menjawab; \"Aku tidak bisa hadir atau mungkin aku pernah menghadirinya.\" Dia berkata; \"Maukah engkau menyampaikan pesan dariku untuk sekali ini saja?\" Dia menjawab; \"Ya.\" Sang pekerja berkata; \"Jika engkau menghadiri Mausim maka serulah, 'Hai orang-orang quraisy', jika mereka menjawabmu maka panggillah, 'Hai orang-orang Bani Hasyim', jika mereka menjawabmu maka tanyakan perihal Abu Thalib dan kabarkan kepadanya bahwa Fulan membunuhku karena sebuah tali.\" Lalu matilah si pekerja. Ketika si majikan datang, Abu Thalib menemuinya dan berkata; \"Apa yang terjadi dengan teman kami?\" Dia menjawab, \"Dia sakit lalu aku mengobatinya, lalu dia mati maka aku singgah di suatu tempat dan menguburnya.\" Abu Tholib berkata; \"Dia memiliki pekerjaan bagimu, lalu dia berhenti sejenak kemudian datanglah seorang penduduk Yaman yang dia beri wasiat agar dia sampaikan di Mausim. Dia berkata; \"Wahai orang-orang Quraisy!\" Mereka menjawab; \"Ini kami, orang-orang Quraisy.\" \"Wahai orang-orang Bani Hasyim!\" Mereka menjawab; \"Ini kami, orang-orang Bani Hasyim.\" \"Di mana Abu Thalib?\" \"Ini dia Abu Tholib.\" Dia berkata; \"Sesungguhnya Fulan menyuruhku untuk menyampaikan pesan bahwa fulan membunuhnya dengan sebab tali pengikat, lalu Abu Thalib berkata; \"Pilihlah salah satu di antara tiga hal, jika engkau mau maka engkau membayar seratus ekor unta, karena engkau membunuh teman kami secara salah, jika engkau mau maka limapuluh orang dari kaummu bersumpah bahwa engkau tidak membunuhnya, jika engkau enggan maka kami akan membunuhmu.\" Lalu dia mendatangi kaumnya dan mengabari mereka, mereka berkata; \"Kami akan bersumpah.\" lalu seorang wanita dari Bani Hasyim yang pernah menjadi isteri salah seorang dari mereka dan telah melahirkan anaknya berkata; \"Wahai Abu Thalib aku ingin agar engkau memasukkan anak ini ke dalam lima puluh orang dan janganlah engkau anggap sumpahnya.\" Abu Tholib pun melakukannya, lalu datanglah seorang laki-laki dari mereka dan berkata; \"Wahai Abu Thalib, engkau ingin agar lima puluh orang bersumpah untuk mengganti seratus ekor unta, sehingga setiap orang sama dengan dua ekor unta, ini ada dua ekor unta ambillah dariku dan janganlah engkau anggap sumpahku, sebagaimana sumpah-sumpah yang lain.\" Lalu Abu Tholib pun menerima keduanya. Maka datanglah empat puluh delapan orang, mereka bersumpa., Ibnu Abbas berkata; \"Demi Dzat yang jiwaku berada ditanganNya, tidak sampai satu tahun empat puluh delapan orang itu semuanya meninggal.\" "},"4412":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ وَيُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَحْمَدُ بْنُ عَمْرٍو قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ وَسُلَيْمَانُ بْنُ يَسَارٍ عَنْ رَجُلٍ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْأَنْصَارِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقَرَّ الْقَسَامَةَ عَلَى مَا كَانَتْ عَلَيْهِ فِي الْجَاهِلِيَّةِ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amru bin As Sarh] dan [Yunus bin Abdul A'la] telah memberitakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] telah berkata Ahmad bin 'Amru telah mengabarkan kepadaku [Abu Salamah] dan [Sulaiman bin Yasar] dari [seorang laki-laki] sahabat Rasulullah shallallahu 'alaihi wasallam dari kalangan Anshar bahwa Rasulullah shallallahu 'alaihi wasallam telah menetapkan qasamah sebagaimana yang terjadi pada zaman jahiliyah. "},"4413":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ هَاشِمٍ قَالَ حَدَّثَنَا الْوَلِيدُ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ وَسُلَيْمَانَ بْنِ يَسَارٍ عَنْ أُنَاسٍ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ الْقَسَامَةَ كَانَتْ فِي الْجَاهِلِيَّةِ فَأَقَرَّهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مَا كَانَتْ عَلَيْهِ فِي الْجَاهِلِيَّةِ وَقَضَى بِهَا بَيْنَ أُنَاسٍ مِنْ الْأَنْصَارِ فِي قَتِيلٍ ادَّعَوْهُ عَلَى يَهُودِ خَيْبَرَخَالَفَهُمَا مَعْمَرٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Hasyim] telah menceritakan kepada kami [Al Walid] telah menceritakan kepada kami [Al Auza'I] dari [Ibnu Syihab] dari [Abu Salamah] dan [Sulaiman bin Yasar] dari [beberapa orang sahabat] Rasulullah shallallahu 'alaihi wasallam bahwa qasamah terjadi pada masa Jahiliyah kemudian Rasulullah shallallahu 'alaihi wasallam menetapkannya sebagaimana yang terjadi pada zaman jahiliyah. Dan beliau memberikan keputusan dengannya terhadap orang-orang Anshar mengenai seseorang yang terbunuh dan mereka menuduh orang-orang Yahudi Khaibar yang melakukannya. Ma'mar menyelisihi keduanya. "},"4414":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ ابْنِ الْمُسَيَّبِ قَالَكَانَتْ الْقَسَامَةُ فِي الْجَاهِلِيَّةِ ثُمَّ أَقَرَّهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْأَنْصَارِيِّ الَّذِي وُجِدَ مَقْتُول��ا فِي جُبِّ الْيَهُودِ فَقَالَتْ الْأَنْصَارُ الْيَهُودُ قَتَلُوا صَاحِبَنَا","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdur Razzaq] telah memberitakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ibnu Al Musayyab], dia berkata; \"Telah terjadi qasamah pada zaman jahiliyah kemudian Rasulullah shallallahu 'alaihi wasallam menetapkannya pada seorang anshar yang didapatkan dalam keadaan terbunuh di wilayah Yahudi, maka orang-orang Anshar berkata orang-orang Yahudi telah membunuh seorang sahabat kami.\""},"4415":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي مَالِكُ بْنُ أَنَسٍ عَنْ أَبِي لَيْلَى بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ الْأَنْصَارِيِّ أَنَّ سَهْلَ بْنَ أَبِي حَثْمَةَ أَخْبَرَهُأَنَّ عَبْدَ اللَّهِ بْنَ سَهْلٍ وَمُحَيِّصَةَ خَرَجَا إِلَى خَيْبَرَ مِنْ جَهْدٍ أَصَابَهُمَا فَأُتِيَ مُحَيِّصَةُ فَأُخْبِرَ أَنَّ عَبْدَ اللَّهِ بْنَ سَهْلٍ قَدْ قُتِلَ وَطُرِحَ فِي فَقِيرٍ أَوْ عَيْنٍ فَأَتَى يَهُودَ فَقَالَ أَنْتُمْ وَاللَّهِ قَتَلْتُمُوهُ فَقَالُوا وَاللَّهِ مَا قَتَلْنَاهُ ثُمَّ أَقْبَلَ حَتَّى قَدِمَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ ثُمَّ أَقْبَلَ هُوَ وَحُوَيِّصَةُ وَهُوَ أَخُوهُ أَكْبَرُ مِنْهُ وَعَبْدُ الرَّحْمَنِ بْنُ سَهْلٍ فَذَهَبَ مُحَيِّصَةُ لِيَتَكَلَّمَ وَهُوَ الَّذِي كَانَ بِخَيْبَرَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَبِّرْ كَبِّرْ وَتَكَلَّمَ حُوَيِّصَةُ ثُمَّ تَكَلَّمَ مُحَيِّصَةُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِمَّا أَنْ يَدُوا صَاحِبَكُمْ وَإِمَّا أَنْ يُؤْذَنُوا بِحَرْبٍ فَكَتَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ذَلِكَ فَكَتَبُوا إِنَّا وَاللَّهِ مَا قَتَلْنَاهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِحُوَيِّصَةَ وَمُحَيِّصَةَ وَعَبْدِ الرَّحْمَنِ تَحْلِفُونَ وَتَسْتَحِقُّونَ دَمَ صَاحِبِكُمْ قَالُوا لَا قَالَ فَتَحْلِفُ لَكُمْ يَهُودُ قَالُوا لَيْسُوا مُسْلِمِينَ فَوَدَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عِنْدِهِ فَبَعَثَ إِلَيْهِمْ بِمِائَةِ نَاقَةٍ حَتَّى أُدْخِلَتْ عَلَيْهِمْ الدَّارَقَالَ سَهْلٌ لَقَدْ رَكَضَتْنِي مِنْهَا نَاقَةٌ حَمْرَاءُ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amru bin As Sarh] telah memberitakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Malik bin Anas] dari [Abu Laila bin Abdullah bin Abdur Rahman Al Anshari] bahwa [Sahl bin Abu Hatsmah] telah mengabarkan kepadanya bahwa Abdullah bin Sahl dan Muhayyishah keluar ke Khaibar karena kesusahan yang menimpa mereka berdua. Kemudian Muhayyishah di datangi dan diberitahu bahwa Abdullah bin Sahl telah terbunuh dan dicampakkan di dalam sumur atau mata air. Kemudian dia mendatangi orang-orang Yahudi lalu berkata; \"Demi Allah, kalian telah membunuhnya.\" Mereka berkata; \"Demi Allah, kami tidak membunuhnya. Kemudian dia berbalik hingga kemudian dia datang menemui Rasulullah shallallahu 'alaihi wasallam dan menceritakan hal tersebut kepada beliau. Kemudian dia dan Huwayyishah yaitu saudara tuanya serta Abdur Rahman bin Sahl datang, lalu Muhayyishah yang tadinya berada di Khaibar maju untuk berbicara, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dahulukan orang yang paling tua.\" Dan Huwayyishah berbicara kemudian Muhayyishah berbicara. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mereka membayar diyat sahabat kalian atau mereka mengumumkan peperangan?\" Kemudian Nabi shallallahu 'alaihi wasallam menulis surat kepada mereka mengenai hal tersebut, lalu mereka membalas; \"Sesungguhnya kami demi Allah, tidak membunuhnya.\" Kemudian beliau bersabda kepada Huwayyishah dan Muhayyishah serta Abdur Rahman: \"Apakah kalian mau bersumpah dan berhak terhadap darah sahabat kalian?\" mereka berkata; \"Tidak.\" Beliau bersabda: \"Apakah kalian mau orang-orang Yahudi bersumpah kepada kalian?\" Mereka berkata; \"Mereka bukanlah orang-orang muslim. Kemudian Rasulullah shallallahu 'alaihi wasallam membayarnya dari harta beliau, beliau mengirimkan kepada mereka seratus unta hingga dimasukkan ke rumah mereka. Sahl berkata; \"Sungguh seekor unta merah dari unta-unta tersebut menyepakku dengan kakinya.\""},"4416":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ أَنْبَأَنَا ابْنُ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ أَبِي لَيْلَى بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ سَهْلٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَ أَنَّهُأَخْبَرَهُ وَرِجَالٌ كُبَرَاءُ مِنْ قَوْمِهِ أَنَّ عَبْدَ اللَّهِ بْنَ سَهْلٍ وَمُحَيِّصَةَ خَرَجَا إِلَى خَيْبَرَ مِنْ جَهْدٍ أَصَابَهُمْ فَأَتَى مُحَيِّصَةُ فَأَخْبَرَ أَنَّ عَبْدَ اللَّهِ بْنَ سَهْلٍ قَدْ قُتِلَ وَطُرِحَ فِي فَقِيرٍ أَوْ عَيْنٍ فَأَتَى يَهُودَ وَقَالَ أَنْتُمْ وَاللَّهِ قَتَلْتُمُوهُ قَالُوا وَاللَّهِ مَا قَتَلْنَاهُ فَأَقْبَلَ حَتَّى قَدِمَ عَلَى قَوْمِهِ فَذَكَرَ لَهُمْ ثُمَّ أَقْبَلَ هُوَ وَأَخُوهُ حُوَيِّصَةُ وَهُوَ أَكْبَرُ مِنْهُ وَعَبْدُ الرَّحْمَنِ بْنُ سَهْلٍ فَذَهَبَ مُحَيِّصَةُ لِيَتَكَلَّمَ وَهُوَ الَّذِي كَانَ بِخَيْبَرَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِمُحَيِّصَةَ كَبِّرْ كَبِّرْ يُرِيدُ السِّنَّ فَتَكَلَّمَ حُوَيِّصَةُ ثُمَّ تَكَلَّمَ مُحَيِّصَةُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِمَّا أَنْ يَدُوا صَاحِبَكُمْ وَإِمَّا أَنْ يُؤْذَنُوا بِحَرْبٍ فَكَتَبَ إِلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ذَلِكَ فَكَتَبُوا إِنَّا وَاللَّهِ مَا قَتَلْنَاهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِحُوَيِّصَةَ وَمُحَيِّصَةَ وَعَبْدِ الرَّحْمَنِ أَتَحْلِفُونَ وَتَسْتَحِقُّونَ دَمَ صَاحِبِكُمْ قَالُوا لَا قَالَ فَتَحْلِفُ لَكُمْ يَهُودُ قَالُوا لَيْسُوا بِمُسْلِمِينَ فَوَدَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عِنْدِهِ فَبَعَثَ إِلَيْهِمْ بِمِائَةِ نَاقَةٍ حَتَّى أُدْخِلَتْ عَلَيْهِمْ الدَّارَقَالَ سَهْلٌ لَقَدْ رَكَضَتْنِي مِنْهَا نَاقَةٌ حَمْرَاءُ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] telah memberitakan kepada kami [Ibnu Al Qasim] telah menceritakan kepadaku [Malik] dari [Abu Laila bin Abdullah bin Abdur Rahman bin Sahl bin Abu Hatsmah] dari [Sahal bin Abi Hatsmah] bahwa dia dan beberapa orang pembesar kaumnya telah mengabarkan kepadanya bahwa Abdullah bin Sahl dan Muhayyishah keluar menuju Khaibar Karena kesusahan yang menimpa mereka. Kemudian Muhayyishah datang dan mengabarkan bahwa Abdullah bin Sahl telah terbunuh dan dilemparkan ke dalam sumur atau mata air. Kemudian dia datang kepada orang-orang Yahudi dan berkata; \"Demi Allah, kalian telah membunuhnya.\" Mereka berkata; \"Demi Allah, kami tidak membunuhnya.\" Kemudian ia pergi hingga datang kepada Rasulullah shallallahu 'alaihi wasallam dan menceritakan hal tersebut kepada beliau. Kemudian dia dan Huwayyishah yaitu kakaknya serta Abdur Rahman bin Sahl datang, lalu Muhayyishah yang tadinya berada di Khaibar maju untuk berbicara, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dahulukan orang yang paling tua.\" Dan Huwayyishah berbicara kemudian Muhayyishah berbicara. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mereka membayar diyat sahabat kalian atau mereka mengumumkan peperangan?\" kemudian Nabi shallallahu 'alaihi wasallam menulis surat kepada mereka mengenai hal tersebut, lalu mereka menulis; \"Sesungguhnya kami demi Allah, tidak membunuhnya.\" Kemudian beliau bersabda kepada Huwayyishah dan Muhayyishah serta Abdur Rahman: \"Apakah kalian bersumpah dan berhak terhadap darah sahabat kalian?\" mereka berkata; \"Tidak.\" Beliau bersabda: \"Apakah kalian mau orang-orang Yahudi bersumpah untuk kalian?\" mereka berkata; \"Mereka bukanlah orang-orang muslim.\" Kemudian Rasulullah shallallahu 'alaihi wasallam membayarnya dari harta beliau, lalu beliau mengirimkan kepada mereka seratus unta hingga dimasukkan ke rumah mereka. Sahl berkata; \"Sungguh seekor unta merah dari unta-unta tersebut menyepakku dengan kakinya.\" "},"4417":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَحْيَى عَنْ بُشَيْرِ بْنِ يَسَارٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَ قَالَ وَحَسِبْتُ قَالَ وَعَنْ رَافِعِ بْنِ خَدِيجٍ أَنَّهُمَا قَالَاخَرَجَ عَبْدُ اللَّهِ بْنُ سَهْلِ بْنِ زَيْدٍ وَمُحَيِّصَةُ بْنُ مَسْعُودٍ حَتَّى إِذَا كَانَا بِخَيْبَرَ تَفَرَّقَا فِي بَعْضِ مَا هُنَالِكَ ثُمَّ إِذَا بِمُحَيِّصَةَ يَجِدُ عَبْدَ اللَّهِ بْنَ سَهْلٍ قَتِيلًا فَدَفَنَهُ ثُمَّ أَقْبَلَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ وَحُوَيِّصَةُ بْنُ مَسْعُودٍ وَعَبْدُ الرَّحْمَنِ بْنُ سَهْلٍ وَكَانَ أَصْغَرَ الْقَوْمِ فَذَهَبَ عَبْدُ الرَّحْمَنِ يَتَكَلَّمُ قَبْلَ صَاحِبَيْهِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَبِّرْ الْكُبْرَ فِي السِّنِّ فَصَمَتَ وَتَكَلَّمَ صَاحِبَاهُ ثُمَّ تَكَلَّمَ مَعَهُمَا فَذَكَرُوا لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَقْتَلَ عَبْدِ اللَّهِ بْنِ سَهْلٍ فَقَالَ لَهُمْ أَتَحْلِفُونَ خَمْسِينَ يَمِينًا وَتَسْتَحِقُّونَ صَاحِبَكُمْ أَوْ قَاتِلَكُمْ قَالُوا كَيْفَ نَحْلِفُ وَلَمْ نَشْهَدْ قَالَ فَتُبَرِّئُكُمْ يَهُودُ بِخَمْسِينَ يَمِينًا قَالُوا وَكَيْفَ نَقْبَلُ أَيْمَانَ قَوْمٍ كُفَّارٍ فَلَمَّا رَأَى ذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطَاهُ عَقْلَهُ","id":"Telah mengabarkan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Yahya] dari [Busyair bin Yasar] dari [Sahl bin Abu Hatsmah], dia berkata; \"Saya mengira dia mengatakan; dan dari [Rafi' bin Khadij] bahwa mereka berkata; \"Abdullah bin Sahl bin Zaid dan Muhayyishah bin Mas'ud telah keluar hingga ketika mereka sampai di Khaibar mereka berpisah di sebagian tempat di sana, kemudian Muhayyishah mendapatkan Abdullah bin Sahl terbunuh. Lalu dia menguburnya kemudian menghadap kepada Rasulullah shallallahu 'alaihi wasallam bersama dengan Huwayyishah bin Mas'ud serta Abdur Rahman bin Sahl dan dia adalah orang yang paling muda. Kemudian Abdur Rahman pergi untuk berbicara sebelum dua orang sahabatnya. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Dahulukanlah yang tua.\" Kemudian dia diam dan dua orang sahabatnya berbicara, kemudian dia berbicara bersama mereka dan mereka menyebutkan kepada Rasulullah shallallahu 'alaihi wasallam mengenai terbunuhnya Abdullah bin Sahl. Lalu beliau bersabda: \"Apakah kalian bersumpah lima puluh sumpah dan kalian berhak terhadap sahabat kalian atau terhadap orang yang menyerang kalian?\" Mereka berkata; \"Bagaimana kami bersumpah sedang kami belum menyaksikan?\" Kemudian beliau bersabda: \"Apakah kalian mau orang-orang Yahudi akan bebas dari tuduhan kalian dengan lima puluh sumpah?\" Mereka berkata; \"Bagaimana kami menerima sumpah orang-orang kafir?\" Kemudian tatkala Rasulullah shallallahu 'alaihi wasallam melihat hal tersebut beliau memberikan diyatnya.\""},"4418":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدَةَ قَالَ أَنْبَأَنَا حَمَّادٌ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ بُشَيْرِ بْنِ يَسَارٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَ وَرَافِعِ بْنِ خَدِيجٍ أَنَّهُمَا حَدَّثَاهُأَنَّ مُحَيِّصَةَ بْنَ مَسْعُودٍ وَعَبْدَ اللَّهِ بْنَ سَهْلٍ أَتَيَا خَيْبَرَ فِي حَاجَةٍ لَهُمَا فَتَفَرَّقَا فِي النَّخْلِ فَقُتِلَ عَبْدُ اللَّهِ بْنُ سَهْلٍ فَجَاءَ أَخُوهُ عَبْدُ الرَّحْمَنِ بْنُ سَهْلٍ وَحُوَيِّصَةُ وَمُحَيِّصَةُ ابْنَا عَمِّهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَكَلَّمَ عَبْدُ الرَّحْمَنِ فِي أَمْرِ أَخِيهِ وَهُوَ أَصْغَرُ مِنْهُمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْكُبْرَ لِيَبْدَأْ الْأَكْبَرُ فَتَكَلَّمَا فِي أَمْرِ صَاحِبِهِمَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَكَرَ كَلِمَةً مَعْنَاهَا يُقْسِمُ خَمْسُونَ مِنْكُمْ فَقَالُوا يَا رَسُولَ اللَّهِ أَمْرٌ لَمْ نَشْهَدْهُ كَيْفَ نَحْلِفُ قَالَ فَتُبَرِّئُكُمْ يَهُودُ بِأَيْمَانِ خَمْسِينَ مِنْهُمْ قَالُوا يَا رَسُولَ اللَّهِ قَوْمٌ كُفَّارٌ فَوَدَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ قِبَلِهِقَالَ سَهْلٌ فَدَخَلْتُ مِرْبَدًا لَهُمْ فَرَكَضَتْنِي نَاقَةٌ مِنْ تِلْكَ الْإِبِلِ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdah] telah memberitakan kepada kami [Hammad] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Busyair bin Yasar] dari [Sahl bin Abu Hatsmah] dan [Rafi' bin Khadij] bahwa mereka telah menceritakan kepadanya bahwa Muhayyishah bin Mas'ud dan Abdullah bin Sahl datang ke Khaibar untuk suatu keperluan kemudian mereka berpisah di sebuah pohon kurma, lalu Abdullah bin Sahl terbunuh maka saudaranya yaitu Abdur Rahman bin Sahl serta Huwayyishah dan Muhayyishah yakni dua orang anak pamannya datang kepada Rasulullah shallallahu 'alaihi wasallam. Lalu Abdur Rahman berbicara mengenai perkara saudaranya padahal dia adalah orang yang paling muda di antara mereka. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaknya yang lebih tua memulai terlebih dahulu.\" Kemudian mereka berdua berbicara mengenai perkara sahabat mereka berdua. Kemudian Rasulullah shallallahu 'alaihi wasallam menyebutkan suatu kalimat yang maknanya; lima puluh orang dari kalian bersumpah. Maka mereka berkata; \"Wahai Rasulullah, itu adalah suatu perkara yang tidak kami saksikansendiri, bagaimana kami bersumpah?\" Beliau bersabda: \"Kalian mau orang-orang Yahudi akan bebas dari tuduhan kalian dengan sumpah lima puluh orang di antara mereka.\" Mereka berkata; \"Wahai Rasulullah, mereka adalah orang-orang kafir.\" Kemudian Rasulullah shallallahu 'alaihi wasallam membayar diyatnya dari beliau sendiri. Sahl berkata; \"Saya memasuki kandang milik mereka, kemudian saya disepak oleh seekor unta dari unta-unta tersebut.\""},"4419":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا بِشْرٌ وَهُوَ ابْنُ الْمُفَضَّلِ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ بُشَيْرِ بْنِ يَسَارٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَأَنَّ عَبْدَ اللَّهِ بْنَ سَهْلٍ وَمُحَيِّصَةَ بْنَ مَسْعُودِ بْنِ زَيْدٍ أَنَّهُمَا أَتَيَا خَيْبَرَ وَهُوَ يَوْمَئِذٍ صُلْحٌ فَتَفَرَّقَا لِحَوَائِجِهِمَا فَأَتَى مُحَيِّصَةُ عَلَى عَبْدِ اللَّهِ بْنِ سَهْلٍ وَهُوَ يَتَشَحَّطُ فِي دَمِهِ قَتِيلًا فَدَفَنَهُ ثُمَّ قَدِمَ الْمَدِينَةَ فَانْطَلَقَ عَبْدُ الرَّحْمَنِ بْنُ سَهْلٍ وَحُوَيِّصَةُ وَمُحَيِّصَةُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَهَبَ عَبْدُ الرَّحْمَنِ يَتَكَلَّمُ وَهُوَ أَحْدَثُ الْقَوْمِ سِنًّا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَبِّرْ الْكُبْرَ فَسَكَتَ فَتَكَلَّمَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَحْلِفُونَ بِخَمْسِينَ يَمِينًا مِنْكُمْ فَتَسْتَحِقُّونَ دَمَ صَاحِبِكُمْ أَوْ قَاتِلِكُمْ قَالُوا يَا رَسُولَ اللَّهِ كَيْفَ نَحْلِفُ وَلَمْ نَشْهَدْ وَلَمْ نَرَ قَالَ تُبَرِّئُكُمْ يَهُودُ بِخَمْسِينَ يَمِينًا قَالُوا يَا رَسُولَ اللَّهِ كَيْفَ نَأْخُذُ أَيْمَانَ قَوْمٍ كُفَّارٍ فَعَقَلَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عِنْدِهِ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] telah menceritakan kepada kami [Bisyr yaitu Ibnu Al Mufadhdhal] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Busyair bin Yasar] dari [Sahl bin Abu Hatsmah] bahwa Abdullah bin Sahl dan Muhayyishah bin Mas'ud bin Zaid datang ke Khaibar pada saat terjadi perdamaian, kemudian mereka berpisah untuk keperluan mereka. Kemudian Muhayyishah mendatangi Abdullah bin Sahl yang mati berlumuran darah, lalu dia menguburkannya. Kemudian dia tiba di Madinah. Maka berangkatlah Abdur Rahman bin Sahl, Huwayyishah dan Muhayyishah menemui Rasulullah shallallahu 'alaihi wasallam, kemudian Abdur Rahman maju untuk berbicara, padahal dia adalah orang yang paling muda. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dahulukan orang yang paling tua.\" Lalu dia diam kemudian mereka berdua berbicara, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah kalian mau bersumpah dengan lima puluh sumpah dari kalian kemudian mendapat hak terhadap darah sahabat kalian atau terhadap orang yang membunuh kalian?\" Mereka berkata; \"Wahai Rasulullah, bagaimana kami bersumpah sedangkan kami tidak menyaksikan dan tidak melihat?\" Beliau bersabda: \"Kalian mau orang-orang Yahudi akan bebas dari tuduhan kalian dengan lima puluh sumpah?\" Mereka berkata; \"Wahai Rasulullah, bagaimana kami mengambil sumpah orang-orang kafir?\" Kemudian Rasulullah shallallahu 'alaihi wasallam membayar diyatnya dari beliau sendiri. "},"4420":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ بُشَيْرِ بْنِ يَسَارٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَ قَالَانْطَلَقَ عَبْدُ اللَّهِ بْنُ سَهْلٍ وَمُحَيِّصَةُ بْنُ مَسْعُودِ بْنِ زَيْدٍ إِلَى خَيْبَرَ وَهِيَ يَوْمَئِذٍ صُلْحٌ فَتَفَرَّقَا فِي حَوَائِجِهِمَا فَأَتَى مُحَيِّصَةُ عَلَى عَبْدِ اللَّهِ بْنِ سَهْلٍ وَهُوَ يَتَشَحَّطُ فِي دَمِهِ قَتِيلًا فَدَفَنَهُ ثُمَّ قَدِمَ الْمَدِينَةَ فَانْطَلَقَ عَبْدُ الرَّحْمَنِ بْنُ سَهْلٍ وَحُوَيِّصَةُ وَمُحَيِّصَةُ ابْنَا مَسْعُودٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَهَبَ عَبْدُ الرَّحْمَنِ يَتَكَلَّمُ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَبِّرْ الْكُبْرَ وَهُوَ أَحْدَثُ الْقَوْمِ فَسَكَتَ فَتَكَلَّمَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَحْلِفُونَ بِخَمْسِينَ يَمِينًا مِنْكُمْ وَتَسْتَحِقُّونَ قَاتِلَكُمْ أَوْ صَاحِبَكُمْ فَقَالُوا يَا رَسُولَ اللَّهِ كَيْفَ نَحْلِفُ وَلَمْ نَشْهَدْ وَلَمْ نَرَ فَقَالَ أَتُبَرِّئُكُمْ يَهُودُ بِخَمْسِينَ فَقَالُوا يَا رَسُولَ اللَّهِ كَيْفَ نَأْخُذُ أَيْمَانَ قَوْمٍ كُفَّارٍ فَعَقَلَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عِنْدِهِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] telah menceritakan kepada kami [Bisyr bin Al Mufadhdhal] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Busyair bin Yasar] dari [Sahl bin Abu Hatsmah], dia berkata; \"Abdullah bin Sahl dan Muhayyishah bin Mas'ud bin Zaid datang ke Khaibar dan pada saat itu terjadi perdamaian. Kemudian mereka berpisah untuk keperluan mereka. Lalu Muhayyishah menemui Abdullah bin Sahl telah terbunuh berlumuran darah. Lalu dia menguburkannya. Kemudian dia tiba di Madinah, maka Abdur Rahman bin Sahl dan Huwaishah serta Muhayyishah bin Mas'ud datang menemui Rasulullah shallallahu 'alaihi wasallam. Lalu Abdur Rahman maju untuk berbicara, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dahulukan orang yang tertua.\" Dia adalah orang yang paling muda, maka dia pun terdiam kemudian mereka berbicara. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah kalian mau bersumpah lima puluh kali sumpah dari kalian dan berhak terhadap orang yang membunuh kalian atau terhadap sahabat kalian?\" Mereka berkata; \"Wahai Rasulullah, bagaimana kami bersumpah sedangkan kami tidak menyaksikan, dan belum melihat?\" Beliau bersabda: \"Apakah kalian mau orang-orang Yahudi akan terbebas dari tuduhan kalian dengan lima kali sumpah?\" Maka mereka berkata; \"Wahai Rasulullah, bagaimana kami mengambil sumpah orang-orang kafir?\" Kemudian Rasulullah shallallahu 'alaihi wasallam membayar diyat dari beliau sendiri. "},"4421":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الْوَهَّابِ قَالَ سَمِعْتُ يَحْيَى بْنَ سَعِيدٍ يَقُولُ أَخْبَرَنِي بُشَيْرُ بْنُ يَسَارٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَأَنَّ عَبْدَ اللَّهِ بْنَ سَهْلٍ الْأَنْصَارِيَّ وَمُحَيِّصَةَ بْنَ مَسْعُودٍ خَرَجَا إِلَى خَيْبَرَ فَتَفَرَّقَا فِي حَاجَتِهِمَا فَقُتِلَ عَبْدُ اللَّهِ بْنُ سَهْلٍ الْأَنْصَارِيُّ فَجَاءَ مُحَيِّصَةُ وَعَبْدُ الرَّحْمَنِ أَخُو الْمَقْتُولِ وَحُوَيِّصَةُ بْنُ مَسْعُودٍ حَتَّى أَتَوْا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَهَبَ عَبْدُ الرَّحْمَنِ يَتَكَلَّمُ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْكُبْرَ الْكُبْرَ فَتَكَلَّمَ مُحَيِّصَةُ وَحُوَيِّصَةُ فَذَكَرُوا شَأْنَ عَبْدِ اللَّهِ بْنِ سَهْلٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَحْلِفُونَ خَمْسِينَ يَمِينًا فَتَسْتَحِقُّونَ قَاتِلَكُمْ قَالُوا كَيْفَ نَحْلِفُ وَلَمْ نَشْهَدْ وَلَمْ نَحْضُرْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتُبَرِّئُكُمْ يَهُودُ بِخَمْسِينَ يَمِينًا قَالُوا يَا رَسُولَ اللَّهِ كَيْفَ نَقْبَلُ أَيْمَانَ قَوْمٍ كُفَّارٍ قَالَ فَوَدَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ بُشَيْرٌ قَالَ لِي سَهْلُ بْنُ أَبِي حَثْمَةَ لَقَدْ رَكَضَتْنِي فَرِيضَةٌ مِنْ تِلْكَ الْفَرَائِضِ فِي مِرْبَدٍ لَنَا","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abdul Wahhab], dia berkata; saya mendengar [Yahya bin Sa'id] berkata; telah mengabarkan kepadaku [Busyair bin Yasar] dari [Sahl bin Abu Hatsmah] bahwa Abdullah bin Sahl Al Anshari dan Muhayyishah bin Mas'ud keluar menuju khaibar, kemudian mereka berpisah untuk keperluan mereka, kemudian Abdullah bin Sahl Al Anshari terbunuh, lalu Muhayyishah dan Abdur Rahman saudara yang terbunuh serta Huwayyishah bin Mas'ud datang kepada Rasulullah shallallahu 'alaihi wasallam, lalu Abdur Rahman maju untuk berbicara, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Dahulukan orang yang paling tua.\" Kemudian Muhayyishah dan Huwayyishah berbicara dan menyebutkan keadaan Abdullah bin Sahl. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah kalian bersumpah lima puluh kali sumpah kemudian mendapatkan hak atas pembunuhnya?\" Mereka berkata; \"Bagaimana kami bersumpah sedangkan kami tidak menyaksikan dan tidak menghadiri?\" Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang-orang Yahudi akan bebas dari tuduhan kalian dengan lima puluh kali sumpah. Mereka berkata; \"Wahai Rasulullah, bagaimana kita menerima sumpah orang-orang kafir?\" Sahl berkata; \"Kemudian Rasulullah shallallahu 'alaihi wasallam membayar diyatnya.\" Busyair berkata; \"Sahl bin Abu Hatsmah berkata kepadaku; \"Sungguh saya telah ditendang seekor unta dari unta-unta tersebut di dalam kandang milik kami.\" "},"4422":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ بُشَيْرِ بْنِ يَسَارٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَ قَالَوُجِدَ عَبْدُ اللَّهِ بْنُ سَهْلٍ قَتِيلًا فَجَاءَ أَخُوهُ وَعَمَّاهُ حُوَيِّصَةُ وَمُحَيِّصَةُ وَهُمَا عَمَّا عَبْدِ اللَّهِ بْنِ سَهْلٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَهَبَ عَبْدُ الرَّحْمَنِ يَتَكَلَّمُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْكُبْرَ الْكُبْرَ قَالَا يَا رَسُولَ اللَّهِ إِنَّا وَجَدْنَا عَبْدَ اللَّهِ بْنَ سَهْلٍ قَتِيلًا فِي قَلِيبٍ مِنْ بَعْضِ قُلُبِ خَيْبَرَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَتَّهِمُونَ قَالُوا نَتَّهِمُ الْيَهُودَ قَالَ أَفَتُقْسِمُونَ خَمْسِينَ يَمِينًا أَنَّ الْيَهُودَ قَتَلَتْهُ قَالُوا وَكَيْفَ نُقْسِمُ عَلَى مَا لَمْ نَرَ قَالَ فَتُبَرِّئُكُمْ الْيَهُودُ بِخَمْسِينَ أَنَّهُمْ لَمْ يَقْتُلُوهُ قَالُوا وَكَيْفَ نَرْضَى بِأَيْمَانِهِمْ وَهُمْ مُشْرِكُونَ فَوَدَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عِنْدِهِأَرْسَلَهُ مَالِكُ بْنُ أَنَسٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Busyair bin Yasar] dari [Sahl bin Abu Hatsmah], dia berkata; \"Abdullah bin Sahl didapatkan dalam keadaan terbunuh, kemudian saudara dan kedua pamannya yaitu Huwayyishah dan Muhayyishah datang kepada Rasulullah shallallahu 'alaihi wasallam, lalu Abdur Rahman maju untuk berbicara, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dahulukan yang paling tua.\" Maka mereka berdua berkata; \"Wahai Rasulullah, sesungguhnya kami mendapati Abdullah bin Sahl dalam keadaan terbunuh di dalam sumur Khaibar.\" Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Siapakah yang kalian tuduh?\" mereka berkata; \"Kami menuduh orang-orang Yahudi.\" Beliau bersabda: \"Apakah kalian mau bersumpah lima puluh kali sumpah bahwa orang-orang Yahudi telah membunuhnya?\" Mereka berkata; \"Bagaimana kami bersumpah terhadap apa yang tidak kami lihat?\" Beliau bersabda: \"Apakah kalian mau orang-orang Yahudi terbebas dari tuduhan kalian dengan bersumpah lima puluh sumpah bahwa mereka tidak membunuhnya?\" Mereka berkata; \"Bagaimana kita rela dengan sumpah mereka, sedangkan mereka adalah orang-orang musyrik?\" Kemudian Rasulullah shallallahu 'alaihi wasallam membayar diyat dari beliau sendiri. Hadits tersebut dimursalkan oleh Malik bin Anas. "},"4423":{"ar":"قَالَ الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ حَدَّثَنِي مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ بُشَيْرِ بْنِ يَسَارٍ أَنَّهُ أَخْبَرَهُأَنَّ عَبْدَ اللَّهِ بْنَ سَهْلٍ الْأَنْصَارِيَّ وَمُحَيِّصَةَ بْنَ مَسْعُودٍ خَرَجَا إِلَى خَيْبَرَ فَتَفَرَّقَا فِي حَوَائِجِهِمَا فَقُتِلَ عَبْدُ اللَّهِ بْنُ سَهْلٍ فَقَدِمَ مُحَيِّصَةُ فَأَتَى هُوَ وَأَخُوهُ حُوَيِّصَةُ وَعَبْدُ الرَّحْمَنِ بْنُ سَهْلٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَهَبَ عَبْدُ الرَّحْمَنِ لِيَتَكَلَّمَ لِمَكَانِهِ مِنْ أَخِيهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَبِّرْ كَبِّرْ فَتَكَلَّمَ حُوَيِّصَةُ وَمُحَيِّصَةُ فَذَكَرُوا شَأْنَ عَبْدِ اللَّهِ بْنِ سَهْلٍ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَحْلِفُونَ خَمْسِينَ يَمِينًا وَتَسْتَحِقُّونَ دَمَ صَاحِبِكُمْ أَوْ قَاتِلِكُمْ قَالَ مَالِكٌ قَالَ يَحْيَى فَزَعَمَ بُشَيْرٌ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَدَاهُ مِنْ عِنْدِهِخَالَفَهُمْ سَعِيدُ بْنُ عُبَيْدٍ الطَّائِيُّ","id":"Telah berkata [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, dari [Ibnu Al Qasim], telah menceritakan kepadaku [Malik] dari [Yahya bin Sa'id] dari [Busyair bin Yasar] bahwa dia telah mengabarkan kepadanya bahwa Abdullah bin Sahl Al Anshari dan Muhayyishah bin Mas'ud keluar menuju Khaibar kemudian mereka berpisah karena keperluan mereka. Lalu Abdullah bin Sahl terbunuh, kemudian Muhayyishah dan saudaranya yaitu Huwayyishah serta Abdur Rahman bin Sahl datang kepada Rasulullah shallallahu 'alaihi wasallam. Lalu Abdur Rahman maju untuk berbicara karena posisinya dari saudaranya yaitu Abdullah bin Sahl. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dahulukan yang lebih tua, dahulukan yang lebih tua.\" Lalu Huwayyishah dan Muhayyishah berbicara dan menyebutkan keadaan Abdullah bin Sahl. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah kalian mau bersumpah lima puluh sumpah dan berhak terhadap darah sahabat kalian atau terhadap pembunuh kalian?\" Malik berkata; Yahya berkata; kemudian Busyair mengaku bahwa Rasulullah shallallahu 'alaihi wasallam membayar diyat dari beliau sendiri. Sa'id bin 'Ubaid Ath Thai menyelisihi hal tersebut.\""},"4424":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا سَعِيدُ بْنُ عُبَيْدٍ الطَّائِيُّ عَنْ بُشَيْرِ بْنِ يَسَارٍزَعَمَ أَنَّ رَجُلًا مِنْ الْأَنْصَارِ يُقَالُ لَهُ سَهْلُ بْنُ أَبِي حَثْمَةَ أَخْبَرَهُ أَنَّ نَفَرًا مِنْ قَوْمِهِ انْطَلَقُوا إِلَى خَيْبَرَ فَتَفَرَّقُوا فِيهَا فَوَجَدُوا أَحَدَهُمْ قَتِيلًا فَقَالُوا لِلَّذِينَ وَجَدُوهُ عِنْدَهُمْ قَتَلْتُمْ صَاحِبَنَا قَالُوا مَا قَتَلْنَاهُ وَلَا عَلِمْنَا قَاتِلًا فَانْطَلَقُوا إِلَى نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا يَا نَبِيَّ اللَّهِ انْطَلَقْنَا إِلَى خَيْبَرَ فَوَجَدْنَا أَحَدَنَا قَتِيلًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْكُبْرَ الْكُبْرَ فَقَالَ لَهُمْ تَأْتُونَ بِالْبَيِّنَةِ عَلَى مَنْ قَتَلَ قَالُوا مَا لَنَا بَيِّنَةٌ قَالَ فَيَحْلِفُونَ لَكُمْ قَالُوا لَا نَرْضَى بِأَيْمَانِ الْيَهُودِ وَكَرِهَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَبْطُلَ دَمُهُ فَوَدَاهُ مِائَةً مِنْ إِبِلِ الصَّدَقَةِخَالَفَهُمْ عَمْرُو بْنُ شُعَيْبٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sa'id bin 'Ubaid Ath Thai] dari [Busyair bin Yasar] mengaku bahwa seorang laki-laki Anshar yang dipanggil [Sahl bin Abu Hatsmah] telah mengabarkan kepadanya bahwa beberapa orang dari kaumnya pergi ke Khaibar lalu berpisah. Kemudian mereka mendapatkan salah seorang dari mereka terbunuh. Mereka berkata kepada orang-orang yang ada di sekitarnya; \"Kalian telah membunuh sahabat kami.\" Mereka berkata; \"Kami tidak membunuhnya dan tidak mengetahui siapa pembunuhnya.\" Kemudian mereka pergi kepada Nabi shallallahu 'alaihi wasallam lalu berkata; \"Wahai Nabi Allah, kami pergi ke Khaibar dan mendapati salah seorang dari kami terbunuh.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dahulukan yang besar, dahulukan yang besar.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda kepada mereka: \"Kalian datangkan bukti atas orang yang membunuh.\" Mereka berkata; \"Kami tidak memiliki bukti.\" Beliau bersabda: \"Mereka (harus) bersumpah untuk kalian.\" Mereka berkata; \"Kami tidak rela dengan sumpah orang-orang Yahudi.\" Rasulullah shallallahu 'alaihi wasallam tidak ingin darahnya sia-sia, maka beliau membayar diyat seratus unta dari unta shadaqah. 'Amru bin Syu'aib menyelisihi mereka. "},"4425":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ قَالَ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ الْأَخْنَسِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ ابْنَ مُحَيِّصَةَ الْأَصْغَرَ أَصْبَحَ قَتِيلًا عَلَى أَبْوَابِ خَيْبَرَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقِمْ شَاهِدَيْنِ عَلَى مَنْ قَتَلَهُ أَدْفَعْهُ إِلَيْكُمْ بِرُمَّتِهِ قَالَ يَا رَسُولَ اللَّهِ وَمِنْ أَيْنَ أُصِيبُ شَاهِدَيْنِ وَإِنَّمَا أَصْبَحَ قَتِيلًا عَلَى أَبْوَابِهِمْ قَالَ فَتَحْلِفُ خَمْسِينَ قَسَامَةً قَالَ يَا رَسُولَ اللَّهِ وَكَيْفَ أَحْلِفُ عَلَى مَا لَا أَعْلَمُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَسْتَحْلِفُ مِنْهُمْ خَمْسِينَ قَسَامَةً فَقَالَ يَا رَسُولَ اللَّهِ كَيْفَ نَسْتَحْلِفُهُمْ وَهُمْ الْيَهُودُ فَقَسَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِيَتَهُ عَلَيْهِمْ وَأَعَانَهُمْ بِنِصْفِهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'mar] telah menceritakan kepada kami [Rauh bin 'Ubadah] telah menceritakan kepada kami ['Ubaidullah bin Al Akhnas] dari ['Amru bin Syu'aib] dari [ayahnya] dari [kakeknya] bahwa Ibn Muhayyishah kecil terbunuh di pintu gerbang Khaibar, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Datangkan dua orang saksi atas siapa yang membunuhnya, maka aku akan menyerahkannya kepada kalian dengan tali yang mengikatnya.\" Seseorang berkata; \"Wahai Rasulullah, dari mana aku mendapatkan dua orang saksi, sesungguhnya dia terbunuh di pintu gerbang mereka.\" Beliau bersabda: \"Kalian bersumpah lima puluh kali sumpah.\" Dia berkata; \"Wahai Rasulullah, bagaimana aku bersumpah atas apa yang tidak aku ketahui?\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kita minta lima puluh orang dari mereka untuk bersumpah, \" Dia berkata; \"Wahai Rasulullah, bagaimana kita minta mereka bersumpah sedangkan mereka adalah orang-orang Yahudi?\" Rasulullah shallallahu 'alaihi wasallam membagi diyat di antara mereka dan membantu mereka setengahnya."},"4426":{"ar":"أَخْبَرَنَا بِشْرُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مُرَّةَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ دَمُ امْرِئٍ مُسْلِمٍ إِلَّا بِإِحْدَى ثَلَاثٍ النَّفْسُ بِالنَّفْسِ وَالثَّيِّبُ الزَّانِي وَالتَّارِكُ دِينَهُ الْمُفَارِقُ","id":"Telah mengabarkan kepada kami [Bisyr bin Khalid] telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Sulaiman], dia berkata; \"Saya mendengar [Abdullah bin Murrah] dari [Masruq] dari [Abdullah] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: 'Tidak halal darah seorang muslim kecuali dengan salah satu dari tiga perkara, yaitu: membunuh jiwa, janda yang berzina, dan orang yang meninggalkan agamanya.\""},"4427":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ وَأَحْمَدُ بْنُ حَرْبٍ وَاللَّفْظُ لِأَحْمَدَ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقُتِلَ رَجُلٌ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُفِعَ الْقَاتِلُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَفَعَهُ إِلَى وَلِيِّ الْمَقْتُولِ فَقَالَ الْقَاتِلُ يَا رَسُولَ اللَّهِ لَا وَاللَّهِ مَا أَرَدْتُ قَتْلَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِوَلِيِّ الْمَقْتُولِ أَمَا إِنَّهُ إِنْ كَانَ صَادِقًا ثُمَّ قَتَلْتَهُ دَخَلْتَ النَّارَ فَخَلَّى سَبِيلَهُ قَالَ وَكَانَ مَكْتُوفًا بِنِسْعَةٍ فَخَرَجَ يَجُرُّ نِسْعَتَهُ فَسُمِّيَ ذَا النِّسْعَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala`] dan [Ahmad bin Harb], sedang lafazhnya adalah lafazh Ahmad, mereka berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah], dia berkata, \"Seseorang terbunuh pada masa Rasulullah shallallahu 'alaihi wasallam lalu si pembunuh dilaporkan kepada Nabi shallallahu 'alaihi wasallam, lalu beliau menyerahkan kepada wali korban. Orang yang membunuh berkata; \"Wahai Rasulullah, tidak, demi Allah, aku tidak bermaksud membunuhnya.\" Rasulullah shallallahu 'alaihi wasallam bersabda kepada wali si korban: \"Jika dia benar kemudian engkau membunuhnya maka engkau akan masuk neraka.\" Kemudian wali si korban pun membebaskannya. Ketika itu si pembunuh diikat dengan tali pengekang dari kulit lalu dia keluar dengan menyeret ikatannya sehingga dia dikenal dengan pemilik tali pengekang dari kulit.\""},"4428":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا إِسْحَقُ عَنْ عَوْفٍ الْأَعْرَابِيِّ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ الْحَضْرَمِيِّ عَنْ أَبِيهِ قَالَجِيءَ بِالْقَاتِلِ الَّذِي قَتَلَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَ بِهِ وَلِيُّ الْمَقْتُولِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَعْفُو قَالَ لَا قَالَ أَتَقْتُلُ قَالَ نَعَمْ قَالَ اذْهَبْ فَلَمَّا ذَهَبَ دَعَاهُ قَالَ أَتَعْفُو قَالَ لَا قَالَ أَتَأْخُذُ الدِّيَةَ قَالَ لَا قَالَ أَتَقْتُلُ قَالَ نَعَمْ قَالَ اذْهَبْ فَلَمَّا ذَهَبَ قَالَ أَمَا إِنَّكَ إِنْ عَفَوْتَ عَنْهُ فَإِنَّهُ يَبُوءُ بِإِثْمِكَ وَإِثْمِ صَاحِبِكَ فَعَفَا عَنْهُ فَأَرْسَلَهُ قَالَ فَرَأَيْتُهُ يَجُرُّ نِسْعَتَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim] telah menceritakan kepada kami [Ishaq] dari ['Auf Al A'rabi] dari ['Alqamah bin Wail Al Hadhrami] dari [ayahnya], dia berkata; \"Dihadapkan seseorang yang telah membunuh kepada Rasulullah shallallahu 'alaihi wasallam, dia datang bersama wali orang yang terbunuh, lalu Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Maukah engkau memaafkannya?\" Wali korban menjawab; \"Tidak.\" Beliau bersabda: \"Apakah engkau membunuh?\" Si pembunuh menjawab; \"Ya.\" Beliau bersabda: \"Pergilah, \" Ketika dia pergi beliau memanggilnya dan bersabda: \"Maukah engkau memaafkannya?\" Si wali menjawab; \"Tidak.\" Beliau bersabda: \"Maukah engkau mengambil diyat darinya?\" Dia menjawab; \"Tidak.\" Beliau bersabda: \"Apakah engkau membunuh?\" Pembunuh menjawab, \"Ya.\" Beliau bersabda: \"Pergilah.\" Ketika dia pergi beliau bersabda: \"Jika engkau memaafkannya maka dia akan kembali membawa dosamu dan dosa temanmu.\" Lalu si wali pun memaafkan dan melepaskannya. Abu Hurairah berkata; \"Aku melihatnya menyeret tali kekang yang terbuat dari kulit yang mengikatnya.\""},"4429":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عَوْفِ بْنِ أَبِي جَمِيلَةَ قَالَ حَدَّثَنِي حَمْزَةُ أَبُو عُمَرَ الْعَائِذِيُّ قَالَ حَدَّثَنَا عَلْقَمَةُ بْنُ وَائِلٍ عَنْ وَائِلٍ قَالَشَهِدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ جِيءَ بِالْقَاتِلِ يَقُودُهُ وَلِيُّ الْمَقْتُولِ فِي نِسْعَةٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِوَلِيِّ الْمَقْتُولِ أَتَعْفُو قَالَ لَا قَالَ أَتَأْخُذُ الدِّيَةَ قَالَ لَا قَالَ فَتَقْتُلُهُ قَالَ نَعَمْ قَالَ اذْهَبْ بِهِ فَلَمَّا ذَهَبَ بِهِ فَوَلَّى مِنْ عِنْدِهِ دَعَاهُ فَقَالَ لَهُ أَتَعْفُو قَالَ لَا قَالَ أَتَأْخُذُ الدِّيَةَ قَالَ لَا قَالَ فَتَقْتُلُهُ قَالَ نَعَمْ قَالَ اذْهَبْ بِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ ذَلِكَ أَمَا إِنَّكَ إِنْ عَفَوْتَ عَنْهُ يَبُوءُ بِإِثْمِهِ وَإِثْمِ صَاحِبِكَ فَعَفَا عَنْهُ وَتَرَكَهُ فَأَنَا رَأَيْتُهُ يَجُرُّ نِسْعَتَهُأَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا جَامِعُ بْنُ مَطَرٍ الْحَبَطِيُّ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ قَالَ يَحْيَى وَهُوَ أَحْسَنُ مِنْهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Auf bin Abu Jamilah] telah menceritakan kepadaku [Abu Umar Al 'Aidzi] telah menceritakan kepada kami ['Alqamah bin Wail] dari [Wail], dia berkata; \"Saya menyaksikan Rasulullah shallallahu 'alaihi wasallam pada saat dihadapkan kepada beliau seorang pembunuh yang dituntun oleh wali orang yang dibunuh dengan tali kekang dari kulit. Rasulullah shallallahu 'alaihi wasallam bersabda kepada wali orang yang dibunuh: \"Apakah engkau akan memaafkannya?\" Dia berkata; \"Tidak.\" Beliau bersabda: \"Apakah engkau akan mengambil diyat darinya?\" Dia berkata; \"Tidak.\" Beliau bersabda: \"Engkau akan membunuhnya?\" Dia menjawab; \"Ya.\" Beliau bersabda; \"Pergilah bersamanya!\" Tatkala dia telah pergi bersamanya dan berpaling maka beliau memanggilnya dan bersabda kepadanya: \"Apakah engkau akan memaafkannya?\" Dia berkata; \"Tidak.\" Beliau bersabda: \"Apakah engkau akan mengambil diyat darinya?\" Dia berkata; \"Tidak.\" Beliau bersabda: \"Engkau akan membunuhnya?\" Dia menjawab; \"Ya.\" Beliau bersabda; \"Pergilah bersamanya!\" Pada saat itu beliau bersabda: \"Sesungguhnya apabila engkau memaafkannya maka dia akan kembali membawa dosanya dan dosa sahabatmu.\" Lalu dia memaafkannya dan membiarkannya. Saya melihatnya menyeret tali kekang dari kulit. Telah mengabarkan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Jami' bin Mathar Al Habathi] dari ['Alqamah bin Wail] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam dengan hadits yang semisal. Yahya berkata; Dia (hadits ini) lebih baik darinya.\""},"4430":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا حَفْصُ بْنُ عُمَرَ وَهُوَ الْحَوْضِيُّ قَالَ حَدَّثَنَا جَامِعُ بْنُ مَطَرٍ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ عَنْ أَبِيهِ قَالَكُنْتُ قَاعِدًا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَ رَجُلٌ فِي عُنُقِهِ نِسْعَةٌ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ هَذَا وَأَخِي كَانَا فِي جُبٍّ يَحْفِرَانِهَا فَرَفَعَ الْمِنْقَارَ فَضَرَبَ بِهِ رَأْسَ صَاحِبِهِ فَقَتَلَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اعْفُ عَنْهُ فَأَبَى وَقَالَ يَا نَبِيَّ اللَّهِ إِنَّ هَذَا وَأَخِي كَانَا فِي جُبٍّ يَحْفِرَانِهَا فَرَفَعَ الْمِنْقَارَ فَضَرَبَ بِهِ رَأْسَ صَاحِبِهِ فَقَتَلَهُ فَقَالَ اعْفُ عَنْهُ فَأَبَى ثُمَّ قَامَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ هَذَا وَأَخِي كَانَا فِي جُبٍّ يَحْفِرَانِهَا فَرَفَعَ الْمِنْقَارَ أُرَاهُ قَالَ فَضَرَبَ رَأْسَ صَاحِبِهِ فَقَتَلَهُ فَقَالَ اعْفُ عَنْهُ فَأَبَى قَالَ اذْهَبْ إِنْ قَتَلْتَهُ كُنْتَ مِثْلَهُ فَخَرَجَ بِهِ حَتَّى جَاوَزَ فَنَادَيْنَاهُ أَمَا تَسْمَعُ مَا يَقُولُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَجَعَ فَقَالَ إِنْ قَتَلْتُهُ كُنْتُ مِثْلَهُ قَالَ نَعَمْ أَعْفُ فَخَرَجَ يَجُرُّ نِسْعَتَهُ حَتَّى خَفِيَ عَلَيْنَا","id":"Telah mengabarkan kepada kami ['Amru bin Manshur] telah menceritakan kepada kami [Hafsh bin Umar yaitu Al Haudhi] telah menceritakan kepada kami [Jami' bin Mathar] dari ['Alqamah bin Wa`il] dari [ayahnya], dia berkata; \"Saya pernah duduk bersama Rasulullah shallallahu 'alaihi wasallam, lalu datanglah seorang laki-laki yang lehernya terikat tali kekang dari kulit, kemudian dia berkata; \"Wahai Rasulullah, sesungguhnya orang ini dan saudaraku pernah menggali sumur kemudian dia mengangkat cangkul dan memukul kepala temannya dengan menggunakan cangkul tersebut, hingga mati.\" Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Maafkan dia.\" Tapi dia enggan untuk memaafkan, dia berkata; \"Wahai Nabi Allah, sesungguhnya orang ini dan saudaraku pernah menggali sumur kemudian dia mengangkat cangkul dan memukul kepala temannya (saudaraku) dengan menggunakan cangkul tersebut, hingga mati.\" Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Maafkan dia.\" Tetapi dia enggan untuk memaafkan. Kemudian dia berdiri dan berkata; \"Wahai Nabi Allah, sesungguhnya orang ini dan saudaraku pernah menggali sumur kemudian dia mengangkat cangkul dan memukul kepala temannya dengan menggunakan cangkul tersebut, hingga mati.\" Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Maafkan dia.\" Tetapi dia enggan untuk memaafkan. Beliau bersabda: \"Pergilah, apabila engkau membunuhnya maka engkau seperti dirinya.\" Kemudian dia keluar membawa orang tersebut hingga berlalu, kemudian kami memanggilnya; \"Tidakkah engkau mendengar apa yang Rasulullah shallallahu 'alaihi wasallam sabdakan?\" Kemudian dia kembali dan berkata; \"Apabila saya membunuhnya maka saya sepertinya?\" Beliau bersabda; \"Ya.\" \"Saya memaafkannya.\" Kemudian orang yang membunuh tersebut keluar dengan menyeret tali kekang dari kulit hingga dia tidak terlihat oleh kami.\""},"4431":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا حَاتِمٌ عَنْ سِمَاكٍ ذَكَرَ أَنَّ عَلْقَمَةَ بْنَ وَائِلٍ أَخْبَرَهُ عَنْ أَبِيهِأَنَّهُ كَانَ قَاعِدًا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ جَاءَ رَجُلٌ يَقُودُ آخَرَ بِنِسْعَةٍ فَقَالَ يَا رَسُولَ اللَّهِ قَتَلَ هَذَا أَخِي فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقَتَلْتَهُ قَالَ يَا رَسُولَ اللَّهِ لَوْ لَمْ يَعْتَرِفْ أَقَمْتُ عَلَيْهِ الْبَيِّنَةَ قَالَ نَعَمْ قَتَلْتُهُ قَالَ كَيْفَ قَتَلْتَهُ قَالَ كُنْتُ أَنَا وَهُوَ نَحْتَطِبُ مِنْ شَجَرَةٍ فَسَبَّنِي فَأَغْضَبَنِي فَضَرَبْتُ بِالْفَأْسِ عَلَى قَرْنِهِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ لَكَ مِنْ مَالٍ تُؤَدِّيهِ عَنْ نَفْسِكَ قَالَ يَا رَسُولَ اللَّهِ مَالِي إِلَّا فَأْسِي وَكِسَائِي فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتُرَى قَوْمَكَ يَشْتَرُونَكَ قَالَ أَنَا أَهْوَنُ عَلَى قَوْمِي مِنْ ذَاكَ فَرَمَى بِالنِّسْعَةِ إِلَى الرَّجُلِ فَقَالَ دُونَكَ صَاحِبَكَ فَلَمَّا وَلَّى قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ قَتَلَهُ فَهُوَ مِثْلُهُ فَأَدْرَكُوا الرَّجُلَ فَقَالُوا وَيْلَكَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنْ قَتَلَهُ فَهُوَ مِثْلُهُ فَرَجَعَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ حُدِّثْتُ أَنَّكَ قُلْتَ إِنْ قَتَلَهُ فَهُوَ مِثْلُهُ وَهَلْ أَخَذْتُهُ إِلَّا بِأَمْرِكَ فَقَالَ مَا تُرِيدُ أَنْ يَبُوءَ بِإِثْمِكَ وَإِثْمِ صَاحِبِكَ قَالَ بَلَى قَالَ فَإِنْ ذَاكَ قَالَ ذَلِكَ كَذَلِكَأَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا أَبُو يُونُسَ عَنْ سِمَاكِ بْنِ حَرْبٍ أَنَّ عَلْقَمَةَ بْنَ وَائِلٍ حَدَّثَهُ أَنَّ أَبَاهُ حَدَّثَهُ قَالَ إِنِّي لَقَاعِدٌ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ جَاءَ رَجُلٌ يَقُودُ آخَرَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] telah menceritakan kepada kami [Khalid] telah menceritakan kepada kami [Hatim] dari [Simak], dia menyebutkan bahwa ['Alqamah bin Wail] telah mengabarkan kepadanya dari [ayahnya] bahwa dia pernah duduk-duduk bersama Rasulullah shallallahu 'alaihi wasallam, tiba-tiba datang seorang laki-laki yang menuntun orang lain dengan tali kekang dari kulit lalu berkata; \"Wahai Rasulullah, orang ini telah membunuh saudaraku.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya; \"Apakah engkau membunuhnya?\" Dia berkata; \"Wahai Rasulullah, apabila dia tidak mengaku maka akan saya datangkan bukti.\" Orang tersebut berkata; \"Ya, saya telah membunuhnya.\" Beliau bersabda: \"Bagaimana engkau membunuhnya?\" Orang tersebut menjawab; \"Saya bersamanya mencari kayu bakar dari sebuah pohon, kemudian dia menghinaku dan membuatku marah. Kemudian saya memukul kepalanya dengan menggunakan kapak.\" Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Apakah engkau memiliki harta untuk menebus dirimu?\" Orang tersebut berkata; \"Wahai Rasulullah, saya tidak memiliki apapun kecuali kapak dan pakaianku.\" Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Apakah engkau melihat bahwa kaummu akan membelimu?\" Dia berkata; \"Saya lebih hina bagi kaumku daripada orang itu.\" Beliau melemparkan tali kekang tersebut kepada orang tersebut dan bersabda: 'Bawalah temanmu.\" Kemudian tatkala dia telah pergi Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila dia membunuhnya berarti dia seperti orang tersebut.\" Kemudian mereka menemui orang tersebut dan berkata; \"Celaka engkau, sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila dia membunuhnya maka dia sepertinya.\" Kemudian orang tersebut kembali kepada Rasulullah shallallahu 'alaihi wasallam dan berkata; \"Wahai Rasulullah, saya diberitahu bahwa Tuan mengatakan: \"Apabila dia membunuhnya maka dia sepertinya.\" Tidaklah saya membawanya kecuali dengan perintah Tuan.\" Beliau bersabda: \"Apakah engkau tidak mau dia membawa dosamu dan dosa sahabatmu?\" Dia berkata; \"Ya.\" Beliau bersabda: \"Jika demikian?\" Dia berkata; \"Berarti ya seperti itu.\" Telah mengabarkan kepada kami [Zakariya bin Yahya] telah menceritakan kepada kami ['Ubaidullah bin Mu'adz] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Abu Yunus] dari [Simak bin Harb] bahwa ['Alqamah bin Wail] telah menceritakan kepadanya bahwa [ayahnya] telah menceritakan kepadanya, dia berkata; \"Saya sedang duduk bersama Rasulullah shallallahu 'alaihi wasallam, tiba-tiba datang seorang laki-laki yang menuntun orang lain. Sama seperti hadits di atas."},"4432":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ حَمَّادٍ عَنْ أَبِي عَوَانَةَ عَنْ إِسْمَعِيلَ بْنِ سَالِمٍ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ أَنَّ أَبَاهُ حَدَّثَهُمْأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِرَجُلٍ قَدْ قَتَلَ رَجُلًا فَدَفَعَهُ إِلَى وَلِيِّ الْمَقْتُولِ يَقْتُلُهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِجُلَسَائِهِ الْقَاتِلُ وَالْمَقْتُولُ فِي النَّارِ قَالَ فَاتَّبَعَهُ رَجُلٌ فَأَخْبَرَهُ فَلَمَّا أَخْبَرَهُ تَرَكَهُ قَالَ فَلَقَدْ رَأَيْتُهُ يَجُرُّ نِسْعَتَهُ حِينَ تَرَكَهُ يَذْهَبُفَذَكَرْتُ ذَلِكَ لِحَبِيبٍ فَقَالَ حَدَّثَنِي سَعِيدُ بْنُ أَشْوَعَ قَالَ وَذَكَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ الرَّجُلَ بِالْعَفْوِ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'mar] telah menceritakan kepada kami [Yahya bin Hammad] dari [Abu 'Awanah] dari [Isma'il bin Salim] dari ['Alqamah bin Wail] bahwa [ayahnya] telah menceritakan kepada mereka bahwa didatangkan kepada Nabi shallallahu 'alaihi wasallam seorang laki-laki yang telah membunuh orang. Kemudian beliau menyerahkannya kepada wali orang yang dibunuh, Nabi shallallahu 'alaihi wasallam bersabda kepada orang-orang yang duduk bersama beliau; \"Orang yang membunuh dan yang dibunuh berada di neraka.\" Kemudian terdapat seseorang yang mengikuti orang yang melapor tadi dan memberitahukan (sabda Nabi tersebut) kepadanya. Kemudian tatkala dia telah memberitahukan kepadanya maka dia meninggalkan orang yang membunuh tersebut. Ayah 'Alqamah berkata; \"Sungguh saya melihatnya menyeret tali kekang dari kulit ketika wali orang yang dibunuh tersebut membiarkannya pergi. Kemudian hal tersebut saya ceritakan kepada [Habib], lalu dia berkata; telah menceritakan kepadaku [Sa'id bin Asywa'], ia berkata dan dia menyebutkan bahwa Nabi shallallahu 'alaihi wasallam memerintahkan orang tersebut untuk memaafkan. "},"4433":{"ar":"أَخْبَرَنَا عِيسَى بْنُ يُونُسَ قَالَ حَدَّثَنَا ضَمْرَةُ عَنْ عَبْدِ اللَّهِ بْنِ شَوْذَبٍ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَجُلًا أَتَى بِقَاتِلِ وَلِيِّهِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اعْفُ عَنْهُ فَأَبَى فَقَالَ خُذْ الدِّيَةَ فَأَبَى قَالَ اذْهَبْ فَاقْتُلْهُ فَإِنَّكَ مِثْلُهُ فَذَهَبَ فَلُحِقَ الرَّجُلُ فَقِيلَ لَهُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اقْتُلْهُ فَإِنَّكَ مِثْلُهُ فَخَلَّى سَبِيلَهُ فَمَرَّ بِي الرَّجُلُ وَهُوَ يَجُرُّ نِسْعَتَهُ","id":"Telah mengabarkan kepada kami [Isa bin Yunus] telah menceritakan kepada kami [Dhamrah] dari [Abdullah bin Syaudzab] dari [Tsabit Al Bunani] dari [Anas bin Malik] bahwa seseorang datang dengan pembunuh walinya kepada Rasulullah shallallahu 'alaihi wasallam, lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Maafkanlah dia, \" Namun dia enggan. Beliau bersabda: \"Ambillah diyatnya, \" Tapi dia enggan, beliau bersabda: \"Pergi dan bunuhlah karena engkau sama sepertinya, \" Lalu dia pergi dan bertemu dengan seseorang, dikatakan kepadanya sesungguhnya Rasulullah Shallallahu' alaihi wa sallam bersabda: \"Bunuhlah dia karena engkau sama sepertinya, \" Lalu dia membebaskannya, orang itu melewatiku dan menyeret tali kekang dari kulit."},"4434":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ إِسْحَقَ الْمَرْوَزِيُّ قَالَ حَدَّثَنِي خَالِدُ بْنُ خِدَاشٍ قَالَ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ بَشِيرِ بْنِ الْمُهَاجِرِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ رَجُلًا جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ هَذَا الرَّجُلَ قَتَلَ أَخِي قَالَ اذْهَبْ فَاقْتُلْهُ كَمَا قَتَلَ أَخَاكَ فَقَالَ لَهُ الرَّجُلُ اتَّقِ اللَّهَ وَاعْفُ عَنِّي فَإِنَّهُ أَعْظَمُ لِأَجْرِكَ وَخَيْرٌ لَكَ وَلِأَخِيكَ يَوْمَ الْقِيَامَةِ قَالَ فَخَلَّى عَنْهُ قَالَ فَأُخْبِرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ فَأَخْبَرَهُ بِمَا قَالَ لَهُ قَالَ فَأَعْنَفَهُ أَمَا إِنَّهُ كَانَ خَيْرًا مِمَّا هُوَ صَانِعٌ بِكَ يَوْمَ الْقِيَامَةِ يَقُولُ يَا رَبِّ سَلْ هَذَا فِيمَ قَتَلَنِي","id":"Telah mengabarkan kepada kami [Al Hasan bin Ishaq Al Marwazi] telah menceritakan kepadaku [Khalid bin Khidasy] telah menceritakan kepada kami [Hatim bin Isma'il] dari [Basyir bin Al Muhajir] dari [Abdullah bin Buraidah] dari [ayahnya] bahwa seorang laki-laki datang menemui Nabi shallallahu 'alaihi wasallam lalu berkata; \"Sesungguhnya orang ini telah membunuh saudaraku.\" Beliau bersabda: \"Pergi dan bunuhlah dia sebagaimana dia membunuh saudaramu.\" Kemudian orang tersebut berkata; \"Bertakwalah kepada Allah dan maafkan saya, sesungguhnya hal itu lebih besar pahalanya bagimu dan lebih baik untukmu dan saudaramu pada Hari Kiamat.\" Kemudian orang tersebut melepaskannya. Lalu Nabi shallallahu 'alaihi wasallam diberitahu mengenai hal tersebut kemudian beliau bertanya kepadanya, maka orang tersebut mengabarkan kepada beliau tentang apa yang telah dia katakan kepadanya. Beliau bersabda dan mencelanya: \"Adapun yang lebih baik dari apa yang dia lakukan kepadamu pada hari kiamat adalah dia akan berkata; wahai Tuhanku tanyakan kepada orang ini, kenapa dia membunuhku.\""},"4435":{"ar":"أَخْبَرَنَا الْقَاسِمُ بْنُ زَكَرِيَّا بْنِ دِينَارٍ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى قَالَ أَنْبَأَنَا عَلِيٌّ وَهُوَ بْنُ صَالِحٍ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابنِ عَبَّاسٍ قَالَكَانَ قُرَيْظَةُ وَالنَّضِيرُ وَكَانَ النَّضِيرُ أَشْرَفَ مِنْ قُرَيْظَةَ وَكَانَ إِذَا قَتَلَ رَجُلٌ مِنْ قُرَيْظَةَ رَجُلًا مِنْ النَّضِيرِ قُتِلَ بِهِ وَإِذَا قَتَلَ رَجُلٌ مِنْ النَّضِيرِ رَجُلًا مِنْ قُرَيْظَةَ أَدَّى مِائَةَ وَسْقٍ مِنْ تَمْرٍ فَلَمَّا بُعِثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَتَلَ رَجُلٌ مِنْ النَّضِيرِ رَجُلًا مِنْ قُرَيْظَةَ فَقَالُوا ادْفَعُوهُ إِلَيْنَا نَقْتُلْهُ فَقَالُوا بَيْنَنَا وَبَيْنَكُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَوْهُ فَنَزَلَتْ{ وَإِنْ حَكَمْتَ فَاحْكُمْ بَيْنَهُمْ بِالْقِسْطِ }وَالْقِسْطُ النَّفْسُ بِالنَّفْسِ ثُمَّ نَزَلَتْ{ أَفَحُكْمَ الْجَاهِلِيَّةِ يَبْغُونَ }","id":"Telah mengabarkan kepada kami [Al Qasim bin Zakariya bin Dinar] telah menceritakan kepada kami ['Ubaidullah bin Musa] telah memberitakan kepada kami ['Ali yaitu Ibnu Shalih] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas], dia berkata; \"Terdapat Bani Quraidhah dan Bani Nadhir, Bani Nadhir lebih mulia dari pada Bani Quraidhah, jika seseorang dari Bani Quraidhah membunuh seorang Bani Nadhir maka dia dibunuh karenanya, dan jika seorang Bani Nadhir membunuh seorang Bani Quraidhah maka dia membayar seratus wasq (satu wasq sama dengan enampuluh sho') dari kurma, ketika Nabi shallallahu 'alaihi wasallam diutus, seorang Bani Nadhir membunuh seorang Bani Quraidhah, mereka berkata kembalikan dia kepada kami agar kami membunuhnya, mereka berkata di antara kami dan kalian ada seorang Nabi shallallahu 'alaihi wasallam, lalu mereka mendatangi beliau, dan turunlah ayat (Jika engkau menghukumi maka hukumilah dengan adil) dan yang dimaksud Qisth adalah nyawa dibalas dengan nyawa, lalu turunlah ayat: (Apakah mereka mengharapkan hukum Jahiliyah) "},"4436":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدٍ قَالَ حَدَّثَنَا عَمِّي قَالَ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ أَخْبَرَنِي دَاوُدُ بْنُ الْحُصَيْنِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ الْآيَاتِ الَّتِي فِي الْمَائِدَةِ الَّتِي قَالَهَا اللَّهُ عَزَّ وَجَلَّ{ فَاحْكُمْ بَيْنَهُمْ أَوْ أَعْرِضْ عَنْهُمْ إِلَى الْمُقْسِطِينَ }إِنَّمَا نَزَلَتْ فِي الدِّيَةِ بَيْنَ النَّضِيرِ وَبَيْنَ قُرَيْظَةَ وَذَلِكَ أَنَّ قَتْلَى النَّضِيرِ كَانَ لَهُمْ شَرَفٌ يُودَوْنَ الدِّيَةَ كَامِلَةً وَأَنَّ بَنِي قُرَيْظَةَ كَانُوا يُودَوْنَ نِصْفَ الدِّيَةِ فَتَحَاكَمُوا فِي ذَلِكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ ذَلِكَ فِيهِمْ فَحَمَلَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْحَقِّ فِي ذَلِكَ فَجَعَلَ الدِّيَةَ سَوَاءً","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'd] telah menceritakan kepada kami [pamanku] telah menceritakan kepada kami [ayahku] dari [Ibnu Ishaq], telah mengabarkan kepadaku [Daud bin Al Hushain] dari [Ikrimah] dari [Ibnu Abbas] bahwa ayat-ayat yang turun dalam Surat Al Maidah yang Allah 'azza wajalla firmankan yaitu: (Maka putuskanlah (perkara itu) di antara mereka, atau berpalinglah dari mereka) hingga firmanNya: (orang-orang yang adil) ayat tersebut turun mengenai diyat antara Bani Nadhir dan Bani Quraizhah yang demikian itu yaitu bahwa orang-orang yang dibunuh dari Bani Nazhir memiliki kemuliaan, mereka dibayar diyat dengan sempurna, sedang Bani Quraizhah mereka dibayar setengah diyat. Kemudian mereka berhukum kepada Rasulullah shallallahu 'alaihi wasallam, maka Allah 'azza wajalla menurunkan ayat tersebut mengenai mereka. Kemudian Rasulullah shallallahu 'alaihi wasallam membawa mereka di atas kebenaran dalam hal tersebut dan menjadikan diyat sama. "},"4437":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ قَيْسِ بْنِ عُبَادٍ قَالَانْطَلَقْتُ أَنَا وَالْأَشْتَرُ إِلَى عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ فَقُلْنَا هَلْ عَهِدَ إِلَيْكَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا لَمْ يَعْهَدْهُ إِلَى النَّاسِ عَامَّةً قَالَ لَا إِلَّا مَا كَانَ فِي كِتَابِي هَذَا فَأَخْرَجَ كِتَابًا مِنْ قِرَابِ سَيْفِهِ فَإِذَا فِيهِ الْمُؤْمِنُونَ تَكَافَأُ دِمَاؤُهُمْ وَهُمْ يَدٌ عَلَى مَنْ سِوَاهُمْ وَيَسْعَى بِذِمَّتِهِمْ أَدْنَاهُمْ أَلَا لَا يُقْتَلُ مُؤْمِنٌ بِكَافِرٍ وَلَا ذُو عَهْدٍ بِعَهْدِهِ مَنْ أَحْدَثَ حَدَثًا فَعَلَى نَفْسِهِ أَوْ آوَى مُحْدِثًا فَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Al Hasan] dari [Qais bin 'Ubad], dia berkata; \"Saya dan Al Asytar pergi menemui [Ali radliallahu 'anhu] kemudian kami mengatakan; \"Apakah Rasulullah shallallahu 'alaihi wasallam mewasiatkan sesuatu yang tidak diwasiatkan kepada orang-orang secara umum?\" Dia berkata; \"Tidak, selain apa yang ada dalam catatanku ini. Kemudian dia mengeluarkan catatan dari sarung pedangnya, ternyata isinya adalah bahwa \"Orang-orang mukmin darah mereka sederajat, dan mereka adalah satu tangan atas orang selain mereka, orang yang paling rendah diantara mereka berjalan dengan jaminan keamanan dari mereka, ketahuilah tidaklah orang yang mukmin dibunuh lantaran orang kafir, dan tidak pula dibunuh orang yang memiliki perjanjian selama dalam perjanjiannya, barang siapa yang melakukan perkara yang dilarang maka kerugiannya terhadap dirinya atau melindungi orang yang berbuat kejahatan maka laknat Allah, malaikat dan seluruh manusia tertimpa atas dirinya.\""},"4438":{"ar":"أَخْبَرَنِي أَبُو بَكْرِ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا الْقَوَارِيرِيُّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْوَاحِدِ قَالَ حَدَّثَنَا عَمْرُو بْنُ عَامِرٍ عَنْ قَتَادَةَ عَنْ أَبِي حَسَّانَ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُؤْمِنُونَ تَكَافَأُ دِمَاؤُهُمْ وَهُمْ يَدٌ عَلَى مَنْ سِوَاهُمْ يَسْعَى بِذِمَّتِهِمْ أَدْنَاهُمْ لَا يُقْتَلُ مُؤْمِنٌ بِكَافِرٍ وَلَا ذُو عَهْدٍ فِي عَهْدِهِ","id":"Telah mengabarkan kepada kami [Abu Bakar bin Ali] telah menceritakan kepada kami [Al Qawariri] telah menceritakan kepada kami [Muhammad bin Abdul Wahid] telah menceritakan kepada kami ['Amru bin 'Amir] dari [Qatadah] dari [Abu Hassan] dari [Ali radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Orang-orang mukmin darah mereka sederajat, dan mereka adalah satu tangan atas orang selain mereka, orang yang paling rendah diantara mereka berjalan dengan jaminan keamanan dari mereka, ketahuilah tidaklah orang yang mukmin dibunuh lantaran orang kafir, dan tidak pula dibunuh orang yang memiliki perjanjian selama dalam perjanjiannya.\""},"4439":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ هُوَ الْمَرْوَزِيُّ قَالَ حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ قَالَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَتَلَ عَبْدَهُ قَتَلْنَاهُ وَمَنْ جَدَعَهُ جَدَعْنَاهُ وَمَنْ أَخْصَاهُ أَخْصَيْنَاهُ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan yaitu Al Marwazi] telah menceritakan kepada kami [Abu Daud Ath Thayalisi] telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Al Hasan] dari [Samurah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang membunuh budaknya maka kami akan membunuhnya dan barang siapa yang memotong ujung-ujungnya maka kami akan memotong ujung-ujungnya, dan barang siapa yang mengebirinya maka kami akan mengebirinya.\" "},"4440":{"ar":"أَخْبَرَنَا نَصْرُ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَتَلَ عَبْدَهُ قَتَلْنَاهُ وَمَنْ جَدَعَ عَبْدَهُ جَدَعْنَاهُ","id":"Telah mengabarkan kepada kami [Nashr bin Ali] telah menceritakan kepada kami [Khalid] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Al Hasan] dari [Samurah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"\"Barang siapa yang membunuh budaknya maka kami akan membunuhnya dan barang siapa yang memotong ujung-ujungnya maka kami akan memotong ujung-ujungnya.\""},"4441":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَتَلَ عَبْدَهُ قَتَلْنَاهُ وَمَنْ جَدَعَ عَبْدَهُ جَدَعْنَاهُ","id":"Telah mengabarkan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Al Hasan] dari [Samurah], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"\"Barang siapa yang membunuh budaknya maka kami akan membunuhnya dan barang siapa yang memotong ujung-ujungnya maka kami akan memotong ujung-ujungnya.\""},"4442":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ دِينَارٍ أَنَّهُ سَمِعَ طَاوُسًا يُحَدِّثُ عَنْ ابْنِ عَبَّاسٍعَنْ عُمَرَ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ نَشَدَ قَضَاءَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ذَلِكَ فَقَامَ حَمَلُ بْنُ مَالِكٍ فَقَالَ كُنْتُ بَيْنَ حُجْرَتَيْ امْرَأَتَيْنِ فَضَرَبَتْ إِحْدَاهُمَا الْأُخْرَى بِمِسْطَحٍ فَقَتَلَتْهَا وَجَنِينَهَا فَقَضَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جَنِينِهَا بِغُرَّةٍ وَأَنْ تُقْتَلَ بِهَا","id":"Telah mengabarkan kepada kami [Yusuf bin Sa'id] telah menceritakan kepada kami [Hajjaj bin Muhammad] dari [Ibnu Juraij] telah mengabarkan kepadaku ['Amru bin Dinar] bahwa dia mendengar [Thawus] menceritakan dari [Ibnu Abbas] dari Umar radliallahu 'anhu bahwa dia meminta keputusan Rasulullah shallallahu 'alaihi wasallam mengenai hal itu lalu berdirilah [Hamal bin Malik] lalu berkata; \"Aku berada di antara dua kamar dua orang wanita, lalu seorang dari mereka memukul yang lain dengan tiang kemah hingga membunuhnya beserta janinnya, lalu Nabi shallallahu 'alaihi wasallam menetapkan untuk janinnya dengan seorang budak dan wanita (yang membunuh) itu dibunuh.\""},"4443":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدَةُ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ يَهُودِيًّا قَتَلَ جَارِيَةً عَلَى أَوْضَاحٍ لَهَا فَأَقَادَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah memberitakan kepada kami ['Abdah] dari [Sa'id] dari [Qatadah] dari [Anas radliallahu 'anhu] bahwa seorang Yahudi membunuh seorang wanita untuk mendapatkan perhiasannya, kemudian Rasulullah shallallahu 'alaihi wasallam membalas karenanya. "},"4444":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا أَبُو هِشَامٍ قَالَ حَدَّثَنَا أَبَانُ بْنُ يَزِيدَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ يَهُودِيًّا أَخَذَ أَوْضَاحًا مِنْ جَارِيَةٍ ثُمَّ رَضَخَ رَأْسَهَا بَيْنَ حَجَرَيْنِ فَأَدْرَكُوهَا وَبِهَا رَمَقٌ فَجَعَلُوا يَتَّبِعُونَ بِهَا النَّاسَ هُوَ هَذَا هُوَ هَذَا قَالَتْ نَعَمْ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُضِخَ رَأْسُهُ بَيْنَ حَجَرَيْنِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Al Mubarak] telah menceritakan kepada kami [Abu Hisyam] telah menceritakan kepada kami [Aban bin Yazid] dari [Qatadah] dari [Anas bin Malik] bahwa seorang Yahudi mengambil perhiasan dari seorang wanita kemudian menggencet (menjepit) kepalanya di antara dua batu. Kemudian orang-orang menemukannya masih bernyawa, kemudian mereka menyebutkan beberapa orang kepadanya, apakah orang yang membunuh adalah ini? Apakah orang yang membunuh adalah ini? Lalu wanita tersebut berkata; \"Ya.\" Kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk menangkapnya kemudian kepalanya digencet di antara dua batu.\" "},"4445":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا يَزِيدُ بْنُ هَارُونَ عَنْ هَمَّامٍ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَخَرَجَتْ جَارِيَةٌ عَلَيْهَا أَوْضَاحٌ فَأَخَذَهَا يَهُودِيٌّ فَرَضَخَ رَأْسَهَا وَأَخَذَ مَا عَلَيْهَا مِنْ الْحُلِيِّ فَأُدْرِكَتْ وَبِهَا رَمَقٌ فَأُتِيَ بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ قَتَلَكِ فُلَانٌ قَالَتْ بِرَأْسِهَا لَا قَالَ فُلَانٌ قَالَ حَتَّى سَمَّى الْيَهُودِيَّ قَالَتْ بِرَأْسِهَا نَعَمْ فَأُخِذَ فَاعْتَرَفَ فَأَمَرَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُضِخَ رَأْسُهُ بَيْنَ حَجَرَيْنِ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] telah memberitakan kepada kami [Yazid bin Harun] dari [Hammam] dari [Qatadah] dari [Anas bin Malik], dia berkata; \"Seorang wanita keluar dengan memakai perhiasan kemudian perhiasan tersebut diambil oleh seorang Yahudi, kemudian dia menggencet kepala wanita tersebut dan mengambil perhiasan yang ada padanya. Lalu wanita tersebut ditemukan masih bernyawa, kemudian dihadapkan kepada Rasulullah shallallahu 'alaihi wasallam lalu beliau bersabda: \"Siapakah yang membunuhmu? Fulan?\" kemudian dia menjawab dengan kepalanya; \"Tidak.\" Beliau bersabda: \"Fulan?\" hingga beliau menyebutkan seorang Yahudi tersebut. Dia menjawab dengan kepalanya; \"Ya.\" Kemudian Yahuditersebut ditangkap dan mengaku, kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan agar kepalanya digencet, maka digencetlah kepalanya di antara dua batu.\" "},"4446":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَفْصِ بْنِ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي إِبْرَاهِيمُ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَا يَحِلُّ قَتْلُ مُسْلِمٍ إِلَّا فِي إِحْدَى ثَلَاثِ خِصَالٍ زَانٍ مُحْصَنٌ فَيُرْجَمُ وَرَجُلٌ يَقْتُلُ مُسْلِمًا مُتَعَمِّدًا وَرَجُلٌ يَخْرُجُ مِنْ الْإِسْلَامِ فَيُحَارِبُ اللَّهَ عَزَّ وَجَلَّ وَرَسُولَهُ فَيُقْتَلُ أَوْ يُصَلَّبُ أَوْ يُنْفَى مِنْ الْأَرْضِ","id":"Telah mengabarkan kepada kami [Ahmad bin Hafsh bin Abdullah] telah menceritakan kepadaku [ayahku] telah menceritakan kepadaku [Ibrahim] dari [Abdul Aziz bin Rufai'] dari ['Ubaid bin 'Umair] dari ['Aisyah, Ummul mukminin] dari Rasulullah shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Tidak halal membunuh seorang muslim kecuali dengan tiga sifat; seorang pezina yang telah menikah, maka dia dirajam, seseorang yang membunuh orang muslim secara sengaja dan seseorang yang keluar dari Islam lalu memerangi Allah 'azza wajalla dan RasulNya, maka dia dibunuh, atau disalib, atau disingkirkan dari negeri.\" "},"4447":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مُطَرِّفِ بْنِ طَرِيفٍ عَنْ الشَّعْبِيِّ قَالَ سَمِعْتُ أَبَا جُحَيْفَةَ يَقُولُ سَأَلْنَا عَلِيًّا فَقُلْنَاهَلْ عِنْدَكُمْ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْءٌ سِوَى الْقُرْآنِ فَقَالَ لَا وَالَّذِي فَلَقَ الْحَبَّةَ وَبَرَأَ النَّسَمَةَ إِلَّا أَنْ يُعْطِيَ اللَّهُ عَزَّ وَجَلَّ عَبْدًا فَهْمًا فِي كِتَابِهِ أَوْ مَا فِي هَذِهِ الصَّحِيفَةِ قُلْتُ وَمَا فِي الصَّحِيفَةِ قَالَ فِيهَا الْعَقْلُ وَفِكَاكُ الْأَسِيرِ وَأَنْ لَا يُقْتَلَ مُسْلِمٌ بِكَافِرٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] telah menceritakan kepada kami [Sufyan] dari [Mutharrif bin Tharif] dari [Asy Sya'bi], dia berkata; \"Saya mendengar [Abu Juhaifah] berkata; 'Kami bertanya kepada [Ali]. Kami katakan; 'Apakah engkau memiliki sesuatu dari Rasulullah shallallahu 'alaihi wasallam selain Al Qur'an? ' Lalu dia berkata; 'Tidak, demi Dzat yang menumbuhkan biji, dan menciptakan jiwa kecuali Allah 'azza wajalla memberikan pemahaman kepada seorang hamba dalam Al Qur'an, atau apa yang ada dalam lembaran ini.' Saya katakan; 'Apa yang ada dalam lembaran tersebut? ' Dia berkata; 'Isinya adalah diyat, pembebasan tawanan, dan seorang muslim tidak dibunuh lantaran orang kafir.\" "},"4448":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا الْحَجَّاجُ بْنُ مِنْهَالٍ قَالَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَبِي حَسَّانَ قَالَ قَالَ عَلِيٌّمَا عَهِدَ إِلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَيْءٍ دُونَ النَّاسِ إِلَّا فِي صَحِيفَةٍ فِي قِرَابِ سَيْفِي فَلَمْ يَزَالُوا بِهِ حَتَّى أَخْرَجَ الصَّحِيفَةَ فَإِذَا فِيهَا الْمُؤْمِنُونَ تَكَافَأُ دِمَاؤُهُمْ يَسْعَى بِذِمَّتِهِمْ أَدْنَاهُمْ وَهُمْ يَدٌ عَلَى مَنْ سِوَاهُمْ لَا يُقْتَلُ مُؤْمِنٌ بِكَافِرٍ وَلَا ذُو عَهْدٍ فِي عَهْدِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Al Hajjaj bin Minhal] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Abu Hassan], [Ali] berkata; \"Rasulullah shallallahu 'alaihi wasallam tidak mewasiatkan sesuatupun kepadaku, tidak juga kepada orang-orang kecuali dalam lembaran yang ada dalam sarung pedangku.\" Mereka terus bertanya hingga dia mengeluarkan lembaran yang ternyata isinya adalah: \"Orang-orang mukmin darah mereka sederajat, dan mereka adalah satu tangan atas orang selain mereka, orang yang paling rendah di antara mereka berjalan dengan jaminan keamanan dari mereka, ketahuilah tidaklah seorang mukmin dibunuh lantaran orang kafir, dan tidak pula dibunuh orang yang memiliki perjanjian selama dalam perjanjiannya\"."},"4449":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَفْصٍ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ الْحَجَّاجِ بْنِ الْحَجَّاجِ عَنْ قَتَادَةَ عَنْ أَبِي حَسَّانَ الْأَعْرَجِ عَنْ الْأَشْتَرِ أَنَّهُ قَالَ لِعَلِيٍّإِنَّ النَّاسَ قَدْ تَفَشَّغَ بِهِمْ مَا يَسْمَعُونَ فَإِنْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَهِدَ إِلَيْكَ عَهْدًا فَحَدِّثْنَا بِهِ قَالَ مَا عَهِدَ إِلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَهْدًا لَمْ يَعْهَدْهُ إِلَى النَّاسِ غَيْرَ أَنَّ فِي قِرَابِ سَيْفِي صَحِيفَةً فَإِذَا فِيهَا الْمُؤْمِنُونَ تَتَكَافَأُ دِمَاؤُهُمْ يَسْعَى بِذِمَّتِهِمْ أَدْنَاهُمْ لَا يُقْتَلُ مُؤْمِنٌ بِكَافِرٍ وَلَا ذُو عَهْدٍ فِي عَهْدِهِ مُخْتَصَرٌ","id":"Telah mengabarkan kepada kami [Ahmad bin Hafsh] telah menceritakan kepadaku [ayahku] telah menceritakan kepadaku [Ibrahim bin Thahman] dari [Al Hajjaj bin Al Hajjaj] dari [Qatadah] dari [Abu Hasan Al A'raj] dari [Al Asytar] bahwa dia berkata kepada Ali; \"Sesungguhnya apa yang didengar orang-orang telah menyebar, maaka apabila Rasulullah shallallahu 'alaihi wasallam telah mewasiatkan sesuatu kepadamu maka ceritakan kepada kami.\" ['Ali] berkata; \"Rasulullah shallallahu 'alaihi wasallam tidak mewasiatkan sesuatupun kepadaku yang tidak diwasiatkan kepada manusia, hanya saja dalam sarung pedangku ini terdapat lembaran yang ternyata isinya adalah: \"Orang-orang mukmin darah mereka sederajat, dan mereka adalah satu tangan atas orang selain mereka, orang yang paling rendah diantara mereka berjalan dengan jaminan keamanan dari mereka, ketahuilah tidaklah orang yang mukmin dibunuh lantaran orang kafir, dan tidak pula dibunuh orang yang memiliki perjanjian selama dalam perjanjiannya\"."},"4450":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ عَنْ عُيَيْنَةَ قَالَ أَخْبَرَنِي أَبِي قَالَ قَالَ أَبُو بَكْرَةَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَتَلَ مُعَاهِدًا فِي غَيْرِ كُنْهِهِ حَرَّمَ اللَّهُ عَلَيْهِ الْجَنَّةَ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] telah menceritakan kepada kami [Khalid] dari ['Uyainah] telah mengabarkan kepadaku [ayahku] telah berkata [Abu Bakarah]; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \" Barang siapa yang membunuh orang kafir mu'ahid (ada dalam perjanjian) tidak pada waktunya maka Allah mengharamkan baginya Surga.\""},"4451":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ عَنْ يُونُسَ عَنْ الْحَكَمِ بْنِ الْأَعْرَجِ عَنْ الْأَشْعَثِ بْنِ ثُرْمُلَةَ عَنْ أَبِي بَكْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَتَلَ نَفْسًا مُعَاهِدَةً بِغَيْرِ حِلِّهَا حَرَّمَ اللَّهُ عَلَيْهِ الْجَنَّةَ أَنْ يَشُمَّ رِيحَهَا","id":"Telah mengabarkan kepada kami [Al Husain bin Huraits] telah menceritakan kepada kami [Isma'il] dari [Yunus] dari [Al Hakam bin Al A'raj] dari [Al Asy'ats bin Tsurmulah] dari [Abu Bakarah], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang membunuh orang kafir mu'ahid tidak pada waktu halalnya maka Allah mengharamkan baginya untuk mencium bau Surga.\""},"4452":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا النَّضْرُ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ الْقَاسِمِ بْنِ مُخَيْمِرَةَ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَتَلَ رَجُلًا مِنْ أَهْلِ الذِّمَّةِ لَمْ يَجِدْ رِيحَ الْجَنَّةِ وَإِنَّ رِيحَهَا لَيُوجَدُ مِنْ مَسِيرَةِ سَبْعِينَ عَامًا","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [An Nadhr] telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Hilal bin Yasaf] dari [Al Qasim bin Mukhaimirah] dari [seorang sahabat] Nabi shallallahu 'alaihi wasallam bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang membunuh seseorang dari ahli dzimmah maka dia tidak akan mendapatkan bau Surga padahal baunya tercium dari jarak perjalanan tujuh puluh tahun.\""},"4453":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ دُحَيْمٌ قَالَ حَدَّثَنَا مَرْوَانُ قَالَ حَدَّثَنَا الْحَسَنُ وَهُوَ ابْنُ عَمْرٍو عَنْ مُجَاهِدٍ عَنْ جُنَادَةَ بْنِ أَبِي أُمَيَّةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَتَلَ قَتِيلًا مِنْ أَهْلِ الذِّمَّةِ لَمْ يَجِدْ رِيحَ الْجَنَّةِ وَإِنَّ رِيحَهَا لَيُوجَدُ مِنْ مَسِيرَةِ أَرْبَعِينَ عَامًا","id":"Telah mengabarkan kepada kami [Abdur Rahman bin Ibrahim Dukhaim] telah menceritakan kepada kami [Marwan] telah menceritakan kepada kami [Al Hasan yaitu Ibnu 'Amru] dari [Mujahid] dari [Junadah bin Abu Umayyah] dari [Abdullah bin 'Amru], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang membunuh seseorang dari ahli dzimmah maka dia tidak akan mendapatkan bau Surga padahal baunya tercium dari jarak perjalanan empat puluh tahun.\""},"4454":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ أَبِي نَضْرَةَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ غُلَامًا لِأُنَاسٍ فُقَرَاءَ قَطَعَ أُذُنَ غُلَامٍ لِأُنَاسٍ أَغْنِيَاءَ فَأَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَجْعَلْ لَهُمْ شَيْئًا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah memberitakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [ayahku] dari [Qatadah] dari [Abu Nadhrah] dari [Imran bin Hushain] bahwa seorang anak orang miskin memotong telinga anak orang kaya, lalu mereka mendatangi Nabi shallallahu 'alaihi wasallam dan beliau tidak menetapkan sesuatupun bagi mereka."},"4455":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا أَبُو خَالِدٍ سُلَيْمَانُ بْنُ حَيَّانَ قَالَ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِالْقِصَاصِ فِي السِّنِّ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كِتَابُ اللَّهِ الْقِصَاصُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah memberitakan kepada kami [Abu Khalid Sulaiman bin Hayyan] telah menceritakan kepada kami [Humaid] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam menetapkan qishas pada masalah gigi. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketetapan Allah itu adalah qishas.\""},"4456":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَتَلَ عَبْدَهُ قَتَلْنَاهُ وَمَنْ جَدَعَ عَبْدَهُ جَدَعْنَاهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Al Hasan] dari [Samurah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang membunuh budaknya maka kami akan membunuhnya dan barangsiapa memotong ujung-ujung (dari anggota tubuh) budaknya niscaya kami akan memotong ujung-ujungnya.\" "},"4457":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ خَصَى عَبْدَهُ خَصَيْنَاهُ وَمَنْ جَدَعَ عَبْدَهُ جَدَعْنَاهُوَاللَّفْظُ لِابْنِ بَشَّارٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar], mereka berkata; telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [ayahku] dari [Qatadah] dari [Al Hasan] dari [Samurah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang mengebiri budaknya maka kami akan mengebirinya dan barang siapa yang memotong ujung-ujungnya maka kami akan memotong ujungnya.\" Lafazh hadits tersebut adalah lafazh Ibnu Basysyar. "},"4458":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسٍأَنَّ أُخْتَ الرُّبَيِّعِ أُمَّ حَارِثَةَ جَرَحَتْ إِنْسَانًا فَاخْتَصَمُوا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْقِصَاصَ الْقِصَاصَ فَقَالَتْ أُمُّ الرَّبِيعِ يَا رَسُولَ اللَّهِ أَيُقْتَصُّ مِنْ فُلَانَةَ لَا وَاللَّهِ لَا يُقْتَصُّ مِنْهَا أَبَدًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُبْحَانَ اللَّهِ يَا أُمَّ الرَّبِيعِ الْقِصَاصُ كِتَابُ اللَّهِ قَالَتْ لَا وَاللَّهِ لَا يُقْتَصُّ مِنْهَا أَبَدًا فَمَا زَالَتْ حَتَّى قَبِلُوا الدِّيَةَ قَالَ إِنَّ مِنْ عِبَادِ اللَّهِ مَنْ لَوْ أَقْسَمَ عَلَى اللَّهِ لَأَبَرَّهُ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Tsabit] dari [Anas] bahwa saudara perempuan Ar Rubayyi' yaitu Ummu Haritsah telah melukai seseorang kemudian mereka melaporkannya kepada Nabi shallallahu 'alaihi wasallam, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Qishashlah- qishashlah!\". Kemudian Ummu Ar Rabi' berkata; \"Wahai Rasulullah, apakah Fulanah akan diqishash? Tidak, demi Allah, dia tidak akan diqishash selamanya. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Subahanallah, wahai ummu Ar Rabi', qishash adalah ketentuan Allah.\" Dia berkata; \"Tidak, demi Allah, dia tidak akan diqishash selamanya. Dan dia terus mengatakan hal tersebut hingga mereka menerima diyat. Beliau bersabda: \"Sesungguhnya di antara hamba-hamba Allah terdapat orang yang apabila dia bersumpah atas nama Allah maka Allah akan menepatinya.\""},"4459":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ وَإِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا بِشْرٌ عَنْ حُمَيْدٍ قَالَ ذَكَرَ أَنَسٌأَنَّ عَمَّتَهُ كَسَرَتْ ثَنِيَّةَ جَارِيَةٍ فَقَضَى نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْقِصَاصِ فَقَالَ أَخُوهَا أَنَس�� بْنُ النَّضْرِ أَتُكْسَرُ ثَنِيَّةُ فُلَانَةَ لَا وَالَّذِي بَعَثَكَ بِالْحَقِّ لَا تُكْسَرُ ثَنِيَّةُ فُلَانَةَ قَالَ وَكَانُوا قَبْلَ ذَلِكَ سَأَلُوا أَهْلَهَا الْعَفْوَ وَالْأَرْشَ فَلَمَّا حَلَفَ أَخُوهَا وَهُوَ عَمُّ أَنَسٍ وَهُوَ الشَّهِيدُ يَوْمَ أُحُدٍ رَضِيَ الْقَوْمُ بِالْعَفْوِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ عِبَادِ اللَّهِ مَنْ لَوْ أَقْسَمَ عَلَى اللَّهِ لَأَبَرَّهُ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dan [Isma'il bin Mas'ud] telah menceritakan kepada kami [Bisyr] dari [Humaid], dia berkata; \" [Anas] menyebutkan bahwa bibinya telah memecahkan gigi seri seorang wanita, kemudian Nabi shallallahu 'alaihi wasallam memutuskan dengan qishash. Kemudian saudaranya yaitu Anas bin An Nadhr mengatakan; \"Apakah gigi seri Fulanah akan dipecahkan? Tidak, demi Dzat yang mengutus Tuan dengan kebenaran, gigi seri Fulanah tidak akan dipecahkan.\" Sebelum itu mereka telah meminta maaf dan denda kepada keluarga wanita tersebut. Setelah saudaranya yang merupakan paman Anas dan pernah mengikuti perang Uhud bersumpah maka orang-orang tersebut rela memberikan maaf. kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya diantara hamba-hamba Allah terdapat orang yang apabila dia bersumpah atas nama Allah maka Allah akan menepatinya.\" "},"4460":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ قَالَكَسَرَتْ الرُّبَيِّعُ ثَنِيَّةَ جَارِيَةٍ فَطَلَبُوا إِلَيْهِمْ الْعَفْوَ فَأَبَوْا فَعُرِضَ عَلَيْهِمْ الْأَرْشُ فَأَبَوْا فَأَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِالْقِصَاصِ قَالَ أَنَسُ بْنُ النَّضْرِ يَا رَسُولَ اللَّهِ تُكْسَرُ ثَنِيَّةُ الرُّبَيِّعِ لَا وَالَّذِي بَعَثَكَ بِالْحَقِّ لَا تُكْسَرُ قَالَ يَا أَنَسُ كِتَابُ اللَّهِ الْقِصَاصُ فَرَضِيَ الْقَوْمُ وَعَفَوْا فَقَالَ إِنَّ مِنْ عِبَادِ اللَّهِ مَنْ لَوْ أَقْسَمَ عَلَى اللَّهِ لَأَبَرَّهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna], telah menceritakan kepada kami [Khalid] telah menceritakan kepada kami [Humaid] dari [Anas], dia berkata; \"Ar Rubayyi' telah memecahkan gigi seri seorang wanita, kemudian mereka meminta kepada wali wanita tersebut untuk memaafkan namun mereka menolak. Kemudian ditawarkan kepada mereka denda, namun mereka menolak, lalu mereka mendatangi Nabi shallallahu 'alaihi wasallam, kemudian beliau memerintahkan untuk diqishash. Anas bin An Nadhr berkata; \"Wahai Rasulullah, apakah gigi seri Ar Rubayyi' akan dipecah? Tidak, demi Dzat yang mengutus Tuan dengan kebenaran. Gigi serinya tidak akan dipecah.\" Beliau bersabda, \"Wahai Anas, ketetapan Allah adalah qishash.\" Kemudian kaum tersebut rela dan memaafkannya.\" Lantas beliau pun bersabda; \"Sesungguhnya di antara hamba-hamba Allah ada yang apabila dia bersumpah atas nama Allah niscaya Allah akan menepatinya.\""},"4461":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عُثْمَانَ أَبُو الْجَوْزَاءِ قَالَ أَنْبَأَنَا قُرَيْشُ بْنُ أَنَسٍ عَنْ ابْنِ عَوْنٍ عَنْ ابْنِ سِيرِينَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ رَجُلًا عَضَّ يَدَ رَجُلٍ فَانْتَزَعَ يَدَهُ فَسَقَطَتْ ثَنِيَّتُهُ أَوْ قَالَ ثَنَايَاهُ فَاسْتَعْدَى عَلَيْهِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَأْمُرُنِي تَأْمُرُنِي أَنْ آمُرَهُ أَنْ يَدَعَ يَدَهُ فِي فِيكَ تَقْضَمُهَا كَمَا يَقْضَمُ الْفَحْلُ إِنْ شِئْتَ فَادْفَعْ إِلَيْهِ يَدَكَ حَتَّى يَقْضَمَهَا ثُمَّ انْتَزِعْهَا إِنْ شِئْتَ","id":"Telah mengabarkan kepada kami [Ahmad bin Utsman Abu Al Jauza`], ia berkata; telah memberitakan kepada kami [Quraisy bin Anas] dari [Ibnu 'Aun] dari [Ibnu Sirin] dari [Imran bin Hushain] bahwa seorang laki-laki menggigit tangan seorang laki-laki yang lain. Kemudian ia menarik tangannya hingga gigi serinya copot atau beberapa serinya kemudian minta bantuan kepada Rasulullah shallallahu 'alaihi wasallam. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa yang engkau minta dariku, apakah engkau minta aku agar dia melepaskan tangannya yang ada di mulutmu? Engkau menggigitnya sebagaimana pejantan sedang menggigit, apabila engkau mau maka serahkan tanganmu kepadanya hingga dia menggigitnya kemudian tariklah apabila engkau mau.\""},"4462":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَزِيدُ قَالَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ رَجُلًا عَضَّ آخَرَ عَلَى ذِرَاعِهِ فَاجْتَذَبَهَا فَانْتَزَعَتْ ثَنِيَّتَهُ فَرُفِعَ ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَبْطَلَهَا وَقَالَ أَرَدْتَ أَنْ تَقْضَمَ لَحْمَ أَخِيكَ كَمَا يَقْضَمُ الْفَحْلُ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] telah menceritakan kepada kami [Yazid] telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Zurarah bin Aufa] dari [Imran bin Hushain] bahwa seorang laki-laki menggigit seseorang pada hastanya, kemudian orang tersebut menariknya sehingga gigi serinya terlepas. Kemudian hal tersebut dilaporkan kepada Nabi shallallahu 'alaihi wasallam. Lalu beliau membantahnya seraya bersabda: \"Engkau ingin menggigit daging saudaramu sebagaimana pejantan sedang menggigit.\""},"4463":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ زُرَارَةَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَقَاتَلَ يَعْلَى رَجُلًا فَعَضَّ أَحَدُهُمَا صَاحِبَهُ فَانْتَزَعَ يَدَهُ مِنْ فِيهِ فَنَدَرَتْ ثَنِيَّتُهُ فَاخْتَصَمَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَعَضُّ أَحَدُكُمْ أَخَاهُ كَمَا يَعَضُّ الْفَحْلُ لَا دِيَةَ لَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Zurarah] dari [Imran bin Hushain], dia berkata; \"Ya'la berkelahi dengan seseorang, kemudian salah seorang dari mereka menggigit temannya kemudian dia menarik tangannya dari mulut orang yang menggigitnya sehingga gigi seri orang tersebut lepas. Kemudian mereka melaporkan peristiwa tersebut kepada Rasulullah shallallahu 'alaihi wasallam. Kemudian beliau bersabda: \"Salah seorang diantara kalian menggigit saudaranya seperti pejantan yang sedang menggigit. Tidak ada diyat untuknya.\""},"4464":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ زُرَارَةَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ يَعْلَى قَالَ فِي الَّذِي عَضَّ فَنَدَرَتْ ثَنِيَّتُهُ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا دِيَةَ لَكَ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] telah memberitakan kepada kami [Abdullah] dari [Syu'bah] dari [Qatadah] dari [Zurarah] dari [Imran bin Hushain] bahwa Ya'la berkata mengenai orang yang menggigit kemudian gigi serinya terlepas; sesungguhnya Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada diyat untukmu.\""},"4465":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا أَبُو هِشَامٍ قَالَ حَدَّثَنَا أَبَانُ قَالَ حَدَّثَنَا قَتَادَةُ قَالَ حَدَّثَنَا زُرَارَةُ بْنُ أَوْفَى عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ رَجُلًا عَضَّ ذِرَاعَ رَجُلٍ فَانْتَزَعَ ثَنِيَّتَهُ فَانْطَلَقَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَقَالَ أَرَدْتَ أَنْ تَقْضَمَ ذِرَاعَ أَخِيكَ كَمَا يَقْضَمُ الْفَحْلُ فَأَبْطَلَهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Al Mubarak] telah menceritakan kepada kami [Abu Hisyam] telah menceritakan kepada kami [Aban] telah menceritakan kepada kami [Qatadah] telah menceritakan kepada kami [Zurarah bin Aufa] dari [Imran bin Hushain] bahwa seorang laki-laki menggigit hasta laki-laki lain hingga gigi serinya lepas. Kemudian dia pergi kepada Nabi shallallahu 'alaihi wasallam dan menceritakan hal tersebut kepada beliau. Maka beliau bersabda: \"Engkau ingin menggigit hasta saudaramu sebagaimana pejantan yang sedang menggigit.\" Kemudian beliau membatalkan diyat. "},"4466":{"ar":"أَخْبَرَنَا مَالِكُ بْنُ الْخَلِيلِ قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ الْحَكَمِ عَنْ مُجَاهِدٍ عَنْ يَعْلَى ابْنِ مُنْيَةَأَنَّهُ قَاتَلَ رَجُلًا فَعَضَّ أَحَدُهُمَا صَاحِبَهُ فَانْتَزَعَ يَدَهُ مِنْ فِيهِ فَقَلَعَ ثَنِيَّتَهُ فَرُفِعَ ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَعَضُّ أَحَدُكُمْ أَخَاهُ كَمَا يَعَضُّ الْبَكْرُ فَأَبْطَلَهَا","id":"Telah mengabarkan kepada kami [Malik bin Al Khalil] telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Syu'bah] dari [Al Hakam] dari [Mujahid] dari [Ya'la bin Munyah] bahwa dia berkelahi dengan seseorang, Kemudian salah seorang dari mereka menggigit sahabatnya kemudian orang yang digigit menarik tangannya dari mulutnya hingga gigi seri orang yang menggigitnya lepas. Kemudian hal tersebut dilaporkan kepada Rasulullah shallallahu 'alaihi wasallam. Kemudian beliau bersabda: \"Salah seorang diantara kalian menggigit saudaranya seperti pejantan yang sedang menggigit.\" Lalu beliau membatalkan diyat."},"4467":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عُبَيْدِ بْنِ عَقِيلٍ قَالَ حَدَّثَنَا جَدِّي قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ مُجَاهِدٍ عَنْ يَعْلَى ابْنِ مُنْيَةَأَنَّ رَجُلًا مِنْ بَنِي تَمِيمٍ قَاتَلَ رَجُلًا فَعَضَّ يَدَهُ فَانْتَزَعَهَا فَأَلْقَى ثَنِيَّتَهُ فَاخْتَصَمَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَعَضُّ أَحَدُكُمْ أَخَاهُ كَمَا يَعَضُّ الْبَكْرُ فَأَطَلَّهَا أَيْ أَبْطَلَهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin 'Ubaid bin 'Aqil] telah menceritakan kepada kami [kakekku] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Mujahid] dari [Ya'la bin Munyah] bahwa seseorang dari Bani Tamim berkelahi dengan seseorang, kemudian dia menggigit tangan orang tersebut. Orang tersebut menariknya hingga melepaskan gigi serinya. Kemudian mereka melaporkan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam. Kemudian beliau bersabda: \"Salah seorang diantara kalian menggigit saudaranya seperti pejantan yang sedang menggigit. Kemudian beliau membatalkan diyat. "},"4468":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ بَكَّارٍ قَالَ أَنْبَأَنَا أَحْمَدُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا مُحَمَّدٌ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ صَفْوَانَ بْنِ عَبْدِ اللَّهِ عَنْ عَمَّيْهِ سَلَمَةَ وَيَعْلَى ابْنَيْ أُمَيَّةَ قَالَاخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ تَبُوكَ وَمَعَنَا صَاحِبٌ لَنَا فَقَاتَلَ رَجُلًا مِنْ الْمُسْلِمِينَ فَعَضَّ الرَّجُلُ ذِرَاعَهُ فَجَذَبَهَا مِنْ فِيهِ فَطَرَحَ ثَنِيَّتَهُ فَأَتَى الرَّجُلُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَلْتَمِسُ الْعَقْلَ فَقَالَ يَنْطَلِقُ أَحَدُكُمْ إِلَى أَخِيهِ فَيَعَضُّهُ كَعَضِيضِ الْفَحْلِ ثُمَّ يَأْتِي يَطْلُبُ الْعَقْلَ لَا عَقْلَ لَهَا فَأَبْطَلَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Imran bin Bakkar] telah memberitakan kepada kami [Ahmad bin Khalid] telah menceritakan kepada kami [Muhammad] dari ['Atho` bin Abu Rabah] dari [Shafwan bin Abdullah] dari dua orang pamannya, yaitu [Salamah bin Umayyah] dan [Ya'la bin Umayyah]. mereka berkata; \"Kami keluar bersama Rasulullah shallallahu 'alaihi wasallam dalam perang Tabuk dan bersama kami ada seorang sahabat kami. Kemudian dia berkelahi dengan seorang muslim lalu orang tersebut menggigit hastanya kemudian dia menarik tangannya dari mulutnya hingga melepaskan gigi serinya. Lalu orang tersebut datang menghadap kepada Rasulullah shallallahu 'alaihi wasallam mengharapkan diyat. Kemudian beliau bersabda: \"Salah seorang dari kalian mendekati saudaranya kemudian menggigitnya seperti gigitan pejantan, kemudian datang meminta diyat. Tidak ada diyat.\" Maka Rasulullah shallallahu 'alaihi wasallam membatalkan diyat. "},"4469":{"ar":"أَخْبَرَنَا عَبْدُ الْجَبَّارِ بْنُ الْعَلَاءِ بْنِ عَبْدِ الْجَبَّارِ عَنْ سُفْيَانَ عَنْ عَمْرٍو عَنْ عَطَاءٍ عَنْ صَفْوَانَ بْنِ يَعْلَى عَنْ أَبِيهِأَنَّ رَجُلًا عَضَّ يَدَ رَجُلٍ فَانْتُزِعَتْ ثَنِيَّتُهُ فَأَتَى النَّبِيَّ صَلَّى ال��َّهُ عَلَيْهِ وَسَلَّمَ فَأَهْدَرَهَا","id":"Telah mengabarkan kepada kami [Abdul Jabbar bin Al 'Ala` bin Abdul Jabbar] dari [Sufyan] dari ['Amru] dari ['Atho`] dari [Shafwan bin Ya'la] dari [ayahnya] bahwa seorang laki-laki menggigit tangan orang lain kemudian gigi serinya tercabut, kemudian dia datang kepada Nabi shallallahu 'alaihi wasallam dan beliau membatalkannya dan tidak memberinya diyat."},"4470":{"ar":"أَخْبَرَنَا عَبْدُ الْجَبَّارِ مَرَّةً أُخْرَى عَنْ سُفْيَانَ عَنْ عَمْرٍو عَنْ عَطَاءٍ عَنْ صَفْوَانَ بْنِ يَعْلَى عَنْ يَعْلَى وَابْنُ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ صَفْوَانَ بْنِ يَعْلَى عَنْ يَعْلَىأَنَّهُ اسْتَأْجَرَ أَجِيرًا فَقَاتَلَ رَجُلًا فَعَضَّ يَدَهُ فَانْتُزِعَتْ ثَنِيَّتُهُ فَخَاصَمَهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَيَدَعُهَا يَقْضَمُهَا كَقَضْمِ الْفَحْلِ","id":"Telah mengabarkan kepada kami [Abdul Jabbar] sekali lagi dari [Sufyan] dari ['Amru] dari ['Atho`] dari [Shafwan bin Ya'la] dari [Ya'la] dan [Ibnu Juraij] dari ['Atho`] dari [Shafwan bin Ya'la] dari [Ya'laa] bahwa dia mempekerjakan orang upahan kemudian orang tadi berkelahi dengan orang lain dan menggigit tangannya hingga gigi serinya tercabut, kemudian dia melaporkannya kepada Nabi shallallahu 'alaihi wasallam. Lalu beliau bersabda: \"Apakah dia membiarkan tangannya tergigit seperti gigitan pejantan?\""},"4471":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ صَفْوَانَ بْنِ يَعْلَى عَنْ أَبِيهِ قَالَغَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ تَبُوكَ فَاسْتَأْجَرْتُ أَجِيرًا فَقَاتَلَ أَجِيرِي رَجُلًا فَعَضَّ الْآخَرُ فَسَقَطَتْ ثَنِيَّتُهُ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَأَهْدَرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah memberitakan kepada kami [Sufyan] dari [Ibnu Juraij] dari ['Atho`] dari [Shafwan bin Ya'la] dari [ayahya], dia berkata; \"Saya berperang bersama Rasulullah shallallahu 'alaihi wasallam dalam perang Tabuk kemudian saya menyewa orang upahan kemudian orang upahanku tersebut berkelahi dengan seorang laki-laki, kemudian orang lain tersebut menggigit hingga gigi serinya lepas, kemudian dia mendatangi Nabi shallallahu 'alaihi wasallam dan menceritakan hal tersebut kepada beliau. Kemudian Nabi shallallahu 'alaihi wasallam membatalkannya dan tidak memberinya diyat. "},"4472":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ قَالَ أَنْبَأَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَطَاءٌ عَنْ صَفْوَانَ بْنِ يَعْلَى عَنْ يَعْلَى بْنِ أُمَيَّةَ قَالَغَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَيْشَ الْعُسْرَةِ وَكَانَ أَوْثَقَ عَمَلٍ لِي فِي نَفْسِي وَكَانَ لِي أَجِيرٌ فَقَاتَلَ إِنْسَانًا فَعَضَّ أَحَدُهُمَا إِصْبَعَ صَاحِبِهِ فَانْتَزَعَ إِصْبَعَهُ فَأَنْدَرَ ثَنِيَّتَهُ فَسَقَطَتْ فَانْطَلَقَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَهْدَرَ ثَنِيَّتَهُ وَقَالَ أَفَيَدَعُ يَدَهُ فِي فِيكَ تَقْضَمُهَا أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ فِي حَدِيثِ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ عَطَاءٍ عَنْ ابْنِ يَعْلَى عَنْ أَبِيهِ بِمِثْلِ الَّذِي عَضَّ فَنَدَرَتْ ثَنِيَّتُهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا دِيَةَ لَكَ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Ibnu 'Ulayyah] telah memberitakan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku ['Atho`] dari [Shafwan bin Ya'la] dari [Ya'la bin Umayyah], dia berkata; \"Saya perang bersama Rasulullah shallallahu 'alaihi wasallam pada saat terdapat pasukan 'usrah. Itu adalah amalanku yang paling kuat (menghujam) dalam diriku, saya memiliki orang upahan, kemudian dia berkelahi dengan seseorang kemudian salah seorang dari mereka menggigit jari sahabatnya, kemudian dia menarik jarinya hingga melepaskan gigi serinya dan terjatuh. Kemudian dia pergi kepada Nabi shallallahu 'alaihi wasallam. Lalu beliau membatalkannya dan tidak memberikan diyatnya, beliau bersabda: \"Apakah dia akan membiarkan tangannya kau gigit dalam mulutmu?\" Telah mengabarkan kepada kami [Suwaid bin Nashr] dalam hadits [Abdullah bin Al Mubarak] dari [Syu'bah] dari [Qatadah] dari ['Atho`] dari [Ibnu Ya'la] dari [ayahnya] seperti (hadits tentang) orang yang menggigit kemudian gigi serinya tercabut, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada diyat bagimu.\""},"4473":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ بُدَيْلِ بْنِ مَيْسَرَةَ عَنْ عَطَاءٍ عَنْ صَفْوَانَ بْنِ يَعْلَى ابْنِ مُنْيَةَأَنَّ أَجِيرًا لِيَعْلَى ابْنِ مُنْيَةَ عَضَّ آخَرُ ذِرَاعَهُ فَانْتَزَعَهَا مِنْ فِيهِ فَرَفَعَ ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ سَقَطَتْ ثَنِيَّتُهُ فَأَبْطَلَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ أَيَدَعُهَا فِي فِيكَ تَقْضَمُهَا كَقَضْمِ الْفَحْلِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah memberitakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [ayahku] dari [Qatadah] dari [Budail bin Maisarah] dari ['Atho`] dari [Shafwan bin Ya'la bin Munyah] bahwa seorang pekerja upahan milik Ya'la bin Munyah telah digigit hastanya oleh seseorang, kemudian dia menariknya dari mulut. Kemudian orang tersebut melaporkan perkara tersebut kepada Nabi shallallahu 'alaihi wasallam. Sedang gigi serinya telah tanggal. Kemudian Rasulullah shallallahu 'alaihi wasallam membatalkannya dan tidak memberi diyat. Beliau bersabda: 'Apakah ia akan membiarkan tangannya engkau gigit dalam mulutmu seperti pejantan yang sedang menggigit?\""},"4474":{"ar":"أَخْبَرَنِي أَبُو بَكْرِ بْنُ إِسْحَقَ قَالَ حَدَّثَنَا أَبُو الْجَوَّابِ قَالَ حَدَّثَنَا عَمَّارٌ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ الْحَكَمِ عَنْ مُحَمَّدِ بْنِ مُسْلِمٍ عَنْ صَفْوَانَ بْنِ يَعْلَىأَنَّ أَبَاهُ غَزَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ تَبُوكَ فَاسْتَأْجَرَ أَجِيرًا فَقَاتَلَ رَجُلًا فَعَضَّ الرَّجُلُ ذِرَاعَهُ فَلَمَّا أَوْجَعَهُ نَتَرَهَا فَأَنْدَرَ ثَنِيَّتَهُ فَرُفِعَ ذَلِكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَعْمِدُ أَحَدُكُمْ فَيَعَضُّ أَخَاهُ كَمَا يَعَضُّ الْفَحْلُ فَأَبْطَلَ ثَنِيَّتَهُ","id":"Telah mengabarkan kepada kami [Abu Bakar bin Ishaq] telah menceritakan kepada kami [Abu Al Jawwab] telah menceritakan kepada kami ['Ammar] dari [Muhammad bin Abdur Rahman bin Abu Laila] dari [Al Hakam] dari [Muhammad bin Muslim] dari [Shafwan bin Ya'la] bahwa ayahnya melakukan perang bersama Rasulullah shallallahu 'alaihi wasallam dalam perang Tabuk, dia menyewa orang upahan, kemudian orang upahan tersebut berkelahi dengan laki-laki lain. Lalu laki-laki tersebut menggigit hastanya, kemudian tatkala dia merasa sakit dia menariknya hingga mencabut gigi seri laki-laki tersebut. Kemudian hal tersebut dilaporkan kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Salah seorang diantara kalian pergi dan menggigit saudaranya seperti pejantan sedang menggigit.\" Maka beliau membatalkan gigi seri tersebut (tidak memberi diyat). "},"4475":{"ar":"أَخْبَرَنَا وَهْبُ بْنُ بَيَانٍ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ عَنْ عَبِيدَةَ بْنِ مُسَافِعٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَبَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْسِمُ شَيْئًا أَقْبَلَ رَجُلٌ فَأَكَبَّ عَلَيْهِ فَطَعَنَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعُرْجُونٍ كَانَ مَعَهُ فَخَرَجَ الرَّجُلُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعَالَ فَاسْتَقِدْ قَالَ بَلْ قَدْ عَفَوْتُ يَا رَسُولَ اللَّهِ","id":"Telah mengabarkan kepada kami [Wahb bin Bayan] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku ['Amru bin Al Harits] dari [Bukair bin Abdullah] dari ['Ubaidah bin Musafi'] dari [Abu Sa'id Al Khudri], dia berkata; \"Ketika Rasulullah shallallahu 'alaihi wasallam membagi sesuatu, datanglah seseorang mendesak-desak beliau, lalu Rasulullah shallallahu 'alaihi wasallam menusuknya dengan dahan pohon kurma yang beliau bawa, lalu orang itu keluar dan Rasulullah shallallahu 'alaihi wasallam bersabda: \" Kemari dan balaslah.\" Dia berkata; \"Aku sudah maafkan wahai Rasulullah.\""},"4476":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سَعِيدٍ الرِّبَاطِيُّ قَالَ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ أَنْبَأَنَا أَبِي قَالَ سَمِعْتُ يَحْيَى يُحَدِّثُ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ عَنْ عَبِيدَةَ بْنِ مُسَافِعٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَبَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْسِمُ شَيْئًا إِذْ أَكَبَّ عَلَيْهِ رَجُلٌ فَطَعَنَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعُرْجُونٍ كَانَ مَعَهُ فَصَاحَ الرَّجُلُ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعَالَ فَاسْتَقِدْ قَالَ بَلْ عَفَوْتُ يَا رَسُولَ اللَّهِ","id":"Telah mengabarkan kepada kami [Ahmad bin Sa'id Ar Ribathi] telah menceritakan kepada kami [Wahb bin Jarir] telah memberitakan kepada kami [ayahku], ia berkata; saya mendengar [Yahya] menceritakan dari [Bukair bin Abdullah] dari ['Ubaidah bin Musafi'] dari [Abu Sa'id Al Khudri], ia berkata; ketika Rasulullah shallallahu 'alaihi wasallam membagi sesuatu, datanglah seseorang dan menyibukkannya, lalu Rasulullah shallallahu 'alaihi wasallam menusuknya dengan dahan pohon kurma yang beliau bawa, lalu orang itu berteriak kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \" Kemari dan balaslah.\" Ia berkata; aku sudah maafkan wahai Rasulullah."},"4477":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ أَنْبَأَنَا عُبَيْدُ اللَّهِ عَنْ إِسْرَائِيلَ عَنْ عَبْدِ الْأَعْلَى أَنَّهُ سَمِعَ سَعِيدَ بْنَ جُبَيْرٍ يَقُولُ أَخْبَرَنِي ابْنُ عَبَّاسٍأَنَّ رَجُلًا وَقَعَ فِي أَبٍ كَانَ لَهُ فِي الْجَاهِلِيَّةِ فَلَطَمَهُ الْعَبَّاسُ فَجَاءَ قَوْمُهُ فَقَالُوا لَيَلْطِمَنَّهُ كَمَا لَطَمَهُ فَلَبِسُوا السِّلَاحَ فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَعِدَ الْمِنْبَرَ فَقَالَ أَيُّهَا النَّاسُ أَيُّ أَهْلِ الْأَرْضِ تَعْلَمُونَ أَكْرَمُ عَلَى اللَّهِ عَزَّ وَجَلَّ فَقَالُوا أَنْتَ فَقَالَ إِنَّ الْعَبَّاسَ مِنِّي وَأَنَا مِنْهُ لَا تَسُبُّوا مَوْتَانَا فَتُؤْذُوا أَحْيَاءَنَا فَجَاءَ الْقَوْمُ فَقَالُوا يَا رَسُولَ اللَّهِ نَعُوذُ بِاللَّهِ مِنْ غَضَبِكَ اسْتَغْفِرْ لَنَا","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] telah memberitakan kepada kami ['Ubaidullah] dari [Israil] dari [Abdul A'la] bahwa dia mendengar [Sa'id bin Jubair] berkata; telah mengabarkan kepadaku [Ibnu Abbas] bahwa seseorang mencela ayahnya pada zaman Jahiliyah kemudian Al Abbas menamparnya, lalu kaumnya datang dan berkata; \"Sungguh dia akan menamparnya sebagaimana dia menamparnya.\" Kemudian mereka menghunus senjata, lalu hal tersebut sampai kepada Nabi shallallahu 'alaihi wasallam kemudian beliau naik mimbar dan bersabda: \"Wahai manusia, siapakah penduduk bumi yang engkau ketahui paling mulia di sisi Allah 'azza wajalla?\" mereka mengatakan; \"Tuan.\" Lalu beliau bersabda: 'Sesungguhnya Al Abbas adalah bagian dariku sedang aku bagian darinya, janganlah kalian mencela orang-orang yang telah mati di antara kita, sehingga menyakiti orang yang masih hidup diantara kita.\" Kemudian datanglah kaum tersebut dan berkata; \"Wahai Rasulullah, kami berlindung kepada Allah dari kemurkaan Tuan, mintakanlah ampunan untuk kami.\""},"4478":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ عَلِيِّ بْنِ مَيْمُونٍ قَالَ حَدَّثَنِي الْقَعْنَبِيُّ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ هِلَالٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَكُنَّا نَقْعُدُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ فَإِذَا قَامَ قُمْنَا فَقَامَ يَوْمًا وَقُمْنَا مَعَهُ حَتَّى لَمَّا بَلَغَ وَسَطَ الْمَسْجِدِ أَدْرَكَهُ رَجُلٌ فَجَبَذَ بِرِدَائِهِ مِنْ وَرَائِهِ وَك��انَ رِدَاؤُهُ خَشِنًا فَحَمَّرَ رَقَبَتَهُ فَقَالَ يَا مُحَمَّدُ احْمِلْ لِي عَلَى بَعِيرَيَّ هَذَيْنِ فَإِنَّكَ لَا تَحْمِلُ مِنْ مَالِكَ وَلَا مِنْ مَالِ أَبِيكَ فَقَالَ رَسُولُ اللَّهِ ��َلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا وَأَسْتَغْفِرُ اللَّهَ لَا أَحْمِلُ لَكَ حَتَّى تُقِيدَنِي مِمَّا جَبَذْتَ بِرَقَبَتِي فَقَالَ الْأَعْرَابِيُّ لَا وَاللَّهِ لَا أُقِيدُكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَلِكَ ثَلَاثَ مَرَّاتٍ كُلُّ ذَلِكَ يَقُولُ لَا وَاللَّهِ لَا أُقِيدُكَ فَلَمَّا سَمِعْنَا قَوْلَ الْأَعْرَابِيِّ أَقْبَلْنَا إِلَيْهِ سِرَاعًا فَالْتَفَتَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عَزَمْتُ عَلَى مَنْ سَمِعَ كَلَامِي أَنْ لَا يَبْرَحَ مَقَامَهُ حَتَّى آذَنَ لَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِرَجُلٍ مِنْ الْقَوْمِ يَا فُلَانُ احْمِلْ لَهُ عَلَى بَعِيرٍ شَعِيرًا وَعَلَى بَعِيرٍ تَمْرًا ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْصَرِفُوا","id":"Telah mengabarkan kepada kami [Muhammad bin Ali bin Maimun] telah menceritakan kepadaku [Al Qa'nabi] telah menceritakan kepadaku [Muhammad bin Hilal] dari [ayahnya] dari [Abu Hurairah], dia berkata; \"Kami duduk bersama Rasulullah shallallahu 'alaihi wasallam di masjid, jika beliau berdiri maka kami berdiri bersamanya, pada suatu hari beliau berdiri dan kami berdiri bersama beliau hingga ketika beliau sampai di tengah masjid, seseorang mengejar beliau dan menarik selendang beliau dari belakang, padahal selendang beliau tebal sehingga menjadikan leher beliau memerah. Dia berkata; \"Wahai Muhammad, bawakan makanan untukku di atas dua untaku ini karena sesungguhnya engkau tidak membawa hartamu dan harta ayahmu.\" Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak, aku akan meminta ampunan Allah, aku tidak akan membawakan untukmu hingga engkau membalasku dengan apa yang engkau tarik pada leherku, \" Lalu seorang badui berkata, \"Tidak, demi Allah, aku tidak akan membalasmu.\" Lalu Rasulullah shallallahu 'alaihi wasallam mengatakan hal itu sebanyak tiga kali, setiap beliau mengatakannya dia menjawab tidak, demi Allah aku tidak akan membalasmu, ketika kami mendengar perkataan orang badui itu kami mendatanginya dengan cepat lalu Rasulullah shallallahu 'alaihi wasallam menoleh kearah kami dan bersabda: \" aku ingin siapa saja yang mendengar perkataanku agar tidak beranjak dari tempatnya hingga aku ijinkan, \" lalu Rasulullah shallallahu 'alaihi wasallam bersabda kepada seseorang dari kami: \"hai fulan bawakanlah gandum untuknya keatas satu unta dan kurma ke atas unta yang lain\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pergilah kalian.\""},"4479":{"ar":"أَخْبَرَنَا مُؤَمَّلُ بْنُ هِشَامٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبُو مَسْعُودٍ سَعِيدُ بْنُ إِيَاسٍ الْجُرَيْرِيُّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي فِرَاسٍ أَنَّ عُمَرَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقِصُّ مِنْ نَفْسِهِ","id":"Telah mengabarkan kepada kami [Muammal bin Hisyam] telah menceritakan kepada kami [Isma'il bin Ibrahim] telah menceritakan kepada kami [Abu Mas'ud Sa'id bin Iyas Al Jurairi] dari [Abu Nadhrah] dari [Abu Firas] bahwa [Umar] berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam meminta qishash untuk diri beliau.\""},"4480":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ أَبَا جَهْمِ بْنَ حُذَيْفَةَ مُصَدِّقًا فَلَاحَّهُ رَجُلٌ فِي صَدَقَتِهِ فَضَرَبَهُ أَبُو جَهْمٍ فَأَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ الْقَوَدُ يَا رَسُولَ اللَّهِ فَقَالَ لَكُمْ كَذَا وَكَذَا فَلَمْ يَرْضَوْا بِهِ فَقَالَ لَكُمْ كَذَا وَكَذَا فَرَضُوا بِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي خَاطِبٌ عَلَى النَّاسِ وَمُخْبِرُهُمْ بِرِضَاكُمْ قَالُوا نَعَمْ فَخَطَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ هَؤُلَاءِ أَتَوْنِي يُرِيدُونَ الْقَوَدَ فَعَرَضْتُ عَلَيْهِمْ كَذَا وَكَذَا فَرَضُوا قَالُوا لَا فَهَمَّ الْمُهَاجِرُونَ بِهِمْ فَأَمَرَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَكُفُّوا فَكَفُّوا ثُمَّ دَعَاهُمْ قَالَ أَرَضِيتُمْ قَالُوا نَعَمْ قَالَ فَإِنِّي خَاطِبٌ عَلَى النَّاسِ وَمُخْبِرُهُمْ بِرِضَاكُمْ قَالُوا نَعَمْ فَخَطَبَ النَّاسَ ثُمَّ قَالَ أَرَضِيتُمْ قَالُوا نَعَمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdur Razzaq] dari [Ma'mar] dari [Az Zuhri] dari [Urwah] dari ['Aisyah] bahwa Nabi shallallahu 'alaihi wasallam mengutus Abu Jahm bin Hudzaifah sebagai pengurus shadaqah, kemudian terdapat seorang laki-laki yang terus mendesak dalam meminta shadaqah, sehingga Abu Jahm memukulnya, kemudian orang-orang mendatangi Nabi shallallahu 'alaihi wasallam dan berkata; \"Kami meminta balasan wahai Rasulullah, \" Beliau bersabda: \"Maukah Kalian mendapatkan ini dan itu?\" Namun mereka tidak ridha, lalu beliau bersabda: \"kalian mendapatkan ini dan itu, \" lalu mereka ridha. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku akan berkhutbah kepada manusia dan akan aku kabari mereka dengan keridhaan kalian, \" Mereka menjawab; \"Ya.\" Lalu Nabi shallallahu 'alaihi wasallam berkhutbah dan beliau bersabda: \" Sesungguhnya mereka mendatangiku ingin memintaku balasan, lalu aku tawarkan kepada mereka ini dan itu, lalu mereka ridho, \" Mereka berkata; \"Tidak.\" Maka orang-orang muhajirin hendak melawan mereka, lalu Rasulullah shallallahu 'alaihi wasallam menyuruh mereka untuk menahan hal itu, dan mereka menahannya, lalu beliau memanggil mereka dan bersabda: \" Apakah kalian ridha, \" mereka menjawab iya, beliau bersabda: \" aku akan berkhutbah di hadapan manusia dan mengabarkan mereka akan keridhaan kalian, \" kemudian beliau berkhutbah di hadapan manusia dan bersabda: \"Apakah kalian ridha, \" mereka menjawab; \"Ya.\""},"4481":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ عَنْ هِشَامِ بْنِ زَيْدٍ عَنْ أَنَسٍأَنَّ يَهُودِيًّا رَأَى عَلَى جَارِيَةٍ أَوْضَاحًا فَقَتَلَهَا بِحَجَرٍ فَأُتِيَ بِهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِهَا رَمَقٌ فَقَالَ أَقَتَلَكِ فُلَانٌ فَأَشَارَ شُعْبَةُ بِرَأْسِهِ يَحْكِيهَا أَنْ لَا فَقَالَ أَقَتَلَكِ فُلَانٌ فَأَشَارَ شُعْبَةُ بِرَأْسِهِ يَحْكِيهَا أَنْ لَا قَالَ أَقْتَلَكِ فُلَانٌ فَأَشَارَ شُعْبَةُ بِرَأْسِهِ يَحْكِيهَا أَنْ نَعَمْ فَدَعَا بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَتَلَهُ بَيْنَ حَجَرَيْنِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] telah menceritakan kepada kami [Khalid] dari [Syu'bah] dari [Hisyam bin Zaid] dari [Anas] bahwa seorang Yahudi melihat perhiasan yang dipakai oleh seorang wanita, kemudian dia membunuhnya dengan batu. Lalu wanita tersebut dihadapkan kepada Nabi shallallahu 'alaihi wasallam dalam keadaan masih bernyawa. Kemudian beliau bertanya: 'Apakah yang membunuhmu adalah Fulan? Syu'bah memberi isyarat menceritakan mengenai wanita tersebut yang menjawab; tidak. Beliau bersabda: \"Apakah yang membunuhmu adalah Fulan?\" Syu'bah memberi isyarat menceritakan mengenai wanita tersebut yang menjawab; tidak. Beliau bersabda: \"Apakah yang membunuhmu adalah Fulan?\" Syu'bah memberi isyarat menceritakan mengenai wanita tersebut yang menjawab; ya. Kemudian beliau meminta agar orang tersebut dihadapkan kepada beliau, lalu beliau membunuhnya di antara dua batu."},"4482":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا أَبُو خَالِدٍ عَنْ إِسْمَعِيلَ عَنْ قَيْسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ سَرِيَّةً إِلَى قَوْمٍ مِنْ خَثْعَمَ فَاسْتَعْصَمُوا بِالسُّجُودِ فَقُتِلُوا فَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنِصْفِ الْعَقْلِ وَقَالَ إِنِّي بَرِيءٌ مِنْ كُلِّ مُسْلِمٍ مَعَ مُشْرِكٍ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا لَا تَرَاءَى نَارَاهُمَا","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala`] telah menceritakan kepada kami [Abu Khalid] dari [Isma'il] dari [Qois] bahwa Rasulullah shallallahu 'alaihi wasallam mengirim pasukan kepada suatu kaum dari Khats'am lalu mereka berlindung dengan melakukan sujud, lalu mereka dibunuh, kemudian Rasulullah shallallahu 'alaihi wasallam menetapkan dengan setengah diyat dan bersabda: \"Sesungguhnya aku berlepas diri dari setiap muslim bersama seorang musyrik, \" kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \" Ketahuilah api keduanya tidak akan saling melihat.\""},"4483":{"ar":"قَالَ الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ سُفْيَانَ عَنْ عَمْرٍو عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ فِي بَنِي إِسْرَائِيلَ الْقِصَاصُ وَلَمْ تَكُنْ فِيهِمْ الدِّيَةُ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ كُتِبَ عَلَيْكُمْ الْقِصَاصُ فِي الْقَتْلَى الْحُرُّ بِالْحُرِّ وَالْعَبْدُ بِالْعَبْدِ وَالْأُنْثَى بِالْأُنْثَى إِلَى قَوْلِهِ فَمَنْ عُفِيَ لَهُ مِنْ أَخِيهِ شَيْءٌ فَاتِّبَاعٌ بِالْمَعْرُوفِ وَأَدَاءٌ إِلَيْهِ بِإِحْسَانٍ }فَالْعَفْوُ أَنْ يَقْبَلَ الدِّيَةَ فِي الْعَمْدِ وَاتِّبَاعٌ بِمَعْرُوفٍ يَقُولُ يَتَّبِعُ هَذَا بِالْمَعْرُوفِ وَأَدَاءٌ إِلَيْهِ بِإِحْسَانٍ وَيُؤَدِّي هَذَا بِإِحْسَانٍ ذَلِكَ تَخْفِيفٌ مِنْ رَبِّكُمْ وَرَحْمَةٌ مِمَّا كُتِبَ عَلَى مَنْ كَانَ قَبْلَكُمْ إِنَّمَا هُوَ الْقِصَاصُ لَيْسَ الدِّيَةَ","id":"[Al Harits bin Miskin] berkata dengan membacakan riwayat dan saya mendengar dari [Sufyan] dari ['Amru] dari [Mujahid] dari [Ibnu Abbas], dia berkata; dahulu pada Bani Israil terdapat hukum qishas namun tidak ada diyat pada mereka, lalu Allah Azza wa jalla menurunkan ayat: (Hai orang-orang yang beriman, diwajibkan atas kamu qishash berkenaan dengan orang-orang yang dibunuh; orang merdeka dengan orang merdeka, hamba dengan hamba, dan wanita dengan wanita. Maka barangsiapa yang mendapat suatu pema'afan dari saudaranya, hendaklah (yang mema'afkan) mengikuti dengan cara yang baik, dan hendaklah (yang diberi ma'af) membayar (diat) kepada yang memberi ma'af dengan cara yang baik (pula)). Pemberian maaf itu adalah menerima diyat pada pembunuhan dengan sengaja, dan hendaklah (yang mema'afkan) mengikuti dengan cara yang baik, dan hendaklah (yang diberi ma'af) membayar (diat) kepada yang memberi ma'af dengan cara yang baik (pula)), serta melaksanakan ini dengan kebaikan. Yang demikian itu adalah suatu keringanan dari Tuhan kamu dan suatu rahmat dari apa yang diwajibkan atas kaum sebelum kalian, sesungguhnya hal tersebut adalah qishas bukan diyat."},"4484":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَلِيُّ بْنُ حَفْصٍ قَالَ حَدَّثَنَا وَرْقَاءُ عَنْ عَمْرٍو عَنْ مُجَاهِدٍ قَالَ{ كُتِبَ عَلَيْكُمْ الْقِصَاصُ فِي الْقَتْلَى الْحُرُّ بِالْحُرِّ }قَالَ كَانَ بَنُو إِسْرَائِيلَ عَلَيْهِمْ الْقِصَاصُ وَلَيْسَ عَلَيْهِمْ الدِّيَةُ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ عَلَيْهِمْ الدِّيَةَ فَجَعَلَهَا عَلَى هَذِهِ الْأُمَّةِ تَخْفِيفًا عَلَى مَا كَانَ عَلَى بَنِي إِسْرَائِيلَ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim] telah menceritakan kepada kami [Ali bin Hafsh] telah menceritakan kepada kami [Warqa`] dari ['Amru] dari [Mujahid], dia berkata; \"Diwajibkan atas kamu qishaash berkenaan dengan orang-orang yang dibunuh; orang merdeka dengan orang merdeka. Mujahid berkata; \"Dahulu Bani Israil memiliki kewajiban qishas namun mereka tidak memiliki kewjiban membayar diyat, lalu Allah Azza wa jalla menurunkan ayat tentang diyat kepada mereka dan menjadikannya sebagai keringanan bagi umat atas apa yang dahulu terjadi pada Bani Israil.\""},"4485":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ وَهُوَ ابْنُ بَكْرِ بْنِ عَبْدِ اللَّهِ الْمُزَنِيُّ عَنْ عَطَاءِ بْنِ أَبِي مَيْمُونَةَ عَنْ أَنَسٍ قَالَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قِصَاصٍ فَأَمَرَ فِيهِ بِالْعَفْوِ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah menceritakan kepada kami [Abdur Rahman] telah menceritakan kepada kami [Abdullah yaitu Ibnu Bakr bin Abdullah Al Muzani] dari ['Atho` bin Abu Maimunah] dari [Anas], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam dihadapkan pada perkara mengenai qishash kemudian beliau memerintahkan agar memberikan maaf.\" "},"4486":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ وَبَهْزُ بْنُ أَسَدٍ وَعَفَّانُ بْنُ مُسْلِمٍ قَالُوا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَكْرٍ الْمُزَنِيُّ قَالَ حَدَّثَنَا عَطَاءُ بْنُ أَبِي مَيْمُونَةَ وَلَا أَعْلَمُهُ إِلَّا عَنْ أَنَسِ بْنِ مَالِكٍ قَالَمَا أُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شَيْءٍ فِيهِ قِصَاصٌ إِلَّا أَمَرَ فِيهِ بِالْعَفْوِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abdur Rahman bin Mahdi] dan [Bahz bin Asad] serta ['Affan bin Muslim], telah menceritakan kepada kami [Abdullah bin Bakr Al Muzani] telah menceritakan kepada kami ['Atho` bin Abu Maimunah] dan saya tidak mengetahui kecuali dari [Anas bin Malik], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam dihadapkan pada perkara mengenai qishash hanya saja beliau memerintahkan agar memberikan maaf.\""},"4487":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ أَشْعَثَ قَالَ حَدَّثَنَا أَبُو مُسْهِرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ وَهُوَ ابْنُ عَبْدِ اللَّهِ بْنِ سَمَاعَةَ قَالَ أَنْبَأَنَا الْأَوْزَاعِيُّ قَالَ أَخْبَرَنِي يَحْيَى قَالَ حَدَّثَنِي أَبُو سَلَمَةَ قَالَ حَدَّثَنِي أَبُو هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قُتِلَ لَهُ قَتِيلٌ فَهُوَ بِخَيْرِ النَّظَرَيْنِ إِمَّا أَنْ يُقَادَ وَإِمَّا أَنْ يُفْدَى","id":"Telah menceritakan kepada kami [Muhammad bin Abdur Rahman bin Asy'ats] telah menceritakan kepada kami [Abu Mushir] telah menceritakan kepada kami [Isma'il yaitu Ibnu Abdullah bin Sama'ah] telah menceritakan kepada kami [Al Auza'I] telah menceritakan kepadaku [Yahya] telah menceritakan kepadaku [Abu Salamah] telah menceritakan kepadaku [Abu Hurairah], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang dibunuh sedang dia memiliki keluarga maka dia (bisa) memilih salah satu dari dua pandangan yang terbaik, dibalaskan untuknya atau diberi diyat.\""},"4488":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ بْنِ مَزْيَدَ قَالَ أَخْبَرَنِي أَبِي قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ قَالَ حَدَّثَنَا أَبُو هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قُتِلَ لَهُ قَتِيلٌ فَهُوَ بِخَيْرِ النَّظَرَيْنِ إِمَّا أَنْ يُقَادَ وَإِمَّا أَنْ يُفْدَى","id":"Telah menceritakan kepada kami [Al Abbas bin Al Walid bin Mazid] telah menceritakan kepadaku [ayahku] telah menceritakan kepada kami [Al Auza'I] telah menceritakan kepadaku [Yahya bin Abu Katsir] telah menceritakan kepadaku [Abu Salamah] telah menceritakan kepada kami [Abu Hurairah], dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang dibunuh sedang dia memiliki keluarga maka dia (bisa) memilih salah satu dari dua pandangan yang terbaik, dibalaskan untuknya atau diberi diyat.\""},"4489":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ بْنِ مُحَمَّدٍ قَالَ أَنْبَأَنَا ابْنُ عَائِذٍ قَالَ حَدَّثَنَا يَحْيَى هُوَ ابْنُ حَمْزَةَ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو سَلَمَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قُتِلَ لَهُ قَتِيلٌمُرْسَلٌ","id":"Telah menceritakan kepada kami [Ahmad bin Ibrahim bin Muhammad] telah menceritakan kepada kami [Ibnu 'Aidz] telah menceritakan kepada kami [Yahya yaitu Ibnu Hamzah] telah menceritakan kepada kami [Al Auza'I] telah menceritakan kepada kami [Yahya bin Abu Katsir] telah menceritakan kepadaku [Abu Salamah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang dibunuh sedang dia memiliki keluarga...\" secara mursal."},"4490":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا الْوَلِيدُ عَنْ الْأَوْزَاعِيِّ قَالَ حَدَّثَنِي حِصْنٌ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ ح وَأَنْبَأَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ حَدَّثَنَا الْوَلِيدُ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي حِصْنٌ أَنَّهُ سَمِعَ أَبَا سَلَمَةَ يُحَدِّثُ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَعَلَى الْمُقْتَتِلِينَ أَنْ يَنْحَجِزُوا الْأَوَّلَ فَالْأَوَّلَ وَإِنْ كَانَتْ امْرَأَةٌ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah menceritakan kepada kami [Al Walid] dari [Al Auza'I] telah menceritakan kepadaku [Hishn] telah menceritakan kepadaku [Abu Salamah]. Dalam jalur lain disebutkan: telah menceritakan kepada kami [Al Husain bin Huraits] telah menceritakan kepada kami [Al Walid] telah menceritakan kepadaku [Al Auza'I] telah menceritakan kepadaku [Hishn] bahwa dia mendengar [Abu Salamah] menceritakan dari ['Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \" Kepada keluarga pembunuh dan yang terbunuh hendaknya saling memaafkan masing-masing kerabatnya meskipun dia seorang wanita.\""},"4491":{"ar":"أَخْبَرَنَا هِلَالُ بْنُ الْعَلَاءِ بْنِ هِلَالٍ قَالَ حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ قَالَ أَنْبَأَنَا سُلَيْمَانُ بْنُ كَثِيرٍ قَالَ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قُتِلَ فِي عِمِّيَّا أَوْ رِمِّيَّا تَكُونُ بَيْنَهُمْ بِحَجَرٍ أَوْ سَوْطٍ أَوْ بِعَصًا فَعَقْلُهُ عَقْلُ خَطَإٍ وَمَنْ قَتَلَ عَمْدًا فَقَوَدُ يَدِهِ فَمَنْ حَالَ بَيْنَهُ وَبَيْنَهُ فَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ لَا يُقْبَلُ مِنْهُ صَرْفٌ وَلَا عَدْلٌ","id":"Telah menceritakan kepada kami [Hilal bin Al 'Ala` bin Hilal] telah menceritakan kepada kami [Sa'id bin Sulaiman] telah menceritakan kepada kami [Sulaiman bin Katsir] telah menceritakan kepada kami ['Amru bin Dinar] dari [Thawus] dari [Ibnu Abbas], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang terbunuh karena sesuatu yang tidak jelas atau menjadi sasaran lemparan batu, cambuk atau tongkat, maka diyatnya adalah diyat pembunuhan secara tidak sengaja, dan barangsiapa yang membunuh secara sengaja maka ia dibalas, barangsiapa yang menghalanginya maka dia akan mendapatkan laknat Allah, malaikat dan seluruh manusia. Tidak diterima darinya taubat ataupun fidyah.\""},"4492":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ كَثِيرٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍيَرْفَعُهُ قَالَ مَنْ قُتِلَ فِي عِمِّيَّةٍ أَوْ رِمِّيَّةٍ بِحَجَرٍ أَوْ سَوْطٍ أَوْ عَصًا فَعَقْلُهُ عَقْلُ الْخَطَإِ وَمَنْ قُتِلَ عَمْدًا فَهُوَ قَوَدٌ وَمَنْ حَالَ بَيْنَهُ وَبَيْنَهُ فَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ لَا يَقْبَلُ اللَّهُ مِنْهُ صَرْفًا وَلَا عَدْلًا","id":"Telah menceritakan kepada kami [Muhammad bin Ma'mar] telah menceritakan kepada kami [Muhammad bin Katsir] telah menceritakan kepada kami [Sulaiman bin Katsir] dari ['Amru bin Dinar] dari [Thawus] dari [Ibnu Abbas] dan dia memarfu'kannya, dia berkata; \"Barangsiapa yang terbunuh karena sesuatu yang tidak jelas atau menjadi sasaran lemparan batu, cambuk atau tongkat maka diyatnya adalah diyat pembunuhan secara tidak sengaja, dan barangsiapa yang membunuh secara sengaja maka ia dibalas, barangsiapa yang menghalanginya maka ia akan mendapatkan laknat Allah, malaikat dan seluruh manusia, Allah tidak menerima darinya taubat ataupun fidyah.\""},"4493":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَيُّوبَ السَّخْتِيَانِيِّ عَنْ الْقَاسِمِ بْنِ رَبِيعَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَتِيلُ الْخَطَإِ شِبْهِ الْعَمْدِ بِالسَّوْطِ أَوْ الْعَصَا مِائَةٌ مِنْ الْإِبِلِ أَرْبَعُونَ مِنْهَا فِي بُطُونِهَا أَوْلَادُهَا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abdur Rahman] telah menceritakan kepada kami [Syu'bah] dari [Ayyub As Sakhtiyani] dari [Al Qasim bin Rabi'ah] dari [Abdullah bin 'Amru] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda; \"Orang yang terbunuh karena tidak sengaja adalah mirip dengan orang yang terbunuh karena disiksa dengan cambuk, atau tongkat diyatnya adalah seratus unta, empat puluh di antaranya sedang bunting.\" "},"4494":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يُونُسُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ الْقَاسِمِ بْنِ رَبِيعَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ يَوْمَ الْفَتْحِمُرْسَلٌ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il bin Ibrahim] telah menceritakan kepada kami [Yunus] telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Al Qasim bin Rabi'ah] bahwa Rasulullah shallallahu 'alaihi wasallam berkhutbah pada saat penaklukan Mekkah. Hadits mursal."},"4495":{"ar":"أَخْبَرَنِي يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ قَالَ أَنْبَأَنَا حَمَّادٌ عَنْ خَالِدٍ يَعْنِي الْحَذَّاءَ عَنْ الْقَاسِمِ بْنِ رَبِيعَةَ عَنْ عُقْبَةَ بْنِ أَوْسٍ عَنْ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا وَإِنَّ قَتِيلَ الْخَطَإِ شِبْهِ الْعَمْدِ مَا كَانَ بِالسَّوْطِ وَالْعَصَا مِائَةٌ مِنْ الْإِبِلِ أَرْبَعُونَ فِي بُطُونِهَا أَوْلَادُهَا","id":"Telah menceritakan kepada kami [Yahya bin Habib bin 'Arabi] telah menceritakan kepada kami [Hammad] dari [Khalid yaitu Al Hadzdza`] dari [Al Qasim bin Rabi'ah] dari ['Uqbah bin Aus] dari [Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketahuilah sesungguhnya orang yang terbunuh karena tidak sengaja adalah mirip dengan orang yang terbunuh karena disiksa dengan cambuk, dan tongkat. Diyatnya adalah seratus ekor unta, empat puluh di antaranya sedang bunting.\""},"4496":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَامِلٍ قَالَ حَدَّثَنَا هُشَيْمٌ عَنْ خَالِدٍ عَنْ الْقَاسِمِ بْنِ رَبِيعَةَ عَنْ عُقْبَةَ بْنِ أَوْسٍ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَخَطَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فَتْحِ مَكَّةَ فَقَالَ أَلَا وَإِنَّ قَتِيلَ الْخَطَإِ شِبْهِ الْعَمْدِ بِالسَّوْطِ وَالْعَصَا وَالْحَجَرِ مِائَةٌ مِنْ الْإِبِلِ فِيهَا أَرْبَعُونَ ثَنِيَّةً إِلَى بَازِلِ عَامِهَا كُلُّهُنَّ خَلِفَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Kamil] telah menceritakan kepada kami [Husyaim] dari [Khalid] dari [Al Qasim bin Rabi'ah] dari ['Uqbah bin Aus] dari [seorang sahabat] Nabi shallallahu 'alaihi wasallam, dia berkata; Nabi shallallahu 'alaihi wasallam berkhutbah pada saat penaklukan Mekkah, kemudian beliau bersabda: \"Ingatlah, bahwa orang yang terbunuh karena tidak sengaja adalah mirip orang yang terbunuh karena disiksa dengan cambuk, tongkat, dan batu. Diyatnya adalah seratus ekor unta, padanya terdapat empat puluh ekor unta yang berumur enam hingga delapan tahun yang seluruhnya bunting.\" "},"4497":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ عَنْ ابْنِ أَبِي عَدِيٍّ عَنْ خَالِدٍ عَنْ الْقَاسِمِ عَنْ عُقْبَةَ بْنِ أَوْسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا إِنَّ قَتِيلَ الْخَطَإِ قَتِيلَ السَّوْطِ وَالْعَصَا فِيهِ مِائَةٌ مِنْ الْإِبِلِ مُغَلَّظَةٌ أَرْبَعُونَ مِنْهَا فِي بُطُونِهَا أَوْلَادُهَا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dari [Ibnu Abu 'Adi] dari [Khalid] dari [Al Qasim] dari ['Uqbah bin Aus] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketahuilah bahwa orang yang terbunuh karena ketidak sengajaan adalah mirip dengan orang yang terbunuh karena disiksa dengan cambuk dan tongkat, padanya terdapat diyat seratus ekor unta yang ditekankan, empat puluh di antaranya sedang bunting.\""},"4498":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ الْقَاسِمِ بْنِ رَبِيعَةَ عَنْ يَعْقُوبَ بْنِ أَوْسٍ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا دَخَلَ مَكَّةَ يَوْمَ الْفَتْحِ قَالَ أَلَا ��َإِنَّ كُلَّ قَتِيلِ خَطَإِ الْعَمْدِ أَوْ شِبْهِ الْعَمْدِ قَتِيلِ السَّوْطِ وَالْعَصَا مِنْهَا أَرْبَعُونَ فِي بُطُونِهَا أَوْلَادُهَا","id":"Telah menceritakan kepada kami [Isma'il bin Mas'ud] telah menceritakan kepada kami [Bisyr bin Al Mufadhdhal] dari [Khalid Al Hadzdza`] dari [Al Qasim bin Rabi'ah] dari [Ya'qub bin Aus] dari [seorang laki-laki] dari sahabat Nabi shallallahu 'alaihi wasallam bahwa Rasulullah shallallahu 'alaihi wasallam tatkala memasuki Mekkah pada saat penaklukan Mekkah bersabda: \"Ingatlah, Sesungguhnya orang yang terbunuh karena ketidak sengajaan atau yang mirip dengan terbunuh karena disiksa dengan cambuk dan tongkat, sebagian diyatnya adalah empat puluh ekor unta yang lagi bunting.\""},"4499":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ بَزِيعٍ قَالَ حَدَّثَنَا يَزِيدُ قَالَ حَدَّثَنَا خَالِدٌ عَنْ الْقَاسِمِ بْنِ رَبِيعَةَ عَنْ يَعْقُوبَ بْنِ أَوْسٍ أَنَّ رَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا قَدِمَ مَكَّةَ عَامَ الْفَتْحِ قَالَ أَلَا وَإِنَّ قَتِيلَ الْخَطَإِ الْعَمْدِ قَتِيلَ السَّوْطِ وَالْعَصَا مِنْهَا أَرْبَعُونَ فِي بُطُونِهَا أَوْلَادُهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Bazi'] telah menceritakan kepada kami [Yazid] telah menceritakan kepada kami [Khalid] dari [Al Qasim bin Rabi'ah] dari [Ya'qub bin Aus] bahwa [seorang laki-laki] dari sahabat Nabi shallallahu 'alaihi wasallam telah menceritakan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam ketika tiba di Mekkah pada saat penaklukan Mekkah, beliau bersabda: \"Ketahuilah, sesungguhnya orang yang terbunuh karena ketidak sengajaan adalah (seperti) orang yang terbunuh karena disiksa dengan cambuk dan tongkatSebagian diyatnya empat puluh ekor unta yang lagi bunting.\""},"4500":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ بَزِيعٍ قَالَ أَنْبَأَنَا يَزِيدُ عَنْ خَالِدٍ عَنْ الْقَاسِمِ بْنِ رَبِيعَةَ عَنْ يَعْقُوبَ بْنِ أَوْسٍ أَنَّ رَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ مَكَّةَ عَامَ الْفَتْحِ قَالَ أَلَا وَإِنَّ قَتِيلَ الْخَطَإِ الْعَمْدِ قَتِيلَ السَّوْطِ وَالْعَصَا مِنْهَا أَرْبَعُونَ فِي بُطُونِهَا أَوْلَادُهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Bazi'] telah menceritakan kepada kami [Yazid] dari [Khalid] dari [Al Qasim bin Rabi'ah] dari [Ya'qub bin Aus] bahwa [salah seorang sahabat] Nabi shallallahu 'alaihi wasallam bercerita kepadanya bahwa Nabi shallallahu 'alaihi wasallam datang ke Mekkah pada saat penaklukan Mekkah, beliau bersabda: \"Ketahuilah, sesungguhnya orang yang terbunuh karena ketidak sengajaan adalah (seperti) orang yang terbunuh (karena disiksa) dengan cambuk dan tongkat. Sebagian dari (diyat) nya adalah empat puluh ekor unta yang lagi bunting.\""}};
